-- Poems batch 435
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('yuding-15','閑園即事寄韋侍郎','蘇頲','唐','御定全唐诗','yuding','','[]','結廬東城下，直望江南山。青靄遠相接，白雲來複還。',72,'御定全唐詩/json/074.json','["結廬東城下，直望江南山。青靄遠相接，白雲來複還。", "拂筵紅蘚上，開幔綠條間。物應春偏好，情忘趣轉閑。", "憲臣饒美度，聯事惜徂顏。有酒空盈酌，高車不可攀。"]'),
('yuding-16','扈從溫泉同紫微黃門群公泛渭川得齊字','蘇頲','唐','御定全唐诗','yuding','','[]','虹旗映綠荑，春仗漢豐西。侍蹕浮清渭，揚舲降紫泥。',72,'御定全唐詩/json/074.json','["虹旗映綠荑，春仗漢豐西。侍蹕浮清渭，揚舲降紫泥。", "近臨鈞石地，遙指釣璜溪。岸轉帆飛疾，川平棹舉齊。", "傅舟來是用，軒馭往應迷。興闋菱歌動，沙洲亂夕鷖。"]'),
('yuding-17','餞趙尚書攝御史大夫赴朔方軍','蘇頲','唐','御定全唐诗','yuding','','[]','勁虜欲南窺，揚兵護朔陲。趙堯甯易印，鄧禹即分麾。',72,'御定全唐詩/json/074.json','["勁虜欲南窺，揚兵護朔陲。趙堯甯易印，鄧禹即分麾。", "野餞回三傑，軍謀用六奇。雲邊愁出塞，日下愴臨岐。", "拔劍行人舞，揮戈戰馬馳。明年麟閣上，充國畫於斯。"]'),
('yuding-18','曉發興州入陳平路','蘇頲','唐','御定全唐诗','yuding','','[]','旌節指巴岷，年年行且巡。暮來青嶂宿，朝去綠江春。',72,'御定全唐詩/json/074.json','["旌節指巴岷，年年行且巡。暮來青嶂宿，朝去綠江春。", "魚貫梁緣馬，猿奔樹息人。邑祠猶是漢，溪道即名陳。", "舊史饒遷謫，恒情厭苦辛。甯知報恩者，天子一忠臣。"]'),
('yuding-19','同餞陽將軍兼源州都督禦史中丞','蘇頲','唐','御定全唐诗','yuding','','[]','右地接龜沙，中朝任虎牙。然明方改俗，去病不為家。',72,'御定全唐詩/json/074.json','["右地接龜沙，中朝任虎牙。然明方改俗，去病不為家。", "將禮登壇盛，軍容出塞華。朔風搖漢鼓，邊馬思胡笳。", "旗合無邀正，冠危有觸邪。當看勞還日，及此禦溝花。"]'),
('yuding-20','扈從鳳泉和崔黃門喜恩旨解嚴罷圍之作','蘇頲','唐','御定全唐诗','yuding','','[]','輦路岐山曲，儲胥渭水湄。教成提將鼓，禮備植虞旗。',72,'御定全唐詩/json/074.json','["輦路岐山曲，儲胥渭水湄。教成提將鼓，禮備植虞旗。", "不取從畋樂，先流去殺慈。舜韶同舞日，湯祝盡飛時。", "物應陽和施，人知雨露私。何如穆天子，七萃幾勞師。"]'),
('yuding-21','秋夜寓直中書呈黃門舅','蘇頲','唐','御定全唐诗','yuding','','[]','簾櫳上夜鉤，清列聽更籌。忽共雞枝老，還如騎省秋。',84,'御定全唐詩/json/074.json','["簾櫳上夜鉤，清列聽更籌。忽共雞枝老，還如騎省秋。", "循庭喜三入，對渚憶雙遊。紫紱名初拜，黃縑跡尚留。", "月舒當北幌，雲賦直東樓。恩渥迷天施，童蒙慰我求。", "遲君台鼎節，聞義一承流。"]'),
('yuding-22','先是新昌小園期京兆尹一訪兼郎官數子自頃沉屙年復一年茲願不果率然成章','蘇頲','唐','御定全唐诗','yuding','','[]','獨好中林隱，先期上月春。閑花傍戶落，喧鳥逼簷馴。',96,'御定全唐詩/json/074.json','["獨好中林隱，先期上月春。閑花傍戶落，喧鳥逼簷馴。", "寂寞東坡叟，傳呼北裏人。在山琴易調，開甕酒歸醇。", "佇望應三接，彌留忽幾旬。不疑丹火變，空負綠條新。", "鬥蟻聞常日，歌龍值此辰。其如眾君子，嘉會阻清塵。"]'),
('yuding-23','奉和馬常侍寺中之作','蘇頲','唐','御定全唐诗','yuding','','[]','怨暑時雲謝，愆陽澤暫偏。鼎陳從祀日，鑰動問刑年。',120,'御定全唐詩/json/074.json','["怨暑時雲謝，愆陽澤暫偏。鼎陳從祀日，鑰動問刑年。", "絳服龍雩寢，玄冠馬使旋。作霖期傅說，為旱聽周宣。", "河岳陰符啟，星辰暗檄傳。浮涼吹景氣，飛動灑空煙。", "颯颯將秋近，沉沉與暝連。分湍涇水石，合穎雍州田。", "德施超三五，文雄賦十千。及斯何以樂，明主敬人天。"]'),
('yuding-24','慈恩寺二月半寓言','蘇頲','唐','御定全唐诗','yuding','','[]','二月韶春半，三空霽景初。獻來應有受，滅盡竟無餘。',120,'御定全唐詩/json/074.json','["二月韶春半，三空霽景初。獻來應有受，滅盡竟無餘。", "化跡傳官寺，歸誠謁梵居。殿堂花覆席，觀閣柳垂疏。", "共命枝間鳥，長生水上魚。問津窺彼岸，迷路得真車。", "行密幽關靜，談精俗態祛。稻麻欣所遇，蓬籜愴焉如。", "不駐秦京陌，還題蜀郡輿。愛離方自此，回望獨躕躇。"]'),
('yuding-25','餞澤州盧使君赴任','蘇頲','唐','御定全唐诗','yuding','','[]','聞道降綸書，為邦建彩旟。政憑循吏往，才以貴卿除。',120,'御定全唐詩/json/074.json','["聞道降綸書，為邦建彩旟。政憑循吏往，才以貴卿除。", "詞賦良無敵，聲華藹有餘。榮承四嶽後，請絕五天初。", "關路通秦壁，城池接晉墟。撰期行子賦，分典列侯居。", "別望喧追餞，離言系慘舒。平蕪寒蛩亂，喬木夜蟬疏。", "寥泬秋先起，推移月向諸。舊交何以贈，客至待烹魚。"]'),
('yuding-26','陳倉別隴州司戶李維深','蘇頲','唐','御定全唐诗','yuding','','[]','京國自攜手，同途欣解頤。情言正的的，春物宛遲遲。',120,'御定全唐詩/json/074.json','["京國自攜手，同途欣解頤。情言正的的，春物宛遲遲。", "忽背雕戎役，旋瞻獲寶祠。蜀城余出守，吳嶽爾歸思。", "歡愜更傷此，眷殷殊念茲。揚麾北林徑，跂石南澗湄。", "中作壺觴餞，回添道路悲。數花臨磴日，百草覆田時。", "有美同人意，無為行子辭。酣歌拔劍起，毋是答恩私。"]'),
('yuding-27','奉和崔尚書贈大理陸卿鴻臚劉卿見示之作','蘇頲','唐','御定全唐诗','yuding','','[]','戲藻嘉魚樂，棲梧見鳳飛。類從皆有召，聲應乃無違。',144,'御定全唐詩/json/074.json','["戲藻嘉魚樂，棲梧見鳳飛。類從皆有召，聲應乃無違。", "美價逢時出，奇才選眾稀。避堂貽後政，掃第發前幾。", "出曳仙人履，還熏侍女衣。省中何赫奕，庭際滿芳菲。", "吏部端清鑒，丞郎肅紫機。會心歌詠是，回跡宴言非。", "北寺鄰玄闕，南城寫翠微。參差交隱見，仿佛接光輝。", "賓序嘗柔德，刑孚已霽威。巨源林下契，不速自同歸。"]'),
('yuding-28','敬和崔尚書大明朝堂雨後望終南山見示之作','蘇頲','唐','御定全唐诗','yuding','','[]','奕奕輕車至，清晨朝未央。未央在霄極，中路視咸陽。',168,'御定全唐詩/json/074.json','["奕奕輕車至，清晨朝未央。未央在霄極，中路視咸陽。", "委曲漢京近，周回秦塞長。日華動涇渭，天翠合岐梁。", "五丈旌旗色，百層枌橑光。東連歸馬地，南指鬥雞場。", "晴壑照金戺，秋雲含璧璫。由余窺霸國，蕭相奉興王。", "功役隱不見，頌聲存複揚。權宜珍構絕，聖作寶圖昌。", "在德期巢燧，居安法禹湯。塚卿才順美，多士賦成章。", "價重三台俊，名超百郡良。焉知掖垣下，陳力自迷方。"]'),
('yuding-29','夜聞故梓州韋使君明當引紼感而成章','蘇頲','唐','御定全唐诗','yuding','','[]','惻矣南鄰問，冥然東岱幽。裏閈寧相杵，朝歎忽遷舟。',144,'御定全唐詩/json/074.json','["惻矣南鄰問，冥然東岱幽。裏閈寧相杵，朝歎忽遷舟。", "君心惟伯仲，吾人複款遊。對連時亦早，交喜歲才周。", "序發扶陽贈，文因司寇酬。詎期危露盡，相續逝川流。", "臥疾無三吊，居閑有百憂。振風吟鼓夕，明月照帷秋。", "蘚駁題詩館，楊疏奏伎樓。共將歌笑歎，轉為弟兄留。", "感物存如夢，觀生去若浮。餘非忘情者，雪涕報林丘。"]'),
('yuding-30','禦箭連中雙兔','蘇頲','唐','御定全唐诗','yuding','','[]','宸游經上苑，羽獵向閒田。狡兔初迷窟，纖驪詎著鞭。',72,'御定全唐詩/json/074.json','["宸游經上苑，羽獵向閒田。狡兔初迷窟，纖驪詎著鞭。", "三驅仍百步，一發遂雙連。影射含霜草，魂消向月弦。", "歡聲動寒木，喜氣滿晴天。那似陳王意，空隨樂府篇。"]'),
('yuding-31','奉和聖制過潼津關','蘇頲','唐','御定全唐诗','yuding','','[]','在德何夷險，觀風複往還。自能同善閉，中路可無關。',24,'御定全唐詩/json/074.json','["在德何夷險，觀風複往還。自能同善閉，中路可無關。"]'),
('yuding-32','山鷓鴣詞二首','蘇頲','唐','御定全唐诗','yuding','','[]','玉關征戍久，空閨人獨愁。寒露濕青苔，別來蓬鬢秋。',48,'御定全唐詩/json/074.json','["玉關征戍久，空閨人獨愁。寒露濕青苔，別來蓬鬢秋。", "人坐青樓晚，鶯語百花時。愁多人易老，斷腸君不知。"]'),
('yuding-33','汾上驚秋','蘇頲','唐','御定全唐诗','yuding','','[]','北風吹白雲，萬里渡河汾。心緒逢搖落，秋聲不可聞。',24,'御定全唐詩/json/074.json','["北風吹白雲，萬里渡河汾。心緒逢搖落，秋聲不可聞。"]'),
('yuding-34','山驛閑臥即事','蘇頲','唐','御定全唐诗','yuding','','[]','息燕歸簷靜，飛花落院閑。不愁愁自著，誰道憶鄉關。',24,'御定全唐詩/json/074.json','["息燕歸簷靜，飛花落院閑。不愁愁自著，誰道憶鄉關。"]'),
('yuding-35','將赴益州題小園壁','蘇頲','唐','御定全唐诗','yuding','','[]','歲窮惟益老，春至卻辭家。可惜東園樹，無人也作花。',24,'御定全唐詩/json/074.json','["歲窮惟益老，春至卻辭家。可惜東園樹，無人也作花。"]'),
('yuding-36','詠禮部尚書廳後鵲','蘇頲','唐','御定全唐诗','yuding','','[]','懷印喜將歸，窺巢戀且依。自知棲不定，還欲向南飛。',24,'御定全唐詩/json/074.json','["懷印喜將歸，窺巢戀且依。自知棲不定，還欲向南飛。"]'),
('yuding-37','詠死兔','蘇頲','唐','御定全唐诗','yuding','','[]','兔子死蘭彈，持來掛竹竿。試將明鏡照，何異月中看。',24,'御定全唐詩/json/074.json','["兔子死蘭彈，持來掛竹竿。試將明鏡照，何異月中看。"]'),
('yuding-38','夜宴安樂公主新宅','蘇頲','唐','御定全唐诗','yuding','','[]','車如流水馬如龍，仙史高臺十二重。',32,'御定全唐詩/json/074.json','["車如流水馬如龍，仙史高臺十二重。", "天上初移衡漢匹，可憐歌舞夜相從。"]'),
('yuding-39','侍宴桃花園詠桃花應制','蘇頲','唐','御定全唐诗','yuding','','[]','桃花灼灼有光輝，無數成蹊點更飛。',32,'御定全唐詩/json/074.json','["桃花灼灼有光輝，無數成蹊點更飛。", "為見芳林含笑待，遂同溫樹不言歸。"]'),
('yuding-40','奉和聖制幸韋嗣立莊應制','蘇頲','唐','御定全唐诗','yuding','','[]','樹色參差隱翠微，泉流百尺向空飛。',32,'御定全唐詩/json/074.json','["樹色參差隱翠微，泉流百尺向空飛。", "傳聞此處投竿住，遂使茲辰扈蹕歸。"]'),
('yuding-41','重送舒公','蘇頲','唐','御定全唐诗','yuding','','[]','散騎金貂服彩衣，松花水上逐春歸。',32,'御定全唐詩/json/074.json','["散騎金貂服彩衣，松花水上逐春歸。", "懸知邑裏遙相望，事主榮親代所稀。"]'),
('yuding-42','句','蘇頲','唐','御定全唐诗','yuding','','[]','飛埃結紅霧，游蓋飄青雲。',44,'御定全唐詩/json/074.json','["飛埃結紅霧，游蓋飄青雲。", "指如十挺墨，耳似兩張匙。", "醜雖有足，甲不全身。見君無口，知伊少人。"]'),
('yuding-0','龍池篇','薑晞','唐','御定全唐诗','yuding','','[]','靈沼縈回邸第前，浴日涵春寫曙天。始見龍台升鳳闕，',40,'御定全唐詩/json/075.json','["靈沼縈回邸第前，浴日涵春寫曙天。始見龍台升鳳闕，", "欲化帝圖從此受，正同河變一千年。"]'),
('yuding-1','龍池篇','姜皎','唐','御定全唐诗','yuding','','[]','龍池初出此龍山，常經此地謁龍顏。日日芙蓉生夏水，',40,'御定全唐詩/json/075.json','["龍池初出此龍山，常經此地謁龍顏。日日芙蓉生夏水，", "願似飄颻五雲影，從來從去九天關。"]'),
('yuding-2','奉和聖制龍池篇','蔡孚','唐','御定全唐诗','yuding','','[]','帝宅王家大道邊，神馬潛龍湧聖泉。昔日昔時經此地，',40,'御定全唐詩/json/075.json','["帝宅王家大道邊，神馬潛龍湧聖泉。昔日昔時經此地，", "莫疑波上春雲少，只為從龍直上天。"]'),
('yuding-3','打球篇','蔡孚','唐','御定全唐诗','yuding','','[]','德陽宮北苑東頭，雲作高臺月作樓。金錘玉鎣千金地，',72,'御定全唐詩/json/075.json','["德陽宮北苑東頭，雲作高臺月作樓。金錘玉鎣千金地，", "容色由來荷恩顧，意氣平生事俠游。共道用兵如斷蔗，", "奔星亂下花場裏，初月飛來畫杖頭。自有長鳴須決勝，"]'),
('yuding-4','阮公體','徐晶','唐','御定全唐诗','yuding','','[]','秦王按劍怒，發卒戍龍沙。雄圖尚未畢，海內已紛拏。',48,'御定全唐詩/json/075.json','["秦王按劍怒，發卒戍龍沙。雄圖尚未畢，海內已紛拏。", "黃塵暗天起，白日斂精華。唯見長城外，僵屍如亂麻。"]'),
('yuding-5','同蔡孚五亭詠','徐晶','唐','御定全唐诗','yuding','','[]','章奏中京罷，雲泉別業歸。拂琴鋪野席，牽柳掛朝衣。',48,'御定全唐詩/json/075.json','["章奏中京罷，雲泉別業歸。拂琴鋪野席，牽柳掛朝衣。", "翡翠巢書幌，鴛鴦立釣磯。幽棲可憐處，春事滿林扉。"]'),
('yuding-6','蔡起居山亭','徐晶','唐','御定全唐诗','yuding','','[]','文史歸休日，棲閑臥草亭。薔薇一架紫，石竹數重青。',48,'御定全唐詩/json/075.json','["文史歸休日，棲閑臥草亭。薔薇一架紫，石竹數重青。", "垂露和仙藥，燒香誦道經。莫將山水弄，持與世人聽。"]'),
('yuding-7','送友人尉蜀中','徐晶','唐','御定全唐诗','yuding','','[]','故友漢中尉，請為西蜀吟。人家多種橘，風土愛彈琴。',48,'御定全唐詩/json/075.json','["故友漢中尉，請為西蜀吟。人家多種橘，風土愛彈琴。", "水向昆明闊，山連大夏深。理閑無別事，時寄一登臨。"]'),
('yuding-8','贈溫駙馬汝陽王','徐晶','唐','御定全唐诗','yuding','','[]','疇昔承餘論，文章幸濫推。夜陪銀漢賞，朝奉桂山詞。',120,'御定全唐詩/json/075.json','["疇昔承餘論，文章幸濫推。夜陪銀漢賞，朝奉桂山詞。", "梁邸調歌日，秦樓按舞時。登高頻作賦，體物屢為詩。", "連騎長楸下，浮觴曲水湄。北堂留上客，南陌送佳期。", "憶昨陪臨泛，於今阻宴私。再看冬雪滿，三見夏花滋。", "都尉朝青閣，淮王侍紫墀。甯知倦游者，華髮老京師。"]'),
('yuding-9','邊詞','張敬忠','唐','御定全唐诗','yuding','','[]','五原春色舊來遲，二月垂楊未掛絲。',32,'御定全唐詩/json/075.json','["五原春色舊來遲，二月垂楊未掛絲。", "即今河畔冰開日，正是長安花落時。"]'),
('yuding-10','戲詠','張敬忠','唐','御定全唐诗','yuding','','[]','有意嫌兵部，專心望考功。誰知腳蹭蹬，幾落省牆東。',24,'御定全唐詩/json/075.json','["有意嫌兵部，專心望考功。誰知腳蹭蹬，幾落省牆東。"]'),
('yuding-11','題巴州光福寺楠木','史俊','唐','御定全唐诗','yuding','','[]','近郭城南山寺深，亭亭奇樹出禪林。結根幽壑不知歲，',64,'御定全唐詩/json/075.json','["近郭城南山寺深，亭亭奇樹出禪林。結根幽壑不知歲，", "經行綠葉望成蓋，宴坐黃花長滿襟。此木嘗聞生豫章，", "會待良工時一眄，應歸法水作慈航。"]'),
('yuding-0','儀坤廟樂章：永和','徐彥伯','唐','御定全唐诗','yuding','','[]','猗若清廟，肅肅熒熒。國薦嚴祀，坤興淑靈。',40,'御定全唐詩/json/076.json','["猗若清廟，肅肅熒熒。國薦嚴祀，坤興淑靈。", "有幾在室，有樂在庭。臨茲孝享，百祿惟寧。"]'),
('yuding-1','儀坤廟樂章：金奏','徐彥伯','唐','御定全唐诗','yuding','','[]','陰靈效祉，軒曜降精。祥符淑氣，慶集柔明。',40,'御定全唐詩/json/076.json','["陰靈效祉，軒曜降精。祥符淑氣，慶集柔明。", "瑤俎既列，雕桐發聲。徽猷永遠，比德皇英。"]'),
('yuding-2','擬古三首','徐彥伯','唐','御定全唐诗','yuding','','[]','遙裔煙嶼鴻，雙影旦夕同。交翰倚沙月，和鳴弄江風。',361,'御定全唐詩/json/076.json','["遙裔煙嶼鴻，雙影旦夕同。交翰倚沙月，和鳴弄江風。", "vK若茂芳序，君子從遠戎。雲生陰海沒，花落春潭空。", "紅淚掩促柱，錦衾羅熏籠。自傷瓊草綠，詎惜鉛粉紅。", "裂帛附雙燕，為予向遼東。", "讀書三十載，馳騖週六經。儒衣幹時主，忠策獻闕廷。", "一朝奉休盼，從容廁群英。束身趨建禮，秉筆坐承明。", "廨署相填噎，僚吏紛縱橫。五日休浣時，屠蘇繞玉屏。", "橘花覆北沼，桂樹交西榮。樹棲兩鴛鴦，含春向我鳴。", "皎潔綺羅豔，便娟絲管清。擾擾天地間，出處各有情。", "何必岩石下，枯槁閑此生。", "頹光無淹晷，逝水有迅流。綠苔紛易歇，紅顏不再求。", "歌笑當及春，無令壯志秋。弱年仕關輔，簃門豁禦溝。", "敷愉東城際，婉孌南陌頭。荷花嬌綠水，楊葉暖青樓。", "中有綺羅人，可憐名莫愁。畫屏繞金膝，珠簾懸玉鉤。", "纖指調寶琴，泠泠哀且柔。贈君鴛鴦帶，因以鷫鸘裘。", "窗曉吟日坐，閨夕秉燭遊。無作北門客，咄咄懷百憂。"]'),
('yuding-3','贈劉舍人古意','徐彥伯','唐','御定全唐诗','yuding','','[]','女床閟靈鳥，文章世所希。巢君碧梧樹，舞君青瑣闈。',108,'御定全唐詩/json/076.json','["女床閟靈鳥，文章世所希。巢君碧梧樹，舞君青瑣闈。", "或言鳳池樂，撫翼更西飛。鳳池環禁林，仙閣靄沉沉。", "璿題激流日，珠綴綿清陰。郁穆絲言重，熒煌台座深。", "風張丹戺翮，月弄紫庭音。眾彩結不散，孤英跂莫尋。", "浩歌在西省，經傳恣潛心。"]'),
('yuding-4','和李適答宋十一入崖口五渡見贈','徐彥伯','唐','御定全唐诗','yuding','','[]','聞有獨往客，拂衣捐世心。結欣薄枉渚，撰念縈舊林。',120,'御定全唐詩/json/076.json','["聞有獨往客，拂衣捐世心。結欣薄枉渚，撰念縈舊林。", "經亙去崖合，冥綿歸壑深。琪樹環碧彩，金潭生翠陰。", "沿洄弄沙榜，詭仄眺明岑。夕聞桂裏猿，曉玩松上禽。", "雜佩蘊孤袖，瓊敷綴雙襟。我懷滄洲想，懿爾白雲吟。", "秉願理方協，存期跡易尋。茲言庶不負，為報岩中琴。"]'),
('yuding-5','雪','徐彥伯','唐','御定全唐诗','yuding','','[]','雪暗窮海雲，灑空紛似露。朔風吹故里，宛轉玉階樹。',48,'御定全唐詩/json/076.json','["雪暗窮海雲，灑空紛似露。朔風吹故里，宛轉玉階樹。", "孤妾調玉瑟，早寒生錦衿。況君張羅幕，愁坐北庭陰。"]'),
('yuding-6','比干墓','徐彥伯','唐','御定全唐诗','yuding','','[]','大位天下寶，維賢國之鎮。殷道微而在，受辛纂頹胤。',264,'御定全唐詩/json/076.json','["大位天下寶，維賢國之鎮。殷道微而在，受辛纂頹胤。", "山鳴鬼又哭，地裂川亦震。媟黷皆佞諛，虔劉盡英雋。", "孤卿帝叔父，特進貞而順。玉床逾皓潔，銅柱方歊焮。", "奉國曆三朝，觀竅明一瞬。季代倡狂主，蓄怒提白刃。", "之子彌忠讜，憤然更勇進。撫膺誓隕越，知死故不吝。", "已矣竟剖心，哲婦亦同殉。驪龍暴雙骨，太嶽摧孤仞。", "周發次商郊，冤骸悲莫殣。鋒劍剿遺孽，報復一何迅。", "駐罕歌淑靈，命徒封旅櫬。自爾銜幽酷，于嗟流景駿。", "丘墳被宿莽，壇戺緣飛磷。貞觀戒北征，維皇念忠信。", "荒墳護草木，刻桷吹煨燼。代遠恩更崇，身頹名益振。", "帝詞書樂石，國饌羅芳釁。偉哉烈士圖，奇英千古徇。"]'),
('yuding-7','題東山子李適碑陰二首','徐彥伯','唐','御定全唐诗','yuding','','[]','隴嶂縈紫氣，金光赫氛氳。美人含遙靄，桃李芳自熏。',96,'御定全唐詩/json/076.json','["隴嶂縈紫氣，金光赫氛氳。美人含遙靄，桃李芳自熏。", "圖高黃鶴羽，寶奪驪龍群。忽驚薤露曲，掩噎東山雲。", "回也實夭折，賈生亦脆促。今複哀若人，危光迅風燭。", "夜台淪清鏡，窮塵埋結綠。何以贈下泉，生芻唯一束。"]'),
('yuding-8','淮亭吟','徐彥伯','唐','御定全唐诗','yuding','','[]','貞寂慮兮淮山幽，憐芳若兮攬中洲。崩湍委咽日夜流，',82,'御定全唐詩/json/076.json','["貞寂慮兮淮山幽，憐芳若兮攬中洲。崩湍委咽日夜流，", "熠耀飛兮蟋蟀吟，倚清瑟兮橫涼琴。擷瑤芳兮吊楚水，", "金光延起兮驟興沒，青苔竟兮綠蘋歇。", "綠蘋歇兮凋朱顏，美人寂曆兮何時閑，"]'),
('yuding-9','芳樹','徐彥伯','唐','御定全唐诗','yuding','','[]','玉花珍簟上，金縷畫屏開。曉月憐箏柱，春風憶鏡臺。',48,'御定全唐詩/json/076.json','["玉花珍簟上，金縷畫屏開。曉月憐箏柱，春風憶鏡臺。", "箏柱春風吹曉月，芳樹落花朝暝歇。稿砧刀頭未有期，"]'),
('yuding-10','游禁苑幸臨渭亭遇雪應制','徐彥伯','唐','御定全唐诗','yuding','','[]','玉律藏冰候，彤階飛雪時。日寒消不盡，風定舞還遲。',48,'御定全唐詩/json/076.json','["玉律藏冰候，彤階飛雪時。日寒消不盡，風定舞還遲。", "瓊樹留宸矚，璿花入睿詞。懸知穆天子，黃竹謾言詩。"]'),
('yuding-11','奉和送金城公主適西蕃應制','徐彥伯','唐','御定全唐诗','yuding','','[]','鳳扆憐簫曲，鸞閨念掌珍。羌庭遙築館，廟策重和親。',48,'御定全唐詩/json/076.json','["鳳扆憐簫曲，鸞閨念掌珍。羌庭遙築館，廟策重和親。", "星轉銀河夕，花移玉樹春。聖心淒送遠，留蹕望征塵。"]'),
('yuding-12','幸白鹿觀應制','徐彥伯','唐','御定全唐诗','yuding','','[]','鳳輿乘八景，龜籙向三仙。日月移平地，雲霞綴小天。',48,'御定全唐詩/json/076.json','["鳳輿乘八景，龜籙向三仙。日月移平地，雲霞綴小天。", "金童擎紫藥，玉女獻青蓮。花洞留宸賞，還旗繞夕煙。"]'),
('yuding-13','胡無人行','徐彥伯','唐','御定全唐诗','yuding','','[]','十月繁霜下，征人遠鑿空。雲搖錦車節，海照角端弓。',48,'御定全唐詩/json/076.json','["十月繁霜下，征人遠鑿空。雲搖錦車節，海照角端弓。", "暗磧埋沙樹，沖飆卷塞蓬。方隨膜拜入，歌舞玉門中。"]'),
('yuding-14','婕妤','徐彥伯','唐','御定全唐诗','yuding','','[]','君恩忽斷絕，妾思終未央。巾櫛不可見，枕席空餘香。',48,'御定全唐詩/json/076.json','["君恩忽斷絕，妾思終未央。巾櫛不可見，枕席空餘香。", "窗暗網羅白，階秋苔蘚黃。應門寂已閉，流涕向昭陽。"]'),
('yuding-15','採蓮曲','徐彥伯','唐','御定全唐诗','yuding','','[]','妾家越水邊，搖艇入江煙。既覓同心侶，複采同心蓮。',48,'御定全唐詩/json/076.json','["妾家越水邊，搖艇入江煙。既覓同心侶，複采同心蓮。", "折藕絲能脆，開花葉正圓。春歌弄明月，歸棹落花前。"]'),
('yuding-16','孤燭歎','徐彥伯','唐','御定全唐诗','yuding','','[]','切切夜閨冷，微微孤燭然。玉盤紅淚滴，金燼彩光圓。',48,'御定全唐詩/json/076.json','["切切夜閨冷，微微孤燭然。玉盤紅淚滴，金燼彩光圓。", "暖手縫輕素，嚬蛾續斷弦。相思咽不語，回向錦屏眠。"]'),
('yuding-17','閨怨','徐彥伯','唐','御定全唐诗','yuding','','[]','征客戍金微，愁閨獨掩扉。塵埃生半榻，花絮落殘機。',48,'御定全唐詩/json/076.json','["征客戍金微，愁閨獨掩扉。塵埃生半榻，花絮落殘機。", "褪暖蠶初臥，巢昏燕欲歸。春風日向盡，銜涕作征衣。"]'),
('yuding-18','餞唐州高使君赴任','徐彥伯','唐','御定全唐诗','yuding','','[]','香萼媚紅滋，垂條縈綠絲。情人拂瑤袂，共惜此芳時。',48,'御定全唐詩/json/076.json','["香萼媚紅滋，垂條縈綠絲。情人拂瑤袂，共惜此芳時。", "驌驦已躑躅，鳥隼方葳蕤。跂予望太守，流潤及京師。"]'),
('yuding-19','奉和幸新豐溫泉宮應制','徐彥伯','唐','御定全唐诗','yuding','','[]','姬典歌時邁，虞篇記省方。何如黑帝月，玄覽白雲鄉。',156,'御定全唐詩/json/076.json','["姬典歌時邁，虞篇記省方。何如黑帝月，玄覽白雲鄉。", "翠仗縈船岸，明旆應萯陽。風搖花眊彩，雪豔寶戈芒。", "禦陌開函次，離宮夾樹行。桂枝籠騕褭，松葉覆堂皇。", "仙石含珠液，溫池孕璧房。湧疑神瀵溢，澄若帝台漿。", "獨沸流常熱，潛蒸氣轉香。青壇環玉甃，紅礎鑠金光。", "藻曜凝芳潔，葳蕤獻淑祥。五龍歸寶算，九扈葉時康。", "同預華封老，中衢祝聖皇。"]'),
('yuding-20','同韋舍人元旦早朝','徐彥伯','唐','御定全唐诗','yuding','','[]','夕轉清壺漏，晨驚長樂鐘。逶迤綸禁客，假寐守銅龍。',72,'御定全唐詩/json/076.json','["夕轉清壺漏，晨驚長樂鐘。逶迤綸禁客，假寐守銅龍。", "予亦趨三殿，肩隨謁九重。繁珂接曙響，華劍比春容。", "相問韶光歇，彌憐芳意濃。願言乘日旰，攜手即雲峰。"]'),
('yuding-21','侍宴韋嗣立山莊應制','徐彥伯','唐','御定全唐诗','yuding','','[]','鼎臣休浣隙，方外結遙心。別業青霞境，孤潭碧樹林。',96,'御定全唐詩/json/076.json','["鼎臣休浣隙，方外結遙心。別業青霞境，孤潭碧樹林。", "每馳東墅策，遙弄北溪琴。帝眷紓時豫，台園賞歲陰。", "移鑾明月沼，張組白雲岑。禦酒瑤觴落，仙壇竹徑深。", "三光懸聖藻，五等冠朝簪。自昔皇恩感，咸言獨自今。"]'),
('yuding-22','送特進李嶠入都袝廟','徐彥伯','唐','御定全唐诗','yuding','','[]','特進三公下，台臣百揆先。孝圖開寢石，祠主蔔牲筵。',96,'御定全唐詩/json/076.json','["特進三公下，台臣百揆先。孝圖開寢石，祠主蔔牲筵。", "恩級青綸賜，徂裝紫橐懸。綢繆金鼎席，宴餞玉潢川。", "北斗分征路，東山起贈篇。樂池歌綠藻，梁苑藉紅荃。", "騎轉商岩日，旌搖關塞煙。廟堂須鯁議，錦節佇來旋。"]'),
('yuding-23','春閨','徐彥伯','唐','御定全唐诗','yuding','','[]','戍客戍清波，幽閨幽思多。暗梁聞語燕，夜燭見飛蛾。',72,'御定全唐詩/json/076.json','["戍客戍清波，幽閨幽思多。暗梁聞語燕，夜燭見飛蛾。", "寶鴨藏脂粉，金屏綴綺羅。裁衣卷紋素，織錦度鳴梭。", "有使通西極，緘書寄北河。年光只恐盡，征戰莫蹉跎。"]'),
('yuding-24','奉和興慶池戲競渡應制','徐彥伯','唐','御定全唐诗','yuding','','[]','夾道傳呼翊翠虯，天回日轉禦芳洲。青潭曉靄籠仙蹕，',40,'御定全唐詩/json/076.json','["夾道傳呼翊翠虯，天回日轉禦芳洲。青潭曉靄籠仙蹕，", "群臣相慶嘉魚樂，共哂橫汾歌吹秋。"]'),
('yuding-25','苑中遇雪應制','徐彥伯','唐','御定全唐诗','yuding','','[]','千鐘聖酒禦筵披，六出祥英亂繞枝。',32,'御定全唐詩/json/076.json','["千鐘聖酒禦筵披，六出祥英亂繞枝。", "即此神仙對瓊圃，何煩轍跡向瑤池。"]'),
('yuding-26','上巳日祓禊渭濱應制','徐彥伯','唐','御定全唐诗','yuding','','[]','晴風麗日滿芳洲，柳色春筵祓錦流。',32,'御定全唐詩/json/076.json','["晴風麗日滿芳洲，柳色春筵祓錦流。", "皆言侍蹕橫汾宴，暫似乘槎天漢遊。"]'),
('yuding-27','夜宴安樂公主新宅應制','徐彥伯','唐','御定全唐诗','yuding','','[]','鳳樓開闔引明光，花酎連添醉益香。',32,'御定全唐詩/json/076.json','["鳳樓開闔引明光，花酎連添醉益香。", "欲知帝女熏天貴，金柯玉柱夜成行。"]'),
('yuding-28','餞唐永昌','徐彥伯','唐','御定全唐诗','yuding','','[]','金溪碧水玉潭沙，鳧舄翩翩弄日華。',32,'御定全唐詩/json/076.json','["金溪碧水玉潭沙，鳧舄翩翩弄日華。", "鬥雞香陌行春倦，為摘東園桃李花。"]'),
('yuding-29','侍宴桃花園','徐彥伯','唐','御定全唐诗','yuding','','[]','源水叢花無數開，丹跗紅萼間青梅。',32,'御定全唐詩/json/076.json','["源水叢花無數開，丹跗紅萼間青梅。", "從今結子三千歲，預喜仙遊複摘來。"]'),
('yuding-30','石淙','徐彥伯','唐','御定全唐诗','yuding','','[]','碧澱紅涔崿嶂間，淙嵌洑岨洊成灣。琪樹璿娟花未落，',40,'御定全唐詩/json/076.json','["碧澱紅涔崿嶂間，淙嵌洑岨洊成灣。琪樹璿娟花未落，", "張蔦席雲平圃宴，焜煌金記蘊名山。"]'),
('yuding-0','夏日游德州贈高四','駱賓王','唐','御定全唐诗','yuding','','[]','日觀鄰全趙，星臨俯舊吳。鬲津開巨浸，稽阜鎮名都。',576,'御定全唐詩/json/077.json','["日觀鄰全趙，星臨俯舊吳。鬲津開巨浸，稽阜鎮名都。", "紫雲浮劍匣，青山孕寶符。封疆恢霸道，問鼎競雄圖。", "神光包四大，皇威震八區。風煙通地軸，星象正天樞。", "天樞限南北，地軸殊鄉國。辟門通舜賓，比屋封堯德。", "言謝垂鉤隱，來參負鼎職。天子不見知，群公詎相識。", "未展從東駿，空戢圖南翼。時命欲何言，撫膺長歎息。", "歎息將如何，遊人意氣多。白雪梁山曲，寒風易水歌。", "泣魏傷吳起，思趙切廉頗。淒斷韓王劍，生死翟公羅。", "羅悲翟公意，劍負韓王氣。驕餌去易論，忌途良可畏。", "夙昔懷江海，平生混涇渭。千載契風雲，一言忘賤貴。", "去去訪林泉，空穀有遺賢。言投爵裏刺，來泛野人船。", "締交君贈縞，投分我忘筌。成風郢匠斫，流水伯牙弦。", "牙弦忘道術，漳濱恣閒逸。聊安張蔚廬，詎掃陳蕃室。", "虛室狎招尋，敬愛混浮沉。一諾黃金信，三複白珪心。", "霜松貞雅節，月桂朗沖襟。靈台萬頃浚，學府九流深。", "談玄明毀璧，拾紫陋籝金。鷺濤開碧海，鳳彩綴詞林。", "林虛星華映，水澈霞光淨。霞水兩分紅，川源四望通。", "霧卷天山靜，煙銷太史空。鳥聲流向薄，蝶影亂芳叢。", "柳陰低槧水，荷氣上熏風。風月芳菲節，物華紛可悅。", "將歡促席賞，遽爾又歸別。積水帶吳門，通波連禹穴。", "贈言雖欲盡，機心庶應絕。潘岳本自閑，梁鴻不因熱。", "一瓢欣狎道，三月聊棲拙。棲拙隱金華，狎道訪仙查。", "放曠愚公穀，消散野人家。一頃南山豆，五色東陵瓜。", "野衣裁薜葉，山酒酌藤花。白雲離望遠，青溪隱路賒。"]'),
('yuding-1','在江南贈宋五之問','駱賓王','唐','御定全唐诗','yuding','','[]','井絡雙源浚，潯陽九派長。淪波通地穴，輸委下歸塘。',432,'御定全唐詩/json/077.json','["井絡雙源浚，潯陽九派長。淪波通地穴，輸委下歸塘。", "別島籠朝蜃，連洲擁夕漲。韞珠澄積潤，讓璧動浮光。", "浮光凝折水，積潤疏圓沚。玉輪涵地開，劍閣連星起。", "風煙標迥秀，英靈信多美。懷德踐遺芳，端操慚謀己。", "謀己謬觀光，牽跡強悽惶。揆拙迷三省，勞生昧兩忘。", "彈隨空被笑，獻楚自多傷。一朝殊默語，千里易炎涼。", "炎涼幾遷貿，川陸疲臻湊。積水架吳濤，連山橫楚岫。", "風月雖殊昔，星河猶是舊。姑蘇望南浦，邯鄲通北走。", "北走平生親，南浦別離津。瀟湘一超忽，洞庭多苦辛。", "秋江無綠芷，寒汀有白蘋。采之將何遺，故人漳水濱。", "漳濱已遼遠，江潭未旋返。為聽短歌行，當想長洲苑。", "露金熏菊岸，風佩搖蘭阪。蟬鳴稻葉秋，雁起蘆花晚。", "晚秋雲日明，亭皋風霧清。獨負平生氣，重牽搖落情。", "占星非聚德，夢月詎懸名。寂寥傷楚奏，淒斷泣秦聲。", "秦聲懷舊裏，楚奏悲無已。郢路少知音，叢台富奇士。", "溫輝淩愛日，壯氣驚寒水。一顧重風雲，三冬足文史。", "文史盛紛綸，京洛多風塵。猶輕五車富，未重一囊貧。", "李仙非易托，蘇鬼尚難因。不惜勞歌盡，誰為聽陽春。"]'),
('yuding-2','晚憩田家','駱賓王','唐','御定全唐诗','yuding','','[]','轉蓬勞遠役，披薜下田家。山形類九折，水勢急三巴。',96,'御定全唐詩/json/077.json','["轉蓬勞遠役，披薜下田家。山形類九折，水勢急三巴。", "懸樑接斷岸，澀路擁崩查。霧岩淪曉魄，風漵漲寒沙。", "心跡一朝舛，關山萬里賒。龍章徒表越，閩俗本殊華。", "旅行悲泛梗，離贈折疏麻。唯有寒潭菊，獨似故園花。"]'),
('yuding-3','出石門','駱賓王','唐','御定全唐诗','yuding','','[]','層岩遠接天，絕嶺上棲煙。松低輕蓋偃，藤細弱絲懸。',48,'御定全唐詩/json/077.json','["層岩遠接天，絕嶺上棲煙。松低輕蓋偃，藤細弱絲懸。", "石明如掛鏡，苔分似列錢。暫策為龍杖，何處得神仙。"]'),
('yuding-4','至分陝','駱賓王','唐','御定全唐诗','yuding','','[]','陝西開勝壤，召南分沃疇。列樹巢維鵲，平渚下睢鳩。',48,'御定全唐詩/json/077.json','["陝西開勝壤，召南分沃疇。列樹巢維鵲，平渚下睢鳩。", "憩棠疑勿剪，曳葛似攀樛。至今王化美，非獨在隆周。"]'),
('yuding-5','寓居洛濱對雪憶謝二','駱賓王','唐','御定全唐诗','yuding','','[]','旅思眇難裁，沖飆恨易哀。曠望洛川晚，飄颻瑞雪來。',72,'御定全唐詩/json/077.json','["旅思眇難裁，沖飆恨易哀。曠望洛川晚，飄颻瑞雪來。", "積彩明書幌，流韻繞琴台。色奪迎仙羽，花避犯霜梅。", "謝庭賞方逸，袁扉掩未開。高人儻有訪，興盡詎須回。"]'),
('yuding-6','北眺舂陵','駱賓王','唐','御定全唐诗','yuding','','[]','攬轡疲宵邁，驅馬倦晨興。既出封泥穀，還過避雨陵。',48,'御定全唐詩/json/077.json','["攬轡疲宵邁，驅馬倦晨興。既出封泥穀，還過避雨陵。", "山行明照上，溪宿密雲蒸。登高徒欲賦，詞殫獨撫膺。"]'),
('yuding-7','夏日遊目聊作','駱賓王','唐','御定全唐诗','yuding','','[]','暫屏囂塵累，言尋物外情。致逸心逾默，神幽體自輕。',48,'御定全唐詩/json/077.json','["暫屏囂塵累，言尋物外情。致逸心逾默，神幽體自輕。", "浦夏荷香滿，田秋麥氣清。詎假滄浪上，將濯楚臣纓。"]'),
('yuding-8','同崔駙馬曉初登樓思京','駱賓王','唐','御定全唐诗','yuding','','[]','麗譙通四望，繁憂起萬端。綺疏低晚魄，鏤檻肅初寒。',48,'御定全唐詩/json/077.json','["麗譙通四望，繁憂起萬端。綺疏低晚魄，鏤檻肅初寒。", "白雲鄉思遠，黃圖歸路難。唯餘西向笑，暫似當長安。"]'),
('yuding-9','月夜有懷簡諸同病','駱賓王','唐','御定全唐诗','yuding','','[]','閒庭落景盡，疏簾夜月通。山靈響似應，水淨望如空。',48,'御定全唐詩/json/077.json','["閒庭落景盡，疏簾夜月通。山靈響似應，水淨望如空。", "棲枝猶繞鵲，遵渚未來鴻。可歎高樓婦，悲思杳難終。"]'),
('yuding-10','敘寄員半千','駱賓王','唐','御定全唐诗','yuding','','[]','薄宦三河道，自負十餘年。不應驚若厲，只為直如弦。',144,'御定全唐詩/json/077.json','["薄宦三河道，自負十餘年。不應驚若厲，只為直如弦。", "坐曆山川險，籲嗟陵穀遷。長吟空抱膝，短翮詎沖天。", "魂歸滄海上，望斷白雲前。釣名勞拾紫，隱跡自談玄。", "不學多能聖，徒思鴻寶仙。斯志良難已，此道豈徒然。", "嗟為刀筆吏，恥從繩墨牽。岐路情雖狎，人倫地本偏。", "長揖謝時事，獨往訪林泉。寄言二三子，生死不來旋。"]'),
('yuding-11','詠懷古意上裴侍郎','駱賓王','唐','御定全唐诗','yuding','','[]','三十二餘罷，鬢是潘安仁。四十九仍入，年非朱買臣。',168,'御定全唐詩/json/077.json','["三十二餘罷，鬢是潘安仁。四十九仍入，年非朱買臣。", "縱橫愁系越，坎壈倦游秦。出籠窮短翮，委轍涸枯鱗。", "窮經不沾用，彈鋏欲誰申。天子未驅策，歲月幾沉淪。", "輕生長慷慨，效死獨殷勤。徒歌易水客，空老渭川人。", "一得視邊塞，萬里何苦辛。劍匣胡霜影，弓開漢月輪。", "金刀動秋色，鐵騎想風塵。為國堅誠款，捐軀忘賤貧。", "勒功思比憲，決略暗欺陳。若不犯霜雪，虛擲玉京春。"]'),
('yuding-12','春夜韋明府宅宴得春字','駱賓王','唐','御定全唐诗','yuding','','[]','酌桂陶芳夜，披薜嘯幽人。雅琴馴魯雉，清歌落範塵。',48,'御定全唐詩/json/077.json','["酌桂陶芳夜，披薜嘯幽人。雅琴馴魯雉，清歌落範塵。", "宿雲低迥蓋，殘月上虛輪。幸此承恩洽，聊當故鄉春。"]'),
('yuding-13','過張平子墓','駱賓王','唐','御定全唐诗','yuding','','[]','西鄂該通理，南陽擅德音。玉卮浮藻麗，銅渾積思深。',60,'御定全唐詩/json/077.json','["西鄂該通理，南陽擅德音。玉卮浮藻麗，銅渾積思深。", "忽懷今日昔，非複昔時今。日落豐碑暗，風來古木吟。", "惟歎窮泉下，終鬱羨魚心。"]'),
('yuding-14','從軍中行路難二首','駱賓王','唐','御定全唐诗','yuding','','[]','君不見封狐雄虺自成群，馮深負固結妖氛。',412,'御定全唐詩/json/077.json','["君不見封狐雄虺自成群，馮深負固結妖氛。", "玉璽分兵征惡少，金壇受律動將軍。將軍擁旄宣廟略，", "閣道岧嶢起戍樓，劍門遙裔俯靈丘。邛關九折無平路，", "杳杳丘陵出，蒼蒼林薄遠。途危紫蓋峰，路澀青泥阪。", "去去指哀牢，行行入不毛。絕壁千里險，連山四望高。", "中外分區宇，夷夏殊風土。交趾枕南荒，昆彌臨北戶。", "川原繞毒霧，溪穀多淫雨。行潦四時流，崩查千歲古。", "漂梗飛蓬不自安，捫藤引葛度危巒。昔時聞道從軍樂，", "南中南斗映星河，秦川秦塞阻煙波。三春邊地風光少，", "向月彎繁弱，連星轉太阿。重義輕生懷一顧，", "灞城隅，滇池水，天涯望轉積，地際行無已。", "徒覺炎涼節物非，不知關山千萬里。棄置勿重陳，", "絳節朱旗分白羽，丹心白刃酬明主。但令一被君王知，", "君不見玉關塵色暗邊庭，銅鞮雜虜寇長城。", "天子按劍征餘勇，將軍受脤事橫行。七德龍韜開玉帳，", "連營去去無窮極，擁旆遙遙過絕國。陣雲朝結晦天山，", "長驅萬里讋祁連，分麾三命武功宣。百發烏號遙碎柳，", "雁門迢遞尺書稀，鴛被相思雙帶緩。行路難，行路難，"]'),
('yuding-15','帝京篇','駱賓王','唐','御定全唐诗','yuding','','[]','山河千里國，城闕九重門。不睹皇居壯，安知天子尊。',422,'御定全唐詩/json/077.json','["山河千里國，城闕九重門。不睹皇居壯，安知天子尊。", "皇居帝裏崤函穀，鶉野龍山侯甸服。五緯連影集星躔，", "桂殿嶔岑對玉樓，椒房窈窕連金屋。三條九陌麗城隈，", "劍履南宮入，簪纓北闕來。聲名冠寰宇，文物象昭回。", "鉤陳肅蘭戺，璧沼浮槐市。銅羽應風回，金莖承露起。", "校文天祿閣，習戰昆明水。朱邸抗平臺，黃扉通戚裏。", "平臺戚裏帶崇墉，炊金饌玉待鳴鐘。小堂綺帳三千戶，", "繡柱璿題粉壁映，鏘金鳴玉王侯盛。王侯貴人多近臣，", "趙李經過密，蕭朱交結親。丹鳳朱城白日暮，", "倡家桃李自芳菲，京華遊俠盛輕肥。延年女弟雙鳳入，", "春朝桂尊尊百味，秋夜蘭燈燈九微。翠幌珠簾不獨映，", "古來榮利若浮雲，人生倚伏信難分。始見田竇相移奪，", "朱門無複張公子，灞亭誰畏李將軍。相顧百齡皆有待，", "春去春來苦自馳，爭名爭利徒爾為。久留郎署終難遇，", "倏忽摶風生羽翼，須臾失浪委泥沙。黃雀徒巢桂，", "紅顏宿昔白頭新，脫粟布衣輕故人。故人有湮淪，", "已矣哉，歸去來。馬卿辭蜀多文藻，揚雄仕漢乏良媒。", "三冬自矜誠足用，十年不調幾邅回。汲黯薪逾積，"]'),
('yuding-16','疇昔篇','駱賓王','唐','御定全唐诗','yuding','','[]','少年重英俠，弱歲賤衣冠。既托寰中賞，方承膝下歡。',546,'御定全唐詩/json/077.json','["少年重英俠，弱歲賤衣冠。既托寰中賞，方承膝下歡。", "遨遊灞水曲，風月洛城端。且知無玉饌，誰肯逐金丸。", "金丸玉饌盛繁華，自言輕侮季倫家。五霸爭馳千里馬，", "池中舊水如懸鏡，屋裏新妝不讓花。意氣風雲倏如昨，", "當時門客今何在，疇昔交朋已疏索。莫教憔悴損容儀，", "一朝披短褐，六載奉長廊。賦文慚昔馬，執戟歎前揚。", "揮戈出武帳，荷筆入文昌。文昌隱隱皇城裏，", "卿相未曾識，王侯甯見擬。垂釣甘成白首翁，", "不應永棄同芻狗，且複飄颻類轉蓬。容鬢年年異，", "脂車秣馬辭鄉國，縈轡西南使邛僰。玉壘銅梁不易攀，", "陽關積霧萬里昏，劍閣連山千種色。蜀路何悠悠，", "華陽舊地標神制，石鏡蛾眉真秀麗。諸葛才雄已號龍，", "雲氣橫開八陣形，橋形遙分七星勢。川平煙霧開，", "他鄉冉冉消年月，帝裏沉沉限城闕。不見猿聲助客啼，", "故園梅柳尚餘春，來時勿使芳菲歇。解鞅欲言歸，", "十年不調為貧賤，百日屢遷隨倚伏。只為須求負郭田，", "涘江拂潮沖白日，淮海長波接遠天。", "叢竹凝朝露，孤山起暝煙。賴有邊城月，常伴客旌懸。", "東南美箭稱吳會，名都隱軫三江外。塗山執玉應昌期，", "未看白馬對蘆芻，且覺浮雲似車蓋。江南節序多，", "眺聽煙霞正流眄，即從王事歸艫轉。芝田花月屢裴回，", "峰開華嶽聳疑蓮，水激龍門急如箭。人事謝光陰，", "年來歲去成銷鑠，懷抱心期漸寥落。掛冠裂冕已辭榮，", "自有林泉堪隱棲，何必山中事丘壑。我住青門外，"]'),
('yuding-17','豔情代郭氏答盧照鄰','駱賓王','唐','御定全唐诗','yuding','','[]','迢迢芊路望芝田，眇眇函關恨蜀川。歸雲已落涪江外，',262,'御定全唐詩/json/077.json','["迢迢芊路望芝田，眇眇函關恨蜀川。歸雲已落涪江外，", "銅駝路上柳千條，金穀園中花幾色。柳葉園花處處新，", "此時離別那堪道，此日空床對芳沼。芳沼徒遊比目魚，", "擲果河陽君有分，貨酒成都妾亦然。莫言貧賤無人重，", "良人何處醉縱橫，直如循默守空名。倒提新縑成慊慊，", "別日分明相約束，已取宜家成誡勖。當時擬弄掌中珠，", "思君欲上望夫台，端居懶聽將雛曲。沉沉落日向山低，", "舞蝶臨階只自舞，啼鳥逢人亦助啼。獨坐傷孤枕，", "錦字回文欲贈君，劍壁層峰自糾紛。平江淼淼分清浦，", "無那短封即疏索，不在長情守期契。傳聞織女對牽牛，", "情知唾井終無理，情知覆水也難收。不復下山能借問，"]'),
('yuding-18','代女道士王靈妃贈道士李榮','駱賓王','唐','御定全唐诗','yuding','','[]','玄都五府風塵絕，碧海三山波浪深。桃實千年非易待，',408,'御定全唐詩/json/077.json','["玄都五府風塵絕，碧海三山波浪深。桃實千年非易待，", "台前鏡影伴仙娥，樓上簫聲隨鳳史。鳳樓迢遞絕塵埃，", "雙童綽約時遊陟，三鳥聯翩報消息。盡言真侶出遨遊，", "個時無數並妖妍，個裏無窮總可憐。別有眾中稱黜帝，", "自言少小慕幽玄，只言容易得神仙。佩中邀勒經時序，", "漫道燒丹止七飛，空傳化石曾三轉。寄語天上弄機人，", "想知人意自相尋，果得深心共一心。一心一意無窮已，", "相憐相念倍相親，一生一代一雙人。不把丹心比玄石，", "不能京兆畫蛾眉，翻向成都騁騶引。青牛紫氣度靈關，", "此時空床難獨守，此日別離那可久。梅花如雪柳如絲，", "春時物色無端緒，雙枕孤眠誰分許。分念嬌鶯一種啼，", "落花泛泛浮靈沼，垂柳長長拂禦溝。禦溝大道多奇賞，", "香輪寶騎競繁華，可憐今夜宿倡家。鸚鵡杯中浮竹葉，", "千回鳥信說眾諸，百過鶯啼說長短。長短眾諸判不尋，", "南陌西鄰咸自保，還轡歸期須及早。為想三春狹斜路，", "蘋風入馭來應易，竹杖成龍去不難。龍飆去去無消息，", "上林三月鴻欲稀，華表千年鶴未歸。不分淹留桑路待，"]'),
('yuding-0','從軍行','駱賓王','唐','御定全唐诗','yuding','','[]','平生一顧重，意氣溢三軍。野日分戈影，天星合劍文。',48,'御定全唐詩/json/078.json','["平生一顧重，意氣溢三軍。野日分戈影，天星合劍文。", "弓弦抱漢月，馬足踐胡塵。不求生入塞，唯當死報君。"]'),
('yuding-1','王昭君','駱賓王','唐','御定全唐诗','yuding','','[]','斂容辭豹尾，緘恨度龍鱗。金鈿明漢月，玉箸染胡塵。',48,'御定全唐詩/json/078.json','["斂容辭豹尾，緘恨度龍鱗。金鈿明漢月，玉箸染胡塵。", "古鏡菱花暗，愁眉柳葉顰。唯有清笳曲，時聞芳樹春。"]'),
('yuding-2','於紫雲觀贈道士','駱賓王','唐','御定全唐诗','yuding','','[]','碧落澄秋景，玄門啟曙關。人疑列禦至，客似令威還。',48,'御定全唐詩/json/078.json','["碧落澄秋景，玄門啟曙關。人疑列禦至，客似令威還。", "羽蓋徒欣仰，雲車未可攀。只應傾玉醴，時許寄頹顏。"]'),
('yuding-3','渡瓜步江','駱賓王','唐','御定全唐诗','yuding','','[]','捧檄辭幽徑，鳴榔下貴洲。驚濤疑躍馬，積氣似連牛。',48,'御定全唐詩/json/078.json','["捧檄辭幽徑，鳴榔下貴洲。驚濤疑躍馬，積氣似連牛。", "月迥寒沙淨，風急夜江秋。不學浮雲影，他鄉空滯留。"]'),
('yuding-4','途中有懷','駱賓王','唐','御定全唐诗','yuding','','[]','眷然懷楚奏，悵矣背秦關。涸鱗驚照轍，墜羽怯虛彎。',48,'御定全唐詩/json/078.json','["眷然懷楚奏，悵矣背秦關。涸鱗驚照轍，墜羽怯虛彎。", "素服三川化，烏裘十上還。莫言無皓齒，時俗薄朱顏。"]'),
('yuding-5','至分水戍','駱賓王','唐','御定全唐诗','yuding','','[]','行役忽離憂，複此愴分流。濺石回湍咽，縈叢曲澗幽。',48,'御定全唐詩/json/078.json','["行役忽離憂，複此愴分流。濺石回湍咽，縈叢曲澗幽。", "陰岩常結晦，宿莽競含秋。況乃霜晨早，寒風入戍樓。"]'),
('yuding-6','望鄉夕泛','駱賓王','唐','御定全唐诗','yuding','','[]','歸懷剩不安，促榜犯風瀾。落宿含樓近，浮月帶江寒。',48,'御定全唐詩/json/078.json','["歸懷剩不安，促榜犯風瀾。落宿含樓近，浮月帶江寒。", "喜逐行前至，憂從望裏寬。今夜南枝鵲，應無繞樹難。"]'),
('yuding-7','久客臨海有懷','駱賓王','唐','御定全唐诗','yuding','','[]','天涯非日觀，地屺望星樓。練光搖亂馬，劍氣上連牛。',48,'御定全唐詩/json/078.json','["天涯非日觀，地屺望星樓。練光搖亂馬，劍氣上連牛。", "草濕姑蘇夕，葉下洞庭秋。欲知淒斷意，江上涉安流。"]'),
('yuding-8','遊兗部逢孔君自衛來，欣然相遇若舊','駱賓王','唐','御定全唐诗','yuding','','[]','遊人自衛返，背客隔淮來。傾蓋金蘭合，忘筌玉葉開。',48,'御定全唐詩/json/078.json','["遊人自衛返，背客隔淮來。傾蓋金蘭合，忘筌玉葉開。", "繁花明日柳，疏蕊落風梅。將期重交態，時慰不然灰。"]'),
('yuding-9','西京守歲','駱賓王','唐','御定全唐诗','yuding','','[]','閒居寡言宴，獨坐慘風塵。忽見嚴冬盡，方知列宿春。',48,'御定全唐詩/json/078.json','["閒居寡言宴，獨坐慘風塵。忽見嚴冬盡，方知列宿春。", "夜將寒色去，年共曉光新。耿耿他鄉夕，無由展舊親。"]'),
('yuding-10','同辛簿簡仰酬思玄上人林泉四首','駱賓王','唐','御定全唐诗','yuding','','[]','聞君招隱地，仿佛武陵春。緝芰知還楚，披榛似避秦。',192,'御定全唐詩/json/078.json','["聞君招隱地，仿佛武陵春。緝芰知還楚，披榛似避秦。", "崩查年祀積，幽草歲時新。一謝滄浪水，安知有逸人。", "芳晨臨上月，幽賞狎中園。有蝶堪成夢，無羊可觸藩。", "忘懷南澗藻，蠲思北堂萱。坐歎華滋歇，思君誰為言。", "林泉恣探曆，風景暫裴徊。客有遷鶯處，人無結駟來。", "聚花如薄雪，沸水若輕雷。今日徒招隱，終知異鑿壞。", "俗遠風塵隔，春還初服遲。林疑中散地，人似上皇時。", "芳杜湘君曲，幽蘭楚客詞。山中有春草，長似寄相思。"]'),
('yuding-11','秋日餞陸道士陳文林','駱賓王','唐','御定全唐诗','yuding','','[]','青牛游華岳，赤馬走吳宮。玉柱離鴻怨，金罍浮蟻空。',48,'御定全唐詩/json/078.json','["青牛游華岳，赤馬走吳宮。玉柱離鴻怨，金罍浮蟻空。", "日霽崤陵雨，塵起洛陽風。唯當玄度月，千里與君同。"]'),
('yuding-12','送鄭少府入遼共賦俠客遠從戎','駱賓王','唐','御定全唐诗','yuding','','[]','邊烽警榆塞，俠客度桑幹。柳葉開銀鏑，桃花照玉鞍。',48,'御定全唐詩/json/078.json','["邊烽警榆塞，俠客度桑幹。柳葉開銀鏑，桃花照玉鞍。", "滿月臨弓影，連星入劍端。不學燕丹客，空歌易水寒。"]'),
('yuding-13','送費六還蜀','駱賓王','唐','御定全唐诗','yuding','','[]','星樓望蜀道，月峽指吳門。萬行流別淚，九折切驚魂。',48,'御定全唐詩/json/078.json','["星樓望蜀道，月峽指吳門。萬行流別淚，九折切驚魂。", "雪影含花落，雲陰帶葉昏。還愁三徑晚，獨對一清尊。"]'),
('yuding-14','秋日送侯四得彈字','駱賓王','唐','御定全唐诗','yuding','','[]','我留安豹隱，君去學鵬摶。岐路分襟易，風雲促膝難。',48,'御定全唐詩/json/078.json','["我留安豹隱，君去學鵬摶。岐路分襟易，風雲促膝難。", "夕漲流波急，秋山落日寒。惟有思歸引，淒斷為君彈。"]'),
('yuding-15','秋日送尹大赴京','駱賓王','唐','御定全唐诗','yuding','','[]','掛瓢餘隱舜，負鼎爾幹湯。竹葉離樽滿，桃花別路長。',48,'御定全唐詩/json/078.json','["掛瓢餘隱舜，負鼎爾幹湯。竹葉離樽滿，桃花別路長。", "低河耿秋色，落月抱寒光。素書如可嗣，幽谷佇賓行。"]'),
('yuding-16','秋夜送閻五還潤州','駱賓王','唐','御定全唐诗','yuding','','[]','通莊抵舊裏，溝水泣新知。斷雲飄易滯，連露積難披。',48,'御定全唐詩/json/078.json','["通莊抵舊裏，溝水泣新知。斷雲飄易滯，連露積難披。", "素風啼迥堞，驚月繞疏枝。無力勵短翰，輕舉送長離。"]'),
('yuding-17','送王明府參選賦得鶴','駱賓王','唐','御定全唐诗','yuding','','[]','振衣遊紫府，飛蓋背青田。虛心恒警露，孤影尚淩煙。',48,'御定全唐詩/json/078.json','["振衣遊紫府，飛蓋背青田。虛心恒警露，孤影尚淩煙。", "離歌淒妙曲，別操繞繁弦。在陰如可和，清響會聞天。"]'),
('yuding-18','秋日送別','駱賓王','唐','御定全唐诗','yuding','','[]','寂寥心事晚，搖落歲時秋。共此傷年發，相看惜去留。',48,'御定全唐詩/json/078.json','["寂寥心事晚，搖落歲時秋。共此傷年發，相看惜去留。", "當歌應破涕，哀命返窮愁。別後能相憶，東陵有故侯。"]'),
('yuding-19','別李嶠得勝字','駱賓王','唐','御定全唐诗','yuding','','[]','芳尊徒自滿，別恨轉難勝。客似遊江岸，人疑上灞陵。',48,'御定全唐詩/json/078.json','["芳尊徒自滿，別恨轉難勝。客似遊江岸，人疑上灞陵。", "寒更承夜永，涼景向秋澄。離心何以贈，自有玉壺冰。"]'),
('yuding-20','在兗州餞宋五之問','駱賓王','唐','御定全唐诗','yuding','','[]','淮沂泗水地，梁甫汶陽東。別路青驪遠，離尊綠蟻空。',48,'御定全唐詩/json/078.json','["淮沂泗水地，梁甫汶陽東。別路青驪遠，離尊綠蟻空。", "柳寒凋密翠，棠晚落疏紅。別後相思曲，淒斷入琴風。"]'),
('yuding-21','遊靈公觀','駱賓王','唐','御定全唐诗','yuding','','[]','靈峰標勝境，神府枕通川。玉殿斜連漢，金堂迥架煙。',48,'御定全唐詩/json/078.json','["靈峰標勝境，神府枕通川。玉殿斜連漢，金堂迥架煙。", "斷風疏晚竹，流水切危弦。別有青門外，空懷玄圃仙。"]'),
('yuding-22','夏日遊山家同夏少府','駱賓王','唐','御定全唐诗','yuding','','[]','返照下層岑，物外狎招尋。蘭徑熏幽佩，槐庭落暗金。',48,'御定全唐詩/json/078.json','["返照下層岑，物外狎招尋。蘭徑熏幽佩，槐庭落暗金。", "穀靜風聲徹，山空月色深。一遣樊籠累，唯餘松桂心。"]'),
('yuding-23','初秋登王司馬樓宴得同字','駱賓王','唐','御定全唐诗','yuding','','[]','展驥端居暇，登龍喜宴同。締賞三清滿，承歡六義通。',48,'御定全唐詩/json/078.json','["展驥端居暇，登龍喜宴同。締賞三清滿，承歡六義通。", "野晦寒陰積，潭虛夕照空。顧慚非夢鳥，濫此廁雕蟲。"]'),
('yuding-24','初秋于竇六郎宅宴','駱賓王','唐','御定全唐诗','yuding','','[]','千里風雲契，一朝心賞同。意盡深交合，神靈俗累空。',48,'御定全唐詩/json/078.json','["千里風雲契，一朝心賞同。意盡深交合，神靈俗累空。", "草帶銷寒翠，花枝發夜紅。唯將澹若水，長揖古人風。"]'),
('yuding-25','冬日宴','駱賓王','唐','御定全唐诗','yuding','','[]','二三物外友，一百杖頭錢。賞洽袁公地，情披樂令天。',48,'御定全唐詩/json/078.json','["二三物外友，一百杖頭錢。賞洽袁公地，情披樂令天。", "促席鸞觴滿，當爐獸炭然。何須攀桂樹，逢此自留連。"]'),
('yuding-26','鏤雞子','駱賓王','唐','御定全唐诗','yuding','','[]','幸遇清明節，欣逢舊練人。刻花爭臉態，寫月競眉新。',48,'御定全唐詩/json/078.json','["幸遇清明節，欣逢舊練人。刻花爭臉態，寫月競眉新。", "暈罷空餘月，詩成並道春。誰知懷玉者，含響未吟晨。"]'),
('yuding-27','詠美人在天津橋','駱賓王','唐','御定全唐诗','yuding','','[]','美女出東鄰，容與上天津。整衣香滿路，移步襪生塵。',48,'御定全唐詩/json/078.json','["美女出東鄰，容與上天津。整衣香滿路，移步襪生塵。", "水下看妝影，眉頭畫月新。寄言曹子建，個是洛川神。"]'),
('yuding-28','送宋五之問得涼字','駱賓王','唐','御定全唐诗','yuding','','[]','願言游泗水，支離去二漳。道術君所篤，筌蹄餘自忘。',48,'御定全唐詩/json/078.json','["願言游泗水，支離去二漳。道術君所篤，筌蹄餘自忘。", "雪威侵竹冷，秋爽帶池涼。欲驗離襟切，岐路在他鄉。"]'),
('yuding-29','憲台出縶寒夜有懷','駱賓王','唐','御定全唐诗','yuding','','[]','獨坐懷明發，長謠苦未安。自應迷北叟，誰肯問南冠。',48,'御定全唐詩/json/078.json','["獨坐懷明發，長謠苦未安。自應迷北叟，誰肯問南冠。", "生死交情異，殷憂歲序闌。空餘朝夕鳥，相伴夜啼寒。"]'),
('yuding-30','送郭少府探得憂字','駱賓王','唐','御定全唐诗','yuding','','[]','開筵枕德水，輟棹艤仙舟。貝闕桃花浪，龍門竹箭流。',48,'御定全唐詩/json/078.json','["開筵枕德水，輟棹艤仙舟。貝闕桃花浪，龍門竹箭流。", "當歌淒別曲，對酒泣離憂。還望青門外，空見白雲浮。"]'),
('yuding-31','冬日過故人任處士書齋','駱賓王','唐','御定全唐诗','yuding','','[]','神交尚投漆，虛室罷游蘭。網積窗文亂，苔深履跡殘。',48,'御定全唐詩/json/078.json','["神交尚投漆，虛室罷游蘭。網積窗文亂，苔深履跡殘。", "雪明書帳冷，水靜墨池寒。獨此琴台夜，流水為誰彈。"]'),
('yuding-32','送劉少府遊越州','駱賓王','唐','御定全唐诗','yuding','','[]','一丘余枕石，三越爾懷鉛。離亭分鶴蓋，別岸指龍川。',48,'御定全唐詩/json/078.json','["一丘余枕石，三越爾懷鉛。離亭分鶴蓋，別岸指龍川。", "露下蟬聲斷，寒來雁影連。如何溝水上，淒斷聽離弦。"]'),
('yuding-33','賦得白雲抱幽石','駱賓王','唐','御定全唐诗','yuding','','[]','重岩抱危石，幽澗曳輕雲。繞鎮仙衣動，飄蓬羽蓋分。',48,'御定全唐詩/json/078.json','["重岩抱危石，幽澗曳輕雲。繞鎮仙衣動，飄蓬羽蓋分。", "錦色連花靜，苔光帶葉熏。詎知吳會影，長抱穀城文。"]'),
('yuding-34','賦得春雲處處生','駱賓王','唐','御定全唐诗','yuding','','[]','千里年光靜，四望春雲生。槧日祥光舉，疏雲瑞葉輕。',48,'御定全唐詩/json/078.json','["千里年光靜，四望春雲生。槧日祥光舉，疏雲瑞葉輕。", "蓋陰籠迥樹，陣影抱危城。非將吳會遠，飄蕩帝鄉情。"]'),
('yuding-35','在獄詠蟬','駱賓王','唐','御定全唐诗','yuding','','[]','西陸蟬聲唱，南冠客思侵。那堪玄鬢影，來對白頭吟。',48,'御定全唐詩/json/078.json','["西陸蟬聲唱，南冠客思侵。那堪玄鬢影，來對白頭吟。", "露重飛難進，風多響易沉。無人信高潔，誰為表予心。"]'),
('yuding-36','詠水','駱賓王','唐','御定全唐诗','yuding','','[]','列名通地紀，疏派合天津。波隨月色淨，態逐桃花春。',48,'御定全唐詩/json/078.json','["列名通地紀，疏派合天津。波隨月色淨，態逐桃花春。", "照霞如隱石，映柳似沉鱗。終當挹上善，屬意澹交人。"]'),
('yuding-37','同張二詠雁','駱賓王','唐','御定全唐诗','yuding','','[]','唼藻滄江遠，銜蘆紫塞長。霧深迷曉景，風急斷秋行。',48,'御定全唐詩/json/078.json','["唼藻滄江遠，銜蘆紫塞長。霧深迷曉景，風急斷秋行。", "陣照通宵月，書封幾夜霜。無複能鳴分，空知愧稻粱。"]'),
('yuding-38','詠雪','駱賓王','唐','御定全唐诗','yuding','','[]','龍雲玉葉上，鶴雪瑞花新。影亂銅烏吹，光銷玉馬津。',48,'御定全唐詩/json/078.json','["龍雲玉葉上，鶴雪瑞花新。影亂銅烏吹，光銷玉馬津。", "含輝明素篆，隱跡表祥輪。幽蘭不可儷，徒自繞陽春。"]'),
('yuding-39','詠雲酒','駱賓王','唐','御定全唐诗','yuding','','[]','朔空曾紀曆，帶地舊疏泉。色泛臨碭瑞，香流赴蜀仙。',48,'御定全唐詩/json/078.json','["朔空曾紀曆，帶地舊疏泉。色泛臨碭瑞，香流赴蜀仙。", "款交欣散玉，洽友悅沉錢。無複中山賞，空吟吳會篇。"]'),
('yuding-40','塵灰','駱賓王','唐','御定全唐诗','yuding','','[]','洛川流雅韻，秦道擅苛威。聽歌梁上動，應律管中飛。',48,'御定全唐詩/json/078.json','["洛川流雅韻，秦道擅苛威。聽歌梁上動，應律管中飛。", "光飄神女襪，影落羽人衣。願言心未翳，終冀效輕微。"]'),
('yuding-41','秋晨同淄川毛司馬秋九詠：秋風','駱賓王','唐','御定全唐诗','yuding','','[]','紫陌炎氛歇，青蘋晚吹浮。亂竹搖疏影，縈池織細流。',48,'御定全唐詩/json/078.json','["紫陌炎氛歇，青蘋晚吹浮。亂竹搖疏影，縈池織細流。", "飄香曳舞袖，帶粉泛妝樓。不分君恩絕，紈扇曲中秋。"]'),
('yuding-42','秋晨同淄川毛司馬秋九詠：秋雲','駱賓王','唐','御定全唐诗','yuding','','[]','南陸銅渾改，西郊玉葉輕。泛鬥瑤光動，臨陽瑞色明。',48,'御定全唐詩/json/078.json','["南陸銅渾改，西郊玉葉輕。泛鬥瑤光動，臨陽瑞色明。", "蓋陰連鳳闕，陣影翼龍城。詎知時不遇，空傷流滯情。"]'),
('yuding-43','秋晨同淄川毛司馬秋九詠：秋蟬','駱賓王','唐','御定全唐诗','yuding','','[]','九秋行已暮，一枝聊暫安。隱榆非諫楚，噪柳異悲潘。',48,'御定全唐詩/json/078.json','["九秋行已暮，一枝聊暫安。隱榆非諫楚，噪柳異悲潘。", "分形妝薄鬢，鏤影飾危冠。自憐疏影斷，寒林夕吹寒。"]'),
('yuding-44','秋晨同淄川毛司馬秋九詠：秋露','駱賓王','唐','御定全唐诗','yuding','','[]','玉關寒氣早，金塘秋色歸。泛掌光逾淨，添荷滴尚微。',48,'御定全唐詩/json/078.json','["玉關寒氣早，金塘秋色歸。泛掌光逾淨，添荷滴尚微。", "變霜凝曉液，承月委圓輝。別有吳臺上，應濕楚臣衣。"]'),
('yuding-45','秋晨同淄川毛司馬秋九詠：秋月','駱賓王','唐','御定全唐诗','yuding','','[]','雲披玉繩淨，月滿鏡輪圓。裛露珠暉冷，淩霜桂影寒。',48,'御定全唐詩/json/078.json','["雲披玉繩淨，月滿鏡輪圓。裛露珠暉冷，淩霜桂影寒。", "漏彩含疏薄，浮光漾急瀾。西園徒自賞，南飛終未安。"]'),
('yuding-46','秋晨同淄川毛司馬秋九詠：秋水','駱賓王','唐','御定全唐诗','yuding','','[]','貝闕寒流徹，玉輪秋浪清。圖雲錦色淨，寫月練花明。',48,'御定全唐詩/json/078.json','["貝闕寒流徹，玉輪秋浪清。圖雲錦色淨，寫月練花明。", "泛曲鶤弦動，隨軒鳳轄驚。唯當禦溝上，淒斷送歸情。"]'),
('yuding-47','秋晨同淄川毛司馬秋九詠：秋螢','駱賓王','唐','御定全唐诗','yuding','','[]','玉虯分靜夜，金螢照晚涼。含輝疑泛月，帶火怯淩霜。',48,'御定全唐詩/json/078.json','["玉虯分靜夜，金螢照晚涼。含輝疑泛月，帶火怯淩霜。", "散彩縈虛牖，飄花繞洞房。下帷如不倦，當解惜餘光。"]'),
('yuding-48','秋晨同淄川毛司馬秋九詠：秋菊','駱賓王','唐','御定全唐诗','yuding','','[]','擢秀三秋晚，開芳十步中。分黃俱笑日，含翠共搖風。',48,'御定全唐詩/json/078.json','["擢秀三秋晚，開芳十步中。分黃俱笑日，含翠共搖風。", "碎影涵流動，浮香隔岸通。金翹徒可泛，玉斝竟誰同。"]'),
('yuding-49','秋晨同淄川毛司馬秋九詠：秋雁','駱賓王','唐','御定全唐诗','yuding','','[]','聯翩辭海曲，遙曳指江幹。陣去金河冷，書歸玉塞寒。',48,'御定全唐詩/json/078.json','["聯翩辭海曲，遙曳指江幹。陣去金河冷，書歸玉塞寒。", "帶月淩空易，迷煙逗浦難。何當同顧影，刷羽泛清瀾。"]'),
('yuding-50','樂大夫挽詞五首','駱賓王','唐','御定全唐诗','yuding','','[]','可歎浮生促，籲嗟此路難。丘陵一起恨，言笑幾時歡。',240,'御定全唐詩/json/078.json','["可歎浮生促，籲嗟此路難。丘陵一起恨，言笑幾時歡。", "蕭索郊埏晚，荒涼井徑寒。誰當門下客，獨見有任安。", "蒿裏誰家地，松門何代丘。百年三萬日，一別幾千秋。", "返照寒無影，窮泉凍不流。居然同物化，何處欲藏舟。", "昔去梅笳發，今來薤露晞。彤騶朝帝闕，丹旐背王畿。", "城郭猶疑是，原陵稍覺非。九原如可作，千載與誰歸。", "一旦先朝菌，千秋掩夜台。青烏新兆去，白馬故人來。", "草露當春泣，松風向暮哀。寧知荒壟外，吊鶴自裴徊。", "忽見泉台路，猶疑水鏡懸。何如開白日，非複睹青天。", "華表迎千歲，幽扃送百年。獨嗟流水引，長掩伯牙弦。"]'),
('yuding-51','丹陽刺史挽詞三首','駱賓王','唐','御定全唐诗','yuding','','[]','百齡嗟倏忽，一旦向山阿。丹桂銷已盡，青松哀更多。',144,'御定全唐詩/json/078.json','["百齡嗟倏忽，一旦向山阿。丹桂銷已盡，青松哀更多。", "熏風虛聽曲，薤露反成歌。自有藏舟處，誰憐隙駟過。", "惻愴恒山羽，留連棣萼篇。佳城非舊日，京兆即新阡。", "城郭三千歲，丘陵幾萬年。唯餘松柏壟，朝夕起寒煙。", "短歌三獻曲，長夜九泉台。此室玄扃掩，何年白日開。", "荒郊疏古木，寒隧積陳荄。獨此傷心地，松聲薄暮來。"]'),
('yuding-52','稱心寺','駱賓王','唐','御定全唐诗','yuding','','[]','征帆恣遠尋，逶迤過稱心。凝滯蘅vK岸，沿洄楂柚林。',49,'御定全唐詩/json/078.json','["征帆恣遠尋，逶迤過稱心。凝滯蘅vK岸，沿洄楂柚林。", "穿漵不厭曲，艤潭惟愛深。為樂凡幾許，聽取舟中琴。"]'),
('yuding-53','陪潤州薛司空丹徒桂明府遊招隱寺','駱賓王','唐','御定全唐诗','yuding','','[]','共尋招隱寺，初識戴顒家。還依舊泉壑，應改昔雲霞。',48,'御定全唐詩/json/078.json','["共尋招隱寺，初識戴顒家。還依舊泉壑，應改昔雲霞。", "綠竹寒天筍，紅蕉臘月花。金繩倘留客，為系日光斜。"]'),
('yuding-0','棹歌行','駱賓王','唐','御定全唐诗','yuding','','[]','寫月塗黃罷，淩波拾翠通。鏡花搖芰日，衣麝入荷風。',72,'御定全唐詩/json/079.json','["寫月塗黃罷，淩波拾翠通。鏡花搖芰日，衣麝入荷風。", "葉密舟難蕩，蓮疏浦易空。鳳媒羞自托，鴛翼恨難窮。", "秋帳燈華翠，倡樓粉色紅。相思無別曲，並在棹歌中。"]'),
('yuding-1','海曲書情','駱賓王','唐','御定全唐诗','yuding','','[]','薄遊倦千里，勞生負百年。未能槎上漢，詎肯劍游燕。',60,'御定全唐詩/json/079.json','["薄遊倦千里，勞生負百年。未能槎上漢，詎肯劍游燕。", "白雲照春海，青山橫曙天。江濤讓雙璧，渭水擲三錢。", "坐惜風光晚，長歌獨塊然。"]'),
('yuding-2','蓬萊鎮','駱賓王','唐','御定全唐诗','yuding','','[]','旅客春心斷，邊城夜望高。野樓疑海氣，白鷺似江濤。',60,'御定全唐詩/json/079.json','["旅客春心斷，邊城夜望高。野樓疑海氣，白鷺似江濤。", "結綬疲三入，承冠泣二毛。將飛憐弱羽，欲濟乏輕舠。", "賴有陽春曲，窮愁且代勞。"]'),
('yuding-3','和李明府','駱賓王','唐','御定全唐诗','yuding','','[]','傳聞葉懸履，飛向洛陽城。馳道臨層掖，津門對小平。',60,'御定全唐詩/json/079.json','["傳聞葉懸履，飛向洛陽城。馳道臨層掖，津門對小平。", "霞殘疑制錦，雲度似飄纓。藻掞潘江澈，塵虛範甑清。", "詎憐沖鬥氣，猶向匣中鳴。"]'),
('yuding-4','春晚從李長史游開道林故山','駱賓王','唐','御定全唐诗','yuding','','[]','幽尋極幽壑，春望陟春台。雲光棲斷樹，靈影入仙杯。',60,'御定全唐詩/json/079.json','["幽尋極幽壑，春望陟春台。雲光棲斷樹，靈影入仙杯。", "古藤依格上，野徑約山隈。落蕊翻風去，流鶯滿樹來。", "興闌荀禦動，歸路起浮埃。"]'),
('yuding-5','冬日野望','駱賓王','唐','御定全唐诗','yuding','','[]','故人無與晤，安步陟山椒。野靜連雲卷，川明斷霧銷。',60,'御定全唐詩/json/079.json','["故人無與晤，安步陟山椒。野靜連雲卷，川明斷霧銷。", "靈岩聞曉籟，洞浦漲秋潮。三江歸望斷，千里故鄉遙。", "勞歌徒自奏，客魂誰為招。"]'),
('yuding-6','晚渡黃河','駱賓王','唐','御定全唐诗','yuding','','[]','千里尋歸路，一葦亂平源。通波連馬頰，迸水急龍門。',72,'御定全唐詩/json/079.json','["千里尋歸路，一葦亂平源。通波連馬頰，迸水急龍門。", "照日榮光淨，驚風瑞浪翻。棹唱臨風斷，樵謳入聽喧。", "岸迥秋霞落，潭深夕霧繁。誰堪逝川上，日暮不歸魂。"]'),
('yuding-7','宿山莊','駱賓王','唐','御定全唐诗','yuding','','[]','金陵一超忽，玉燭幾還周。露積吳台草，風入郢門楸。',72,'御定全唐詩/json/079.json','["金陵一超忽，玉燭幾還周。露積吳台草，風入郢門楸。", "林虛宿斷霧，磴險掛懸流。拾青非漢策，化緇類秦裘。", "牽跡猶多蹇，勞生未寡尤。獨此他鄉夢，空山明月秋。"]'),
('yuding-8','晚度天山有懷京邑','駱賓王','唐','御定全唐诗','yuding','','[]','忽上天山路，依然想物華。雲疑上苑葉，雪似禦溝花。',72,'御定全唐詩/json/079.json','["忽上天山路，依然想物華。雲疑上苑葉，雪似禦溝花。", "行歎戎麾遠，坐憐衣帶賒。交河浮絕塞，弱水浸流沙。", "旅思徒漂梗，歸期未及瓜。寧知心斷絕，夜夜泣胡笳。"]'),
('yuding-9','夕次蒲類津','駱賓王','唐','御定全唐诗','yuding','','[]','二庭歸望斷，萬里客心愁。山路猶南屬，河源自北流。',72,'御定全唐詩/json/079.json','["二庭歸望斷，萬里客心愁。山路猶南屬，河源自北流。", "晚風連朔氣，新月照邊秋。灶火通軍壁，烽煙上戍樓。", "龍庭但苦戰，燕頷會封侯。莫作蘭山下，空令漢國羞。"]'),
('yuding-10','遠使海曲春夜多懷','駱賓王','唐','御定全唐诗','yuding','','[]','長嘯三春晚，端居百慮盈。未安蝴蝶夢，遽切魯禽情。',72,'御定全唐詩/json/079.json','["長嘯三春晚，端居百慮盈。未安蝴蝶夢，遽切魯禽情。", "別島連寰海，離魂斷戍城。流星疑伴使，低月似依營。", "懷祿甯期達，牽時匪徇名。艱虞行已遠，時跡自相驚。"]'),
('yuding-11','早發諸暨','駱賓王','唐','御定全唐诗','yuding','','[]','征夫懷遠路，夙駕上危巒。薄煙橫絕巘，輕凍澀回湍。',72,'御定全唐詩/json/079.json','["征夫懷遠路，夙駕上危巒。薄煙橫絕巘，輕凍澀回湍。", "野霧連空暗，山風入曙寒。帝城臨灞涘，禹穴枕江幹。", "橘性行應化，蓬心去不安。獨掩窮途淚，長歌行路難。"]'),
('yuding-12','望月有所思','駱賓王','唐','御定全唐诗','yuding','','[]','九秋涼風肅，千里月華開。圓光隨露湛，碎影逐波來。',72,'御定全唐詩/json/079.json','["九秋涼風肅，千里月華開。圓光隨露湛，碎影逐波來。", "似霜明玉砌，如鏡寫珠胎。晚色依關近，邊聲雜吹哀。", "離居分照耀，怨緒共裴徊。自繞南飛羽，空忝北堂才。"]'),
('yuding-13','送吳七游蜀','駱賓王','唐','御定全唐诗','yuding','','[]','日觀分齊壤，星橋接蜀門。桃花嘶別路，竹葉瀉離樽。',72,'御定全唐詩/json/079.json','["日觀分齊壤，星橋接蜀門。桃花嘶別路，竹葉瀉離樽。", "夏老蘭猶茂，秋深柳尚繁。霧銷山望迥，風高野聽喧。", "勞歌徒欲奏，贈別竟無言。唯有當秋月，空照野人園。"]'),
('yuding-14','西行別東台詳正學士','駱賓王','唐','御定全唐诗','yuding','','[]','意氣坐相親，關河別故人。客似秦川上，歌疑易水濱。',72,'御定全唐詩/json/079.json','["意氣坐相親，關河別故人。客似秦川上，歌疑易水濱。", "塞荒行辨玉，台遠尚名輪。泄井懷邊將，尋源重漢臣。", "上苑梅花早，禦溝楊柳新。只應持此曲，別作邊城春。"]'),
('yuding-15','和王記室從趙王春日遊陀山寺','駱賓王','唐','御定全唐诗','yuding','','[]','鳥旟陪訪道，鷲嶺狎棲真。四禪明靜業，三空廣勝因。',72,'御定全唐詩/json/079.json','["鳥旟陪訪道，鷲嶺狎棲真。四禪明靜業，三空廣勝因。", "祥河疏疊澗，慧日皎重輪。葉暗龍宮密，花明鹿苑春。", "雕談筌奧旨，妙辯漱玄津。雅曲終難和，徒自奏巴人。"]'),
('yuding-16','夏日夜憶張二','駱賓王','唐','御定全唐诗','yuding','','[]','伏枕憂思深，擁膝獨長吟。烹鯉無尺素，筌魚勞寸心。',84,'御定全唐詩/json/079.json','["伏枕憂思深，擁膝獨長吟。烹鯉無尺素，筌魚勞寸心。", "疏麻空有折，芳桂湛無斟。廣庭含夕氣，閑宇澹虛陰。", "織蟲垂夜砌，驚鳥棲暝林。歡娛百年促，羈病一生侵。", "詎堪孤月夜，流水入鳴琴。"]'),
('yuding-17','寒夜獨坐遊子多懷簡知己','駱賓王','唐','御定全唐诗','yuding','','[]','故鄉眇千里，離憂積萬端。鶉服長悲碎，蝸廬未卜安。',84,'御定全唐詩/json/079.json','["故鄉眇千里，離憂積萬端。鶉服長悲碎，蝸廬未卜安。", "富鉤徒有想，貧鋏為誰彈。柳秋風葉脆，荷曉露文團。", "晚金叢岸菊，餘佩下幽蘭。伐木傷心易，維桑歸去難。", "獨有孤明月，時照客庭寒。"]'),
('yuding-18','在軍中贈先還知己','駱賓王','唐','御定全唐诗','yuding','','[]','蓬轉俱行役，瓜時獨未還。魂迷金闕路，望斷玉門關。',84,'御定全唐詩/json/079.json','["蓬轉俱行役，瓜時獨未還。魂迷金闕路，望斷玉門關。", "獻凱多慚霍，論封幾謝班。風塵催白首，歲月損紅顏。", "落雁低秋塞，驚鳧起暝灣。胡霜如劍鍔，漢月似刀環。", "別後邊庭樹，相思幾度攀。"]'),
('yuding-19','秋日山行簡梁大官','駱賓王','唐','御定全唐诗','yuding','','[]','乘馬陟層阜，回首睇山川。攢峰銜宿霧，疊巘架寒煙。',96,'御定全唐詩/json/079.json','["乘馬陟層阜，回首睇山川。攢峰銜宿霧，疊巘架寒煙。", "百重含翠色，一道落飛泉。香吹分岩桂，鮮雲抱石蓮。", "地偏心易遠，致默體逾玄。得性虛遊刃，忘言已棄筌。", "彈冠勞巧拙，結綬倦牽纏。不如從四皓，丘中鳴一弦。"]'),
('yuding-20','晚泊江鎮','駱賓王','唐','御定全唐诗','yuding','','[]','四運移陰律，三翼泛陽侯。荷香銷晚夏，菊氣入新秋。',96,'御定全唐詩/json/079.json','["四運移陰律，三翼泛陽侯。荷香銷晚夏，菊氣入新秋。", "夜烏喧粉堞，宿雁下蘆洲。海霧籠邊徼，江風繞戍樓。", "轉蓬驚別渚，徙橘愴離憂。魂飛灞陵岸，淚盡洞庭流。", "振影希鴻陸，逃名謝蟻丘。還嗟帝鄉遠，空望白雲浮。"]'),
('yuding-21','浮槎','駱賓王','唐','御定全唐诗','yuding','','[]','昔負千尋質，高臨九仞峰。真心淩晚桂，勁節掩寒松。',96,'御定全唐詩/json/079.json','["昔負千尋質，高臨九仞峰。真心淩晚桂，勁節掩寒松。", "忽值風飆折，坐為波浪沖。摧殘空有恨，擁腫遂無庸。", "渤海三千里，泥沙幾萬重。似舟飄不定，如梗泛何從。", "仙客終難托，良工豈易逢。徒懷萬乘器，誰為一先容。"]'),
('yuding-22','晚泊河曲','駱賓王','唐','御定全唐诗','yuding','','[]','三秋倦行役，千里泛歸潮。通波竹箭水，輕舸木蘭橈。',96,'御定全唐詩/json/079.json','["三秋倦行役，千里泛歸潮。通波竹箭水，輕舸木蘭橈。", "金堤連曲岸，貝闕影浮橋。水淨千年近，星飛五老遙。", "疊花開宿浪，浮葉下涼飆。浦荷疏晚菂，津柳漬寒條。", "恓惶勞梗泛，淒斷倦蓬飄。仙槎不可托，河上獨長謠。"]'),
('yuding-23','早發淮口望盱眙','駱賓王','唐','御定全唐诗','yuding','','[]','養蒙分四瀆，習坎奠三荊。徙帝留餘地，封王表舊城。',96,'御定全唐詩/json/079.json','["養蒙分四瀆，習坎奠三荊。徙帝留餘地，封王表舊城。", "岸昏涵蜃氣，潮滿應雞聲。洲迥連沙靜，川虛積溜明。", "一朝從捧檄，千里倦懸旌。背流桐柏遠，逗浦木蘭輕。", "小山迷隱路，大塊切勞生。唯有貞心在，獨映寒潭清。"]'),
('yuding-24','邊城落日','駱賓王','唐','御定全唐诗','yuding','','[]','紫塞流沙北，黃圖灞水東。一朝辭俎豆，萬里逐沙蓬。',96,'御定全唐詩/json/079.json','["紫塞流沙北，黃圖灞水東。一朝辭俎豆，萬里逐沙蓬。", "候月恒持滿，尋源屢鑿空。野昏邊氣合，烽迥戍煙通。", "膂力風塵倦，疆場歲月窮。河流控積石，山路遠崆峒。", "壯志淩蒼兕，精誠貫白虹。君恩如可報，龍劍有雌雄。"]'),
('yuding-25','宿溫城望軍營','駱賓王','唐','御定全唐诗','yuding','','[]','虜地寒膠折，邊城夜柝聞。兵符關帝闕，天策動將軍。',96,'御定全唐詩/json/079.json','["虜地寒膠折，邊城夜柝聞。兵符關帝闕，天策動將軍。", "塞靜胡笳徹，沙明楚練分。風旗翻翼影，霜劍轉龍文。", "白羽搖如月，青山斷若雲。煙疏疑卷幔，塵滅似銷氛。", "投筆懷班業，臨戎想顧勳。還應雪漢恥，持此報明君。"]'),
('yuding-26','過故宋','駱賓王','唐','御定全唐诗','yuding','','[]','舊國千年盡，荒城四望通。雲浮非隱帝，日舉類游童。',96,'御定全唐詩/json/079.json','["舊國千年盡，荒城四望通。雲浮非隱帝，日舉類游童。", "綺琴朝化洽，祥石夜論空。馬去遙奔鄭，蛇分近帶豐。", "池文斂束水，竹影漏寒叢。園兔承行月，川禽避斷風。", "故宋誠難定，從梁事未工。唯當過周客，獨愧吳台空。"]'),
('yuding-27','邊夜有懷','駱賓王','唐','御定全唐诗','yuding','','[]','漢地行逾遠，燕山去不窮。城荒猶築怨，碣毀尚銘功。',96,'御定全唐詩/json/079.json','["漢地行逾遠，燕山去不窮。城荒猶築怨，碣毀尚銘功。", "古戍煙塵滿，邊庭人事空。夜關明隴月，秋塞急胡風。", "倚伏良難定，榮枯豈易通。旅魂勞泛梗，離恨斷征蓬。", "蘇武封猶薄，崔駰宦不工。惟餘北叟意，欲寄南飛鴻。"]'),
('yuding-28','傷祝阿王明府','駱賓王','唐','御定全唐诗','yuding','','[]','洛川真氣上，重泉惠政融。含章光後烈，繼武嗣前雄。',96,'御定全唐詩/json/079.json','["洛川真氣上，重泉惠政融。含章光後烈，繼武嗣前雄。", "與善良難驗，生涯忽易窮。翔鳧猶化履，狎雉尚馴童。", "錢滿荒階綠，塵浮虛帳紅。夏餘將宿草，秋近未驚蓬。", "煙晦泉門閉，日盡夜台空。誰堪孤隴外，獨聽白楊風。"]'),
('yuding-29','四月八日題七級','駱賓王','唐','御定全唐诗','yuding','','[]','化城分鳥堞，香閣俯龍川。複棟侵黃道，重簷架紫煙。',108,'御定全唐詩/json/079.json','["化城分鳥堞，香閣俯龍川。複棟侵黃道，重簷架紫煙。", "銘書非晉代，壁畫是梁年。霸略今何在，王宮尚巋然。", "二帝曾遊聖，三卿是偶賢。因茲遊勝侶，超彼托良緣。", "我出有為界，君登非想天。悠悠青曠裏，蕩蕩白雲前。", "今日經行處，曲音號蓋煙。"]'),
('yuding-30','和孫長史秋日臥病','駱賓王','唐','御定全唐诗','yuding','','[]','霍第疏天府，潘園近帝台。調弦三婦至，置驛五侯來。',120,'御定全唐詩/json/079.json','["霍第疏天府，潘園近帝台。調弦三婦至，置驛五侯來。", "尚想歡娛洽，籲嗟歲月催。金壇分上將，玉帳引瑰材。", "決勝鯨波靜，騰謀鳥穀開。白雲淮水外，紫陌灞陵隈。", "節變驚衰柳，笳繁思落梅。調神和玉燭，掞藻握珠胎。", "悵矣欣懷土，居然欲死灰。還因承雅曲，暫喜躍沈鰓。"]'),
('yuding-31','餞鄭安陽入蜀','駱賓王','唐','御定全唐诗','yuding','','[]','彭山折阪外，井絡少城隈。地是三巴俗，人非百里材。',120,'御定全唐詩/json/079.json','["彭山折阪外，井絡少城隈。地是三巴俗，人非百里材。", "畏途君悵望，岐路我裴徊。心賞風煙隔，容華歲月催。", "遙遙分鳳野，去去轉龍媒。遺錦非前邑，鳴琴即舊台。", "劍門千仞起，石路五丁開。海客乘槎渡，仙童馭竹回。", "魂將離鶴遠，思逐斷猿哀。唯有雙鳧舄，飛去複飛來。"]'),
('yuding-32','詠懷','駱賓王','唐','御定全唐诗','yuding','','[]','少年識事淺，不知交道難。一言芬若桂，四海臭如蘭。',132,'御定全唐詩/json/079.json','["少年識事淺，不知交道難。一言芬若桂，四海臭如蘭。", "寶劍思存楚，金錘許報韓。虛心徒有托，循跡諒無端。", "太息關山險，籲嗟歲月闌。忘機殊會俗，守拙異懷安。", "阮籍空長嘯，劉琨獨未歡。十步庭芳斂，三秋隴月團。", "槐疏非盡意，松晚夜淩寒。悲調弦中急，窮愁醉裏寬。", "莫將流水引，空向俗人彈。"]'),
('yuding-33','春日離長安客中言懷','駱賓王','唐','御定全唐诗','yuding','','[]','年華開早律，霽色蕩芳晨。城闕千門曉，山河四望春。',144,'御定全唐詩/json/079.json','["年華開早律，霽色蕩芳晨。城闕千門曉，山河四望春。", "禦溝通太液，戚裏對平津。寶瑟調中婦，金罍引上賓。", "劇談推曼倩，驚坐揖陳遵。意氣一言合，風期萬里親。", "自惟安直道，守拙忌因人。談器非先木，圖榮異後薪。", "揶揄慚路鬼，憔悴切波臣。玄草終疲漢，烏裘幾滯秦。", "生涯無歲月，岐路有風塵。還嗟太行道，處處白頭新。"]'),
('yuding-34','夕次舊吳','駱賓王','唐','御定全唐诗','yuding','','[]','維舟背楚服，振策下吳畿。盛德弘三讓，雄圖枕九圍。',144,'御定全唐詩/json/079.json','["維舟背楚服，振策下吳畿。盛德弘三讓，雄圖枕九圍。", "黃池通霸跡，赤壁暢戎威。文物俄遷謝，英靈有盛衰。", "行歎鴟夷沒，遽惜湛盧飛。地古煙塵暗，年深館宇稀。", "山川四望是，人事一朝非。懸劍空留信，亡珠尚識機。", "鄭風遙可托，關月眇難依。西北雲逾滯，東南氣轉微。", "徒懷伯通隱，多謝買臣歸。唯有荒台露，薄暮濕征衣。"]'),
('yuding-35','早秋出塞寄東台詳正學士','駱賓王','唐','御定全唐诗','yuding','','[]','促駕逾三水，長驅望五原。天階分鬥極，地理接樓煩。',168,'御定全唐詩/json/079.json','["促駕逾三水，長驅望五原。天階分鬥極，地理接樓煩。", "溪月明關隴，戎雲聚塞垣。山川殊物候，風壤異涼暄。", "戍古秋塵合，沙寒宿霧繁。昔余迷學步，投跡忝詞源。", "蘭渚浮延閣，蓬山款禁園。彯纓陪紱冕，載筆偶璵璠。", "汲塚寧詳蠹，秦牢詎辨冤。一朝從篚服，千里騖輕軒。", "鄉夢隨魂斷，邊聲入聽喧。南圖終鎩翮，北上遽催轅。", "吊影慚連茹，浮生倦觸藩。數奇何以托，桃李自無言。"]'),
('yuding-36','幽縶書情通簡知己','駱賓王','唐','御定全唐诗','yuding','','[]','昔歲逢楊意，觀光貴楚材。穴疑丹鳳起，場似白駒來。',216,'御定全唐詩/json/079.json','["昔歲逢楊意，觀光貴楚材。穴疑丹鳳起，場似白駒來。", "一命淪驕餌，三緘慎禍胎。不言勞倚伏，忽此遘邅回。", "驄馬刑章峻，蒼鷹獄吏猜。絕縑非易辨，疑璧果難裁。", "揆畫慚周道，端憂滯夏台。生涯一滅裂，岐路幾裴徊。", "青陸春芳動，黃沙旅思催。圓扉長寂寂，疏網尚恢恢。", "入阱先搖尾，迷津正曝腮。覆盆徒望日，蟄戶未經雷。", "霜歇蘭猶敗，風多木屢摧。地幽蠶室閉，門靜雀羅開。", "自憫秦冤痛，誰憐楚奏哀。漢陽窮鳥客，梁甫臥龍才。", "有氣還沖鬥，無時會鑿壞。莫言韓長孺，長作不然灰。"]'),
('yuding-37','久戍邊城有懷京邑','駱賓王','唐','御定全唐诗','yuding','','[]','擾擾風塵地，遑遑名利途。盈虛一易舛，心跡兩難俱。',456,'御定全唐詩/json/079.json','["擾擾風塵地，遑遑名利途。盈虛一易舛，心跡兩難俱。", "弱齡小山志，寧期大丈夫。九微光賁玉，千仞忽彈珠。", "棘寺遊三禮，蓬山簉八儒。懷鉛慚後進，投筆願前驅。", "北走非通趙，西之似化胡。錦車朝促候，刁鬥夜傳呼。", "戰士青絲絡，將軍黃石符。連星入寶劍，半月上雕弧。", "拜井開疏勒，鳴桴動密須。戎機習短蔗，祆祲靜長榆。", "季月炎初盡，邊亭草早枯。層陰籠古木，窮色變寒蕪。", "海鶴聲嘹唳，城烏尾畢逋。葭繁秋色引，桂滿夕輪虛。", "行役風霜久，鄉園夢想孤。灞池遙夏國，秦海望陽紆。", "沙塞三千里，京城十二衢。楊溝連鳳闕，槐路擬鴻都。", "璧殿規宸象，金堤法鬥樞。雲浮西北蓋，月照東南隅。", "寶帳垂連理，銀床轉轆轤。廣筵留上客，豐饌引中廚。", "漏緩金徒箭，嬌繁玉女壺。秋濤飛喻馬，秋水泛仙艫。", "意氣風雲合，言忘道術趨。共矜名已泰，詎肯沫相濡。", "有志慚雕朽，無庸類散樗。關山暫超忽，形影歎艱虞。", "結網空知羨，圖榮豈自誣。忘情同塞馬，比德類宛駒。", "隴阪肝腸絕，陽關亭候迂。迷魂驚落雁，離恨斷飛鳧。", "春去榮華盡，年來歲月蕪。邊愁傷郢調，鄉思繞吳歈。", "河氣通中國，山途限外區。相思若可寄，冰泮有銜蘆。"]'),
('yuding-38','在軍登城樓','駱賓王','唐','御定全唐诗','yuding','','[]','城上風威冷，江中水氣寒。戎衣何日定，歌舞入長安。',24,'御定全唐詩/json/079.json','["城上風威冷，江中水氣寒。戎衣何日定，歌舞入長安。"]'),
('yuding-39','于易水送人','駱賓王','唐','御定全唐诗','yuding','','[]','此地別燕丹，壯士發沖冠。昔時人已沒，今日水猶寒。',24,'御定全唐詩/json/079.json','["此地別燕丹，壯士發沖冠。昔時人已沒，今日水猶寒。"]'),
('yuding-40','詠鏡','駱賓王','唐','御定全唐诗','yuding','','[]','寫月無芳桂，照日有花菱。不持光謝水，翻將影學冰。',24,'御定全唐詩/json/079.json','["寫月無芳桂，照日有花菱。不持光謝水，翻將影學冰。"]'),
('yuding-41','挑燈杖','駱賓王','唐','御定全唐诗','yuding','','[]','稟質非貪熱，焦心豈憚熬。終知不自潤，何處用脂膏。',24,'御定全唐詩/json/079.json','["稟質非貪熱，焦心豈憚熬。終知不自潤，何處用脂膏。"]'),
('yuding-42','詠塵','駱賓王','唐','御定全唐诗','yuding','','[]','淩波起羅襪，含風染素衣。別有知音調，聞歌應自飛。',24,'御定全唐詩/json/079.json','["淩波起羅襪，含風染素衣。別有知音調，聞歌應自飛。"]'),
('yuding-43','玩初月','駱賓王','唐','御定全唐诗','yuding','','[]','忌滿光先缺，乘昏影暫流。既能明似鏡，何用曲如鉤。',24,'御定全唐詩/json/079.json','["忌滿光先缺，乘昏影暫流。既能明似鏡，何用曲如鉤。"]'),
('yuding-44','送別','駱賓王','唐','御定全唐诗','yuding','','[]','寒更承夜永，涼夕向秋澄。離心何以贈，自有玉壺冰。',24,'御定全唐詩/json/079.json','["寒更承夜永，涼夕向秋澄。離心何以贈，自有玉壺冰。"]'),
('yuding-45','憶蜀地佳人','駱賓王','唐','御定全唐诗','yuding','','[]','東西吳蜀關山遠，魚來雁去兩難聞。',32,'御定全唐詩/json/079.json','["東西吳蜀關山遠，魚來雁去兩難聞。", "莫怪常有千行淚，只為陽臺一片雲。"]'),
('yuding-46','詠鵝','駱賓王','唐','御定全唐诗','yuding','','[]','鵝鵝鵝，曲項向天歌。白毛浮綠水，紅掌撥清波。',22,'御定全唐詩/json/079.json','["鵝鵝鵝，曲項向天歌。白毛浮綠水，紅掌撥清波。"]'),
('yuding-0','奉和聖制夏日游石淙山','武三思','唐','御定全唐诗','yuding','','[]','此地岩壑數千重，吾君駕鶴□乘龍。掩映葉光含翡翠，',40,'御定全唐詩/json/080.json','["此地岩壑數千重，吾君駕鶴□乘龍。掩映葉光含翡翠，", "對酒鳴琴追野趣，時聞清吹入長松。"]'),
('yuding-1','仙鶴篇','武三思','唐','御定全唐诗','yuding','','[]','白鶴乘空何處飛，青田紫蓋本相依。緱山七月雖長去，',136,'御定全唐詩/json/080.json','["白鶴乘空何處飛，青田紫蓋本相依。緱山七月雖長去，", "經隨羽客步丹丘，曾逐仙人游碧落。迢迢碧落斷氛埃，", "九皋獨唳方清切，五裏驚群俄斷絕。月下分行似度雲，", "宛轉能傾吳國市，裴回巧拂漢皇壇。琴中作曲從來易，", "別有聞簫出紫煙，還如化履上青天。霜毛忽控三神下，", "莫言一舉輕千里，為與三山送九仙。"]'),
('yuding-2','宴龍泓','武三思','唐','御定全唐诗','yuding','','[]','登臨開勝托，眺矚盡良遊。岩崿縈紆上，澄潭屈曲流。',48,'御定全唐詩/json/080.json','["登臨開勝托，眺矚盡良遊。岩崿縈紆上，澄潭屈曲流。", "泛蘭清興洽，折桂野文遒。別後相思處，崎嶇碧澗幽。"]'),
('yuding-3','凝碧池侍宴應制得出水槎','武三思','唐','御定全唐诗','yuding','','[]','彼木生何代，為槎複幾年。欲乘銀漢曲，先泛玉池邊。',48,'御定全唐詩/json/080.json','["彼木生何代，為槎複幾年。欲乘銀漢曲，先泛玉池邊。", "擁溜根橫岸，沉波影倒懸。無勞問蜀客，此處即高天。"]'),
('yuding-4','奉和宴小山池賦得溪字應制','武三思','唐','御定全唐诗','yuding','','[]','年光開碧沼，雲色斂青溪。凍解魚方戲，風暄鳥欲啼。',60,'御定全唐詩/json/080.json','["年光開碧沼，雲色斂青溪。凍解魚方戲，風暄鳥欲啼。", "岩泉飛野鶴，石鏡舞山雞。柳發龍鱗出，松新麈尾齊。", "九韶從此驗，三月定應迷。"]'),
('yuding-5','奉和過梁王宅即目應制','武三思','唐','御定全唐诗','yuding','','[]','岩居多水石，野宅滿風煙。本謂開三徑，俄欣降九天。',60,'御定全唐詩/json/080.json','["岩居多水石，野宅滿風煙。本謂開三徑，俄欣降九天。", "穿林移步輦，拂岸轉行旃。鳳竹初垂籜，龜河未吐蓮。", "願持山作壽，恒用劫為年。"]'),
('yuding-6','奉和春日游龍門應制','武三思','唐','御定全唐诗','yuding','','[]','鳳駕臨香地，龍輿上翠微。星宮含雨氣，月殿抱春輝。',72,'御定全唐詩/json/080.json','["鳳駕臨香地，龍輿上翠微。星宮含雨氣，月殿抱春輝。", "碧澗長虹下，雕梁早燕歸。雲疑浮寶蓋，石似拂天衣。", "露草侵階長，風花繞席飛。日斜宸賞洽，清吹入重闈。"]'),
('yuding-7','秋日於天中寺尋複禮上人','武三思','唐','御定全唐诗','yuding','','[]','妙域三時殿，香岩七寶宮。金繩先界道，玉柄即談空。',120,'御定全唐詩/json/080.json','["妙域三時殿，香岩七寶宮。金繩先界道，玉柄即談空。", "喻筏知何極，傳燈竟不窮。彌天高義遠，初地勝因通。", "理詣歸一處，心行不二中。有無雙惑遣，真俗兩緣同。", "摘葉疑焚翠，投花若散紅。網珠遙映日，簷鐸近吟風。", "定沼寒光素，禪枝暝色蔥。願隨方便力，長冀釋塵籠。"]'),
('yuding-8','句','武三思','唐','御定全唐诗','yuding','','[]','雲螭非易匹，月駟本難儔。',12,'御定全唐詩/json/080.json','["雲螭非易匹，月駟本難儔。"]'),
('yuding-9','奉和聖制夏日游石淙山','張易之','唐','御定全唐诗','yuding','','[]','六龍驤首曉駸駸，七聖陪軒集潁陰。千丈松蘿交翠幕，',40,'御定全唐詩/json/080.json','["六龍驤首曉駸駸，七聖陪軒集潁陰。千丈松蘿交翠幕，", "山中日暮幽岩下，泠然香吹落花深。"]'),
('yuding-10','侍從過公主南宅侍宴探得風字應制','張易之','唐','御定全唐诗','yuding','','[]','逐賞平陽第，鳴笳上苑東。鳥吟千戶竹，蝶舞百花叢。',48,'御定全唐詩/json/080.json','["逐賞平陽第，鳴笳上苑東。鳥吟千戶竹，蝶舞百花叢。", "時攀小山桂，共挹大王風。坐客無勞起，秦簫曲未終。"]'),
('yuding-11','出塞','張易之','唐','御定全唐诗','yuding','','[]','俠客重恩光，駿馬飾金裝。瞥聞傳羽檄，馳突救邊荒。',84,'御定全唐詩/json/080.json','["俠客重恩光，駿馬飾金裝。瞥聞傳羽檄，馳突救邊荒。", "轉戰磨笄地，橫行戴鬥鄉。將軍占太白，小婦怨流黃。", "騕褭青絲騎，娉婷紅粉妝。一春鶯度曲，八月雁成行。", "誰堪坐秋思，羅袖拂空床。"]'),
('yuding-12','泛舟侍宴應制','張易之','唐','御定全唐诗','yuding','','[]','平明出禦溝，解纜坐回舟。綠水澄明月，紅羅結綺樓。',48,'御定全唐詩/json/080.json','["平明出禦溝，解纜坐回舟。綠水澄明月，紅羅結綺樓。", "弦歌爭浦入，冠蓋逐川流。白魚臣作伴，相對舞王舟。"]'),
('yuding-13','奉和聖制夏日游石淙山','張昌宗','唐','御定全唐诗','yuding','','[]','雲車遙裔三珠樹，帳殿交陰八桂叢。澗險泉聲疑度雨，',40,'御定全唐詩/json/080.json','["雲車遙裔三珠樹，帳殿交陰八桂叢。澗險泉聲疑度雨，", "即此陪歡游閬苑，無勞辛苦向崆峒。"]'),
('yuding-14','少年行','張昌宗','唐','御定全唐诗','yuding','','[]','少年不識事，落魄游韓魏。珠軒流水車，玉勒浮雲騎。',96,'御定全唐詩/json/080.json','["少年不識事，落魄游韓魏。珠軒流水車，玉勒浮雲騎。", "縱橫意不一，然諾心無二。白璧贈穰苴，黃金奉毛遂。", "妙舞飄龍管，清歌吟鳳吹。三春小苑遊，千日中山醉。", "直言身可沉，誰論名與利。依倚孟嘗君，自知能市義。"]'),
('yuding-15','太平公主山亭侍宴','張昌宗','唐','御定全唐诗','yuding','','[]','淮南有小山，嬴女隱其間。折桂芙蓉浦，吹簫明月灣。',48,'御定全唐詩/json/080.json','["淮南有小山，嬴女隱其間。折桂芙蓉浦，吹簫明月灣。", "扇掩將雛曲，釵承墮馬鬟。歡情本無限，莫掩洛城關。"]'),
('yuding-16','奉和聖制夏日游石淙山','薛曜','唐','御定全唐诗','yuding','','[]','玉洞幽尋更是天，朱霞綠景鎮韶年。飛花藉藉迷行路，',40,'御定全唐詩/json/080.json','["玉洞幽尋更是天，朱霞綠景鎮韶年。飛花藉藉迷行路，", "此中碧酒恒參聖，浪道昆山別有仙。"]'),
('yuding-17','子夜冬歌','薛曜','唐','御定全唐诗','yuding','','[]','朔風扣群木，嚴霜凋百草。借問月中人，安得長不老。',24,'御定全唐詩/json/080.json','["朔風扣群木，嚴霜凋百草。借問月中人，安得長不老。"]'),
('yuding-18','舞馬篇','薛曜','唐','御定全唐诗','yuding','','[]','星精龍種競騰驤，雙眼黃金紫豔光。一朝逢遇升平代，',183,'御定全唐詩/json/080.json','["星精龍種競騰驤，雙眼黃金紫豔光。一朝逢遇升平代，", "昔聞九代有餘名，今日百獸先來舞。鉤陳周衛儼旌旄，", "奔塵飛箭若麟螭，躡景追風忽見知。咀銜拉鐵並權奇，", "隨歌鼓而電驚，逐丸劍而飆馳。態聚ey還急，驕凝驟不移。", "光敵白日下，氣擁綠煙垂。婉轉盤跚殊未已，", "蘅垂桂裛香氛氳，長鳴汗血盡浮雲。不辭辛苦來東道，", "鸞鏘鏘，車翼翼，備國容兮為戎飾。充雲翹兮天子庭，", "大易占雲南山壽，䟃𧽼共樂聖明時。"]'),
('yuding-19','《正夜侍宴應詔','薛曜','唐','御定全唐诗','yuding','','[]','重關鐘漏通，夕敞鳳凰宮。雙闕祥煙裏，千門明月中。',48,'御定全唐詩/json/080.json','["重關鐘漏通，夕敞鳳凰宮。雙闕祥煙裏，千門明月中。", "酒杯浮湛露，歌曲唱流風。侍臣咸醉止，恒慚恩遇崇。"]'),
('yuding-20','送道士入天臺','薛曜','唐','御定全唐诗','yuding','','[]','洛陽陌上多離別，蓬萊山下足波潮。',32,'御定全唐詩/json/080.json','["洛陽陌上多離別，蓬萊山下足波潮。", "碧海桑田何處在，笙歌一聽一遙遙。"]'),
('yuding-21','奉和聖制夏日游石淙山','楊敬述','唐','御定全唐诗','yuding','','[]','山中別有神仙地，屈曲幽深碧澗垂。岩前暫駐黃金輦，',40,'御定全唐詩/json/080.json','["山中別有神仙地，屈曲幽深碧澗垂。岩前暫駐黃金輦，", "林壑偏能留睿賞，長天莫遽下丹曦。"]'),
('yuding-22','奉和聖制夏日游石淙山','于季子','唐','御定全唐诗','yuding','','[]','九旗雲布臨嵩室，萬騎星陳集潁川。瑞液含滋登禹膳，',40,'御定全唐詩/json/080.json','["九旗雲布臨嵩室，萬騎星陳集潁川。瑞液含滋登禹膳，", "微臣獻壽迎千壽，願奉堯年倚萬年。"]'),
('yuding-23','詠雲','于季子','唐','御定全唐诗','yuding','','[]','瑞雲千里映，祥輝四望新。隨風亂鳥翅，泛水結魚鱗。',48,'御定全唐詩/json/080.json','["瑞雲千里映，祥輝四望新。隨風亂鳥翅，泛水結魚鱗。", "布葉疑臨夏，開花詎待春。願得承嘉景，無令掩桂輪。"]'),
('yuding-24','詠螢','于季子','唐','御定全唐诗','yuding','','[]','卉草誠幽賤，枯朽絕因依。忽逢借羽翼，不覺生光輝。',48,'御定全唐詩/json/080.json','["卉草誠幽賤，枯朽絕因依。忽逢借羽翼，不覺生光輝。", "直念恩華重，長嗟報效微。方思助日月，為許願曾飛。"]'),
('yuding-25','早春洛陽答杜審言','于季子','唐','御定全唐诗','yuding','','[]','梓澤年光往復來，杜霸遊人去不回。若非載筆登麟閣，',40,'御定全唐詩/json/080.json','["梓澤年光往復來，杜霸遊人去不回。若非載筆登麟閣，", "分明寄語長安道，莫教留滯洛陽才。"]'),
('yuding-26','詠項羽','于季子','唐','御定全唐诗','yuding','','[]','北伐雖全趙，東歸不王秦。空歌拔山力，羞作渡江人。',24,'御定全唐詩/json/080.json','["北伐雖全趙，東歸不王秦。空歌拔山力，羞作渡江人。"]'),
('yuding-27','詠漢高祖','于季子','唐','御定全唐诗','yuding','','[]','百戰方夷項，三章且代秦。功歸蕭相國，氣盡戚夫人。',24,'御定全唐詩/json/080.json','["百戰方夷項，三章且代秦。功歸蕭相國，氣盡戚夫人。"]'),
('yuding-28','《南行別弟','于季子','唐','御定全唐诗','yuding','','[]','萬里人南去，三春雁北飛。不知何歲月，得與爾同歸。',24,'御定全唐詩/json/080.json','["萬里人南去，三春雁北飛。不知何歲月，得與爾同歸。"]'),
('yuding-0','長信宮中樹','喬知之','唐','御定全唐诗','yuding','','[]','婀娜當軒樹，zv茸倚蘭殿。葉豔九春華，香搖五明扇。',49,'御定全唐詩/json/081.json','["婀娜當軒樹，zv茸倚蘭殿。葉豔九春華，香搖五明扇。", "餘花鳥弄盡，新葉蟲書遍。零落心自知，芳菲君不見。"]'),
('yuding-1','下山逢故夫','喬知之','唐','御定全唐诗','yuding','','[]','妾身本薄命，輕棄城南隅。庭前厭芍藥，山上采蘼蕪。',48,'御定全唐詩/json/081.json','["妾身本薄命，輕棄城南隅。庭前厭芍藥，山上采蘼蕪。", "春風罥紈袖，零露濕羅襦。羞將憔悴日，提籠逢故夫。"]'),
('yuding-2','巫山高','喬知之','唐','御定全唐诗','yuding','','[]','巫山十二峰，參差互隱見。潯陽幾千里，周覽忽已遍。',72,'御定全唐詩/json/081.json','["巫山十二峰，參差互隱見。潯陽幾千里，周覽忽已遍。", "想像神女姿，摘芳共珍薦。楚雲何逶迤，紅樹日蔥蒨。", "楚雲沒湘源，紅樹斷荊門。郢路不可見，況複夜聞猿。"]'),
('yuding-3','棄妾篇','喬知之','唐','御定全唐诗','yuding','','[]','妾本叢台右，君在雁門陲。悠悠淇水曲，彩燕入桑枝。',72,'御定全唐詩/json/081.json','["妾本叢台右，君在雁門陲。悠悠淇水曲，彩燕入桑枝。", "不因媒結好，本以容相知。容謝君應去，情移會有離。", "還君結縷帶，歸妾織成詩。此物雖輕賤，不用使人嗤。"]'),
('yuding-4','苦寒行','喬知之','唐','御定全唐诗','yuding','','[]','胡天夜清迥，孤雲獨飄颺。遙裔出雁關，逶迤含晶光。',108,'御定全唐詩/json/081.json','["胡天夜清迥，孤雲獨飄颺。遙裔出雁關，逶迤含晶光。", "陰陵久裴回，幽都無多陽。初寒凍巨海，殺氣流大荒。", "朔馬飲寒冰，行子履胡霜。路有從役倦，臥死黃沙場。", "羈旅因相依，慟之淚沾裳。由來從軍行，賞存不賞亡。", "亡者誠已矣，徒令存者傷。"]'),
('yuding-5','從軍行','喬知之','唐','御定全唐诗','yuding','','[]','南庭結白露，北風掃黃葉。此時鴻雁來，驚鳴催思妾。',144,'御定全唐詩/json/081.json','["南庭結白露，北風掃黃葉。此時鴻雁來，驚鳴催思妾。", "曲房理針線，平砧搗文練。鴛綺裁易成，龍鄉信難見。", "窈窕九重閨，寂寞十年啼。紗窗白雲宿，羅幌月光棲。", "雲月隱微微，夜上流黃機。玉霜凍珠履，金吹薄羅衣。", "漢家已得地，君去將何事。宛轉結蠶書，寂寥無雁使。", "生平荷恩信，本為榮華進。況複落紅顏，蟬聲催綠鬢。"]'),
('yuding-6','擬古贈陳子昂','喬知之','唐','御定全唐诗','yuding','','[]','惸惸孤形影，悄悄獨遊心。以此從王事，常與子同衾。',144,'御定全唐詩/json/081.json','["惸惸孤形影，悄悄獨遊心。以此從王事，常與子同衾。", "別離三河間，征戰二庭深。胡天夜雨霜，胡雁晨南翔。", "節物感離居，同衾違故鄉。南歸日將遠，北方尚蓬飄。", "孟秋七月時，相送出外郊。海風吹涼木，邊聲響梢梢。", "勤役千萬里，將臨五十年。心事為誰道，抽琴歌坐筵。", "一彈再三歎，賓禦淚潺湲。送君竟此曲，從茲長絕弦。"]'),
('yuding-7','定情篇','喬知之','唐','御定全唐诗','yuding','','[]','共君結新婚，歲寒心未蔔。相與遊春園，各隨情所逐。',528,'御定全唐詩/json/081.json','["共君結新婚，歲寒心未蔔。相與遊春園，各隨情所逐。", "君愛菖蒲花，妾感苦寒竹。菖花多豔姿，寒竹有貞葉。", "此時妾比君，君心不如妾。簪玉步河堤，妖韶援綠荑。", "鳧雁將子游，鶯燕從雙棲。君念春光好，妾向春光啼。", "君時不得意，棄妾還金閨。結言本同心，悲歡何未齊。", "怨咽前致辭，願得申所悲。人間丈夫易，世路婦難為。", "始如經天月，終若流星馳。天月相終始，流星無定期。", "長信佳麗人，失意非蛾眉。廬江小吏婦，非關織作遲。", "本願長相對，今已長相思。複有遊宦子，結援從梁陳。", "燕居崇三朝，去來歷九春。誓心妾終始，蠶桑奉所親。", "歸願未克從，黃金贈路人。潔婦懷明義，從泛河之津。", "於今千萬年，誰當問水濱。更憶娼家樓，夫婿事封侯。", "去時恩灼灼，去罷心悠悠。不憐妾歲晏，十載隴西頭。", "以茲常惕惕，百慮恒盈積。由來共結褵，幾人同匪石。", "故歲雕梁燕，雙去今來隻。今日玉庭梅，朝紅暮成碧。", "碧榮始芬敷，黃葉已淅瀝。何用念芳春，芳春有流易。", "何用重歡娛，歡娛俄戚戚。家本巫山陽，歸去路何長。", "敘言情未盡，采菉已盈筐。桑榆日及景，物色盈高岡。", "下有碧流水，上有丹桂香。桂花不須折，碧流清且潔。", "贈君比芳菲，愛惠常不歇。贈君比潺湲，相思無斷絕。", "妾有秦家鏡，寶匣裝珠璣。鑒來年二八，不記易陰暉。", "妾無光寂寂，委照影依依。今日持為贈，相識莫相違。"]'),
('yuding-8','綠珠篇','喬知之','唐','御定全唐诗','yuding','','[]','石家金谷重新聲，明珠十斛買娉婷。此日可憐君自許，',48,'御定全唐詩/json/081.json','["石家金谷重新聲，明珠十斛買娉婷。此日可憐君自許，", "意氣雄豪非分理，驕矜勢力橫相干。辭君去君終不忍，"]'),
('yuding-9','和李侍郎古意','喬知之','唐','御定全唐诗','yuding','','[]','妾家巫山隔漢川，君度南庭向胡苑。高樓迢遞想金天，',96,'御定全唐詩/json/081.json','["妾家巫山隔漢川，君度南庭向胡苑。高樓迢遞想金天，", "自矜夫婿勝王昌，三十曾作侍中郎。一從流落戍漁陽，", "由來花葉同一根，今日枝條分兩處。三星差池光照灼，", "美人長歎豔容萎，含情收取摧折枝。調絲獨彈聲未移，"]'),
('yuding-10','倡女行','喬知之','唐','御定全唐诗','yuding','','[]','石榴酒，葡萄漿。蘭桂芳，茱萸香。願君駐金鞍，',44,'御定全唐詩/json/081.json','["石榴酒，葡萄漿。蘭桂芳，茱萸香。願君駐金鞍，", "莫吹羌笛驚鄰里，不用琵琶喧洞房。且歌新夜曲，"]'),
('yuding-11','羸駿篇','喬知之','唐','御定全唐诗','yuding','','[]','噴玉長鳴西北來，自言當代是龍媒。萬里鐵關行入貢，',192,'御定全唐詩/json/081.json','["噴玉長鳴西北來，自言當代是龍媒。萬里鐵關行入貢，", "玉勒金鞍荷裝飾，路傍觀者無窮極。小山桂樹比權奇，", "去去山川勞日夜，遙遙關塞斷煙霞。山川關塞十年征，", "長城日夕苦風霜，中有連年百戰場。搖珂齧勒金羈盡，", "大宛蒲海北，滇壑雋崖西。沙平留緩步，路遠闇頻嘶。", "從來力盡君須棄，何必尋途我已迷。歲歲年年奔遠道，", "楚水澶溪征戰事，吳塞烏江辛苦地。持來報主不辭勞，", "只應澶漫歸田裏，萬里低昂任生死。君王倘若不見遺，"]'),
('yuding-12','銅雀妓','喬知之','唐','御定全唐诗','yuding','','[]','金閣惜分香，鉛華不重妝。空餘歌舞地，猶是為君王。',48,'御定全唐詩/json/081.json','["金閣惜分香，鉛華不重妝。空餘歌舞地，猶是為君王。", "哀弦調已絕，豔曲不須長。共看西陵暮，秋煙起白楊。"]'),
('yuding-13','侍宴應制得分字','喬知之','唐','御定全唐诗','yuding','','[]','紫禁肅晴氛，朱樓落曉雲。豫游龍駕轉，天樂鳳簫聞。',48,'御定全唐詩/json/081.json','["紫禁肅晴氛，朱樓落曉雲。豫游龍駕轉，天樂鳳簫聞。", "竹外仙亭出，花間輦路分。微臣一何幸，詞賦奉明君。"]'),
('yuding-14','梨園亭子侍宴','喬知之','唐','御定全唐诗','yuding','','[]','年光陌上發，香輦禁中游。草綠鴛鴦殿，花紅翡翠樓。',48,'御定全唐詩/json/081.json','["年光陌上發，香輦禁中游。草綠鴛鴦殿，花紅翡翠樓。", "天杯承露酌，仙管雜風流。今日陪歡豫，皇恩不可酬。"]'),
('yuding-15','和蘇員外寓直','喬知之','唐','御定全唐诗','yuding','','[]','自昔重為郎，伊人練國章。三旬登建禮，五夜直明光。',72,'御定全唐詩/json/081.json','["自昔重為郎，伊人練國章。三旬登建禮，五夜直明光。", "墨草尚書奏，衣飄侍禦香。開軒竹氣靜，拂簟蕙風涼。", "曉漏離閶闔，鳴鐘出未央。從來宿臺上，天子貴文強。"]'),
('yuding-16','哭故人','喬知之','唐','御定全唐诗','yuding','','[]','生死久離居，淒涼曆舊廬。歎茲三徑斷，不踐十年餘。',72,'御定全唐詩/json/081.json','["生死久離居，淒涼曆舊廬。歎茲三徑斷，不踐十年餘。", "古木巢禽合，荒庭愛客疏。匣留彈罷劍，床積讀殘書。", "玉沒終無像，蘭言強問虛。平生不得意，泉路複何如。"]'),
('yuding-17','折楊柳','喬知之','唐','御定全唐诗','yuding','','[]','可憐濯濯春楊柳，攀折將來就纖手。',32,'御定全唐詩/json/081.json','["可憐濯濯春楊柳，攀折將來就纖手。", "妾容與此同盛衰，何必君恩能獨久。"]'),
('yuding-18','人日登高','喬侃','唐','御定全唐诗','yuding','','[]','僕本多悲者，年來不悟春。登高一遊目，始覺柳條新。',60,'御定全唐詩/json/081.json','["僕本多悲者，年來不悟春。登高一遊目，始覺柳條新。", "杜陵猶識漢，桃源不辨秦。暫若升雲霧，還似出囂塵。", "賴得煙霞氣，淹留攀桂人。"]'),
('yuding-19','出塞','喬備','唐','御定全唐诗','yuding','','[]','沙場三萬里，猛將五千兵。旌斷冰溪戍，笳吹鐵關城。',48,'御定全唐詩/json/081.json','["沙場三萬里，猛將五千兵。旌斷冰溪戍，笳吹鐵關城。", "陰雲暮下雪，寒日晝無晶。直為懷恩苦，誰知邊塞情。"]'),
('yuding-20','長門怨','喬備','唐','御定全唐诗','yuding','','[]','秋入長門殿，木落洞房虛。妾思宵徒靜，君恩日更疏。',48,'御定全唐詩/json/081.json','["秋入長門殿，木落洞房虛。妾思宵徒靜，君恩日更疏。", "墜露清金閣，流螢點玉除。還將閨裏恨，遙問馬相如。"]'),
('yuding-0','將軍行','劉希夷','唐','御定全唐诗','yuding','','[]','將軍辟轅門，耿介當風立。諸將欲言事，逡巡不敢入。',120,'御定全唐詩/json/082.json','["將軍辟轅門，耿介當風立。諸將欲言事，逡巡不敢入。", "劍氣射雲天，鼓聲振原隰。黃塵塞路起，走馬追兵急。", "彎弓從此去，飛箭如雨集。截圍一百里，斬首五千級。", "代馬流血死，胡人抱鞍泣。古來養甲兵，有事常討襲。", "乘我廟堂運，坐使干戈戢。獻凱歸京師，軍容何翕習。"]'),
('yuding-1','從軍行','劉希夷','唐','御定全唐诗','yuding','','[]','秋天風颯颯，群胡馬行疾。嚴城晝不開，伏兵暗相失。',108,'御定全唐詩/json/082.json','["秋天風颯颯，群胡馬行疾。嚴城晝不開，伏兵暗相失。", "天子廟堂拜，將軍凶門出。紛紛伊洛道，戎馬幾萬匹。", "軍門壓黃河，兵氣沖白日。平生懷仗劍，慷慨即投筆。", "南登漢月孤，北走代雲密。近取韓彭計，早知孫吳術。", "丈夫清萬里，誰能掃一室。"]'),
('yuding-2','春女行','劉希夷','唐','御定全唐诗','yuding','','[]','春女顏如玉，怨歌陽春曲。巫山春樹紅，沅湘春草綠。',168,'御定全唐詩/json/082.json','["春女顏如玉，怨歌陽春曲。巫山春樹紅，沅湘春草綠。", "自憐妖豔姿，妝成獨見時。愁心伴楊柳，春盡亂如絲。", "目極千餘裏，悠悠春江水。頻想玉關人，愁臥金閨裏。", "尚言春花落，不知秋風起。嬌愛猶未終，悲涼從此始。", "憶昔楚王宮，玉樓妝粉紅。纖腰弄明月，長袖舞春風。", "容華委西山，光陰不可還。桑林變東海，富貴今何在。", "寄言桃李容，胡為閨閣重。但看楚王墓，唯有數株松。"]'),
('yuding-3','孤松篇','劉希夷','唐','御定全唐诗','yuding','','[]','蠶月桑葉青，鶯時柳花白。澹豔煙雨姿，敷芬陽春陌。',192,'御定全唐詩/json/082.json','["蠶月桑葉青，鶯時柳花白。澹豔煙雨姿，敷芬陽春陌。", "如何秋風起，零落從此始。獨有南澗松，不歎東流水。", "玄陰天地冥，皓雪朝夜零。豈不罹寒暑，為君留青青。", "青青好顏色，落落任孤直。群樹遙相望，眾草不敢逼。", "靈龜蔔真隱，仙鳥宜棲息。恥受秦帝封，願言唐侯食。", "寒山夜月明，山冷氣清清。淒兮歸鳳集，吹之作琴聲。", "松子臥仙岑，寂聽疑野心。清泠有真曲，樵采無知音。", "美人何時來，幽徑委綠苔。籲嗟深澗底，棄捐廣廈材。"]'),
('yuding-4','嵩岳聞笙','劉希夷','唐','御定全唐诗','yuding','','[]','月出嵩山東，月明山益空。山人愛清景，散發臥秋風。',108,'御定全唐詩/json/082.json','["月出嵩山東，月明山益空。山人愛清景，散發臥秋風。", "風止夜何清，獨夜草蟲鳴。仙人不可見，乘月近吹笙。", "絳唇吸靈氣，玉指調真聲。真聲是何曲，三山鸞鶴情。", "昔去落塵俗，願言聞此曲。今來臥嵩岑，何幸承幽音。", "神仙樂吾事，笙歌銘夙心。"]'),
('yuding-5','秋日題汝陽潭壁','劉希夷','唐','御定全唐诗','yuding','','[]','獨坐秋陰生，悲來從所適。行見汝陽潭，飛蘿蒙水石。',120,'御定全唐詩/json/082.json','["獨坐秋陰生，悲來從所適。行見汝陽潭，飛蘿蒙水石。", "懸瓢木葉上，風吹何歷歷。幽人不耐煩，振衣步閑寂。", "回流清見底，金沙覆銀礫。錯落非一文，空朧幾千尺。", "魚鱗可憐紫，鴨毛自然碧。吟詠秋水篇，渺然忘損益。", "秋水隨形影，清濁混心跡。歲暮歸去來，東山餘宿昔。"]'),
('yuding-6','采桑','劉希夷','唐','御定全唐诗','yuding','','[]','楊柳送行人，青青西入秦。誰家采桑女，樓上不勝春。',120,'御定全唐詩/json/082.json','["楊柳送行人，青青西入秦。誰家采桑女，樓上不勝春。", "盈盈灞水曲，步步春芳綠。紅臉耀明珠，絳唇含白玉。", "回首渭橋東，遙憐春色同。青絲嬌落日，緗綺弄春風。", "攜籠長歎息，逶遲戀春色。看花若有情，倚樹疑無力。", "薄暮思悠悠，使君南陌頭。相逢不相識，歸去夢青樓。"]'),
('yuding-7','謁漢世祖廟','劉希夷','唐','御定全唐诗','yuding','','[]','舂陵氣初發，漸台首未傳。列營百萬眾，持國十八年。',192,'御定全唐詩/json/082.json','["舂陵氣初發，漸台首未傳。列營百萬眾，持國十八年。", "運開朱旗後，道合赤符先。宛城劍鳴匣，昆陽鏑應弦。", "獷獸血塗地，巨人聲沸天。長驅過北趙，短兵出南燕。", "太守迎門外，王郎死道邊。升壇九城陌，端拱千秋年。", "朝廷方雀躍，劍佩幾聯翩。至德刑四海，神儀翳九泉。", "宗子行舊邑，恭聞清廟篇。君容穆而聖，臣像儼猶賢。", "攢木承危柱，疏蘿掛朽椽。祠庭巢鳥啄，祭器網蟲緣。", "懷古江山在，惟新歷數遷。空餘今夜月，長似舊時懸。"]'),
('yuding-8','巫山懷古','劉希夷','唐','御定全唐诗','yuding','','[]','巫山幽陰地，神女豔陽年。襄王伺容色，落日望悠然。',96,'御定全唐詩/json/082.json','["巫山幽陰地，神女豔陽年。襄王伺容色，落日望悠然。", "歸來高唐夜，金釭焰青煙。頹想臥瑤席，夢魂何翩翩。", "搖落殊未已，榮華倏徂遷。愁思瀟湘浦，悲涼雲夢田。", "猿啼秋風夜，雁飛明月天。巴歌不可聽，聽此益潺湲。"]'),
('yuding-9','歸山','劉希夷','唐','御定全唐诗','yuding','','[]','歸去嵩山道，煙花覆青草。草綠山無塵，山青楊柳春。',36,'御定全唐詩/json/082.json','["歸去嵩山道，煙花覆青草。草綠山無塵，山青楊柳春。", "日暮松聲合，空歌思殺人。"]'),
('yuding-10','代閨人春日','劉希夷','唐','御定全唐诗','yuding','','[]','珠簾的曉光，玉顏豔春彩。林間鳥鳴喚，戶外花相待。',72,'御定全唐詩/json/082.json','["珠簾的曉光，玉顏豔春彩。林間鳥鳴喚，戶外花相待。", "花鳥惜芳菲，鳥鳴花亂飛。人今伴花鳥，日暮不能歸。", "池月憐歌扇，山雲愛舞衣。佳期楊柳陌，攜手莫相違。"]'),
('yuding-11','蜀城懷古','劉希夷','唐','御定全唐诗','yuding','','[]','蜀土繞水竹，吳天積風霜。窮覽通表裏，氣色何蒼蒼。',120,'御定全唐詩/json/082.json','["蜀土繞水竹，吳天積風霜。窮覽通表裏，氣色何蒼蒼。", "舊國有年代，青樓思豔妝。古人無歲月，白骨冥丘荒。", "寂曆彈琴地，幽流讀書堂。玄龜埋蔔室，彩鳳滅詞場。", "陣圖一一在，柏樹雙雙行。鬼神清漢廟，鳥雀參秦倉。", "歎世已多感，懷心益自傷。賴蒙靈丘境，時當明月光。"]'),
('yuding-12','洛川懷古','劉希夷','唐','御定全唐诗','yuding','','[]','萋萋春草綠，悲歌牧征馬。行見白頭翁，坐泣青竹下。',192,'御定全唐詩/json/082.json','["萋萋春草綠，悲歌牧征馬。行見白頭翁，坐泣青竹下。", "感歎前問之，贈予辛苦詞。歲月移今古，山河更盛衰。", "晉家都洛濱，朝廷多近臣。詞賦歸潘岳，繁華稱季倫。", "梓澤春草菲，河陽亂華飛。綠珠不可奪，白首同所歸。", "高樓倏冥滅，茂林久摧折。昔時歌舞台，今成狐兔穴。", "人事互消亡，世路多悲傷。北邙是吾宅，東嶽為吾鄉。", "君看北邙道，髑髏縈蔓草。芳□□□□，□□□□□。", "碑塋或半存，荊棘斂幽魂。揮涕棄之去，不忍聞此言。"]'),
('yuding-13','春日行歌','劉希夷','唐','御定全唐诗','yuding','','[]','山樹落梅花，飛落野人家。野人何所有，滿甕陽春酒。',48,'御定全唐詩/json/082.json','["山樹落梅花，飛落野人家。野人何所有，滿甕陽春酒。", "攜酒上春台，行歌伴落梅。醉罷臥明月，乘夢遊天臺。"]'),
('yuding-14','江南曲八首','劉希夷','唐','御定全唐诗','yuding','','[]','暮宿南洲草，晨行北岸林。日懸滄海闊，水隔洞庭深。',425,'御定全唐詩/json/082.json','["暮宿南洲草，晨行北岸林。日懸滄海闊，水隔洞庭深。", "煙景無留意，風波有異潯。歲遊難極目，春戲易為心。", "朝夕無榮遇，芳菲已滿襟。", "豔唱潮初落，江花露未晞。春洲驚翡翠，朱服弄芳菲。", "畫舫煙中淺，青陽日際微。錦帆衝浪濕，羅袖拂行衣。", "含情罷所采，相嘆惜流暉。", "君為隴西客，妾遇江南春。朝遊含靈果，夕采弄風蘋。", "果氣時不歇，蘋花日自新。以此江南物，持贈隴西人。", "空盈萬里懷，欲贈竟無因。", "皓如楚江月，靄若吳岫雲。波中自皎鏡，山上亦氤氳。", "明月留照妾，輕雲持贈君。山川各離散，光氣乃殊分。", "天涯一為別，江北不相聞。", "艤舟乘潮去，風帆振早涼。潮平見楚甸，天際望維揚。", "洄溯經千里，煙波接兩鄉。雲明江嶼出，日照海流長。", "此中逢歲晏，浦樹落花芳。", "暮春三月晴，維揚吳楚城。城臨大江汜，回映洞浦清。", "晴雲曲金閣，珠樓碧煙裏。月明芳樹群鳥飛，", "北堂紅草盛zv茸，南湖碧水照芙蓉。朝游暮起金花盡，", "人情一去無還日，欲贈懷芳怨不逢。", "憶昔江南年盛時，平生怨在長洲曲。冠蓋星繁江水上，", "誰言此處嬋娟子，珠玉為心以奉君。"]'),
('yuding-15','擣衣篇','劉希夷','唐','御定全唐诗','yuding','','[]','秋天瑟瑟夜漫漫，夜白風清玉露漙。燕山遊子衣裳薄，',120,'御定全唐詩/json/082.json','["秋天瑟瑟夜漫漫，夜白風清玉露漙。燕山遊子衣裳薄，", "攬紅袖兮愁徙倚，盼青砧兮悵盤桓。盤桓徙倚夜已久，", "此時秋月可憐明，此時秋風別有情。君看月下參差影，", "攢眉緝縷思紛紛，對影穿針魂悄悄。聞道還家未有期，", "緘書遠寄交河曲，須及明年春草綠。莫言衣上有斑斑，"]'),
('yuding-16','公子行','劉希夷','唐','御定全唐诗','yuding','','[]','天津橋下陽春水，天津橋上繁華子。馬聲回合青雲外，',120,'御定全唐詩/json/082.json','["天津橋下陽春水，天津橋上繁華子。馬聲回合青雲外，", "可憐楊柳傷心樹，可憐桃李斷腸花。此日遨遊邀美女，", "的的珠簾白日映，娥娥玉顏紅粉妝。花際裴回雙蛺蝶，", "古來容光人所羨，況複今日遙相見。願作輕羅著細腰，", "願作貞松千歲古，誰論芳槿一朝新。百年同謝西山日，"]'),
('yuding-17','代悲白頭翁','劉希夷','唐','御定全唐诗','yuding','','[]','洛陽城東桃李花，飛來飛去落誰家。洛陽女兒惜顏色，',112,'御定全唐詩/json/082.json','["洛陽城東桃李花，飛來飛去落誰家。洛陽女兒惜顏色，", "已見松柏摧為薪，更聞桑田變成海。古人無複洛城東，", "寄言全盛紅顏子，應憐半死白頭翁。此翁白頭真可憐，", "光祿池台開錦繡，將軍樓閣畫神仙。一朝臥病無相識，", "但看古來歌舞地，惟有黃昏鳥雀悲。"]'),
('yuding-18','代秦女贈行人','劉希夷','唐','御定全唐诗','yuding','','[]','鸞鏡曉含春，蛾眉向影嚬。開□衣裳破，那堪粉黛新。',72,'御定全唐詩/json/082.json','["鸞鏡曉含春，蛾眉向影嚬。開□衣裳破，那堪粉黛新。", "春還洛陽道，為憶春階草。楊葉未能攀，梅花待君掃。", "今朝喜鵲傍人飛，應是狂夫走馬歸。遙想行歌共遊樂，"]'),
('yuding-19','洛中晴月送殷四入關','劉希夷','唐','御定全唐诗','yuding','','[]','清洛浮橋南渡頭，天晶萬里散華洲。晴看石瀨光無數，',40,'御定全唐詩/json/082.json','["清洛浮橋南渡頭，天晶萬里散華洲。晴看石瀨光無數，", "欲將此意與君論，複道秦關尚千里。"]'),
('yuding-20','入塞','劉希夷','唐','御定全唐诗','yuding','','[]','將軍陷虜圍，邊務息戎機。霜雪交河盡，旌旗入塞飛。',48,'御定全唐詩/json/082.json','["將軍陷虜圍，邊務息戎機。霜雪交河盡，旌旗入塞飛。", "曉光隨馬度，春色伴人歸。課績朝明主，臨軒拜武威。"]'),
('yuding-21','覽鏡','劉希夷','唐','御定全唐诗','yuding','','[]','青樓掛明鏡，臨照不勝悲。白髮今如此，人生能幾時。',48,'御定全唐詩/json/082.json','["青樓掛明鏡，臨照不勝悲。白髮今如此，人生能幾時。", "秋風下山路，明月上春期。歎息君恩盡，容顏不可思。"]'),
('yuding-22','晚春','劉希夷','唐','御定全唐诗','yuding','','[]','佳人眠洞房，回首見垂楊。寒盡鴛鴦被，春生玳瑁床。',48,'御定全唐詩/json/082.json','["佳人眠洞房，回首見垂楊。寒盡鴛鴦被，春生玳瑁床。", "庭陰幕青靄，簾影散紅芳。寄語同心伴，迎春且薄妝。"]'),
('yuding-23','送友人之新豐','劉希夷','唐','御定全唐诗','yuding','','[]','日暮秋風起，關山斷別情。淚隨黃葉下，愁向綠樽生。',48,'御定全唐詩/json/082.json','["日暮秋風起，關山斷別情。淚隨黃葉下，愁向綠樽生。", "野路歸驂轉，河洲宿鳥驚。賓游寬旅宴，王事促嚴程。"]'),
('yuding-24','餞李秀才赴舉','劉希夷','唐','御定全唐诗','yuding','','[]','鴻鵠振羽翮，翻飛入帝鄉。朝鳴集銀樹，暝宿下金塘。',48,'御定全唐詩/json/082.json','["鴻鵠振羽翮，翻飛入帝鄉。朝鳴集銀樹，暝宿下金塘。", "日月天門近，風煙夜路長。自憐窮浦雁，歲歲不隨陽。"]'),
('yuding-25','夜集張諲所居','劉希夷','唐','御定全唐诗','yuding','','[]','江南成久客，門館日蕭條。惟有圖書在，多傷鬢髮凋。',60,'御定全唐詩/json/082.json','["江南成久客，門館日蕭條。惟有圖書在，多傷鬢髮凋。", "諸生陪講誦，稚子給漁樵。隱室寒燈淨，空階落葉飄。", "滄洲自有趣，誰道隱須招。"]'),
('yuding-26','故園置酒','劉希夷','唐','御定全唐诗','yuding','','[]','酒熟人須飲，春還鬢已秋。願逢千日醉，得緩百年憂。',72,'御定全唐詩/json/082.json','["酒熟人須飲，春還鬢已秋。願逢千日醉，得緩百年憂。", "舊裏多青草，新知盡白頭。風前燈易滅，川上月難留。", "卒卒周姬旦，棲棲魯孔丘。平生能幾日，不及且遨遊。"]'),
('yuding-27','晚憩南陽旅館','劉希夷','唐','御定全唐诗','yuding','','[]','旅館何年廢，征夫此日過。途窮人自哭，春至鳥還歌。',72,'御定全唐詩/json/082.json','["旅館何年廢，征夫此日過。途窮人自哭，春至鳥還歌。", "行路新知少，荒田古徑多。池篁覆丹穀，墳樹繞清波。", "日照蓬陰轉，風微野氣和。傷心不可去，回首怨如何。"]'),
('yuding-0','慶雲章','陳子昂','唐','御定全唐诗','yuding','','[]','昆侖元氣，實生慶雲。大人作矣，五色氤氳。昔在帝媯，',25,'御定全唐詩/json/083.json','["昆侖元氣，實生慶雲。大人作矣，五色氤氳。昔在帝媯，"]'),
('yuding-1','感遇詩三十八首','陳子昂','唐','御定全唐诗','yuding','','[]','微月生西海，幽陽始代升。圓光正東滿，陰魄已朝凝。',565,'御定全唐詩/json/083.json','["微月生西海，幽陽始代升。圓光正東滿，陰魄已朝凝。", "太極生天地，三元更廢興。至精諒斯在，三五誰能征。", "蘭若生春夏，芊蔚何青青。幽獨空林色，朱蕤冒紫莖。", "遲遲白日晚，嫋嫋秋風生。歲華盡搖落，芳意竟何成。", "蒼蒼丁零塞，今古緬荒途。亭堠何摧兀，暴骨無全軀。", "黃沙幕南起，白日隱西隅。漢甲三十萬，曾以事匈奴。", "但見沙場死，誰憐塞上孤。", "樂羊為魏將，食子殉軍功。骨肉且相薄，他人安得忠。", "吾聞中山相，乃屬放麑翁。孤獸猶不忍，況以奉君終。", "市人矜巧智，于道若童蒙。傾奪相誇侈，不知身所終。", "曷見玄真子，觀世玉壺中。窅然遺天地，乘化入無窮。", "吾觀龍變化，乃知至陽精。石林何冥密，幽洞無留行。", "古之得仙道，信與元化並。玄感非象識，誰能測沉冥。", "世人拘目見，酣酒笑丹經。昆侖有瑤樹，安得采其英。", "白日每不歸，青陽時暮矣。茫茫吾何思，林臥觀無始。", "眾芳委時晦，鶗鴂鳴悲耳。鴻荒古已頹，誰識巢居子。", "吾觀昆侖化，日月淪洞冥。精魄相交會，天壤以羅生。", "仲尼推太極，老聃貴窈冥。西方金仙子，崇義乃無明。", "空色皆寂滅，緣業定何成。名教信紛藉，死生俱未停。", "聖人秘元命，懼世亂其真。如何嵩公輩，詼譎誤時人。", "先天誠為美，階亂禍誰因。長城備胡寇，嬴禍發其親。", "赤精既迷漢，子年何救秦。去去桃李花，多言死如麻。", "深居觀元化，悱然爭朵頤。讒說相啖食，利害紛eq々。", "便便誇毗子，榮耀更相持。務光讓天下，商賈競刀錐。"]'),
('yuding-2','觀荊玉篇','陳子昂','唐','御定全唐诗','yuding','','[]','鴟夷雙白玉，此玉有緇磷。懸之千金價，舉世莫知真。',48,'御定全唐詩/json/083.json','["鴟夷雙白玉，此玉有緇磷。懸之千金價，舉世莫知真。", "丹青非異色，輕重有殊倫。勿信玉工言，徒悲荊國人。"]'),
('yuding-3','鴛鴦篇','陳子昂','唐','御定全唐诗','yuding','','[]','飛飛鴛鴦鳥，舉翼相蔽虧。俱來綠潭裏，共向白雲涯。',168,'御定全唐詩/json/083.json','["飛飛鴛鴦鳥，舉翼相蔽虧。俱來綠潭裏，共向白雲涯。", "音容相眷戀，羽翮兩逶迤。蘋萍戲春渚，霜霰繞寒池。", "浦沙連岸淨，汀樹拂潭垂。年年此遊玩，歲歲來追隨。", "鳳凰起丹穴，獨向梧桐枝。鴻雁來紫塞，空憶稻粱肥。", "烏啼倦依託，鶴鳴傷別離。豈若此雙禽，飛翻不異林。", "刷尾青江浦，交頸紫山岑。文章負奇色，和鳴多好音。", "聞有鴛鴦綺，複有鴛鴦衾。持為美人贈，勖此故交心。"]'),
('yuding-4','與東方左史虯修竹篇','陳子昂','唐','御定全唐诗','yuding','','[]','龍種生南嶽，孤翠鬱亭亭。峰嶺上崇崒，煙雨下微冥。',216,'御定全唐詩/json/083.json','["龍種生南嶽，孤翠鬱亭亭。峰嶺上崇崒，煙雨下微冥。", "夜聞鼯鼠叫，晝聒泉壑聲。春風正淡蕩，白露已清泠。", "哀響激金奏，密色滋玉英。歲寒霜雪苦，含彩獨青青。", "豈不厭凝冽，羞比春木榮。春木有榮歇，此節無凋零。", "始願與金石，終古保堅貞。不意伶倫子，吹之學鳳鳴。", "遂偶雲和瑟，張樂奏天庭。妙曲方千變，簫韶亦九成。", "信蒙雕斫美，常願事仙靈。驅馳翠虯駕，伊鬱紫鸞笙。", "結交嬴台女，吟弄升天行。攜手登白日，遠遊戲赤城。", "低昂玄鶴舞，斷續彩雲生。永隨眾仙逝，三山遊玉京。"]'),
('yuding-5','薊丘覽古贈盧居士藏用七首：軒轅台','陳子昂','唐','御定全唐诗','yuding','','[]','北登薊丘望，求古軒轅台。應龍已不見，牧馬空黃埃。',36,'御定全唐詩/json/083.json','["北登薊丘望，求古軒轅台。應龍已不見，牧馬空黃埃。", "尚想廣成子，遺跡白雲隈。"]'),
('yuding-6','薊丘覽古贈盧居士藏用七首：燕昭王','陳子昂','唐','御定全唐诗','yuding','','[]','南登碣石阪，遙望黃金台。丘陵盡喬木，昭王安在哉。',36,'御定全唐詩/json/083.json','["南登碣石阪，遙望黃金台。丘陵盡喬木，昭王安在哉。", "霸圖悵已矣，驅馬複歸來。"]'),
('yuding-7','薊丘覽古贈盧居士藏用七首：樂生','陳子昂','唐','御定全唐诗','yuding','','[]','王道已淪昧，戰國競貪兵。樂生何感激，仗義下齊城。',36,'御定全唐詩/json/083.json','["王道已淪昧，戰國競貪兵。樂生何感激，仗義下齊城。", "雄圖竟中夭，遺歎寄阿衡。"]'),
('yuding-8','薊丘覽古贈盧居士藏用七首：燕太子','陳子昂','唐','御定全唐诗','yuding','','[]','秦王日無道，太子怨亦深。一聞田光義，匕首贈千金。',36,'御定全唐詩/json/083.json','["秦王日無道，太子怨亦深。一聞田光義，匕首贈千金。", "其事雖不立，千載為傷心。"]'),
('yuding-9','薊丘覽古贈盧居士藏用七首：田光先生','陳子昂','唐','御定全唐诗','yuding','','[]','自古皆有死，徇義良獨稀。奈何燕太子，尚使田生疑。',36,'御定全唐詩/json/083.json','["自古皆有死，徇義良獨稀。奈何燕太子，尚使田生疑。", "伏劍誠已矣，感我涕沾衣。"]'),
('yuding-10','薊丘覽古贈盧居士藏用七首：鄒衍','陳子昂','唐','御定全唐诗','yuding','','[]','大運淪三代，天人罕有窺。鄒子何寥廓，漫說九瀛垂。',36,'御定全唐詩/json/083.json','["大運淪三代，天人罕有窺。鄒子何寥廓，漫說九瀛垂。", "興亡已千載，今也則無推。"]'),
('yuding-11','薊丘覽古贈盧居士藏用七首：郭隗','陳子昂','唐','御定全唐诗','yuding','','[]','逢時獨為貴，歷代非無才。隗君亦何幸，遂起黃金台。',24,'御定全唐詩/json/083.json','["逢時獨為貴，歷代非無才。隗君亦何幸，遂起黃金台。"]'),
('yuding-12','西還至散關答喬補闕知之','陳子昂','唐','御定全唐诗','yuding','','[]','葳蕤蒼梧鳳，嘹唳白露蟬。羽翰本非匹，結交何獨全。',120,'御定全唐詩/json/083.json','["葳蕤蒼梧鳳，嘹唳白露蟬。羽翰本非匹，結交何獨全。", "昔君事胡馬，餘得奉戎旃。攜手向沙塞，關河緬幽燕。", "芳歲幾陽止，白日屢徂遷。功業雲台薄，平生玉佩捐。", "歎此南歸日，猶聞北戍邊。代水不可涉，巴江亦潺湲。", "攬衣度函穀，銜涕望秦川。蜀門自茲始，雲山方浩然。"]'),
('yuding-13','度峽口山贈喬補闕知之王二無競','陳子昂','唐','御定全唐诗','yuding','','[]','峽口大漠南，橫絕界中國。叢石何紛糾，赤山複翕赩。',120,'御定全唐詩/json/083.json','["峽口大漠南，橫絕界中國。叢石何紛糾，赤山複翕赩。", "遠望多眾容，逼之無異色。崔崒乍孤斷，逶迤屢回直。", "信關胡馬沖，亦距漢邊塞。豈依河山險，將順休明德。", "物壯誠有衰，勢雄良易極。邐迤忽而盡，泱漭平不息。", "之子黃金軀，如何此荒域。雲台盛多士，待君丹墀側。"]'),
('yuding-14','題居延古城贈喬十二知之','陳子昂','唐','御定全唐诗','yuding','','[]','聞君東山意，宿昔紫芝榮。滄洲今何在，華髮旅邊城。',72,'御定全唐詩/json/083.json','["聞君東山意，宿昔紫芝榮。滄洲今何在，華髮旅邊城。", "還漢功既薄，逐胡策未行。徒嗟白日暮，坐對黃雲生。", "桂枝芳欲晚，薏苡謗誰明。無為空自老，含歎負生平。"]'),
('yuding-15','贈趙六貞固二首','陳子昂','唐','御定全唐诗','yuding','','[]','回中烽火入，塞上追兵起。此時邊朔寒，登隴思君子。',132,'御定全唐詩/json/083.json','["回中烽火入，塞上追兵起。此時邊朔寒，登隴思君子。", "東顧望漢京，南山雲霧裏。", "赤螭媚其彩，婉孌蒼梧泉。昔者琅琊子，躬耕亦慨然。", "美人豈遐曠，之子乃前賢。良辰在何許，白日屢頹遷。", "道心固微密，神用無留連。舒可彌宇宙，攬之不盈拳。", "蓬萊久蕪沒，金石徒精堅。良寶委短褐，閑琴獨嬋娟。"]'),
('yuding-16','答韓使同在邊','陳子昂','唐','御定全唐诗','yuding','','[]','漢家失中策，胡馬屢南驅。聞詔安邊使，曾是故人謨。',144,'御定全唐詩/json/083.json','["漢家失中策，胡馬屢南驅。聞詔安邊使，曾是故人謨。", "廢書悵懷古，負劍許良圖。出關歲方晏，乘障日多虞。", "虜入白登道，烽交紫塞途。連兵屯北地，清野備東胡。", "邊城方晏閉，斥堠始昭蘇。複聞韓長孺，辛苦事匈奴。", "雨雪顏容改，縱橫才位孤。空懷老臣策，未獲趙軍租。", "但蒙魏侯重，不受謗書誣。當取金人祭，還歌凱入都。"]'),
('yuding-17','征東至淇門答宋十一參軍之問','陳子昂','唐','御定全唐诗','yuding','','[]','南星中大火，將子涉清淇。西林改微月，征旆空自持。',48,'御定全唐詩/json/083.json','["南星中大火，將子涉清淇。西林改微月，征旆空自持。", "碧潭去已遠，瑤華折遺誰。若問遼陽戍，悠悠天際旗。"]'),
('yuding-18','答洛陽主人','陳子昂','唐','御定全唐诗','yuding','','[]','平生白雲志，早愛赤松遊。事親恨未立，從宦此中州。',84,'御定全唐詩/json/083.json','["平生白雲志，早愛赤松遊。事親恨未立，從宦此中州。", "主人亦何問，旅客非悠悠。方謁明天子，清宴奉良籌。", "再取連城璧，三陟平津侯。不然拂衣去，歸從海上鷗。", "寧隨當代子，傾側且沉浮。"]'),
('yuding-19','酬暉上人秋夜山亭有贈','陳子昂','唐','御定全唐诗','yuding','','[]','皎皎白林秋，微微翠山靜。禪居感物變，獨坐開軒屏。',48,'御定全唐詩/json/083.json','["皎皎白林秋，微微翠山靜。禪居感物變，獨坐開軒屏。", "風泉夜聲雜，月露宵光冷。多謝忘機人，塵憂未能整。"]'),
('yuding-20','酬李參軍崇嗣旅館見贈','陳子昂','唐','御定全唐诗','yuding','','[]','昨夜銀河畔，星文犯遙漢。今朝紫氣新，物色果逢真。',120,'御定全唐詩/json/083.json','["昨夜銀河畔，星文犯遙漢。今朝紫氣新，物色果逢真。", "言從天上落，乃是地仙人。白璧疑冤楚，烏裘似入秦。", "摧藏多古意，曆覽備艱辛。樂廣雲雖睹，夷吾風未春。", "鳳歌空有問，龍性詎能馴。寶劍終應出，驪珠會見珍。", "未及馮公老，何驚孺子貧。青雲儻可致，北海憶孫賓。"]'),
('yuding-21','酬暉上人夏日林泉','陳子昂','唐','御定全唐诗','yuding','','[]','聞道白雲居，窈窕青蓮宇。岩泉萬丈流，樹石千年古。',48,'御定全唐詩/json/083.json','["聞道白雲居，窈窕青蓮宇。岩泉萬丈流，樹石千年古。", "林臥對軒窗，山陰滿庭戶。方釋塵事勞，從君襲蘭杜。"]'),
('yuding-22','同宋參軍之問夢趙六贈盧陳二子之作','陳子昂','唐','御定全唐诗','yuding','','[]','曉霽望嵩丘，白雲半岩足。氛氳涵翠微，宛如嬴台曲。',240,'御定全唐詩/json/083.json','["曉霽望嵩丘，白雲半岩足。氛氳涵翠微，宛如嬴台曲。", "故人昔所尚，幽琴歌斷續。變化竟無常，人琴遂兩亡。", "白雲失處所，夢想曖容光。疇昔疑緣業，儒道兩相妨。", "前期許幽報，迨此尚茫茫。晤言既已失，感歎情何一。", "始憶攜手期，雲台與峨眉。達兼濟天下，窮獨善其時。", "諸君推管樂，之子慕巢夷。奈何蒼生望，卒為黃綬欺。", "銘鼎功未立，山林事亦微。撫孤一流慟，懷舊日暌違。", "盧子尚高節，終南臥松雪。宋侯逢聖君，驂馭游青雲。", "而我獨蹭蹬，語默道猶屯。征戍在遼陽，蹉跎草再黃。", "丹丘恨不及，白露已蒼蒼。遠聞山陽賦，感涕下沾裳。"]'),
('yuding-23','送別出塞','陳子昂','唐','御定全唐诗','yuding','','[]','平生聞高義，書劍百夫雄。言登青雲去，非此白頭翁。',72,'御定全唐詩/json/083.json','["平生聞高義，書劍百夫雄。言登青雲去，非此白頭翁。", "胡兵屯塞下，漢騎屬雲中。君為白馬將，腰佩騂角弓。", "單于不敢射，天子佇深功。蜀山余方隱，良會何時同。"]'),
('yuding-24','登薊丘樓送賈兵曹入都','陳子昂','唐','御定全唐诗','yuding','','[]','東山宿昔意，北征非我心。孤負平生願，感涕下沾襟。',84,'御定全唐詩/json/083.json','["東山宿昔意，北征非我心。孤負平生願，感涕下沾襟。", "暮登薊樓上，永望燕山岑。遼海方漫漫，胡沙飛且深。", "峨眉杳如夢，仙子曷由尋。擊劍起歎息，白日忽西沉。", "聞君洛陽使，因數寄南音。"]'),
('yuding-25','夏日暉上人房別李參軍崇嗣','陳子昂','唐','御定全唐诗','yuding','','[]','四十九變化，一十三死生。翕忽玄黃裏，驅馳風雨情。',144,'御定全唐詩/json/083.json','["四十九變化，一十三死生。翕忽玄黃裏，驅馳風雨情。", "是非紛妄作，寵辱坐相驚。至人獨幽鑒，窈窕隨昏明。", "咫尺山河道，軒窗日月庭。別離焉足問，悲樂固能並。", "我輩何為爾，棲皇猶未平。金台可攀陟，寶界絕將迎。", "戶牖觀天地，階基上杳冥。自超三界樂，安知萬里征。", "中國要荒內，人寰宇宙榮。弦望如朝夕，寧嗟蜀道行。"]'),
('yuding-26','秋園臥病呈暉上人','陳子昂','唐','御定全唐诗','yuding','','[]','幽寂曠日遙，林園轉清密。疲屙澹無豫，獨坐泛瑤瑟。',120,'御定全唐詩/json/083.json','["幽寂曠日遙，林園轉清密。疲屙澹無豫，獨坐泛瑤瑟。", "懷挾萬古情，憂虞百年疾。綿綿多滯念，忽忽每如失。", "緬想赤松游，高尋白雲逸。榮吝始都喪，幽人遂貞吉。", "圖書紛滿床，山水藹盈室。宿昔心所尚，平生自茲畢。", "願言誰見知，梵筵有同術。八月高秋晚，涼風正蕭瑟。"]'),
('yuding-27','登澤州城北樓宴','陳子昂','唐','御定全唐诗','yuding','','[]','平生倦遊者，觀化久無窮。複來登此國，臨望與君同。',72,'御定全唐詩/json/083.json','["平生倦遊者，觀化久無窮。複來登此國，臨望與君同。", "坐見秦兵壘，遙聞趙將雄。武安君何在，長平事已空。", "且歌玄雲曲，禦酒舞熏風。勿使青衿子，嗟爾白頭翁。"]'),
('yuding-28','山水粉圖','陳子昂','唐','御定全唐诗','yuding','','[]','山圖之白雲兮，若巫山之高丘。紛群翠之鴻溶，',21,'御定全唐詩/json/083.json','["山圖之白雲兮，若巫山之高丘。紛群翠之鴻溶，"]'),
('yuding-29','彩樹歌','陳子昂','唐','御定全唐诗','yuding','','[]','嘉錦筵之珍樹兮，錯眾彩之氛氳。狀瑤台之微月，',44,'御定全唐詩/json/083.json','["嘉錦筵之珍樹兮，錯眾彩之氛氳。狀瑤台之微月，", "結芳意而誰賞，怨絕世之無聞。紅榮碧豔坐看歇，"]'),
('yuding-30','春台引','陳子昂','唐','御定全唐诗','yuding','','[]','感陽春兮生碧草之油油。懷宇宙以傷遠，登高台而寫憂。',156,'御定全唐詩/json/083.json','["感陽春兮生碧草之油油。懷宇宙以傷遠，登高台而寫憂。", "遲美人兮不見，恐青歲之遂遒。從畢公以酣飲，", "何雲木之美麗，而池館之崇幽。星台秀士，月旦諸子。", "嘉青鳥之辰，迎火龍之始。挾寶書與瑤瑟，", "擊青鐘，歌淥水。怨青春之萎絕，贈瑤台之旖旎。", "願一見而道意，結眾芳之綢繆。曷餘情之蕩漾，", "群仙去兮青春頹，歲華歇兮黃鳥哀。富貴榮樂幾時兮，"]'),
('yuding-31','登幽州台歌','陳子昂','唐','御定全唐诗','yuding','','[]','前不見古人，後不見來者。',26,'御定全唐詩/json/083.json','["前不見古人，後不見來者。", "念天地之悠悠，獨愴然而涕下。"]'),
('yuding-32','喜馬參軍相遇醉歌','陳子昂','唐','御定全唐诗','yuding','','[]','獨幽默以三月兮，深林潛居。時歲忽兮，孤憤遐吟。',39,'御定全唐詩/json/083.json','["獨幽默以三月兮，深林潛居。時歲忽兮，孤憤遐吟。", "誰知我心？孺子孺子，其可與理分。"]'),
('yuding-0','度荊門望楚','陳子昂','唐','御定全唐诗','yuding','','[]','遙遙去巫峽，望望下章台。巴國山川盡，荊門煙霧開。',48,'御定全唐詩/json/084.json','["遙遙去巫峽，望望下章台。巴國山川盡，荊門煙霧開。", "城分蒼野外，樹斷白雲隈。今日狂歌客，誰知入楚來。"]'),
('yuding-1','晚次樂鄉縣','陳子昂','唐','御定全唐诗','yuding','','[]','故鄉杳無際，日暮且孤征。川原迷舊國，道路入邊城。',48,'御定全唐詩/json/084.json','["故鄉杳無際，日暮且孤征。川原迷舊國，道路入邊城。", "野戍荒煙斷，深山古木平。如何此時恨，噭噭夜猿鳴。"]'),
('yuding-2','同王員外雨後登開元寺南樓因酬暉上人獨坐山亭有贈','陳子昂','唐','御定全唐诗','yuding','','[]','鐘梵經行罷，香林坐入禪。岩庭交雜樹，石瀨瀉鳴泉。',48,'御定全唐詩/json/084.json','["鐘梵經行罷，香林坐入禪。岩庭交雜樹，石瀨瀉鳴泉。", "水月心方寂，雲霞思獨玄。甯知人世裏，疲病得攀緣。"]'),
('yuding-3','東征答朝臣相送','陳子昂','唐','御定全唐诗','yuding','','[]','平生白雲意，疲苶愧為雄。君王謬殊寵，旌節此從戎。',48,'御定全唐詩/json/084.json','["平生白雲意，疲苶愧為雄。君王謬殊寵，旌節此從戎。", "挼繩當系虜，單馬豈邀功。孤劍將何托，長謠塞上風。"]'),
('yuding-4','詠主人壁上畫鶴，寄喬主簿崔著作','陳子昂','唐','御定全唐诗','yuding','','[]','古壁仙人畫，丹青尚有文。獨舞紛如雪，孤飛曖似雲。',48,'御定全唐詩/json/084.json','["古壁仙人畫，丹青尚有文。獨舞紛如雪，孤飛曖似雲。", "自矜彩色重，甯憶故池群。江海聯翩翼，長鳴誰複聞。"]'),
('yuding-5','居延海樹聞鶯同作','陳子昂','唐','御定全唐诗','yuding','','[]','邊地無芳樹，鶯聲忽聽新。間關如有意，愁絕若懷人。',48,'御定全唐詩/json/084.json','["邊地無芳樹，鶯聲忽聽新。間關如有意，愁絕若懷人。", "明妃失漢寵，蔡女沒胡塵。坐聞應落淚，況憶故園春。"]'),
('yuding-6','題李三書齋','陳子昂','唐','御定全唐诗','yuding','','[]','灼灼青春仲，悠悠白日升。聲容何足恃，榮吝坐相矜。',48,'御定全唐詩/json/084.json','["灼灼青春仲，悠悠白日升。聲容何足恃，榮吝坐相矜。", "願與金庭會，將待玉書征。還丹應有術，煙駕共君乘。"]'),
('yuding-7','送魏大從軍','陳子昂','唐','御定全唐诗','yuding','','[]','匈奴猶未滅，魏絳複從戎。悵別三河道，言追六郡雄。',48,'御定全唐詩/json/084.json','["匈奴猶未滅，魏絳複從戎。悵別三河道，言追六郡雄。", "雁山橫代北，狐塞接雲中。勿使燕然上，惟留漢將功。"]'),
('yuding-8','送殷大入蜀','陳子昂','唐','御定全唐诗','yuding','','[]','禺山金碧路，此地饒英靈。送君一為別，淒斷故鄉情。',48,'御定全唐詩/json/084.json','["禺山金碧路，此地饒英靈。送君一為別，淒斷故鄉情。", "片雲生極浦，斜日隱離亭。坐看征騎沒，惟見遠山青。"]'),
('yuding-9','落第西還別劉祭酒高明府','陳子昂','唐','御定全唐诗','yuding','','[]','別館分周國，歸驂入漢京。地連函穀塞，川接廣陽城。',48,'御定全唐詩/json/084.json','["別館分周國，歸驂入漢京。地連函穀塞，川接廣陽城。", "望迥樓臺出，途遙煙霧生。莫言長落羽，貧賤一交情。"]'),
('yuding-10','落第西還別魏四懍','陳子昂','唐','御定全唐诗','yuding','','[]','轉蓬方不定，落羽自驚弦。山水一為別，歡娛複幾年。',48,'御定全唐詩/json/084.json','["轉蓬方不定，落羽自驚弦。山水一為別，歡娛複幾年。", "離亭暗風雨，征路入雲煙。還因北山徑，歸守東陂田。"]'),
('yuding-11','送客','陳子昂','唐','御定全唐诗','yuding','','[]','故人洞庭去，楊柳春風生。相送河洲晚，蒼茫別思盈。',48,'御定全唐詩/json/084.json','["故人洞庭去，楊柳春風生。相送河洲晚，蒼茫別思盈。", "白蘋已堪把，綠芷複含榮。江南多桂樹，歸客贈生平。"]'),
('yuding-12','春夜別友人二首','陳子昂','唐','御定全唐诗','yuding','','[]','銀燭吐青煙，金樽對綺筵。離堂思琴瑟，別路繞山川。',96,'御定全唐詩/json/084.json','["銀燭吐青煙，金樽對綺筵。離堂思琴瑟，別路繞山川。", "明月隱高樹，長河沒曉天。悠悠洛陽道，此會在何年。", "紫塞白雲斷，青春明月初。對此芳樽夜，離憂悵有餘。", "清冷花露滿，滴瀝簷宇虛。懷君欲何贈，願上大臣書。"]'),
('yuding-13','遂州南江別鄉曲故人','陳子昂','唐','御定全唐诗','yuding','','[]','楚江複為客，征棹方悠悠。故人憫追送，置酒此南洲。',48,'御定全唐詩/json/084.json','["楚江複為客，征棹方悠悠。故人憫追送，置酒此南洲。", "平生亦何恨，夙昔在林丘。違此鄉山別，長謠去國愁。"]'),
('yuding-14','送東萊王學士無競','陳子昂','唐','御定全唐诗','yuding','','[]','寶劍千金買，平生未許人。懷君萬里別，持贈結交親。',48,'御定全唐詩/json/084.json','["寶劍千金買，平生未許人。懷君萬里別，持贈結交親。", "孤松宜晚歲，眾木愛芳春。已矣將何道，無令白首新。"]'),
('yuding-15','送梁李二明府','陳子昂','唐','御定全唐诗','yuding','','[]','負書猶在漢，懷策未聞秦。複此窮秋日，芳樽別故人。',48,'御定全唐詩/json/084.json','["負書猶在漢，懷策未聞秦。複此窮秋日，芳樽別故人。", "黃金裝屢盡，白首契逾新。空羨雙鳧舄，俱飛向玉輪。"]'),
('yuding-16','送魏兵曹使巂州得登字','陳子昂','唐','御定全唐诗','yuding','','[]','陽山淫霧雨，之子慎攀登。羌笮多珍寶，人言有愛憎。',48,'御定全唐詩/json/084.json','["陽山淫霧雨，之子慎攀登。羌笮多珍寶，人言有愛憎。", "欲酬明主惠，當盡使臣能。勿以王陽道，迢遞畏崚嶒。"]'),
('yuding-17','送著作佐郎崔融等從梁王東征','陳子昂','唐','御定全唐诗','yuding','','[]','金天方肅殺，白露始專征。王師非樂戰，之子慎佳兵。',48,'御定全唐詩/json/084.json','["金天方肅殺，白露始專征。王師非樂戰，之子慎佳兵。", "海氣侵南部，邊風掃北平。莫賣盧龍塞，歸邀麟閣名。"]'),
('yuding-18','春晦餞陶七於江南同用風字','陳子昂','唐','御定全唐诗','yuding','','[]','黃鶴煙雲去，青江琴酒同。離帆方楚越，溝水複西東。',48,'御定全唐詩/json/084.json','["黃鶴煙雲去，青江琴酒同。離帆方楚越，溝水複西東。", "芙蓉生夏浦，楊柳送春風。明日相思處，應對菊花叢。"]'),
('yuding-19','喜遇冀侍禦珪崔司議泰之二使','陳子昂','唐','御定全唐诗','yuding','','[]','謝病南山下，幽臥不知春。使星入東井，雲是故交親。',48,'御定全唐詩/json/084.json','["謝病南山下，幽臥不知春。使星入東井，雲是故交親。", "惠風吹寶瑟，微月憶清真。憑軒一留醉，江海寄情人。"]'),
('yuding-20','登薊城西北樓送崔著作融入都','陳子昂','唐','御定全唐诗','yuding','','[]','薊樓望燕國，負劍喜茲登。清規子方奏，單戟我無能。',48,'御定全唐詩/json/084.json','["薊樓望燕國，負劍喜茲登。清規子方奏，單戟我無能。", "仲冬邊風急，雲漢複霜棱。慷慨竟何道，西南恨失朋。"]'),
('yuding-21','月夜有懷','陳子昂','唐','御定全唐诗','yuding','','[]','美人挾趙瑟，微月在西軒。寂寞夜何久，殷勤玉指繁。',48,'御定全唐詩/json/084.json','["美人挾趙瑟，微月在西軒。寂寞夜何久，殷勤玉指繁。", "清光委衾枕，遙思屬湘沅。空簾隔星漢，猶夢感精魂。"]'),
('yuding-22','夏日游暉上人房','陳子昂','唐','御定全唐诗','yuding','','[]','山水開精舍，琴歌列梵筵。人疑白樓賞，地似竹林禪。',48,'御定全唐詩/json/084.json','["山水開精舍，琴歌列梵筵。人疑白樓賞，地似竹林禪。", "對戶池光亂，交軒岩翠連。色空今已寂，乘月弄澄泉。"]'),
('yuding-23','春日登金華觀','陳子昂','唐','御定全唐诗','yuding','','[]','白玉仙台古，丹丘別望遙。山川亂雲日，樓榭入煙霄。',48,'御定全唐詩/json/084.json','["白玉仙台古，丹丘別望遙。山川亂雲日，樓榭入煙霄。", "鶴舞千年樹，虹飛百尺橋。還疑赤松子，天路坐相邀。"]'),
('yuding-24','群公集畢氏林亭','陳子昂','唐','御定全唐诗','yuding','','[]','金門有遺世，鼎實恣和邦。默語誰能識，琴樽寄北窗。',48,'御定全唐詩/json/084.json','["金門有遺世，鼎實恣和邦。默語誰能識，琴樽寄北窗。", "子牟戀魏闕，漁父愛滄江。良時信同此，歲晚跡難雙。"]'),
('yuding-25','宴胡楚真禁所','陳子昂','唐','御定全唐诗','yuding','','[]','人生固有命，天道信無言。青蠅一相點，白璧遂成冤。',48,'御定全唐詩/json/084.json','["人生固有命，天道信無言。青蠅一相點，白璧遂成冤。", "請室閑逾邃，幽庭春未暄。寄謝韓安國，何驚獄吏尊。"]'),
('yuding-26','魏氏園林人賦一物得秋亭萱草','陳子昂','唐','御定全唐诗','yuding','','[]','昔時幽徑裏，榮耀雜春叢。今來玉墀上，銷歇畏秋風。',48,'御定全唐詩/json/084.json','["昔時幽徑裏，榮耀雜春叢。今來玉墀上，銷歇畏秋風。", "細葉猶含綠，鮮花未吐紅。忘憂誰見賞，空此北堂中。"]'),
('yuding-27','《晦日宴高氏林亭','陳子昂','唐','御定全唐诗','yuding','','[]','尋春遊上路，追宴入山家。主第簪纓滿，皇州景望華。',48,'御定全唐詩/json/084.json','["尋春遊上路，追宴入山家。主第簪纓滿，皇州景望華。", "玉池初吐溜，珠樹始開花。歡娛方未極，林閣散餘霞。"]'),
('yuding-28','《晦日重宴高氏林亭','陳子昂','唐','御定全唐诗','yuding','','[]','公子好追隨，愛客不知疲。象筵開玉饌，翠羽飾金卮。',48,'御定全唐詩/json/084.json','["公子好追隨，愛客不知疲。象筵開玉饌，翠羽飾金卮。", "此時高宴所，詎減習家池。循涯倦短翮，何處儷長離。"]'),
('yuding-29','《上元夜效小庾體','陳子昂','唐','御定全唐诗','yuding','','[]','三五月華新，遨遊逐上春。相邀洛城曲，追宴小平津。',48,'御定全唐詩/json/084.json','["三五月華新，遨遊逐上春。相邀洛城曲，追宴小平津。", "樓上看珠妓，車中見玉人。芳宵殊未極，隨意守燈輪。"]'),
('yuding-30','洛城觀酺應制','陳子昂','唐','御定全唐诗','yuding','','[]','聖人信恭己，天命允昭回。蒼極神功被，青雲秘籙開。',96,'御定全唐詩/json/084.json','["聖人信恭己，天命允昭回。蒼極神功被，青雲秘籙開。", "垂衣受金冊，張樂宴瑤台。雲鳳休征滿，魚龍雜戲來。", "崇恩逾五日，惠澤暢三才。玉帛群臣醉，徽章縟禮該。", "方睹升中禪，言觀拜洛回。微臣固多幸，敢上萬年杯。"]'),
('yuding-31','奉和皇帝上禮撫事述懷應制','陳子昂','唐','御定全唐诗','yuding','','[]','大君忘自我，應運居紫宸。揖讓期明辟，謳歌且順人。',120,'御定全唐詩/json/084.json','["大君忘自我，應運居紫宸。揖讓期明辟，謳歌且順人。", "軒宮帝圖盛，皇極禮容申。南面朝萬國，東堂會百神。", "雲陛旗常滿，天庭玉帛陳。鐘石和睿思，雷雨被深仁。", "承平信娛樂，王業本艱辛。願罷瑤池宴，來觀農扈春。", "卑宮昭夏德，尊老睦堯親。微臣敢拜手，歌舞頌維新。"]'),
('yuding-32','酬田逸人遊岩見尋不遇題隱居裏壁','陳子昂','唐','御定全唐诗','yuding','','[]','遊人獻書去，薄暮返靈台。傳道尋仙友，青囊賣蔔來。',60,'御定全唐詩/json/084.json','["遊人獻書去，薄暮返靈台。傳道尋仙友，青囊賣蔔來。", "聞鶯忽相訪，題鳳久裴回。石髓空盈握，金經秘不開。", "還疑縫掖子，複似洛陽才。"]'),
('yuding-33','白帝城懷古','陳子昂','唐','御定全唐诗','yuding','','[]','日落滄江晚，停橈問土風。城臨巴子國，台沒漢王宮。',72,'御定全唐詩/json/084.json','["日落滄江晚，停橈問土風。城臨巴子國，台沒漢王宮。", "荒服仍周甸，深山尚禹功。岩懸青壁斷，地險碧流通。", "古木生雲際，孤帆出霧中。川途去無限，客思坐何窮。"]'),
('yuding-34','峴山懷古','陳子昂','唐','御定全唐诗','yuding','','[]','秣馬臨荒甸，登高覽舊都。猶悲墮淚碣，尚想臥龍圖。',72,'御定全唐詩/json/084.json','["秣馬臨荒甸，登高覽舊都。猶悲墮淚碣，尚想臥龍圖。", "城邑遙分楚，山川半入吳。丘陵徒自出，賢聖幾凋枯。", "野樹蒼煙斷，津樓晚氣孤。誰知萬里客，懷古正躊躕。"]'),
('yuding-35','宿空舲峽青樹村浦','陳子昂','唐','御定全唐诗','yuding','','[]','的的明月水，啾啾寒夜猿。客思浩方亂，洲浦寂無喧。',72,'御定全唐詩/json/084.json','["的的明月水，啾啾寒夜猿。客思浩方亂，洲浦寂無喧。", "憶作千金子，寧知九逝魂。虛聞事朱闕，結綬騖華軒。", "委別高堂愛，窺覦明主恩。今成轉蓬去，歎息複何言。"]'),
('yuding-36','宿襄河驛浦','陳子昂','唐','御定全唐诗','yuding','','[]','沿流辭北渚，結纜宿南洲。合岸昏初夕，回塘暗不流。',72,'御定全唐詩/json/084.json','["沿流辭北渚，結纜宿南洲。合岸昏初夕，回塘暗不流。", "臥聞塞鴻斷，坐聽峽猿愁。沙浦明如月，汀葭晦若秋。", "不及能鳴雁，徒思海上鷗。天河殊未曉，滄海信悠悠。"]'),
('yuding-37','贈嚴倉曹乞推命錄','陳子昂','唐','御定全唐诗','yuding','','[]','少學縱橫術，游楚複游燕。棲遑長委命，富貴未知天。',72,'御定全唐詩/json/084.json','["少學縱橫術，游楚複游燕。棲遑長委命，富貴未知天。", "聞道沉冥客，青囊有秘篇。九宮探萬象，三算極重玄。", "願奉唐生訣，將知躍馬年。非同墨翟問，空滯殺龍川。"]'),
('yuding-38','和陸明府贈將軍重出塞','陳子昂','唐','御定全唐诗','yuding','','[]','忽聞天上將，關塞重橫行。始返樓蘭國，還向朔方城。',72,'御定全唐詩/json/084.json','["忽聞天上將，關塞重橫行。始返樓蘭國，還向朔方城。", "黃金裝戰馬，白羽集神兵。星月開天陣，山川列地營。", "晚風吹畫角，春色耀飛旌。甯知班定遠，猶是一書生。"]'),
('yuding-39','江上暫別蕭四劉三旋欣接遇','陳子昂','唐','御定全唐诗','yuding','','[]','昨夜滄江別，言乖天漢遊。甯期此相遇，尚接武陵洲。',72,'御定全唐詩/json/084.json','["昨夜滄江別，言乖天漢遊。甯期此相遇，尚接武陵洲。", "結綬還逢育，銜杯且對劉。波潭一彌彌，臨望幾悠悠。", "山水丹青雜，煙雲紫翠浮。終愧神仙友，來接野人舟。"]'),
('yuding-40','秋日遇荊州府崔兵曹使宴','陳子昂','唐','御定全唐诗','yuding','','[]','輶軒鳳凰使，林藪鶡雞冠。江湖一相許，雲霧坐交歡。',72,'御定全唐詩/json/084.json','["輶軒鳳凰使，林藪鶡雞冠。江湖一相許，雲霧坐交歡。", "興盡崔亭伯，言忘釋道安。林光稍欲暮，歲物已將闌。", "古樹蒼煙斷，虛亭白露寒。瑤琴山水曲，今日為君彈。"]'),
('yuding-41','臥病家園','陳子昂','唐','御定全唐诗','yuding','','[]','世上無名子，人間歲月賒。縱橫策已棄，寂寞道為家。',72,'御定全唐詩/json/084.json','["世上無名子，人間歲月賒。縱橫策已棄，寂寞道為家。", "臥病誰能問，閒居空物華。猶憶靈台友，棲真隱太霞。", "還丹奔日禦，卻老餌雲芽。甯知白社客，不厭青門瓜。"]'),
('yuding-42','于長史山池三日曲水宴','陳子昂','唐','御定全唐诗','yuding','','[]','摘蘭藉芳月，祓宴坐回汀。泛灩清流滿，葳蕤白芷生。',72,'御定全唐詩/json/084.json','["摘蘭藉芳月，祓宴坐回汀。泛灩清流滿，葳蕤白芷生。", "金弦揮趙瑟，玉指弄秦箏。岩榭風光媚，郊園春樹平。", "煙花飛禦道，羅綺照昆明。日落紅塵合，車馬亂縱橫。"]'),
('yuding-43','合州津口別舍弟至東陽峽步趁不及眷然有憶作以示之','陳子昂','唐','御定全唐诗','yuding','','[]','江潭共為客，洲浦獨迷津。思積芳庭樹，心斷白眉人。',84,'御定全唐詩/json/084.json','["江潭共為客，洲浦獨迷津。思積芳庭樹，心斷白眉人。", "同衾成楚越，別島類胡秦。林岸隨天轉，雲峰逐望新。", "遙遙終不見，默默坐含嚬。念別疑三月，經遊未一旬。", "孤舟多逸興，誰共爾為鄰。"]'),
('yuding-44','萬州曉發放舟乘漲，還寄蜀中親朋','陳子昂','唐','御定全唐诗','yuding','','[]','空蒙岩雨霽，爛熳曉雲歸。嘯旅乘明發，奔橈騖斷磯。',96,'御定全唐詩/json/084.json','["空蒙岩雨霽，爛熳曉雲歸。嘯旅乘明發，奔橈騖斷磯。", "蒼茫林岫轉，絡繹漲濤飛。遠岸孤煙出，遙峰曙日微。", "前瞻未能眴，坐望已相依。曲直多今古，經過失是非。", "還期方浩浩，征思日騑騑。寄謝千金子，江海事多違。"]'),
('yuding-45','入峭峽安居溪伐木溪源幽邃林嶺相映有奇致焉','陳子昂','唐','御定全唐诗','yuding','','[]','肅徒歌伐木，騖楫漾輕舟。靡迤隨回水，潺湲溯淺流。',108,'御定全唐詩/json/084.json','["肅徒歌伐木，騖楫漾輕舟。靡迤隨回水，潺湲溯淺流。", "煙沙分兩岸，露島夾雙洲。古樹連雲密，交峰入浪浮。", "岩潭相映媚，溪谷屢環周。路迥光逾逼，山深興轉幽。", "麇鼯寒思晚，猿鳥暮聲秋。誓息蘭台策，將從桂樹遊。", "因書謝親愛，千歲覓蓬丘。"]'),
('yuding-46','入東陽峽與李明府舟前後不相及','陳子昂','唐','御定全唐诗','yuding','','[]','東岩初解纜，南浦遂離群。出沒同洲島，沿洄異渚濆。',120,'御定全唐詩/json/084.json','["東岩初解纜，南浦遂離群。出沒同洲島，沿洄異渚濆。", "風煙猶可望，歌笑浩難聞。路轉青山合，峰回白日曛。", "奔濤上漫漫，積水下沄沄。倏忽猶疑及，差池複兩分。", "離離間遠樹，藹藹沒遙氛。地上巴陵道，星連牛鬥文。", "孤狖啼寒月，哀鴻叫斷雲。仙舟不可見，搖思坐氛氳。"]'),
('yuding-47','同旻上人傷壽安傅少府','陳子昂','唐','御定全唐诗','yuding','','[]','生涯良浩浩，天命固諄諄。聞道神仙尉，懷德遂為鄰。',120,'御定全唐詩/json/084.json','["生涯良浩浩，天命固諄諄。聞道神仙尉，懷德遂為鄰。", "疇昔逢堯日，衣冠仕漢辰。交遊紛若鳳，詞翰宛如麟。", "太息勞黃綬，長思謁紫宸。金蘭徒有契，玉樹已埋塵。", "把臂雖無托，平生固亦親。援琴一流涕，舊館幾沾巾。", "杳杳泉中夜，悠悠世上春。幽明長隔此，歌哭為何人。"]'),
('yuding-48','南山家園林木交映盛夏五月幽然清涼獨坐思遠率成十韻','陳子昂','唐','御定全唐诗','yuding','','[]','寂寥守寒巷，幽獨臥空林。松竹生虛白，階庭橫古今。',120,'御定全唐詩/json/084.json','["寂寥守寒巷，幽獨臥空林。松竹生虛白，階庭橫古今。", "鬱蒸炎夏晚，棟宇閟清陰。軒窗交紫靄，簷戶對蒼岑。", "鳳蘊仙人籙，鸞歌素女琴。忘機委人代，閉牖察天心。", "蛺蝶憐紅藥，蜻蜓愛碧潯。坐觀萬象化，方見百年侵。", "擾擾將何息，青青長苦吟。願隨白雲駕，龍鶴相招尋。"]'),
('yuding-49','還至張掖古城，聞東軍告捷，贈韋五虛己','陳子昂','唐','御定全唐诗','yuding','','[]','孟秋首歸路，仲月旅邊亭。聞道蘭山戰，相邀在井陘。',132,'御定全唐詩/json/084.json','["孟秋首歸路，仲月旅邊亭。聞道蘭山戰，相邀在井陘。", "屢鬥關月滿，三捷虜雲平。漢軍追北地，胡騎走南庭。", "君為幕中士，疇昔好言兵。白虎鋒應出，青龍陣幾成。", "披圖見丞相，按節入咸京。寧知玉門道，翻作隴西行。", "北海朱旄落，東歸白露生。縱橫未得意，寂寞寡相迎。", "負劍空歎息，蒼茫登古城。"]'),
('yuding-50','題祀山烽樹贈喬十二侍禦','陳子昂','唐','御定全唐诗','yuding','','[]','漢庭榮巧宦，雲閣薄邊功。可憐驄馬使，白首為誰雄。',24,'御定全唐詩/json/084.json','["漢庭榮巧宦，雲閣薄邊功。可憐驄馬使，白首為誰雄。"]'),
('yuding-51','初入峽苦風寄故鄉親友','陳子昂','唐','御定全唐诗','yuding','','[]','故鄉今日友，歡會坐應同。甯知巴峽路，辛苦石尤風。',24,'御定全唐詩/json/084.json','["故鄉今日友，歡會坐應同。甯知巴峽路，辛苦石尤風。"]'),
('yuding-52','題田洗馬遊岩桔槔','陳子昂','唐','御定全唐诗','yuding','','[]','望苑長為客，商山遂不歸。誰憐北陵井，未息漢陰機。',24,'御定全唐詩/json/084.json','["望苑長為客，商山遂不歸。誰憐北陵井，未息漢陰機。"]'),
('yuding-53','古意題徐令壁','陳子昂','唐','御定全唐诗','yuding','','[]','白雲蒼梧來，氛氳萬里色。聞君太平世，棲泊靈台側。',24,'御定全唐詩/json/084.json','["白雲蒼梧來，氛氳萬里色。聞君太平世，棲泊靈台側。"]'),
('yuding-54','贈別冀侍禦崔司議','陳子昂','唐','御定全唐诗','yuding','','[]','有道君匡國，無悶余在林。白雲峨眉上，歲晚來相尋。',24,'御定全唐詩/json/084.json','["有道君匡國，無悶余在林。白雲峨眉上，歲晚來相尋。"]'),
('yuding-55','《三月三日宴王明府山亭','陳子昂','唐','御定全唐诗','yuding','','[]','暮春嘉月，上巳芳辰。群公禊飲，於洛之濱。',60,'御定全唐詩/json/084.json','["暮春嘉月，上巳芳辰。群公禊飲，於洛之濱。", "奕奕車騎，粲粲都人。連帷競野，袨服縟津。", "青郊樹密，翠渚萍新。今我不樂，含意□申。"]'),
('yuding-0','唐封泰山樂章：豫和六首','張說','唐','御定全唐诗','yuding','','[]','挹泰壇，紫泰清。受天命，報天成。',208,'御定全唐詩/json/085.json','["挹泰壇，紫泰清。受天命，報天成。", "竦皇心，薦樂聲。志上達，歌下迎。", "億上帝，臨下庭。騎日月，陪列星。", "嘉視信，大糦馨。澹神心，醉皇靈。", "相百辟，貢八荒。九歌敘，萬舞翔。", "肅振振，鏗皇皇。帝欣欣，福穰穰。", "高在上，道光明。物資始，德難名。", "承眷命，牧蒼生。寰宇謐，泰階平。", "天道無親，至誠與鄰。山川遍禮，宮征惟新。", "玉帛非盛，聰明會真。正斯一德，通乎百神。", "享帝享親，維孝維聖。緝熙懿德，敷揚成命。", "華夷志同，笙鏞禮盛。明靈降止，感此誠敬。"]'),
('yuding-1','唐封泰山樂章：太和','張說','唐','御定全唐诗','yuding','','[]','孝敬中發，和容外彰。騰華照宇，如升太陽。',40,'御定全唐詩/json/085.json','["孝敬中發，和容外彰。騰華照宇，如升太陽。", "貞璧就奠，玄靈垂光。禮樂具舉，濟濟洋洋。"]'),
('yuding-2','唐封泰山樂章：肅和','張說','唐','御定全唐诗','yuding','','[]','奠祖配天，承天享帝。百靈咸秩，四海來祭。',40,'御定全唐詩/json/085.json','["奠祖配天，承天享帝。百靈咸秩，四海來祭。", "植我蒼璧，布我玄制。華日裴回，神煙容裔。"]'),
('yuding-3','唐封泰山樂章：雍和','張說','唐','御定全唐诗','yuding','','[]','俎豆有馥，粢盛絜豐。亦有和羹，既戒既平。',40,'御定全唐詩/json/085.json','["俎豆有馥，粢盛絜豐。亦有和羹，既戒既平。", "鼓鐘管磬，肅唱和鳴。皇皇我祖，來我思成。"]'),
('yuding-4','唐封泰山樂章：壽和','張說','唐','御定全唐诗','yuding','','[]','烝烝我後，享獻惟寅。躬酌鬱鬯，跪奠明神。',40,'御定全唐詩/json/085.json','["烝烝我後，享獻惟寅。躬酌鬱鬯，跪奠明神。", "孝莫孝乎，配上帝親。敬莫敬乎，教天下臣。"]'),
('yuding-5','唐封泰山樂章：壽和','張說','唐','御定全唐诗','yuding','','[]','皇祖嚴配，配享皇天。皇皇降嘏，天子萬年。',20,'御定全唐詩/json/085.json','["皇祖嚴配，配享皇天。皇皇降嘏，天子萬年。"]'),
('yuding-6','唐封泰山樂章：舒和','張說','唐','御定全唐诗','yuding','','[]','六鐘翕協六變成，八佾徜徉八風生。',32,'御定全唐詩/json/085.json','["六鐘翕協六變成，八佾徜徉八風生。", "樂九韶兮人神感，美七德兮天地清。"]'),
('yuding-7','唐封泰山樂章：凱和','張說','唐','御定全唐诗','yuding','','[]','烈祖順三靈，文宗威四海。黃鉞誅群盜，朱旗掃多罪。',48,'御定全唐詩/json/085.json','["烈祖順三靈，文宗威四海。黃鉞誅群盜，朱旗掃多罪。", "戢兵天下安，約法人心改。大哉幹羽意，常見風雲在。"]'),
('yuding-8','唐封泰山樂章：豫和','張說','唐','御定全唐诗','yuding','','[]','禮樂終，煙燎上。懷靈惠，結皇想。',32,'御定全唐詩/json/085.json','["禮樂終，煙燎上。懷靈惠，結皇想。", "歸風疾，回風爽。百福來，眾神往。"]'),
('yuding-9','唐享太廟樂章：永和三首','張說','唐','御定全唐诗','yuding','','[]','肅九室，諧八音。歌皇慕，動神心。',96,'御定全唐詩/json/085.json','["肅九室，諧八音。歌皇慕，動神心。", "禮宿設，樂妙尋。聲明備，祼奠臨。", "律迓氣，音入玄。依玉幾，禦黼筵。", "聆愾息，僾周旋。九韶遍，百福傳。", "信工祝，永頌聲。來祖考，聽和平。", "相百辟，貢九瀛。神休委，帝孝成。"]'),
('yuding-10','唐享太廟樂章：太和','張說','唐','御定全唐诗','yuding','','[]','時文聖後，清廟肅邕。致誠勤薦，在貌思恭。',40,'御定全唐詩/json/085.json','["時文聖後，清廟肅邕。致誠勤薦，在貌思恭。", "玉節肆夏，金鏘五鐘。繩繩雲步，穆穆天容。"]'),
('yuding-11','唐享太廟樂章：肅和','張說','唐','御定全唐诗','yuding','','[]','天子享孝，工歌溥將。射祼鬱鬯，乃焚膋薌。',40,'御定全唐詩/json/085.json','["天子享孝，工歌溥將。射祼鬱鬯，乃焚膋薌。", "臭以達旨，聲以求陽。奉時烝嘗，永代不忘。"]'),
('yuding-12','唐享太廟樂章：雍和二首','張說','唐','御定全唐诗','yuding','','[]','在滌嘉豢，麗碑敬牲。角握之牝，色純之騂。',80,'御定全唐詩/json/085.json','["在滌嘉豢，麗碑敬牲。角握之牝，色純之騂。", "火傳陽燧，水溉陰精。太公胖俎，傅說和羹。", "俎豆有馥，齊盛潔豐。亦有和羹，既戒既平。", "鼓鐘管磬，肅唱和鳴。皇皇後祖，來我思成。"]'),
('yuding-13','唐享太廟樂章：文舞','張說','唐','御定全唐诗','yuding','','[]','聖謨九德，真言五千。慶集昌胄，符開帝先。高文杖鉞，',50,'御定全唐詩/json/085.json','["聖謨九德，真言五千。慶集昌胄，符開帝先。高文杖鉞，", "圖書霧出，日月清懸。舞形德類，詠諗功傳。黃龍蜿蟺，"]'),
('yuding-14','唐享太廟樂章：光大舞','張說','唐','御定全唐诗','yuding','','[]','肅肅藝祖，滔滔浚源。有雄玉劍，作鎮金門。',40,'御定全唐詩/json/085.json','["肅肅藝祖，滔滔浚源。有雄玉劍，作鎮金門。", "玄王貽緒，後稷謀孫。肇禋九廟，四海來尊。"]'),
('yuding-15','唐享太廟樂章：長髮舞','張說','唐','御定全唐诗','yuding','','[]','具禮崇德，備樂承風。魏推幢主，周贈司空。',40,'御定全唐詩/json/085.json','["具禮崇德，備樂承風。魏推幢主，周贈司空。", "不行而至，無成有終。神興王業，天歸帝功。"]'),
('yuding-16','唐享太廟樂章：大政舞','張說','唐','御定全唐诗','yuding','','[]','於赫元命，權輿帝文。天齊八柱，地半三分。',40,'御定全唐詩/json/085.json','["於赫元命，權輿帝文。天齊八柱，地半三分。", "宗廟觀德，笙鏞樂勳。封唐之兆，成天下君。"]'),
('yuding-17','唐享太廟樂章：大成舞','張說','唐','御定全唐诗','yuding','','[]','帝舞季曆，龍聖生昌。後歌有蟜，胎炎孕黃。',40,'御定全唐詩/json/085.json','["帝舞季曆，龍聖生昌。後歌有蟜，胎炎孕黃。", "天地合德，日月齊光。肅雍孝享，祚我萬方。"]'),
('yuding-18','唐享太廟樂章：大明舞','張說','唐','御定全唐诗','yuding','','[]','赤精亂德，四海困窮。黃旗舉義，三靈會同。',40,'御定全唐詩/json/085.json','["赤精亂德，四海困窮。黃旗舉義，三靈會同。", "早望春雨，雲披大風。溥天來祭，高祖之功。"]'),
('yuding-19','唐享太廟樂章：崇德舞','張說','唐','御定全唐诗','yuding','','[]','皇合一德，朝宗百神。削平天地，大拯生人。',40,'御定全唐詩/json/085.json','["皇合一德，朝宗百神。削平天地，大拯生人。", "上帝配食，單于入臣。戎歌陳武，曄曄震震。"]'),
('yuding-20','唐享太廟樂章：鈞天舞','張說','唐','御定全唐诗','yuding','','[]','高皇邁道，端拱無為。化懷獯鬻，兵戢句驪。',40,'御定全唐詩/json/085.json','["高皇邁道，端拱無為。化懷獯鬻，兵戢句驪。", "禮尊封禪，樂盤來儀。合位媧後，同稱伏羲。"]'),
('yuding-21','唐享太廟樂章：大和舞','張說','唐','御定全唐诗','yuding','','[]','退居江水，鬱起丹陵。禮物還舊，朝章中興。',40,'御定全唐詩/json/085.json','["退居江水，鬱起丹陵。禮物還舊，朝章中興。", "龍圖友及，駿命恭膺。鳴球香瓚，大糦是承。"]'),
('yuding-22','唐享太廟樂章：景雲舞','張說','唐','御定全唐诗','yuding','','[]','景雲霏爛，告我帝符。噫帝沖德，與天為徒。',40,'御定全唐詩/json/085.json','["景雲霏爛，告我帝符。噫帝沖德，與天為徒。", "笙鏞遙遠，俎豆虛無。春秋孝獻，回復此都。"]'),
('yuding-23','唐享太廟樂章：福和','張說','唐','御定全唐诗','yuding','','[]','備禮用樂，崇親致尊。誠通慈降，敬徹愛存。獻懷稱壽，',25,'御定全唐詩/json/085.json','["備禮用樂，崇親致尊。誠通慈降，敬徹愛存。獻懷稱壽，"]'),
('yuding-24','唐享太廟樂章：舒和','張說','唐','御定全唐诗','yuding','','[]','六鐘翕協六變成，八佾徜徉八風生。',32,'御定全唐詩/json/085.json','["六鐘翕協六變成，八佾徜徉八風生。", "樂九韶兮人神感，美七德兮天地清。"]'),
('yuding-25','唐享太廟樂章：凱安三首','張說','唐','御定全唐诗','yuding','','[]','瑟彼瑤爵，亞維上公。室如屏氣，門不容躬。禮殷其本，',90,'御定全唐詩/json/085.json','["瑟彼瑤爵，亞維上公。室如屏氣，門不容躬。禮殷其本，", "禮匝三獻，樂遍九成。降循軒陛，仰欷皇情。福與仁合，", "總總幹戚，填填鼓鐘。奮揚增氣，坐作為容。", "離若鷙鳥，合如戰龍。萬方觀德，肅肅邕邕。"]'),
('yuding-26','唐享太廟樂章：登歌','張說','唐','御定全唐诗','yuding','','[]','止笙磬，撤豆籩。廓無響，窅入玄。主在室，神在天。',40,'御定全唐詩/json/085.json','["止笙磬，撤豆籩。廓無響，窅入玄。主在室，神在天。", "情餘慕，禮罔愆。喜黍稷，屢豐年。"]'),
('yuding-27','唐享太廟樂章：永和','張說','唐','御定全唐诗','yuding','','[]','眇嘉樂，授靈爽。感若來，思如往。休氣散，回風上。',40,'御定全唐詩/json/085.json','["眇嘉樂，授靈爽。感若來，思如往。休氣散，回風上。", "返寂寞，還惚恍。懷靈駕，結空想。"]'),
('yuding-0','奉和聖制賜諸州刺史應制以題坐右','張說','唐','御定全唐诗','yuding','','[]','文明遍禹跡，鰥寡達堯心。正在親人守，能令王澤深。',120,'御定全唐詩/json/086.json','["文明遍禹跡，鰥寡達堯心。正在親人守，能令王澤深。", "朝廷多秀士，熔煉比精金。犀節同分命，熊軒各外臨。", "聖主賦新詩，穆若聽熏琴。先言教為本，次言則是欽。", "三時農不奪，午夜犬無侵。願使天宇內，品物遂浮沉。", "寄情群飛鶴，千里一揚音。共躡華胥夢，龔黃安足尋。"]'),
('yuding-1','奉和聖制送宇文融安輯戶口應制','張說','唐','御定全唐诗','yuding','','[]','至德臨天下，勞情遍九圍。念茲人去本，蓬轉將何依。',96,'御定全唐詩/json/086.json','["至德臨天下，勞情遍九圍。念茲人去本，蓬轉將何依。", "外避征戍數，內傷親黨稀。嗟不逢明盛，胡能照隱微。", "柏台簡行李，蘭殿錫朝衣。別曲動秋風，恩令生春輝。", "使出四海安，詔下萬心歸。怍非夔龍佐，徒歌鴻雁飛。"]'),
('yuding-2','奉和聖制過晉陽宮應制','張說','唐','御定全唐诗','yuding','','[]','太原俗尚武，高皇初奮庸。星軒三晉躔，土樂二堯封。',144,'御定全唐詩/json/086.json','["太原俗尚武，高皇初奮庸。星軒三晉躔，土樂二堯封。", "北風遂舉鵬，西河亦上龍。至德起王業，繼明賴人雍。", "六合啟昌期，再興廣聖蹤。傳呼大駕來，文物如雲從。", "連營火百里，縱觀人千重。翠華渡汾水，白日崒罕峰。", "枌榆恩賞洽，桑梓舊情恭。往運感不追，清時惜難逢。", "詩發尊祖心，頌刊盛德容。願君及春事，回輿綏萬邦。"]'),
('yuding-3','奉和聖制行次成皋應制','張說','唐','御定全唐诗','yuding','','[]','夏氏階隋亂，自言河朔雄。王師進谷水，兵氣臨山東。',72,'御定全唐詩/json/086.json','["夏氏階隋亂，自言河朔雄。王師進谷水，兵氣臨山東。", "前掃成皋陣，卻下洛陽宮。義合帝圖起，威加天宇同。", "軒台百年外，虞典一巡中。戰龍思王業，倚馬賦神功。"]'),
('yuding-4','奉和聖制溫湯對雪應制','張說','唐','御定全唐诗','yuding','','[]','瑞雪帶寒風，寒風入陰管。陰管方凝閉，寒風複淒斷。',48,'御定全唐詩/json/086.json','["瑞雪帶寒風，寒風入陰管。陰管方凝閉，寒風複淒斷。", "宮似瑤林匝，庭如月華滿。正賡挾纊詞，非近溫泉暖。"]'),
('yuding-5','奉和聖制義成校獵喜雪應制','張說','唐','御定全唐诗','yuding','','[]','文教資武功，郊畋閱邦政。不知仁育久，徒看禽獸盛。',108,'御定全唐詩/json/086.json','["文教資武功，郊畋閱邦政。不知仁育久，徒看禽獸盛。", "夜霰氛埃滅，朝日山川淨。綽仗飛走繁，抨弦筋角勁。", "帝射參神道，龍馳合人性。五豝連一發，百中皆先命。", "勇爵均萬夫，雄圖羅七聖。星為吉符老，雪作豐年慶。", "喜聽行獵詩，威神入軍令。"]'),
('yuding-6','清明日詔宴甯王山池賦得飛字','張說','唐','御定全唐诗','yuding','','[]','今日清明宴，佳境惜芳菲。搖揚花雜下，嬌囀鶯亂飛。',60,'御定全唐詩/json/086.json','["今日清明宴，佳境惜芳菲。搖揚花雜下，嬌囀鶯亂飛。", "綠渚傳歌榜，紅橋度舞旗。和風偏應律，細雨不沾衣。", "承恩如改火，春去春來歸。"]'),
('yuding-7','四月十三日詔宴甯王亭子賦得好字','張說','唐','御定全唐诗','yuding','','[]','何許承恩宴，山亭風日好。綠嫩鳴鶴洲，陰穠鬥雞道。',48,'御定全唐詩/json/086.json','["何許承恩宴，山亭風日好。綠嫩鳴鶴洲，陰穠鬥雞道。", "果思夏來茂，花嫌春去早。行樂無限時，皇情及芳草。"]'),
('yuding-8','藥園宴武輅沙將軍賦得洛字','張說','唐','御定全唐诗','yuding','','[]','東第乘餘興，南園宴清洛。文學引鄒枚，歌鐘陳衛霍。',48,'御定全唐詩/json/086.json','["東第乘餘興，南園宴清洛。文學引鄒枚，歌鐘陳衛霍。", "風高大夫樹，露下將軍藥。待聞出塞還，丹青上麟閣。"]'),
('yuding-9','修書院學士奉敕宴梁王宅賦得樹字','張說','唐','御定全唐诗','yuding','','[]','虎殿成鴻業，猿岩題鳳賦。既荷大君恩，還蒙小山遇。',48,'御定全唐詩/json/086.json','["虎殿成鴻業，猿岩題鳳賦。既荷大君恩，還蒙小山遇。", "秋吹迎弦管，涼雲生竹樹。共惜朱邸歡，無辭洛城暮。"]'),
('yuding-10','夕宴房主簿舍','張說','唐','御定全唐诗','yuding','','[]','歲晏關雍空，風急河渭冰。薄遊羈物役，微尚愜遠憑。',72,'御定全唐詩/json/086.json','["歲晏關雍空，風急河渭冰。薄遊羈物役，微尚愜遠憑。", "旅館月宿永，閉扃雲思興。伊人美修夜，朋酒惠來稱。", "交談既清雅，琴吹亦淒凝。不逢君蹇涸，幽意長鬱蒸。"]'),
('yuding-11','行從方秀川與劉評事文同宿','張說','唐','御定全唐诗','yuding','','[]','方秀美盤遊，頻年降天罕。水共伊川接，山將闕門斷。',120,'御定全唐詩/json/086.json','["方秀美盤遊，頻年降天罕。水共伊川接，山將闕門斷。", "捧日照恩華，攀雲引疲散。野宿霜入帳，孤衾寒不暖。", "靜聞宮漏疏，臥視庭月滿。開爐命溫酎，中夜發清管。", "風送關山長，氣遒星歲短。寓言情思愜，適興真意坦。", "寰中病羈掛，方外嫌縱誕。願君樂盛時，無嗟帶纕緩。"]'),
('yuding-12','送郭大夫元振再使吐蕃','張說','唐','御定全唐诗','yuding','','[]','犬戎廢東獻，漢使馳西極。長策問酋渠，猜阻自夷殛。',96,'御定全唐詩/json/086.json','["犬戎廢東獻，漢使馳西極。長策問酋渠，猜阻自夷殛。", "容發徂邊歲，旌裘敝海色。五年一見家，妻子不相識。", "武庫兵猶動，金方事未息。遠圖待才智，苦節輸筋力。", "脫刀贈分手，書帶加餐食。知君萬里侯，立功在異域。"]'),
('yuding-13','送李侍郎迥秀薛長史季昶同賦得水字','張說','唐','御定全唐诗','yuding','','[]','漢郡接胡庭，幽並對烽壘。旌旗按部曲，文武惟卿士。',72,'御定全唐詩/json/086.json','["漢郡接胡庭，幽並對烽壘。旌旗按部曲，文武惟卿士。", "薛公善籌畫，李相威邊鄙。中冀分兩河，長城各萬里。", "藉馬黃花塞，搜兵白狼水。勝敵在安人，為君汗青史。"]'),
('yuding-14','別平一師','張說','唐','御定全唐诗','yuding','','[]','王子不事俗，高駕眇難追。茅土非屑盼，傾城無樂資。',72,'御定全唐詩/json/086.json','["王子不事俗，高駕眇難追。茅土非屑盼，傾城無樂資。", "宴坐深林中，三世同一時。皎皎獨往心，不為塵網欺。", "朅來已複去，今去何來思。回首謝同行，勤會安請期。"]'),
('yuding-15','送王光庭','張說','唐','御定全唐诗','yuding','','[]','同居洛陽陌，經日懶相求。及爾江湖去，言別悵悠悠。',48,'御定全唐詩/json/086.json','["同居洛陽陌，經日懶相求。及爾江湖去，言別悵悠悠。", "楚雲眇羈翼，海月倦行舟。愛而不可見，徒嗟芳歲流。"]'),
('yuding-16','新都南亭送郭元振盧崇道','張說','唐','御定全唐诗','yuding','','[]','竹徑女蘿蹊，蓮洲文石堤。靜深人俗斷，尋玩往還迷。',72,'御定全唐詩/json/086.json','["竹徑女蘿蹊，蓮洲文石堤。靜深人俗斷，尋玩往還迷。", "碧潭秀初月，素林驚夕棲。褰幌納蟾影，理琴聽猿啼。", "佳辰改宿昔，勝寄坐睽攜。長懷賞心愛，如玉複如珪。"]'),
('yuding-17','贈崔公','張說','唐','御定全唐诗','yuding','','[]','我聞西漢日，四老南山幽。長歌紫芝秀，高臥白雲浮。',132,'御定全唐詩/json/086.json','["我聞西漢日，四老南山幽。長歌紫芝秀，高臥白雲浮。", "朝野光塵絕，榛蕪年貌秋。一朝驅駟馬，連轡入龍樓。", "昔遁高皇去，今從太子游。行藏惟聖節，福禍在人謀。", "卒能匡惠帝，豈不賴留侯。事隨年代遠，名與圖籍留。", "平生欽淳德，慷慨景前修。蚌蛤伺陰兔，蛟龍望鬥牛。", "無嗟異飛伏，同氣幸相求。"]'),
('yuding-18','贈趙公','張說','唐','御定全唐诗','yuding','','[]','湘東股肱守，心與帝鄉期。舟楫中途蹇，風波複來思。',120,'御定全唐詩/json/086.json','["湘東股肱守，心與帝鄉期。舟楫中途蹇，風波複來思。", "嘉我常聯翼，金貂侍玉墀。跡參前馬聖，名綴鬻熊師。", "寒暑一何速，山川遠間之。寧知洞庭上，獨得平生時。", "精意微絕簡，從權討妙棋。林壑為予請，紛靄發華滋。", "流賞忽已散，驚帆杳難追。送君在南浦，侘傺投此詞。"]'),
('yuding-19','贈趙侍禦','張說','唐','御定全唐诗','yuding','','[]','祿放跡異端，偏荒事同蹇。苟忘風波累，俱會雲壑踐。',168,'御定全唐詩/json/086.json','["祿放跡異端，偏荒事同蹇。苟忘風波累，俱會雲壑踐。", "險式壓西湖，僑廬對南峴。夜樓江月入，朝幌山雲卷。", "山勢遠濤連，江途斜漢轉。坐嘯予多暇，行吟子獨善。", "並轡躧郊郭，方舟玩遊演。虛聲萬籟分，水色千里辨。", "不知岸陰謝，再見春露泫。綠壤發欣顏，華年助蟲篆。", "上世時難接，古人情可選。泊渚煩為媒，多才怨成褊。", "長沙鵩作賦，任道可知淺。請從三已心，榮辱兩都遣。"]'),
('yuding-20','答李伯魚桐竹','張說','唐','御定全唐诗','yuding','','[]','結廬桐竹下，室邇人相深。接垣分竹徑，隔戶共桐陰。',60,'御定全唐詩/json/086.json','["結廬桐竹下，室邇人相深。接垣分竹徑，隔戶共桐陰。", "落花朝滿岸，明月夜披林。竹有龍鳴管，桐留鳳舞琴。", "奇聲與高節，非吾誰賞心。"]'),
('yuding-21','寄姚司馬','張說','唐','御定全唐诗','yuding','','[]','共君春種瓜，本期清夏暑。瓜成人已去，失望將誰語。',48,'御定全唐詩/json/086.json','["共君春種瓜，本期清夏暑。瓜成人已去，失望將誰語。", "裛露摘香園，感味懷心許。偶逢西風便，因之寄鄂渚。"]'),
('yuding-22','代書答姜七崔九','張說','唐','御定全唐诗','yuding','','[]','婀娜金閨樹，離披野田草。雖殊兩地榮，幸共三春好。',48,'御定全唐詩/json/086.json','["婀娜金閨樹，離披野田草。雖殊兩地榮，幸共三春好。", "花殊鳥飛處，葉鏤蟲行道。真心獨感人，惆悵令人老。"]'),
('yuding-23','代書寄吉十一','張說','唐','御定全唐诗','yuding','','[]','一雁雪上飛，值我衡陽道。口銜離別字，遠寄當歸草。',60,'御定全唐詩/json/086.json','["一雁雪上飛，值我衡陽道。口銜離別字，遠寄當歸草。", "目想春來遲，心驚寒去早。憶鄉乘羽翮，慕侶盈懷抱。", "零落答故人，將隨江樹老。"]'),
('yuding-24','代書寄薛四','張說','唐','御定全唐诗','yuding','','[]','孤雁東飛來，寄我紋與素。紋足經三象，素當綜群務。',60,'御定全唐詩/json/086.json','["孤雁東飛來，寄我紋與素。紋足經三象，素當綜群務。", "遠見故人心，一言重千金。答之彩毛翰，繼以瑤華音。", "歲寒眾木改，松柏心常在。"]'),
('yuding-25','過蜀道山','張說','唐','御定全唐诗','yuding','','[]','我行春三月，山中百花開。披林入峭蒨，攀登陟崔嵬。',48,'御定全唐詩/json/086.json','["我行春三月，山中百花開。披林入峭蒨，攀登陟崔嵬。", "白雲半峰起，清江出峽來。誰知高深意，緬邈心幽哉。"]'),
('yuding-26','蜀路二首','張說','唐','御定全唐诗','yuding','','[]','雲埃夜澄廓，山日曉晴鮮。葉落蒼江岸，鴻飛白露天。',168,'御定全唐詩/json/086.json','["雲埃夜澄廓，山日曉晴鮮。葉落蒼江岸，鴻飛白露天。", "磷磷含水石，冪冪覆林煙。客心久無緒，秋風殊未然。", "徭蜀時未改，別家鄉念盈。憶昨出門日，春風發鮮榮。", "及茲旋轅地，秋風滿路生。昏曉思魏闕，夢寐還秦京。", "秦京開朱第，魏闕垂紫纓。幽獨玄虛閣，不聞人馬聲。", "藝業為君重，名位為君輕。玉琴知調苦，寶鏡對膽清。", "鷹饑常啄腥，鳳饑亦待瓊。於君自有屬，物外豈能輕。"]'),
('yuding-27','再使蜀道','張說','唐','御定全唐诗','yuding','','[]','眇眇葭萌道，蒼蒼褒斜穀。煙壑爭晦深，雲山共重複。',108,'御定全唐詩/json/086.json','["眇眇葭萌道，蒼蒼褒斜穀。煙壑爭晦深，雲山共重複。", "古來風塵子，同眩望鄉目。芸閣有儒生，軺車倦馳逐。", "青春客岷嶺，白露搖江服。歲月鎮羈孤，山川俄反復。", "魚遊戀深水，鳥遷戀喬木。如何別親愛，坐去文章國。", "蟋蟀鳴戶庭，蠨蛸網琴築。"]'),
('yuding-28','江路憶郡','張說','唐','御定全唐诗','yuding','','[]','霧斂江早明，星翻漢將沒。臥聞峽猿響，起視榜人發。',108,'御定全唐詩/json/086.json','["霧斂江早明，星翻漢將沒。臥聞峽猿響，起視榜人發。", "倚棹攀岸筱，憑船弄波月。水宿厭洲渚，晨光屢揮忽。", "林澤來不窮，煙波去無歇。結思笙竽裏，搖情遊俠窟。", "年貌不暫留，歡愉及玄發。雲涓戀山海，禽馬懷燕越。", "自非行役人，安知慕城闕。"]'),
('yuding-29','過漢南城歎古墳','張說','唐','御定全唐诗','yuding','','[]','舊國多陵墓，荒涼無歲年。洶湧蔽平岡，汨若波濤連。',72,'御定全唐詩/json/086.json','["舊國多陵墓，荒涼無歲年。洶湧蔽平岡，汨若波濤連。", "上世千金子，潛臥九重泉。松柏剪無餘，碑記滅罔傳。", "葬于不毛地，咸謂楚先賢。事盡情可識，使人心悵然。"]'),
('yuding-30','至尉氏','張說','唐','御定全唐诗','yuding','','[]','夕次阮公台，嘯歌臨爽塏。高名安足賴，故物今皆改。',96,'御定全唐詩/json/086.json','["夕次阮公台，嘯歌臨爽塏。高名安足賴，故物今皆改。", "吾兄昔茲邑，遺愛稱賢宰。桑中雉未飛，屋上烏猶在。", "途逢舊甿吏，城有同僚寀。望塵遠見迎，拂館來欣待。", "慈惠留千室，友于存四海。始知魯衛間，優劣相懸倍。"]'),
('yuding-31','襄州景空寺題融上人蘭若','張說','唐','御定全唐诗','yuding','','[]','高名出漢陰，禪閣跨香岑。眾山既圍繞，長川複回臨。',72,'御定全唐詩/json/086.json','["高名出漢陰，禪閣跨香岑。眾山既圍繞，長川複回臨。", "雲峰曉靈變，風木夜虛吟。碧湫龍池滿，蒼松虎徑深。", "舊知青岩意，偏入杳冥心。何由侶飛錫，從此脫朝簪。"]'),
('yuding-32','巡邊在河北作','張說','唐','御定全唐诗','yuding','','[]','撫劍空餘勇，彎弧遂無力。老去事如何，據鞍長歎息。',48,'御定全唐詩/json/086.json','["撫劍空餘勇，彎弧遂無力。老去事如何，據鞍長歎息。", "故交索將盡，後進稀相識。獨憐半死心，尚有寒松直。"]'),
('yuding-33','入海二首','張說','唐','御定全唐诗','yuding','','[]','乘桴入南海，海曠不可臨。茫茫失方面，混混如凝陰。',132,'御定全唐詩/json/086.json','["乘桴入南海，海曠不可臨。茫茫失方面，混混如凝陰。", "雲山相出沒，天地互浮沉。萬里無涯際，雲何測廣深。", "潮波自盈縮，安得會虛心。", "海上三神山，逍遙集眾仙。靈心豈不同，變化無常全。", "龍伯如人類，一釣兩鼇連。金台此淪沒，玉真時播遷。", "問子勞何事，江上泣經年。隰中生紅草，所美非美然。"]'),
('yuding-34','相州山池作','張說','唐','御定全唐诗','yuding','','[]','嘗懷謝公詠，山水陶嘉月。及此年事衰，徒看眾花發。',72,'御定全唐詩/json/086.json','["嘗懷謝公詠，山水陶嘉月。及此年事衰，徒看眾花發。", "觀魚樂何在，聽鳥情都歇。星漢流不停，蓬萊去難越。", "鄴中秋麥秀，淇上春雲沒。日見塵物空，如何靜心闕。"]'),
('yuding-35','嶽州作','張說','唐','御定全唐诗','yuding','','[]','夜夢雲闕間，從容簪履列。朝遊洞庭上，緬望京華絕。',96,'御定全唐詩/json/086.json','["夜夢雲闕間，從容簪履列。朝遊洞庭上，緬望京華絕。", "潦收江未清，火退山更熱。重欷視欲醉，懵滿氣如噎。", "器留魚鱉腥，衣點蚊虻血。發白思益壯，心玄用彌拙。", "冠劍日苔蘚，琴書坐廢撤。唯有報恩字，刻意長不滅。"]'),
('yuding-36','嶽州行郡竹籬','張說','唐','御定全唐诗','yuding','','[]','山郡不溝郭，荒居無翳壅。愛人忠主利，善守閉為勇。',120,'御定全唐詩/json/086.json','["山郡不溝郭，荒居無翳壅。愛人忠主利，善守閉為勇。", "苟非小勤瘁，安得期逸寵。版築恐土疏，襄城嫌役重。", "藩柵聊可固，筠篁近易奉。差池截浦沙，繚繞緣隈壟。", "矗似長雲亙，森如高戟聳。預絕豺狼憂，知免牛羊恐。", "閭裏寬矯步，榛叢恣踏踵。始果遊處心，終日成閑拱。"]'),
('yuding-37','遊洞庭湖湘','張說','唐','御定全唐诗','yuding','','[]','緬邈洞庭岫，蔥蒙水霧色。宛在太湖中，可望不可即。',192,'御定全唐詩/json/086.json','["緬邈洞庭岫，蔥蒙水霧色。宛在太湖中，可望不可即。", "剖竹守窮渚，開門對奇域。城池自縶籠，纓綬為徽纆。", "靡日不思往，經時始願克。飛棹越溟波，維舟恣攀陟。", "窈窕入雲步，崎嶇倚松息。岩壇有鶴過，壁字無人識。", "滴石香乳溜，垂崖靈草植。玩幽輕霧阻，討異忘曛逼。", "寒沙際水準，霜樹籠煙直。空宮聞莫睹，地道窺難測。", "此處學金丹，何人生羽翼。誰傳九光要，幾拜三仙職。", "紫氣徒想像，清潭長眇默。霓裳若有來，覯我雲峰側。"]'),
('yuding-38','灉湖山寺','張說','唐','御定全唐诗','yuding','','[]','楚老遊山寺，提攜觀畫壁。揚袂指辟支，睩眄相鬥鬩。',48,'御定全唐詩/json/086.json','["楚老遊山寺，提攜觀畫壁。揚袂指辟支，睩眄相鬥鬩。", "險哉透撞兒，千金賭一擲。成敗身自受，傍人那歎息。"]'),
('yuding-39','出湖寄趙冬曦','張說','唐','御定全唐诗','yuding','','[]','西泛平湖盡，參差入亂山。東瞻岳陽郡，汗漫太虛間。',84,'御定全唐詩/json/086.json','["西泛平湖盡，參差入亂山。東瞻岳陽郡，汗漫太虛間。", "窘步同行樂，遒文互屢看。山戍上雲桂，江亭臨水關。", "川途倏忽間，風景依如昨。湘浦未賜環，荊門猶主諾。", "何時與美人，載酒游宛洛。"]'),
('yuding-40','岳陽早霽南樓','張說','唐','御定全唐诗','yuding','','[]','山水佳新霽，南樓玩初旭。夜來枝半紅，雨後洲全綠。',96,'御定全唐詩/json/086.json','["山水佳新霽，南樓玩初旭。夜來枝半紅，雨後洲全綠。", "四運相終始，萬形紛代續。適臨青草湖，再變黃鶯曲。", "地穴穿東武，江流下西蜀。歌聞枉渚邅，舞見長沙促。", "心阻意徒馳，神和生自足。白髮悲上春，知常謝先欲。"]'),
('yuding-41','岳陽石門墨山二山相連有禪堂觀天下絕境','張說','唐','御定全唐诗','yuding','','[]','囷輪江上山，近在華容縣。常涉巴丘首，天晴遙可見。',192,'御定全唐詩/json/086.json','["囷輪江上山，近在華容縣。常涉巴丘首，天晴遙可見。", "佳遊屢前諾，芳月愆幽眷。及此符守移，歡言臨道便。", "既攜賞心客，複有送行掾。竹徑入陰窅，松蘿上空蒨。", "草共林一色，雲與峰萬變。探窺石門斷，緣越沙澗轉。", "兩山勢爭雄，峰巘相顧眄。藥妙靈仙寶，境華岩壑選。", "清都西淵絕，金地東敞宴。池果接園畦，風煙邇台殿。", "高尋去石頂，曠覽天宇遍。千山紛滿目，百川豁對面。", "騎來雲氣迎，人去鳥聲戀。長揖桃源士，舉世同企羨。"]'),
('yuding-42','和尹懋秋夜遊灉湖','張說','唐','御定全唐诗','yuding','','[]','坐嘯人事閑，佳遊野情發。山門送落照，湖口升微月。',48,'御定全唐詩/json/086.json','["坐嘯人事閑，佳遊野情發。山門送落照，湖口升微月。", "林尋猿狖居，水戲黿鼉穴。朔風吹飛雁，芳草亦雲歇。"]'),
('yuding-43','五君詠五首：魏齊西元忠','張說','唐','御定全唐诗','yuding','','[]','齊公生人表，迥天聞鶴唳。清論早揣摩，玄心晚超詣。',60,'御定全唐詩/json/086.json','["齊公生人表，迥天聞鶴唳。清論早揣摩，玄心晚超詣。", "入相廊廟靜，出軍沙漠霽。見深呂祿憂，舉後陳平計。", "甘心除君惡，足以報先帝。"]'),
('yuding-44','五君詠五首：蘇許公瑰','張說','唐','御定全唐诗','yuding','','[]','許公信國楨，克美具瞻情。百事資朝問，三章廣世程。',60,'御定全唐詩/json/086.json','["許公信國楨，克美具瞻情。百事資朝問，三章廣世程。", "處高心不有，臨節自為名。朱戶傳新戟，青松拱舊塋。", "淒涼丞相府，餘慶在玄成。"]'),
('yuding-45','五君詠五首：李趙公嶠','張說','唐','御定全唐诗','yuding','','[]','李公實神敏，才華乃天授。睦親何用心，處貴不忘舊。',60,'御定全唐詩/json/086.json','["李公實神敏，才華乃天授。睦親何用心，處貴不忘舊。", "故事遵台閣，新詩冠宇宙。在人忠所奉，惡我誠將宥。", "南浦去莫歸，嗟嗟蔑孫秀。"]'),
('yuding-46','五君詠五首：郭代西元振','張說','唐','御定全唐诗','yuding','','[]','代公舉鵬翼，懸飛摩海霧。志康天地屯，適與雲雷遇。',60,'御定全唐詩/json/086.json','["代公舉鵬翼，懸飛摩海霧。志康天地屯，適與雲雷遇。", "興喪一言決，安危萬心注。大勳書王府，舛命淪江路。", "勢傾北夏門，哀靡東平樹。"]'),
('yuding-47','五君詠五首：趙耿公彥昭','張說','唐','御定全唐诗','yuding','','[]','耿公山嶽秀，才傑心亦妙。鷙鳥峻標立，哀玉扣清調。',60,'御定全唐詩/json/086.json','["耿公山嶽秀，才傑心亦妙。鷙鳥峻標立，哀玉扣清調。", "協贊休明啟，恩華日月照。何意瑤台雲，風吹落江徼。", "湘流下潯陽，灑淚一投吊。"]'),
('yuding-48','游龍山靜勝寺','張說','唐','御定全唐诗','yuding','','[]','每上襄陽樓，遙望龍山樹。鬱茀吐岡嶺，微蒙在煙霧。',120,'御定全唐詩/json/086.json','["每上襄陽樓，遙望龍山樹。鬱茀吐岡嶺，微蒙在煙霧。", "下車歲已成，飾馬閑餘步。苦霜裛野草，愛日揚江煦。", "雲對石上塔，風吹松下路。禪室宴三空，神祠同六趣。", "兒童共戲謔，猿鳥相驚顧。南識桓公台，北望先賢墓。", "世上人何在，時聞心不住。但傳無盡燈，可使有情悟。"]'),
('yuding-49','一柱觀','張說','唐','御定全唐诗','yuding','','[]','舊說江陵觀，初疑神化來。空山結雲閣，綺靡隨風回。',48,'御定全唐詩/json/086.json','["舊說江陵觀，初疑神化來。空山結雲閣，綺靡隨風回。", "奈何任一柱，斯焉容眾材。奇功非長世，今餘草露臺。"]'),
('yuding-50','登九裏台是樊姬墓','張說','唐','御定全唐诗','yuding','','[]','楚國所以霸，樊姬有力焉。不懷沈尹祿，誰諳叔敖賢。',120,'御定全唐詩/json/086.json','["楚國所以霸，樊姬有力焉。不懷沈尹祿，誰諳叔敖賢。", "萬化茫無在，孤墳獨巋然。北分陽臺陌，南識郢城阡。", "漠漠渚宮樹，蒼蒼雲夢田。登高形勝出，訪古令名傳。", "自我來符守，因君樹蕙荃。詩書將變俗，絺纊忽彌年。", "志闡三折後，愁值二毛前。佇立帝京路，遙心寄此篇。"]'),
('yuding-51','過懷王墓','張說','唐','御定全唐诗','yuding','','[]','咿嚘不可信，以此敗懷王。客死嶢關路，返葬岐江陽。',48,'御定全唐詩/json/086.json','["咿嚘不可信，以此敗懷王。客死嶢關路，返葬岐江陽。", "啼狖抱山月，饑狐獵野霜。一聞懷沙事，千載盡悲涼。"]'),
('yuding-52','聞雨','張說','唐','御定全唐诗','yuding','','[]','多雨絕塵事，寥寥入太玄。城陰疏複合，簷滴斷還連。',84,'御定全唐詩/json/086.json','["多雨絕塵事，寥寥入太玄。城陰疏複合，簷滴斷還連。", "念我勞造化，從來五十年。誤將心徇物，近得還自然。", "閒居草木侍，虛室鬼神憐。有時進美酒，有時泛清弦。", "聲真不世識，心醉豈言詮。"]'),
('yuding-53','夜坐','張說','唐','御定全唐诗','yuding','','[]','懷哉四壁時，未有五都價。百金誰見許，鬥酒難為貰。',48,'御定全唐詩/json/086.json','["懷哉四壁時，未有五都價。百金誰見許，鬥酒難為貰。", "落花生芳春，孤月皎清夜。複逢利交客，題戶遙相謝。"]'),
('yuding-54','山夜聞鐘','張說','唐','御定全唐诗','yuding','','[]','夜臥聞夜鐘，夜靜山更響。霜風吹寒月，窈窕虛中上。',60,'御定全唐詩/json/086.json','["夜臥聞夜鐘，夜靜山更響。霜風吹寒月，窈窕虛中上。", "前聲既舂容，後聲複晃蕩。聽之如可見，尋之定無像。", "信知本際空，徒掛生滅想。"]'),
('yuding-55','冬日見牧牛人擔青草歸','張說','唐','御定全唐诗','yuding','','[]','塞上綿應折，江南草可結。欲持梅嶺花，遠競榆關雪。',48,'御定全唐詩/json/086.json','["塞上綿應折，江南草可結。欲持梅嶺花，遠競榆關雪。", "日月無他照，山川何頓別。苟齊兩地心，天問將安說。"]'),
('yuding-56','詠鏡','張說','唐','御定全唐诗','yuding','','[]','寶鏡如明月，出自秦宮樣。隱起雙蟠龍，銜珠儼相向。',60,'御定全唐詩/json/086.json','["寶鏡如明月，出自秦宮樣。隱起雙蟠龍，銜珠儼相向。", "常恐君不察，匣中委清量。積翳掩菱花，虛心蔽塵狀。", "倘蒙羅袖拂，光生玉臺上。"]'),
('yuding-57','詠瓢','張說','唐','御定全唐诗','yuding','','[]','美酒酌懸瓢，真淳好相映。蝸房卷墮首，鶴頸抽長柄。',48,'御定全唐詩/json/086.json','["美酒酌懸瓢，真淳好相映。蝸房卷墮首，鶴頸抽長柄。", "雅色素而黃，虛心輕且勁。豈無雕刻者，貴此成天性。"]'),
('yuding-58','雜詩四首','張說','唐','御定全唐诗','yuding','','[]','抱熏心常焦，舉旆心常搖。天長地自久，歡樂能幾朝。',252,'御定全唐詩/json/086.json','["抱熏心常焦，舉旆心常搖。天長地自久，歡樂能幾朝。", "君看西陵樹，歌舞為誰嬌。", "山閑苦積雨，木落悲時遽。賞心凡幾人，良辰在何處。", "觸石滿堂侈，灑我終夕慮。客鳥懷主人，銜花未能去。", "剖珠貴分明，琢玉思堅貞。要君意如此，終始莫相輕。", "問子青霞意，何事留朱軒。自言心遠俗，未始跡辭喧。", "過蒙良時幸，側息吏途煩。簪纓非宿好，文史棄前言。", "夕臥北窗下，夢歸南山園。白雲慚幽谷，清風愧泉源。", "十年茲賞廢，佳期今複存。掛冠謝朝侶，星駕別君門。", "默念群疑起，玄通百慮清。初心滅陽豔，複見湛虛明。", "悟滅心非盡，求虛見後生。應將無住法，修到不成名。"]'),
('yuding-59','和張監游終南','張說','唐','御定全唐诗','yuding','','[]','宿懷終南意，及此語雲峰。夜聞竹澗靜，曉望林嶺重。',48,'御定全唐詩/json/086.json','["宿懷終南意，及此語雲峰。夜聞竹澗靜，曉望林嶺重。", "春煙生古石，時鳥戲幽松。豈無山中賞，但畏心莫從。"]'),
('yuding-60','古泉驛','張說','唐','御定全唐诗','yuding','','[]','昔聞陳仲子，守義辭三公。身賃妻織屨，樂亦在其中。',60,'御定全唐詩/json/086.json','["昔聞陳仲子，守義辭三公。身賃妻織屨，樂亦在其中。", "豈無窮賤苦，羞與傾巧同。長白臨河上，於陵入濟東。", "我行吊遺跡，感歎古泉空。"]'),
('yuding-61','河上公','張說','唐','御定全唐诗','yuding','','[]','尊師厭塵去，精魄知何明。形氣不復生，弟子空傷情。',48,'御定全唐詩/json/086.json','["尊師厭塵去，精魄知何明。形氣不復生，弟子空傷情。", "濟北神如在，淮南藥未成。共期終莫遂，寥落兩無成。"]'),
('yuding-62','奉和聖制初入秦川路寒食應制','張說','唐','御定全唐诗','yuding','','[]','上陽柳色喚春歸，臨渭桃花拂水飛。總為朝廷巡幸去，',88,'御定全唐詩/json/086.json','["上陽柳色喚春歸，臨渭桃花拂水飛。總為朝廷巡幸去，", "入關正投寒食前，還京遂落清明後。路上天心重豫遊，", "渭橋南渡花如撲，麥隴青青斷人目。漢家行樹直新豐，", "今歲隨宜過寒食，明年陪宴作清明。"]'),
('yuding-63','時樂鳥篇','張說','唐','御定全唐诗','yuding','','[]','舊傳南海出靈禽，時樂名聞不可尋。形貌乍同鸚鵡類，',88,'御定全唐詩/json/086.json','["舊傳南海出靈禽，時樂名聞不可尋。形貌乍同鸚鵡類，", "紅茸糅繡好毛衣，清泠謳鴉好言語。內人試取禦衣牽，", "天情玩訝良無已，察圖果見祥經裏。本持符瑞驗明王，", "人見嚶嚶報恩鳥，多慚碌碌具官臣。"]'),
('yuding-64','安樂郡主花燭行','張說','唐','御定全唐诗','yuding','','[]','青宮朱邸翊皇闈，玉葉瓊蕤發紫微。姬姜本來舅甥國，',168,'御定全唐詩/json/086.json','["青宮朱邸翊皇闈，玉葉瓊蕤發紫微。姬姜本來舅甥國，", "鸞車鳳傳王子來，龍樓月殿天孫出。平臺火樹連上陽，", "綠輧紺幰紛如霧，節鼓清笳前啟路。城隅靡靡稍東還，", "商女香車珠結網，天人寶馬玉繁纓。百壺淥酒千斤肉，", "珊瑚刻盤青玉尊，因之假道入梁園。梁園山竹凝雲漢，", "別起芙蓉織成帳，金縷鴛鴦兩相向。罽茵飾地承雕履，", "藹藹綺庭嬪從列，娥娥紅粉扇中開。黃金兩印雙花綬，"]'),
('yuding-65','離會曲','張說','唐','御定全唐诗','yuding','','[]','何處送客洛橋頭，洛水泛泛中行舟。可憐河樹葉萎蕤，',40,'御定全唐詩/json/086.json','["何處送客洛橋頭，洛水泛泛中行舟。可憐河樹葉萎蕤，", "何人送客故人情，故人今夜何處客。"]'),
('yuding-66','鄴都引','張說','唐','御定全唐诗','yuding','','[]','君不見魏武草創爭天祿，群雄睚眥相馳逐。',76,'御定全唐詩/json/086.json','["君不見魏武草創爭天祿，群雄睚眥相馳逐。", "晝攜壯士破堅陣，夜接詞人賦華屋。都呈繚繞西山陽，", "鄴傍高塚多貴臣，娥眉fT睩共灰塵。", "試上銅台歌舞處，唯有秋風愁殺人。"]'),
('yuding-67','城南亭作','張說','唐','御定全唐诗','yuding','','[]','珂馬朝歸連萬石，槊門洞啟親迎客。北堂珍重琥珀酒，',72,'御定全唐詩/json/086.json','["珂馬朝歸連萬石，槊門洞啟親迎客。北堂珍重琥珀酒，", "舊傳比翼侯家舞，新出將雛主第歌。漢家絳灌餘兵氣，", "誰複遨遊不復歸，閒庭莫畏不芳菲。會待城南春色至，"]'),
('yuding-68','同趙侍禦幹湖作','張說','唐','御定全唐诗','yuding','','[]','江南湖水咽山川，春江溢入共湖連。氣色紛淪橫罩海，',112,'御定全唐詩/json/086.json','["江南湖水咽山川，春江溢入共湖連。氣色紛淪橫罩海，", "欹帆側柁弄風口，赴險臨深繞灣浦。一灣一浦悵邅回，", "暑來寒往運洄洑，潭生水落移陵穀。雲間墜翮散泥沙，", "處處溝洚清源竭，年年舊葦白頭新。天地盈虛尚難保，", "念君宿昔觀物變，安得躊躕不衰老。"]'),
('yuding-69','巡邊在河北作','張說','唐','御定全唐诗','yuding','','[]','去年六月西河西，今年六月北河北。沙場磧路何為爾，',40,'御定全唐詩/json/086.json','["去年六月西河西，今年六月北河北。沙場磧路何為爾，", "會待安邊報明主，作頌封山也未遲。"]'),
('yuding-70','贈崔二安平公樂世詞','張說','唐','御定全唐诗','yuding','','[]','十五紅妝侍綺樓，朝承握槊夜藏鉤。君臣一意金門寵，',48,'御定全唐詩/json/086.json','["十五紅妝侍綺樓，朝承握槊夜藏鉤。君臣一意金門寵，", "地濕莓苔生舞袖，江聲怨歎入箜篌。自憐京兆雙眉嫵，"]'),
('yuding-71','送尹補闕元凱琴歌','張說','唐','御定全唐诗','yuding','','[]','鳳哉鳳哉，啄琅玕，飲瑤池，棲昆侖之山哉。',67,'御定全唐詩/json/086.json','["鳳哉鳳哉，啄琅玕，飲瑤池，棲昆侖之山哉。", "中國有聖人，感和氣，飛來飛來。自歌自舞，先王冊府，", "明年阿閣梧桐花葉開，群飛鳳歸來，群飛鳳歸來。"]'),
('yuding-72','送考功武員外學士使嵩山署舍利塔','張說','唐','御定全唐诗','yuding','','[]','懷玉泉，戀仁者，寂滅真心不可見，空留影塔嵩岩下。',72,'御定全唐詩/json/086.json','["懷玉泉，戀仁者，寂滅真心不可見，空留影塔嵩岩下。", "寶王四海轉千輪，金曇百粒送分身。山中二月娑羅會，", "雖在神仙蘭省間，常持清淨蓮花葉。來亦好，去亦好，"]'),
('yuding-73','遙同蔡起居偃松篇','張說','唐','御定全唐诗','yuding','','[]','清都眾木總榮芬，傳道孤松最出群。名接天庭長景色，',48,'御定全唐詩/json/086.json','["清都眾木總榮芬，傳道孤松最出群。名接天庭長景色，", "不借流膏助仙鼎，願將楨幹捧明君。莫比冥靈楚南樹，"]'),
('yuding-0','奉和聖制登驪山矚眺應制','張說','唐','御定全唐诗','yuding','','[]','寒山上半空，臨眺盡寰中。是日巡遊處，晴光遠近同。',48,'御定全唐詩/json/087.json','["寒山上半空，臨眺盡寰中。是日巡遊處，晴光遠近同。", "川明分渭水，樹暗辨新豐。岩壑清音暮，天歌起大風。"]'),
('yuding-1','奉和聖制幸白鹿觀應制','張說','唐','御定全唐诗','yuding','','[]','洞府寒山曲，天遊日旰回。披雲看石鏡，拂雪上金台。',48,'御定全唐詩/json/087.json','["洞府寒山曲，天遊日旰回。披雲看石鏡，拂雪上金台。", "竹徑龍驂下，松庭鶴轡來。雙童還獻藥，五色耀仙材。"]'),
('yuding-2','奉和聖制送金城公主適西蕃應制','張說','唐','御定全唐诗','yuding','','[]','青海和親日，潢星出降時。戎王子婿寵，漢國舅家慈。',48,'御定全唐詩/json/087.json','["青海和親日，潢星出降時。戎王子婿寵，漢國舅家慈。", "春野開離宴，雲天起別詞。空彈馬上曲，詎減鳳樓思。"]'),
('yuding-3','奉和同皇太子過慈恩寺應制二首','張說','唐','御定全唐诗','yuding','','[]','翼翼宸恩永，煌煌福地開。離光升寶殿，震氣繞香台。',96,'御定全唐詩/json/087.json','["翼翼宸恩永，煌煌福地開。離光升寶殿，震氣繞香台。", "上界幡花合，中天伎樂來。願君無量壽，仙樂屢徘徊。", "朗朗神居峻，軒軒瑞象威。聖君成願果，太子拂天衣。", "至樂三靈會，深仁四皓歸。還聞渦水曲，更繞白雲飛。"]'),
('yuding-4','侍宴武三思山第應制賦得風字','張說','唐','御定全唐诗','yuding','','[]','梁王池館好，曉日鳳樓通。竹町羅千衛，蘭筵降兩宮。',48,'御定全唐詩/json/087.json','["梁王池館好，曉日鳳樓通。竹町羅千衛，蘭筵降兩宮。", "清歌芳樹下，妙舞落花中。臣覺筵中聽，還如大國風。"]'),
('yuding-5','奉和聖制過甯王宅應制','張說','唐','御定全唐诗','yuding','','[]','進酒忘憂觀，簫韶喜降臨。帝堯敦族禮，王季友兄心。',48,'御定全唐詩/json/087.json','["進酒忘憂觀，簫韶喜降臨。帝堯敦族禮，王季友兄心。", "竹院龍鳴笛，梧宮鳳繞林。大風將小雅，一字盡千金。"]'),
('yuding-6','奉和聖制同玉真公主過大哥山池題石壁應制','張說','唐','御定全唐诗','yuding','','[]','綠竹初成苑，丹砂欲化金。乘龍與驂鳳，歌吹滿山林。',48,'御定全唐詩/json/087.json','["綠竹初成苑，丹砂欲化金。乘龍與驂鳳，歌吹滿山林。", "爽氣凝情迥，寒光映浦深。忘憂題此觀，為樂賞同心。"]'),
('yuding-7','奉和聖制賜王公千秋鏡應制','張說','唐','御定全唐诗','yuding','','[]','寶鏡頒神節，凝規寫聖情。千秋題作字，長壽帶為名。',48,'御定全唐詩/json/087.json','["寶鏡頒神節，凝規寫聖情。千秋題作字，長壽帶為名。", "月向天邊下，花從日裏生。不承懸象意，誰辨照心明。"]'),
('yuding-8','奉和聖制經鄒魯祭孔子應制','張說','唐','御定全唐诗','yuding','','[]','孔聖家鄒魯，儒風藹典墳。龍驂回舊宅，鳳德詠餘芬。',48,'御定全唐詩/json/087.json','["孔聖家鄒魯，儒風藹典墳。龍驂回舊宅，鳳德詠餘芬。", "入室神如在，升堂樂似聞。懸知一王法，今日待明君。"]'),
('yuding-9','侍宴蘘荷亭應制','張說','唐','御定全唐诗','yuding','','[]','回鑾青嶽觀，帳殿紫煙峰。仙路迎三鳥，雲衢駐兩龍。',48,'御定全唐詩/json/087.json','["回鑾青嶽觀，帳殿紫煙峰。仙路迎三鳥，雲衢駐兩龍。", "園林看化塔，壇墠識餘封。山外聞簫管，還如天上逢。"]'),
('yuding-10','侍宴滻水賦得濃字','張說','唐','御定全唐诗','yuding','','[]','千行發禦柳，一葉下仙筇。青浦宸游至，朱城佳氣濃。',48,'御定全唐詩/json/087.json','["千行發禦柳，一葉下仙筇。青浦宸游至，朱城佳氣濃。", "雲霞交暮色，草樹喜春容。藹藹天旗轉，清笳入九重。"]'),
('yuding-11','奉和聖制同劉晃喜雨應制','張說','唐','御定全唐诗','yuding','','[]','青氣含春雨，知從岱嶽來。行雲避師出，灑雨待車回。',48,'御定全唐詩/json/087.json','["青氣含春雨，知從岱嶽來。行雲避師出，灑雨待車回。", "厭浥塵清道，空蒙柳映台。最宜三五夜，晴月九重開。"]'),
('yuding-12','奉和聖制觀拔河俗戲應制','張說','唐','御定全唐诗','yuding','','[]','今歲好拖鉤，橫街敞禦樓。長繩系日住，貫索挽河流。',48,'御定全唐詩/json/087.json','["今歲好拖鉤，橫街敞禦樓。長繩系日住，貫索挽河流。", "鬥力頻催鼓，爭都更上籌。春來百種戲，天意在宜秋。"]'),
('yuding-13','奉和聖制途次陝州應制','張說','唐','御定全唐诗','yuding','','[]','周召嘗分陝，詩書空複傳。何如萬乘眷，追賞二南篇。',48,'御定全唐詩/json/087.json','["周召嘗分陝，詩書空複傳。何如萬乘眷，追賞二南篇。", "郡帶洪河側，宮臨大道邊。洛城將日近，佳氣滿山川。"]'),
('yuding-14','奉和聖制野次喜雪應制','張說','唐','御定全唐诗','yuding','','[]','寒更玉漏催，曉色御前開。泱漭雲陰積，氤氳風雪回。',48,'御定全唐詩/json/087.json','["寒更玉漏催，曉色御前開。泱漭雲陰積，氤氳風雪回。", "山知銀作甕，宮見璧成台。欲驗豐年象，飄搖仙藻來。"]'),
('yuding-15','奉和聖制溫泉言志應制','張說','唐','御定全唐诗','yuding','','[]','溫谷媚新豐，驪山橫半空。湯池熏水殿，翠木暖煙宮。',48,'御定全唐詩/json/087.json','["溫谷媚新豐，驪山橫半空。湯池熏水殿，翠木暖煙宮。", "起疾逾仙藥，無私合聖功。始知堯舜德，心與萬人同。"]'),
('yuding-16','皇帝降誕日集賢殿賜宴','張說','唐','御定全唐诗','yuding','','[]','仲秋金帝起，五日土行昭。瑞表壬寅露，光傳甲子宵。',48,'御定全唐詩/json/087.json','["仲秋金帝起，五日土行昭。瑞表壬寅露，光傳甲子宵。", "陰風吹大澤，夢日照昌朝。不獨華封老，千年喜祝堯。"]'),
('yuding-17','晦日詔宴永穆公主亭子賦得流字','張說','唐','御定全唐诗','yuding','','[]','堂邑山林美，朝恩晦日遊。園亭含淑氣，竹樹繞春流。',48,'御定全唐詩/json/087.json','["堂邑山林美，朝恩晦日遊。園亭含淑氣，竹樹繞春流。", "舞席千花妓，歌船五彩樓。群歡與王澤，歲歲滿皇州。"]'),
('yuding-18','恩制賜食於麗正殿書院宴賦得林字','張說','唐','御定全唐诗','yuding','','[]','東壁圖書府，西園翰墨林。誦詩聞國政，講易見天心。',48,'御定全唐詩/json/087.json','["東壁圖書府，西園翰墨林。誦詩聞國政，講易見天心。", "位竊和羹重，恩叨醉酒深。緩歌春興曲，情竭為知音。"]'),
('yuding-19','羽林恩召觀禦書王太尉碑','張說','唐','御定全唐诗','yuding','','[]','隴首名公石，來承聖劄歸。魚龍生意態，鉤劍動鋩輝。',48,'御定全唐詩/json/087.json','["隴首名公石，來承聖劄歸。魚龍生意態，鉤劍動鋩輝。", "字得神明保，詞慚少女徽。誰家羽林將，又逐鳳書飛。"]'),
('yuding-20','東都酺宴四首','張說','唐','御定全唐诗','yuding','','[]','重華升寶曆，軒帝眇閒居。政成天子孝，俗返上皇初。',192,'御定全唐詩/json/087.json','["重華升寶曆，軒帝眇閒居。政成天子孝，俗返上皇初。", "忘味因觀樂，歡心寄合酺。自憐疲馬意，戀戀主恩餘。", "朱城塵曀滅，翠幕景情開。震震靈鼉起，翔翔舞鳳來。", "雕盤裝草樹，綺乘結樓臺。共喜光華日，酣歌捧玉杯。", "曉月調金闕，朝暾對玉盤。爭馳群鳥散，鬥伎百花團。", "遇聖人知幸，承恩物自歡。洛橋將舉燭，醉舞拂歸鞍。", "愷宴惟今席，餘歡殊未窮。入雲歌嫋嫋，向日伎叢叢。", "駛管催酣興，留關待曲終。長安若為樂，應與萬方同。"]'),
('yuding-21','道家四首奉敕撰','張說','唐','御定全唐诗','yuding','','[]','金壇啟曙闈，真氣肅微微。落月銜仙竇，初霞拂羽衣。',192,'御定全唐詩/json/087.json','["金壇啟曙闈，真氣肅微微。落月銜仙竇，初霞拂羽衣。", "香隨龍節下，雲逐鳳簫飛。暫住蓬萊戲，千年始一歸。", "窈窕流精觀，深沉紫翠庭。金奩調上藥，寶案讀仙經。", "作賦看神雨，乘槎辨客星。只應謝人俗，輕舉托雲輧。", "金爐承道訣，玉牒啟玄機。雲逐笙歌度，星流宮殿飛。", "乘風嬉浩蕩，窺月弄光輝。唯有三山鶴，應同千載歸。", "道記開中籙，真官表上清。焚香三鳥至，煉藥九仙成。", "天上靈書下，空中妙伎迎。迎來出煙霧，渺渺戲蓬瀛。"]'),
('yuding-22','鳳樓尋勝地','張說','唐','御定全唐诗','yuding','','[]','西掖持醇酒，東山就白雲。開軒綠池映，命席紫蘭芬。',48,'御定全唐詩/json/087.json','["西掖持醇酒，東山就白雲。開軒綠池映，命席紫蘭芬。", "舞度花為伴，鶯來管作群。太平多樂事，春物共氛氳。"]'),
('yuding-23','幽州夜飲','張說','唐','御定全唐诗','yuding','','[]','涼風吹夜雨，蕭瑟動寒林。正有高堂宴，能忘遲暮心。',48,'御定全唐詩/json/087.json','["涼風吹夜雨，蕭瑟動寒林。正有高堂宴，能忘遲暮心。", "軍中宜劍舞，塞上重笳音。不作邊城將，誰知恩遇深。"]'),
('yuding-24','崔禮部園亭得深字','張說','唐','御定全唐诗','yuding','','[]','窈窕留清館，虛徐步晚陰。水連伊闕近，樹接夏陽深。',48,'御定全唐詩/json/087.json','["窈窕留清館，虛徐步晚陰。水連伊闕近，樹接夏陽深。", "柳蔓憐垂拂，藤梢愛上尋。訝君軒蓋侶，非複俗人心。"]'),
('yuding-25','送鄭大夫惟忠從公主入蕃','張說','唐','御定全唐诗','yuding','','[]','鳳吹遙將斷，龍旗送欲還。傾都邀節使，傳酌緩離顏。',48,'御定全唐詩/json/087.json','["鳳吹遙將斷，龍旗送欲還。傾都邀節使，傳酌緩離顏。", "春磧沙連海，秋城月對關。和戎因賞魏，定遠莫辭班。"]'),
('yuding-26','送崔二長史日知赴潞州','張說','唐','御定全唐诗','yuding','','[]','東山懷臥理，南省悵悲翁。共見前途促，何知後會同。',48,'御定全唐詩/json/087.json','["東山懷臥理，南省悵悲翁。共見前途促，何知後會同。", "莫輕一筵宴，明日半成空。況爾新離闕，思歸迷夢中。"]'),
('yuding-27','同賀八送兗公赴荊州','張說','唐','御定全唐诗','yuding','','[]','疇昔同聲友，騫飛出鳳池。風雲一蕩薄，日月屢參差。',48,'御定全唐詩/json/087.json','["疇昔同聲友，騫飛出鳳池。風雲一蕩薄，日月屢參差。", "此別黃葉下，前期安可知。誰憐楚南樹，不為歲寒移。"]'),
('yuding-28','餞唐州高使君','張說','唐','御定全唐诗','yuding','','[]','常時好閑獨，朋舊少相過。及爾宣風去，方嗟別日多。',48,'御定全唐詩/json/087.json','["常時好閑獨，朋舊少相過。及爾宣風去，方嗟別日多。", "淮流春晼晚，江海路蹉跎。百歲屢分散，歡言複幾何。"]'),
('yuding-29','送王晙自羽林赴永昌令','張說','唐','御定全唐诗','yuding','','[]','將星移北洛，神雨避東京。為負剛腸譽，還追強項名。',48,'御定全唐詩/json/087.json','["將星移北洛，神雨避東京。為負剛腸譽，還追強項名。", "白雲向伊闕，黃葉散昆明。多謝弦歌宰，稀聞桴鼓聲。"]'),
('yuding-30','同王僕射山亭餞岑廣武羲得言字','張說','唐','御定全唐诗','yuding','','[]','聞道長岑令，奮翼宰旅門。長安東陌上，送客滿朱軒。',48,'御定全唐詩/json/087.json','["聞道長岑令，奮翼宰旅門。長安東陌上，送客滿朱軒。", "琴爵留佳境，山池借好園。茲遊恨不見，別尾碼離言。"]'),
('yuding-31','送任禦史江南發糧以賑河北百姓','張說','唐','御定全唐诗','yuding','','[]','河朔人無歲，荊南義廩開。將興泛舟役，必仗濟川才。',48,'御定全唐詩/json/087.json','["河朔人無歲，荊南義廩開。將興泛舟役，必仗濟川才。", "夜月臨江浦，春雲曆楚台。調饑坐相望，繡服幾時回。"]'),
('yuding-32','送王尚一嚴嶷二侍禦赴司馬都督軍','張說','唐','御定全唐诗','yuding','','[]','漢掖通沙塞，邊兵護草腓。將行司馬令，助以鐵冠威。',48,'御定全唐詩/json/087.json','["漢掖通沙塞，邊兵護草腓。將行司馬令，助以鐵冠威。", "白露鷹初下，黃塵騎欲飛。明年春酒熟，留酌二星歸。"]'),
('yuding-33','送李問政河北簡兵','張說','唐','御定全唐诗','yuding','','[]','鬥酒貽朋愛，躊躕出禦溝。依然四牡別，更想八龍遊。',48,'御定全唐詩/json/087.json','["鬥酒貽朋愛，躊躕出禦溝。依然四牡別，更想八龍遊。", "密親仕燕冀，連年邇寇讎。因君閱河朔，垂淚語幽州。"]'),
('yuding-34','送薛植入京','張說','唐','御定全唐诗','yuding','','[]','青組言從史，鴻都忽見求。款言人向老，飲別歲方秋。',48,'御定全唐詩/json/087.json','["青組言從史，鴻都忽見求。款言人向老，飲別歲方秋。", "仿佛長安陌，平生是舊遊。何時複相遇，宛在水中流。"]'),
('yuding-35','相州前池別許鄭二判官景先神力','張說','唐','御定全唐诗','yuding','','[]','數步圓塘水，雙鴻戢羽儀。一飛喬木上，一返故林垂。',48,'御定全唐詩/json/087.json','["數步圓塘水，雙鴻戢羽儀。一飛喬木上，一返故林垂。", "澹泊含秋景，虛明抱夜規。無因留絕翰，雲海意差池。"]'),
('yuding-36','嶽州宴別潭州王熊二首','張說','唐','御定全唐诗','yuding','','[]','絲管清且哀，一曲傾一杯。氣將然諾重，心向友朋開。',96,'御定全唐詩/json/087.json','["絲管清且哀，一曲傾一杯。氣將然諾重，心向友朋開。", "古木無生意，寒雲若死灰。贈君芳杜草，為植建章台。", "縉雲連省閣，溝水遽西東。然諾心猶在，榮華歲不同。", "孤城臨楚塞，遠樹入秦宮。誰念三千里，江潭一老翁。"]'),
('yuding-37','廣州蕭都督入朝過嶽州宴餞得冬字','張說','唐','御定全唐诗','yuding','','[]','孤城抱大江，節使往朝宗。果是台中舊，依然水上逢。',48,'御定全唐詩/json/087.json','["孤城抱大江，節使往朝宗。果是台中舊，依然水上逢。", "京華遙比日，疲老颯如冬。竊羨能言鳥，銜恩向九重。"]'),
('yuding-38','岳州別姚司馬紹之制許歸侍','張說','唐','御定全唐诗','yuding','','[]','和玉悲無已，長沙宦不成。天從扇枕願，人遂倚門情。',48,'御定全唐詩/json/087.json','["和玉悲無已，長沙宦不成。天從扇枕願，人遂倚門情。", "方外懷司馬，江東憶步兵。問君棲泊處，空嶺夜猿驚。"]'),
('yuding-39','送岳州李十從軍桂州','張說','唐','御定全唐诗','yuding','','[]','送客之江上，其人美且才。風波萬里闊，故舊十年來。',48,'御定全唐詩/json/087.json','["送客之江上，其人美且才。風波萬里闊，故舊十年來。", "劍拔蛟隨斷，弓張鳥自摧。陽橋書落落，驛馬定先回。"]'),
('yuding-40','岳州別趙國公王十一琚入朝','張說','唐','御定全唐诗','yuding','','[]','昔濫貂蟬長，同承雨露霏。今參魚鱉守，望美洞庭歸。',48,'御定全唐詩/json/087.json','["昔濫貂蟬長，同承雨露霏。今參魚鱉守，望美洞庭歸。", "浦樹懸秋影，江雲燒落輝。離魂似征帆，恒往帝鄉飛。"]'),
('yuding-41','嶽州別子均','張說','唐','御定全唐诗','yuding','','[]','離筵非燕喜，別酒正銷魂。念汝猶童孺，嗟予隔遠藩。',48,'御定全唐詩/json/087.json','["離筵非燕喜，別酒正銷魂。念汝猶童孺，嗟予隔遠藩。", "津亭拔心草，江路斷腸猿。他日將何見，愁來獨倚門。"]'),
('yuding-42','端州別高六戩','張說','唐','御定全唐诗','yuding','','[]','異壤同羈竄，途中喜共過。愁多時舉酒，勞罷或長歌。',48,'御定全唐詩/json/087.json','["異壤同羈竄，途中喜共過。愁多時舉酒，勞罷或長歌。", "南海風潮壯，西江瘴癘多。於焉複分手，此別傷如何。"]'),
('yuding-43','南中別蔣五岑向青州','張說','唐','御定全唐诗','yuding','','[]','老親依北海，賤子棄南荒。有淚皆成血，無聲不斷腸。',48,'御定全唐詩/json/087.json','["老親依北海，賤子棄南荒。有淚皆成血，無聲不斷腸。", "此中逢故友，彼地送還鄉。願作楓林葉，隨君度洛陽。"]'),
('yuding-44','南中別陳七李十','張說','唐','御定全唐诗','yuding','','[]','二年共遊處，一旦各西東。請君聊駐馬，看我轉征蓬。',48,'御定全唐詩/json/087.json','["二年共遊處，一旦各西東。請君聊駐馬，看我轉征蓬。", "畫鷁愁南海，離駒思北風。何時似春雁，雙入上林中。"]'),
('yuding-45','南中別王陵成崇','張說','唐','御定全唐诗','yuding','','[]','握手與君別，歧路贈一言。曹卿禮公子，楚媼饋王孫。',48,'御定全唐詩/json/087.json','["握手與君別，歧路贈一言。曹卿禮公子，楚媼饋王孫。", "倏爾生六翮，翻飛戾九門。常懷客鳥意，會答主人恩。"]'),
('yuding-46','嶺南送使','張說','唐','御定全唐诗','yuding','','[]','秋雁逢春返，流人何日歸。將余去國淚，灑子入鄉衣。',48,'御定全唐詩/json/087.json','["秋雁逢春返，流人何日歸。將余去國淚，灑子入鄉衣。", "饑狖啼相聚，愁猿喘更飛。南中不可問，書此示京畿。"]'),
('yuding-47','幽州別陰長河行先','張說','唐','御定全唐诗','yuding','','[]','惠好交情重，辛勤世事多。荊南久為別，薊北遠來過。',48,'御定全唐詩/json/087.json','["惠好交情重，辛勤世事多。荊南久為別，薊北遠來過。", "寄目雲中鳥，留歡酒上歌。影移春複間，遲暮兩如何。"]'),
('yuding-48','和朱使欣道峽似巫山之作','張說','唐','御定全唐诗','yuding','','[]','江如曉天淨，石似暮霞張。征帆一流覽，宛若巫山陽。',48,'御定全唐詩/json/087.json','["江如曉天淨，石似暮霞張。征帆一流覽，宛若巫山陽。", "楚客思歸路，秦人謫異鄉。猿鳴孤月夜，再使淚沾裳。"]'),
('yuding-49','和朱使欣二首','張說','唐','御定全唐诗','yuding','','[]','南土多為寇，西江盡畏途。山行阻篁竹，水宿礙萑蒲。',96,'御定全唐詩/json/087.json','["南土多為寇，西江盡畏途。山行阻篁竹，水宿礙萑蒲。", "使越才應有，征蠻力豈無。空傳人贈劍，不見虎銜珠。", "江勢連山遠，天涯此夜愁。霜空極天靜，寒月帶江流。", "思起南征棹，文高北望樓。自憐如墜葉，泛泛侶仙舟。"]'),
('yuding-50','過庾信宅','張說','唐','御定全唐诗','yuding','','[]','蘭成追宋玉，舊宅偶詞人。筆湧江山氣，文驕雲雨神。',48,'御定全唐詩/json/087.json','["蘭成追宋玉，舊宅偶詞人。筆湧江山氣，文驕雲雨神。", "包胥非救楚，隨會反留秦。獨有東陽守，來嗟古樹春。"]'),
('yuding-51','盧巴驛聞張禦史張判官欲到不得待留贈之','張說','唐','御定全唐诗','yuding','','[]','旅竄南方遠，傳聞北使來。舊庭知玉樹，合浦識珠胎。',48,'御定全唐詩/json/087.json','["旅竄南方遠，傳聞北使來。舊庭知玉樹，合浦識珠胎。", "白髮因愁改，丹心托夢回。皇恩若再造，為憶不然灰。"]'),
('yuding-52','南中贈高六戩','張說','唐','御定全唐诗','yuding','','[]','北極辭明代，南溟宅放臣。丹誠由義盡，白髮帶愁新。',48,'御定全唐詩/json/087.json','["北極辭明代，南溟宅放臣。丹誠由義盡，白髮帶愁新。", "鳥墜炎洲氣，花飛洛水春。平生歌舞席，誰憶不歸人。"]'),
('yuding-53','嶽州山城','張說','唐','御定全唐诗','yuding','','[]','山城豐日暇，閉戶見天心。東曠迎朝色，西樓引夕陰。',48,'御定全唐詩/json/087.json','["山城豐日暇，閉戶見天心。東曠迎朝色，西樓引夕陰。", "書觀千載近，學靜二毛深。忽有南風至，吹君堂上琴。"]'),
('yuding-54','和尹懋秋夜遊灉湖','張說','唐','御定全唐诗','yuding','','[]','灉湖佳可遊，既近複能幽。林裏棲精舍，山間轉去舟。',48,'御定全唐詩/json/087.json','["灉湖佳可遊，既近複能幽。林裏棲精舍，山間轉去舟。", "雁飛江月冷，猿嘯野風秋。不是迷鄉客，尋奇處處留。"]'),
('yuding-55','與趙冬曦尹懋子均登南樓','張說','唐','御定全唐诗','yuding','','[]','危樓瀉洞湖，積水照城隅。命駕邀漁火，通家引鳳雛。',48,'御定全唐詩/json/087.json','["危樓瀉洞湖，積水照城隅。命駕邀漁火，通家引鳳雛。", "山晴紅蕊匝，洲曉綠苗鋪。舉目思鄉縣，春光定不殊。"]'),
('yuding-56','遊灉湖上寺','張說','唐','御定全唐诗','yuding','','[]','湖上奇峰積，山中芳樹春。何知絕世境，來遇賞心人。',48,'御定全唐詩/json/087.json','["湖上奇峰積，山中芳樹春。何知絕世境，來遇賞心人。", "清舊岩前樂，呦嚶鳥獸馴。靜言觀聽裏，萬法自成輪。"]'),
('yuding-57','晦日','張說','唐','御定全唐诗','yuding','','[]','晦日嫌春淺，江浦看湔衣。道傍花欲合，枝上鳥猶稀。',48,'御定全唐詩/json/087.json','["晦日嫌春淺，江浦看湔衣。道傍花欲合，枝上鳥猶稀。", "共憶浮橋晚，無人不醉歸。寄書題此日，雁過洛陽飛。"]'),
('yuding-58','湘州九日城北亭子','張說','唐','御定全唐诗','yuding','','[]','西楚茱萸節，南淮戲馬台。甯知沅水上，複有菊花杯。',48,'御定全唐詩/json/087.json','["西楚茱萸節，南淮戲馬台。甯知沅水上，複有菊花杯。", "亭帳憑高出，親朋自遠來。短歌將急景，同使興情催。"]'),
('yuding-59','翻著葛巾呈趙尹','張說','唐','御定全唐诗','yuding','','[]','昔日接z5倒，今我葛巾翻。宿酒何時醒，形骸不復存。',49,'御定全唐詩/json/087.json','["昔日接z5倒，今我葛巾翻。宿酒何時醒，形骸不復存。", "忽聞有嘉客，躧步出閑門。桃花春徑滿，誤識武陵源。"]'),
('yuding-60','戲題草樹','張說','唐','御定全唐诗','yuding','','[]','忽驚石榴樹，遠出渡江來。戲問芭蕉葉，何愁心不開。',48,'御定全唐詩/json/087.json','["忽驚石榴樹，遠出渡江來。戲問芭蕉葉，何愁心不開。", "微霜拂宮桂，淒吹掃庭槐。榮盛更如此，慚君獨見哀。"]'),
('yuding-61','嶽州贈廣平公宋大夫','張說','唐','御定全唐诗','yuding','','[]','亞相本時英，歸來複國楨。朝推長孺直，野慕隱之清。',48,'御定全唐詩/json/087.json','["亞相本時英，歸來複國楨。朝推長孺直，野慕隱之清。", "傳節還閩嶂，皇華入漢京。甯思江上老，歲晏獨無成。"]'),
('yuding-62','和魏僕射還鄉','張說','唐','御定全唐诗','yuding','','[]','富貴還鄉國，光華滿舊林。秋風樹不靜，君子歎何深。',48,'御定全唐詩/json/087.json','["富貴還鄉國，光華滿舊林。秋風樹不靜，君子歎何深。", "故老空懸劍，鄰交日散金。眾芳搖落盡，獨有歲寒心。"]'),
('yuding-63','和張監觀赦','張說','唐','御定全唐诗','yuding','','[]','日禦臨雙闕，天街儼百神。雷茲作解氣，歲複建寅春。',48,'御定全唐詩/json/087.json','["日禦臨雙闕，天街儼百神。雷茲作解氣，歲複建寅春。", "喜候開星驛，歡聲發市人。金環能作賦，來入管弦聲。"]'),
('yuding-64','寄天臺司馬道士','張說','唐','御定全唐诗','yuding','','[]','世上求真客，天臺去不還。傳聞有仙要，夢寐在茲山。',48,'御定全唐詩/json/087.json','["世上求真客，天臺去不還。傳聞有仙要，夢寐在茲山。", "朱闕青霞斷，瑤堂紫月閑。何時枉飛鶴，笙吹接人間。"]'),
('yuding-65','下江南向夔州','張說','唐','御定全唐诗','yuding','','[]','天明江霧歇，洲浦棹歌來。綠水逶迤去，青山相向開。',48,'御定全唐詩/json/087.json','["天明江霧歇，洲浦棹歌來。綠水逶迤去，青山相向開。", "城臨蜀帝祀，雲接楚王台。舊知巫山上，遊子共徘徊。"]'),
('yuding-66','還至端州驛前與高六別處','張說','唐','御定全唐诗','yuding','','[]','舊館分江日，淒然望落暉。相逢傳旅食，臨別換征衣。',48,'御定全唐詩/json/087.json','["舊館分江日，淒然望落暉。相逢傳旅食，臨別換征衣。", "昔記山川是，今傷人代非。往來皆此路，生死不同歸。"]'),
('yuding-67','四月一日過江赴荊州','張說','唐','御定全唐诗','yuding','','[]','春色沅湘盡，三年客始回。夏雲隨北帆，同日過江來。',48,'御定全唐詩/json/087.json','["春色沅湘盡，三年客始回。夏雲隨北帆，同日過江來。", "水漫荊門出，山平郢路開。比肩羊叔子，千載豈無才。"]'),
('yuding-68','湘州北亭','張說','唐','御定全唐诗','yuding','','[]','人務南亭少，風煙北院多。山花迷徑路，池水拂藤蘿。',48,'御定全唐詩/json/087.json','["人務南亭少，風煙北院多。山花迷徑路，池水拂藤蘿。", "萍散魚時躍，林幽鳥任歌。悠然白雲意，乘興抱琴過。"]'),
('yuding-69','荊州亭入朝','張說','唐','御定全唐诗','yuding','','[]','巫山雲雨峽，湘水洞庭波。九辨人猶擯，三秋雁始過。',48,'御定全唐詩/json/087.json','["巫山雲雨峽，湘水洞庭波。九辨人猶擯，三秋雁始過。", "旃裘吳地盡，髫薦楚言多。不果朝宗願，其如江漢何。"]'),
('yuding-70','嶽州守歲','張說','唐','御定全唐诗','yuding','','[]','除夜清樽滿，寒庭燎火多。舞衣連臂拂，醉坐合聲歌。',48,'御定全唐詩/json/087.json','["除夜清樽滿，寒庭燎火多。舞衣連臂拂，醉坐合聲歌。", "至樂都忘我，冥心自委和。今年只如此，來歲知如何。"]'),
('yuding-71','詠塵','張說','唐','御定全唐诗','yuding','','[]','仙浦生羅襪，神京染素衣。裨山期益峻，照日幸增輝。',48,'御定全唐詩/json/087.json','["仙浦生羅襪，神京染素衣。裨山期益峻，照日幸增輝。", "夕伴龍媒合，朝遊鳳輦歸。獨憐範甑下，思繞畫梁飛。"]'),
('yuding-72','闕題','張說','唐','御定全唐诗','yuding','','[]','婚禮知無賀，承家歎有輝。親迎驥子躍，吉兆鳳雛飛。',48,'御定全唐詩/json/087.json','["婚禮知無賀，承家歎有輝。親迎驥子躍，吉兆鳳雛飛。", "溫席開華扇，梁門換褧衣。遙思桃李日，應賦采蘋歸。"]'),
('yuding-73','深渡驛','張說','唐','御定全唐诗','yuding','','[]','旅泊青山夜，荒庭白露秋。洞房懸月影，高枕聽江流。',48,'御定全唐詩/json/087.json','["旅泊青山夜，荒庭白露秋。洞房懸月影，高枕聽江流。", "猿響寒岩樹，螢飛古驛樓。他鄉對搖落，並覺起離憂。"]'),
('yuding-74','惠文太子挽歌二首','張說','唐','御定全唐诗','yuding','','[]','碣館英靈在，瑤山美諡尊。剪桐悲曩戲，攻玉愴新恩。',96,'御定全唐詩/json/087.json','["碣館英靈在，瑤山美諡尊。剪桐悲曩戲，攻玉愴新恩。", "宮仗傳馳道，朝衣送國門。千秋谷門外，明月照西園。", "梁國深文雅，淮王愛道仙。帝歡同宴日，神奪上賓年。", "旒旐飛行樹，帷宮宿野煙。指言君愛弟，揮淚滿山川。"]'),
('yuding-75','節義太子楊妃挽歌二首','張說','唐','御定全唐诗','yuding','','[]','西華三公族，東闈五可才。玉環初受慶，金玦反逢災。',96,'御定全唐詩/json/087.json','["西華三公族，東闈五可才。玉環初受慶，金玦反逢災。", "桂殿花空落，桐園月自開。朝雲將暮雨，長繞望思台。", "昔日三朝路，逶迤四望車。繡腰長命綺，隱髻連枝花。", "今春戾園樹，索然無歲華。共傷千載後，惟號一王家。"]'),
('yuding-76','韋譙公挽歌二首','張說','唐','御定全唐诗','yuding','','[]','五瑞分王國，雙珠映後家。文飛書上鳳，武結笥中蛇。',96,'御定全唐詩/json/087.json','["五瑞分王國，雙珠映後家。文飛書上鳳，武結笥中蛇。", "出豫榮前馬，回鸞喪後車。袞衣將錫命，泉路有光華。", "國騁雙騏驥，庭儀兩鳳凰。將星連相位，玉樹伴金鄉。", "歌舞侯家豔，軒裘戚裏光。安知杜陵下，碑版已相望。"]'),
('yuding-77','右丞相蘇公挽歌二首','張說','唐','御定全唐诗','yuding','','[]','王宰丹青化，春卿禮樂才。緇衣傳舊職，華袞贈新哀。',96,'御定全唐詩/json/087.json','["王宰丹青化，春卿禮樂才。緇衣傳舊職，華袞贈新哀。", "路泣群官送，山嘶駟馬回。佳辰無白日，賓閣有青苔。", "門歌出野田，冠帶寢窮泉。萬事皆身外，平生尚目前。", "西垣紫泥綍，東嶽白雲篇。自惜同聲處，從今遂絕弦。"]'),
('yuding-78','崔尚書挽詞','張說','唐','御定全唐诗','yuding','','[]','相宅隆坤寶，承家占海封。庭中男執雁，門外女乘龍。',48,'御定全唐詩/json/087.json','["相宅隆坤寶，承家占海封。庭中男執雁，門外女乘龍。", "鳴玉遊三省，摐金侍九重。一朝賓客散，留劍在青松。"]'),
('yuding-79','右侍郎集賢院學士徐公挽詞二首','張說','唐','御定全唐诗','yuding','','[]','才美臨淄北，名高淮海東。羽儀三省遍，漁獵五車通。',96,'御定全唐詩/json/087.json','["才美臨淄北，名高淮海東。羽儀三省遍，漁獵五車通。", "玉殿孤新榜，珠英落舊叢。徒懸一寶劍，何處訪徐公。", "歎息書林友，才華天下選。並賦三陽宮，集詩集賢殿。", "具物衣如在，咄嗟長不見。既哀薤露詞，豈忘平生眷。"]'),
('yuding-80','崔司業挽歌二首','張說','唐','御定全唐诗','yuding','','[]','海岱英靈氣，膠庠禮樂資。風流滿天下，人物擅京師。',96,'御定全唐詩/json/087.json','["海岱英靈氣，膠庠禮樂資。風流滿天下，人物擅京師。", "疾起揚雄賦，魂遊謝客詩。從今好文主，遺恨不同時。", "象設存華館，威儀下墓田。鳳池傷舊草，麟史泣遺編。", "帷蓋墟煙沒，幹旌隴日懸。古來埋玉樹，流恨滿山川。"]'),
('yuding-81','李工部挽歌三首','張說','唐','御定全唐诗','yuding','','[]','錦帳為郎日，金門待詔時。楊宮先上賦，柏殿幾連詩。',144,'御定全唐詩/json/087.json','["錦帳為郎日，金門待詔時。楊宮先上賦，柏殿幾連詩。", "瞬息琴歌斷，淒涼簫挽悲。那堪霸陵岸，回首望京師。", "宅兆西陵上，平生雅志從。城臨丹闕近，山望白雲重。", "會葬知元伯，看碑識蔡邕。無由接神理，揮涕向青松。", "常時好賓客，永日對弦歌。是日歸泉下，傷心無奈何。", "墓庭人已散，祭處鳥來過。碑石生苔蘚，榮名豈複多。"]'),
('yuding-82','贈工部尚書馮公挽歌三首','張說','唐','御定全唐诗','yuding','','[]','忠鯁難為事，平生盡畏途。如弦心自直，秀木勢恒孤。',144,'御定全唐詩/json/087.json','["忠鯁難為事，平生盡畏途。如弦心自直，秀木勢恒孤。", "詔葬南陵道，神遊北斗樞。貴門傳萬石，餘慶在雙珠。", "爵位題龍旐，威儀出鳳城。路傍人泣送，門外馬嘶迎。", "萬事非吾有，千悲是世情。昔焉稱夏日，今也諡冬卿。", "窅然長夜台，舉世可哀哉。泉戶一朝閉，松風四面來。", "石碑填駁蘚，珠服聚塵埃。誰言遼東鶴，千年往復回。"]'),
('yuding-83','徐高禦挽歌','張說','唐','御定全唐诗','yuding','','[]','蒲密遙千載，鳴琴始一追。公卿傳世范，仁義續靈基。',48,'御定全唐詩/json/087.json','["蒲密遙千載，鳴琴始一追。公卿傳世范，仁義續靈基。", "不待南游祿，何先北帝期。玉棺從此閉，金鼎代相欺。"]'),
('yuding-84','奉和聖制春日幸望春宮應制','張說','唐','御定全唐诗','yuding','','[]','別館芳菲上苑東，飛花澹蕩禦筵紅。城臨渭水天河靜，',40,'御定全唐詩/json/087.json','["別館芳菲上苑東，飛花澹蕩禦筵紅。城臨渭水天河靜，", "春園既醉心和樂，共識皇恩造化同。"]'),
('yuding-85','侍宴隆慶池應制','張說','唐','御定全唐诗','yuding','','[]','靈池月滿直城隈，黻帳天臨禦路開。東沼初陽疑吐出，',40,'御定全唐詩/json/087.json','["靈池月滿直城隈，黻帳天臨禦路開。東沼初陽疑吐出，", "願似金堤青草馥，長承瑤水白雲杯。"]'),
('yuding-86','奉和聖制春日出苑應制','張說','唐','御定全唐诗','yuding','','[]','禁林豔裔發青陽，春望逍遙出畫堂。雨洗亭皋千畝綠，',40,'御定全唐詩/json/087.json','["禁林豔裔發青陽，春望逍遙出畫堂。雨洗亭皋千畝綠，", "睿賞歡承天保定，遒文更睹日重光。"]'),
('yuding-87','扈從溫泉宮獻詩','張說','唐','御定全唐诗','yuding','','[]','溫泉啟蟄氣氛氳，渭浦歸鴻日數群。騎仗聯聯環北極，',40,'御定全唐詩/json/087.json','["溫泉啟蟄氣氛氳，渭浦歸鴻日數群。騎仗聯聯環北極，", "不知遠夢華胥國，何如親奉帝堯君。"]'),
('yuding-88','三月三日詔宴定昆池宮莊賦得筵字','張說','唐','御定全唐诗','yuding','','[]','鳳凰樓下對天泉，鸚鵡洲中匝管弦。舊識平陽佳麗地，',40,'御定全唐詩/json/087.json','["鳳凰樓下對天泉，鸚鵡洲中匝管弦。舊識平陽佳麗地，", "不降玉人觀禊飲，誰令醉舞拂賓筵。"]'),
('yuding-89','先天應令','張說','唐','御定全唐诗','yuding','','[]','三陽麗景早芳辰，四序嘉園物候新。梅花百般障行路，',40,'御定全唐詩/json/087.json','["三陽麗景早芳辰，四序嘉園物候新。梅花百般障行路，", "唯願聖主南山壽，何愁不賞萬年春。"]'),
('yuding-90','舞馬千秋萬歲樂府詞三首','張說','唐','御定全唐诗','yuding','','[]','金天誕聖千秋節，玉醴還分萬壽觴。試聽紫騮歌樂府，',120,'御定全唐詩/json/087.json','["金天誕聖千秋節，玉醴還分萬壽觴。試聽紫騮歌樂府，", "歲歲相傳指樹日，翩翩來伴慶雲翔。", "聖皇至德與天齊，天馬來儀自海西。腕足徐行拜兩膝，", "更有銜杯終宴曲，垂頭掉尾醉如泥。", "遠聽明君愛逸才，玉鞭金翅引龍媒。不因茲白人間有，", "莫言闕下桃花舞，別有河中蘭葉開。"]'),
('yuding-91','同趙侍禦巴陵早春作','張說','唐','御定全唐诗','yuding','','[]','江上春來早可觀，巧將春物妒餘寒。水苔共繞留烏石，',40,'御定全唐詩/json/087.json','["江上春來早可觀，巧將春物妒餘寒。水苔共繞留烏石，", "意隨北雁雲飛去，直待南州蕙草殘。"]'),
('yuding-92','灉湖山寺','張說','唐','御定全唐诗','yuding','','[]','空山寂曆道心生，虛穀迢遙野鳥聲。禪室從來塵外賞，',40,'御定全唐詩/json/087.json','["空山寂曆道心生，虛穀迢遙野鳥聲。禪室從來塵外賞，", "若使巢由知此意，不將蘿薜易簪纓。"]'),
('yuding-93','幽州新歲作','張說','唐','御定全唐诗','yuding','','[]','去歲荊南梅似雪，今年薊北雪如梅。共知人事何常定，',40,'御定全唐詩/json/087.json','["去歲荊南梅似雪，今年薊北雪如梅。共知人事何常定，", "遙遙西向長安日，願上南山壽一杯。"]'),
('yuding-0','扈從幸韋嗣立山莊應制','張說','唐','御定全唐诗','yuding','','[]','寒灰飛玉管，湯井駐金輿。既得方明相，還尋大隗居。',96,'御定全唐詩/json/088.json','["寒灰飛玉管，湯井駐金輿。既得方明相，還尋大隗居。", "懸泉珠貫下，列帳錦屏舒。騎遠林逾密，笳繁穀自虛。", "門旗塹複磴，殿幕裹通渠。舞鳳迎公主，雕龍賦婕妤。", "地幽天賞洽，酒樂禦筵初。菲才叨侍從，連藻愧應徐。"]'),
('yuding-1','奉和聖制喜雪應制','張說','唐','御定全唐诗','yuding','','[]','聖德與天同，封巒欲報功。詔書期日下，靈感應時通。',72,'御定全唐詩/json/088.json','["聖德與天同，封巒欲報功。詔書期日下，靈感應時通。", "觸石雲呈瑞，含花雪告豐。積如沙照月，散似面從風。", "舞集仙台上，歌流帝樂中。遙知百神喜，灑路待行宮。"]'),
('yuding-2','奉和聖制寒食作應制','張說','唐','御定全唐诗','yuding','','[]','寒食春過半，花穠鳥複嬌。從來禁火日，會接清明朝。',72,'御定全唐詩/json/088.json','["寒食春過半，花穠鳥複嬌。從來禁火日，會接清明朝。", "鬥敵雞殊勝，爭球馬絕調。晴空數雲點，香樹百風搖。", "改木迎新燧，封田表舊燒。皇情愛嘉節，傳曲與簫韶。"]'),
('yuding-3','奉和聖制賜崔日知往潞州應制','張說','唐','御定全唐诗','yuding','','[]','聖情留曩鎮，佳氣翊興王。增戟雄都府，高車轉太常。',72,'御定全唐詩/json/088.json','["聖情留曩鎮，佳氣翊興王。增戟雄都府，高車轉太常。", "川橫八練闊，山帶五龍長。連帥初恩命，天人舊紀綱。", "餞塗飛禦藻，闔境自生光。明主征循吏，何年下鳳凰。"]'),
('yuding-4','春晚侍宴麗正殿探得開字','張說','唐','御定全唐诗','yuding','','[]','聖政惟稽古，賓門引上才。坊因購書立，殿為集賢開。',72,'御定全唐詩/json/088.json','["聖政惟稽古，賓門引上才。坊因購書立，殿為集賢開。", "髦彥星辰下，仙章日月回。字如龍負出，韻是鳳銜來。", "庭柳餘春駐，宮鶯早夏催。喜承芸閣宴，幸奉柏梁杯。"]'),
('yuding-5','奉和聖制花萼樓下宴應制','張說','唐','御定全唐诗','yuding','','[]','萬心翹樂宴，三舍緩昌時。山接夏雲險，台留春日遲。',72,'御定全唐詩/json/088.json','["萬心翹樂宴，三舍緩昌時。山接夏雲險，台留春日遲。", "節移芳未歇，興隔賞仍追。醉後傳嘉惠，樓前舞聖慈。", "皇恩與時合，天意若人期。故發前旬雨，新垂湛露詩。"]'),
('yuding-6','奉和聖制度蒲關應制','張說','唐','御定全唐诗','yuding','','[]','蒲阪橫臨晉，華芝曉望秦。關城雄地險，橋路扼天津。',72,'御定全唐詩/json/088.json','["蒲阪橫臨晉，華芝曉望秦。關城雄地險，橋路扼天津。", "樓映行宮日，堤含宮樹春。黃雲隨寶鼎，紫氣逐真人。", "東詠唐虞跡，西觀周漢塵。山河非國寶，明主愛忠臣。"]'),
('yuding-7','奉和聖制途經華嶽應制','張說','唐','御定全唐诗','yuding','','[]','西嶽鎮皇京，中峰入太清。玉鑾重嶺應，緹騎薄雲迎。',72,'御定全唐詩/json/088.json','["西嶽鎮皇京，中峰入太清。玉鑾重嶺應，緹騎薄雲迎。", "霽日懸高掌，寒空類削成。軒遊會神處，漢幸望仙情。", "舊廟青林古，新碑綠字生。群臣原封岱，還駕勒鴻名。"]'),
('yuding-8','奉和聖制過王浚墓應制','張說','唐','御定全唐诗','yuding','','[]','牛鬥三分國，龍驤一統年。智高寧受制，風急肯回船。',72,'御定全唐詩/json/088.json','["牛鬥三分國，龍驤一統年。智高寧受制，風急肯回船。", "有策擒吳嚭，無言讓范宣。援孤因勢屈，功重為讒偏。", "舊跡灰塵散，枯墳故老傳。百代逢明主，何辭死道邊。"]'),
('yuding-9','奉和聖制經河上公廟應制','張說','唐','御定全唐诗','yuding','','[]','河上無名老，知非漢代人。先探道德要，留待聖明辰。',72,'御定全唐詩/json/088.json','["河上無名老，知非漢代人。先探道德要，留待聖明辰。", "玄妙為天下，清虛用穀神。化將和氣一，風與太初鄰。", "靈廟觀遺像，仙歌入至真。皇心齊萬物，何處不同塵。"]'),
('yuding-10','奉和聖制幸鳳湯泉應制','張說','唐','御定全唐诗','yuding','','[]','周狩聞岐禮，秦都辨雍名。獻禽天子孝，存老聖皇情。',72,'御定全唐詩/json/088.json','["周狩聞岐禮，秦都辨雍名。獻禽天子孝，存老聖皇情。", "溫潤宜冬幸，游畋樂歲成。湯雲出水殿，暖氣入山營。", "坎意無私潔，幹心稱物平。帝歌流樂府，溪谷也增榮。"]'),
('yuding-11','恩賜樂遊園宴','張說','唐','御定全唐诗','yuding','','[]','漢苑佳遊地，軒庭近侍臣。共持榮幸日，來賞豔陽春。',72,'御定全唐詩/json/088.json','["漢苑佳遊地，軒庭近侍臣。共持榮幸日，來賞豔陽春。", "饌玉頒王篚，摐金下帝鈞。池台草色遍，宮觀柳條新。", "花綬光連榻，朱顏暢飲醇。聖朝多樂事，天意每隨人。"]'),
('yuding-12','三月二十日詔宴樂遊園賦得風字','張說','唐','御定全唐诗','yuding','','[]','樂游形勝地，表裏望郊宮。北闕連天頂，南山對掌中。',72,'御定全唐詩/json/088.json','["樂游形勝地，表裏望郊宮。北闕連天頂，南山對掌中。", "皇恩貸芳月，旬宴美成功。魚戲芙蓉水，鶯啼楊柳風。", "春光看欲暮，天澤戀無窮。長袖招斜日，留光待曲終。"]'),
('yuding-13','赴集賢院學士上賜宴應制得輝字','張說','唐','御定全唐诗','yuding','','[]','侍帝金華講，千齡道固稀。位將賢士設，書共學徒歸。',72,'御定全唐詩/json/088.json','["侍帝金華講，千齡道固稀。位將賢士設，書共學徒歸。", "首命深燕隗，通經淺漢韋。列筵榮賜食，送客愧儒衣。", "賀燕窺簷下，遷鶯入殿飛。欲知朝野慶，文教日光輝。"]'),
('yuding-14','端午三殿侍宴應制探得魚字','張說','唐','御定全唐诗','yuding','','[]','小暑夏弦應，徽音商管初。願齎長命縷，來續大恩餘。',84,'御定全唐詩/json/088.json','["小暑夏弦應，徽音商管初。願齎長命縷，來續大恩餘。", "三殿褰珠箔，群官上玉除。助陽嘗麥彘，順節進龜魚。", "甘露垂天酒，芝花捧禦書。合丹同蝘蜓，灰骨共蟾蜍。", "今日傷蛇意，銜珠遂闕如。"]'),
('yuding-15','奉和聖制春中興慶宮酺宴應制','張說','唐','御定全唐诗','yuding','','[]','千齡逢啟聖，萬域共來威。慶接郊禋後，酺承農事稀。',96,'御定全唐詩/json/088.json','["千齡逢啟聖，萬域共來威。慶接郊禋後，酺承農事稀。", "禦樓橫廣路，天樂下重闈。鸞鳳調歌曲，虹霓動舞衣。", "合聲雲上聚，連步月中歸。物睹恩無外，神和道入微。", "鎬京陪樂飲，柏殿奉文飛。徒竭秋雲影，何資春日暉。"]'),
('yuding-16','奉和聖制千秋節宴應制','張說','唐','御定全唐诗','yuding','','[]','五德生王者，千齡啟聖人。赤光來照夜，黃雲上覆晨。',96,'御定全唐詩/json/088.json','["五德生王者，千齡啟聖人。赤光來照夜，黃雲上覆晨。", "海縣銜恩久，朝章獻舞新。高居帝座出，夾道眾官陳。", "槊杖洗清景，磬管凝秋旻。珠囊含瑞露，金鏡抱仙輪。", "何歲無鄉飲，何田不報神。熏歌與名節，傳代幸群臣。"]'),
('yuding-17','奉和聖制太行山中言志應制','張說','唐','御定全唐诗','yuding','','[]','六龍鳴玉鑾，九折步雲端。河絡南浮近，山經北上難。',96,'御定全唐詩/json/088.json','["六龍鳴玉鑾，九折步雲端。河絡南浮近，山經北上難。", "羽儀映松雪，戈甲帶春寒。百穀晨笳動，千岩曉仗攢。", "皇心感韶節，敷藻念人安。既立省方館，複建禮神壇。", "扈蹕參天老，承榮忝夏官。長勤百年意，思見一勝殘。"]'),
('yuding-18','奉和禦制與宋璟源幹曜同日上官命宴東堂賜詩應制','張說','唐','御定全唐诗','yuding','','[]','大塊熔群品，經生偶聖時。猥承三事命，虛忝百僚師。',96,'御定全唐詩/json/088.json','["大塊熔群品，經生偶聖時。猥承三事命，虛忝百僚師。", "右揆謀華碩，前星傅重資。連騫求舊禮，濫典樂賢詩。", "賜釜同榮拜，摐金宴宰司。菊花吹禦酒，蘭葉捧天詞。", "寶曆休明盛，頹年晷漏衰。少留青史筆，未敢赤松期。"]'),
('yuding-19','奉和聖制暇日與兄弟同遊興慶宮作應制','張說','唐','御定全唐诗','yuding','','[]','漢武橫汾日，周王宴鎬年。何如造區夏，複此睦親賢。',120,'御定全唐詩/json/088.json','["漢武橫汾日，周王宴鎬年。何如造區夏，複此睦親賢。", "巢鳳新成閣，飛龍舊躍泉。棣華歌尚在，桐葉戲仍傳。", "禁籞氛埃隔，平臺景物連。聖慈良有裕，王道固無偏。", "問俗兆人阜，觀風五教宣。獻圖開益地，張樂奏鈞天。", "侍酒衢樽滿，詢芻諫鼓懸。永言形友愛，萬國共周旋。"]'),
('yuding-20','奉和聖制送王晙巡邊應制','張說','唐','御定全唐诗','yuding','','[]','六月歌周雅，三邊遣夏卿。欲施攻戰法，先作簡稽行。',120,'御定全唐詩/json/088.json','["六月歌周雅，三邊遣夏卿。欲施攻戰法，先作簡稽行。", "禮樂知謀帥，春秋識用兵。一勞堪定國，萬里即長城。", "策有和戎利，威傳破虜名。軍前雨灑道，樓上月臨營。", "別藻瑤華降，同衣錦襮榮。關山由義近，戎馬為恩輕。", "絲竹路傍散，風雲馬上生。朝廷謂吉甫，邦國望君平。"]'),
('yuding-21','將赴朔方軍應制','張說','唐','御定全唐诗','yuding','','[]','禮樂逢明主，韜鈐用老臣。恭憑神武策，遠禦鬼方人。',120,'御定全唐詩/json/088.json','["禮樂逢明主，韜鈐用老臣。恭憑神武策，遠禦鬼方人。", "供帳榮恩餞，山川喜詔巡。天文日月麗，朝賦管弦新。", "幼志傳三略，衰材謝六鈞。膽由忠作伴，心固道為鄰。", "漢保河南地，胡清塞北塵。連年大軍後，不日小康辰。", "劍舞輕離別，歌酣忘苦辛。從來思博望，許國不謀身。"]'),
('yuding-22','奉和聖制爰因巡省途次舊居應制','張說','唐','御定全唐诗','yuding','','[]','蔥郁興王郡，殷憂啟聖圖。周成會西土，漢武幸南都。',144,'御定全唐詩/json/088.json','["蔥郁興王郡，殷憂啟聖圖。周成會西土，漢武幸南都。", "歲蔔鑾輿邁，農祠雁政敷。武威棱外域，文教靡中區。", "警蹕干戈捧，朝宗萬玉趨。舊藩人事革，新化國容殊。", "壁有真龍畫，庭餘鳴鳳梧。叢觴祝堯壽，合鼎獻湯廚。", "陽樂寒初變，春恩蟄更蘇。三耆頒命服，五稔複田輸。", "君賦大風起，人歌湛露濡。從臣觀玉葉，方願紀靈符。"]'),
('yuding-23','宿直溫泉宮羽林獻詩','張說','唐','御定全唐诗','yuding','','[]','冬狩美秦正，新豐樂漢行。星陳玄武閣，月對羽林營。',60,'御定全唐詩/json/088.json','["冬狩美秦正，新豐樂漢行。星陳玄武閣，月對羽林營。", "寒木羅霜仗，空山響夜更。恩深靈液暖，節勁古松貞。", "文武皆王事，輸心不為名。"]'),
('yuding-24','玄武門侍射','張說','唐','御定全唐诗','yuding','','[]','射觀通玄闕，兵欄辟禦筵。雕弧月半上，畫的暈重圓。',72,'御定全唐詩/json/088.json','["射觀通玄闕，兵欄辟禦筵。雕弧月半上，畫的暈重圓。", "羿後神幽贊，靈王法暗傳。貫心精四返，飲羽妙三聯。", "雪鶴來銜箭，星麟下集弦。一逢軍宴洽，萬慶武功宣。"]'),
('yuding-25','扈從南出雀鼠谷','張說','唐','御定全唐诗','yuding','','[]','豫動三靈贊，時巡四海威。陝關淩曙出，平路半春歸。',72,'御定全唐詩/json/088.json','["豫動三靈贊，時巡四海威。陝關淩曙出，平路半春歸。", "霍鎮迎雲罕，汾河送羽旗。山南柳半密，谷北草全稀。", "遲日宜華蓋，和風入袷衣。上林千里近，應見百花飛。"]'),
('yuding-26','洛橋北亭詔餞諸刺史','張說','唐','御定全唐诗','yuding','','[]','離亭拂禦溝，別曲舞船樓。詔餞朝廷牧，符分海縣憂。',72,'御定全唐詩/json/088.json','["離亭拂禦溝，別曲舞船樓。詔餞朝廷牧，符分海縣憂。", "股肱還入郡，父母更臨州。扇逐仁風轉，車隨霖雨流。", "恩光水上溢，榮色柳間浮。預待群方最，三公不遠求。"]'),
('yuding-27','東都酺宴','張說','唐','御定全唐诗','yuding','','[]','堯舜傳天下，同心致太平。吾君內舉聖，遠合至公情。',120,'御定全唐詩/json/088.json','["堯舜傳天下，同心致太平。吾君內舉聖，遠合至公情。", "錫命承丕業，崇親享大名。二天資廣運，兩曜益齊明。", "道暢昆蟲樂，恩深朽蠹榮。皇輿久西幸，留鎮在東京。", "合宴千官入，分曹百戲呈。樂來嫌景遽，酒著訝寒輕。", "喜氣連雲閣，歡呼動洛城。人間知幾代，今日見河清。"]'),
('yuding-28','奉酬韋祭酒嗣立偶游龍門北溪忽懷驪山別業呈諸留守之作','張說','唐','御定全唐诗','yuding','','[]','石澗泉虛落，松崖路曲回。聞君北溪下，想像南山隈。',120,'御定全唐詩/json/088.json','["石澗泉虛落，松崖路曲回。聞君北溪下，想像南山隈。", "近念鼎湖別，遙思雲嶂陪。不同奇覯往，空睹斯文來。", "歲後寒初變，春前芳未開。黃蕤嫋岸柳，紫萼折村梅。", "盡室茲遊玩，盈門幾樂哉。嗟留洛陽陌，夢詣建章台。", "野失巢由性，朝非元凱才。布懷欽遠跡，幽意日塵埃。"]'),
('yuding-29','奉酬韋祭酒自湯還都經龍門北溪莊見貽之作','張說','唐','御定全唐诗','yuding','','[]','聞君湯井至，瀟灑憩郊林。拂曙攜清賞，披雲覯綠岑。',120,'御定全唐詩/json/088.json','["聞君湯井至，瀟灑憩郊林。拂曙攜清賞，披雲覯綠岑。", "歡言遊覽意，款曲望歸心。是日期佳客，同山忽異尋。", "桃花迂路轉，楊柳間門深。泛舟伊水漲，系馬香樹陰。", "繁弦弄水族，嬌吹狎沙禽。春滿汀色媚，景斜嵐氣侵。", "懷仁殊未遠，重德匪專臨。來藻敷幽思，連詞報所欽。"]'),
('yuding-30','酬崔光祿冬日述懷贈答','張說','唐','御定全唐诗','yuding','','[]','徐陳嘗並作，枚馬亦同時。各負當朝譽，俱承明主私。',264,'御定全唐詩/json/088.json','["徐陳嘗並作，枚馬亦同時。各負當朝譽，俱承明主私。", "夫君邁前侶，觀國騁奇姿。山似鳴威鳳，泉如出寶龜。", "才雄子雲筆，學廣仲舒帷。紫綬拂三寺，朱門臨九逵。", "昔我含香日，聯爾縉雲司。朝攜蘭省步，夕退竹林期。", "中路一分手，數載來何遲。求友還相得，群英複在茲。", "留台少人務，方駕遞尋追。涉玩懷同賞，沾芳憶共持。", "迎賓南澗飲，載妓東城嬉。春郊綠畝秀，秋澗白雲滋。", "名畫披人物，良書討滯疑。興來光不惜，歡往跡如遺。", "歲晏罷行樂，層城間所思。夜魂燈處厭，朝發鏡前衰。", "忽枉崔駰什，兼流韋孟詞。曲高彌寡和，主善代為師。", "齊戒觀華玉，留連歎色絲。終慚起予者，何足與言詩。"]'),
('yuding-31','同劉給事城南宴集','張說','唐','御定全唐诗','yuding','','[]','水竹幽閒地，簪纓近侍臣。雍容乘暇日，瀟灑出囂塵。',72,'御定全唐詩/json/088.json','["水竹幽閒地，簪纓近侍臣。雍容乘暇日，瀟灑出囂塵。", "樹對思朋鳥，池深入養鱗。管弦高逐吹，歌舞妙含春。", "老子叨專席，歡邀隔縉紳。此中情不淺，遙寄賞心人。"]'),
('yuding-32','溫泉馮劉二監客舍觀妓','張說','唐','御定全唐诗','yuding','','[]','溫谷寒林薄，群遊樂事多。佳人蹀駿馬，乘月夜相過。',72,'御定全唐詩/json/088.json','["溫谷寒林薄，群遊樂事多。佳人蹀駿馬，乘月夜相過。", "秀色然紅黛，嬌香發綺羅。鏡前鸞對舞，琴裏鳳傳歌。", "妒寵傾新意，銜恩奈老何。為君留上客，歡笑斂雙蛾。"]'),
('yuding-33','寄許八','張說','唐','御定全唐诗','yuding','','[]','萬類春皆樂，徂顏獨不怡。年來人更老，花發意先衰。',72,'御定全唐詩/json/088.json','["萬類春皆樂，徂顏獨不怡。年來人更老，花發意先衰。", "乳鵲穿壇畫，巢蜂觸網絲。平生美容色，宿昔影中疑。", "遠道何由夢，同心在者誰。西風欲誰語，憫默遂無詞。"]'),
('yuding-34','送蘇合宮頲','張說','唐','御定全唐诗','yuding','','[]','都邑群方首，商泉舊俗訛。變風須愷悌，成化佇弦歌。',72,'御定全唐詩/json/088.json','["都邑群方首，商泉舊俗訛。變風須愷悌，成化佇弦歌。", "疇昔珪璋友，雍容文雅多。振纓遊省闥，鏘玉宰京河。", "別曲鸞初下，行軒雉尚過。百壺非餞意，流詠在人和。"]'),
('yuding-35','送喬安邑備','張說','唐','御定全唐诗','yuding','','[]','書閣移年歲，文明難複辭。歡言冬雪滿，恨別夏雲滋。',72,'御定全唐詩/json/088.json','["書閣移年歲，文明難複辭。歡言冬雪滿，恨別夏雲滋。", "外尹方為政，高明自不欺。老人驂馭往，童子狎雛嬉。", "日茂西河俗，寂寥東觀期。遙懷秀才令，京洛見新詩。"]'),
('yuding-36','送趙二尚書彥昭北伐','張說','唐','御定全唐诗','yuding','','[]','虜地河冰合，邊城備此時。兵連紫塞路，將舉白雲司。',72,'御定全唐詩/json/088.json','["虜地河冰合，邊城備此時。兵連紫塞路，將舉白雲司。", "提劍榮中貴，銜珠盛出師。日華光組練，風色焰旌旗。", "投筆尊前起，橫戈馬上辭。梅花吹別引，楊柳賦歸詩。"]'),
('yuding-37','石門別楊六欽望','張說','唐','御定全唐诗','yuding','','[]','燕人同竄越，萬里自相哀。影響無期會，江山此地來。',60,'御定全唐詩/json/088.json','["燕人同竄越，萬里自相哀。影響無期會，江山此地來。", "暮年傷泛梗，累日慰寒灰。潮水東南落，浮雲西北回。", "俱看石門遠，倚棹兩悲哉。"]'),
('yuding-38','南中送北使二首','張說','唐','御定全唐诗','yuding','','[]','傳聞合蒲葉，曾向洛陽飛。何日南風至，還隨北使歸。',192,'御定全唐詩/json/088.json','["傳聞合蒲葉，曾向洛陽飛。何日南風至，還隨北使歸。", "紅顏渡嶺歇，白首對秋衰。高歌何由見，層堂不可違。", "誰憐炎海曲，淚盡血沾衣。", "待罪居重譯，窮愁暮雨秋。山臨鬼門路，城繞瘴江流。", "人事今如此，生涯尚可求。逢君入鄉縣，傳我念京周。", "別恨歸途遠，離言暮景遒。夷歌翻下淚，蘆酒未消愁。", "聞有胡兵急，深懷漢國羞。和親先是詐，款塞果為讎。", "釋系應分爵，蠲徒幾複侯。廉頗誠未老，孫叔且無謀。", "若道馮唐事，皇恩尚可收。"]'),
('yuding-39','送趙順直郎中赴安西副大都督','張說','唐','御定全唐诗','yuding','','[]','絕鎮功難立，懸軍命匪輕。複承遷相後，彌重任賢情。',96,'御定全唐詩/json/088.json','["絕鎮功難立，懸軍命匪輕。複承遷相後，彌重任賢情。", "將起神仙地，才稱禮樂英。長心堪系虜，短語足論兵。", "日授休門法，星教置陣名。龍泉恩已著，燕頷相終成。", "月窟窮天遠，河源入塞清。老夫操別翰，承旨頌升平。"]'),
('yuding-40','送宋休遠之蜀任','張說','唐','御定全唐诗','yuding','','[]','求友殊損益，行道異窮申。綴我平生氣，吐贈薄遊人。',96,'御定全唐詩/json/088.json','["求友殊損益，行道異窮申。綴我平生氣，吐贈薄遊人。", "結恩事明主，忍愛遠辭親。色麗成都俗，膏腴蜀水濱。", "如何從宦子，堅白共緇磷。日月千齡旦，河山萬族春。", "懷鉛書瑞府，橫草事邊塵。不及安人吏，能令王化淳。"]'),
('yuding-41','岳州別梁六入朝','張說','唐','御定全唐诗','yuding','','[]','遠蒞長沙渚，欣逢賈誼才。江山疲應接，風日複晴開。',108,'御定全唐詩/json/088.json','["遠蒞長沙渚，欣逢賈誼才。江山疲應接，風日複晴開。", "江樹雲間斷，湘山水上來。近洲朝鷺集，古戍夜猿哀。", "岸杼含蒼捄，河蒲秀紫台。月餘偏地賞，心盡故人杯。", "自我違京洛，嗟君此溯洄。容華因別老，交舊與年頹。", "夢見長安陌，朝宗實盛哉。"]'),
('yuding-42','相州冬日早衙','張說','唐','御定全唐诗','yuding','','[]','城外宵鐘斂，閨中曙火殘。朝光曜庭雪，宿凍聚池寒。',72,'御定全唐詩/json/088.json','["城外宵鐘斂，閨中曙火殘。朝光曜庭雪，宿凍聚池寒。", "正色臨廳事，疑詞定筆端。除苛囹圄息，伐枳吏人寬。", "河內功猶淺，淮陽疾未安。鏡中星發變，頓使世情闌。"]'),
('yuding-43','嶽州西城','張說','唐','御定全唐诗','yuding','','[]','水國何遼曠，風波遂極天。西江三紀合，南浦二湖連。',96,'御定全唐詩/json/088.json','["水國何遼曠，風波遂極天。西江三紀合，南浦二湖連。", "危堞臨清境，煩憂暫豁然。九圍觀掌內，萬象閱眸前。", "日去長沙渚，山橫雲夢田。汀葭變秋色，津樹入寒煙。", "潛穴探靈詭，浮生揖聖仙。至今人不見，跡滅事空傳。"]'),
('yuding-44','嶽州觀競渡','張說','唐','御定全唐诗','yuding','','[]','畫作飛鳧艇，雙雙競拂流。低裝山色變，急棹水華浮。',72,'御定全唐詩/json/088.json','["畫作飛鳧艇，雙雙競拂流。低裝山色變，急棹水華浮。", "土尚三閭俗，江傳二女遊。齊歌迎孟姥，獨舞送陽侯。", "鼓發南湖溠，標爭西驛樓。並驅常詫速，非畏日光遒。"]'),
('yuding-45','對酒行巴陵作','張說','唐','御定全唐诗','yuding','','[]','留侯封萬戶，園令壽千金。本為成王業，初由賦上林。',72,'御定全唐詩/json/088.json','["留侯封萬戶，園令壽千金。本為成王業，初由賦上林。", "繁榮安足恃，霜露遞相尋。鳥哭楚山外，猿啼湘水陰。", "夢中城闕近，天畔海雲深。空對忘憂酌，離憂不去心。"]'),
('yuding-46','岳州宴姚紹之','張說','唐','御定全唐诗','yuding','','[]','杞梓滯江濱，光華向日新。難兄金作友，媚子玉為人。',72,'御定全唐詩/json/088.json','["杞梓滯江濱，光華向日新。難兄金作友，媚子玉為人。", "山水含秋興，池亭借善鄰。簷松風送靜，院竹鳥來馴。", "翠斝吹黃菊，雕盤鱠紫鱗。緩歌將醉舞，為拂繡衣塵。"]'),
('yuding-47','嶽州九日宴道觀西閣','張說','唐','御定全唐诗','yuding','','[]','搖落長年歎，蹉跎遠宦心。北風嘶代馬，南浦宿陽禽。',120,'御定全唐詩/json/088.json','["搖落長年歎，蹉跎遠宦心。北風嘶代馬，南浦宿陽禽。", "佳此黃花酌，酣餘白首吟。涼雲霾楚望，蒙雨蔽荊岑。", "登眺思清景，誰將眷濁陰。釣歌出江霧，樵唱入山林。", "魚以嘉名采，木為美材侵。大道由中悟，逍遙匪外尋。", "參佐多君子，詞華妙賞音。留題洞庭觀，望古意何深。"]'),
('yuding-48','嶽州作','張說','唐','御定全唐诗','yuding','','[]','水國生秋草，離居再及瓜。山川臨洞穴，風日望長沙。',72,'御定全唐詩/json/088.json','["水國生秋草，離居再及瓜。山川臨洞穴，風日望長沙。", "物土南州異，關河北信賒。日昏聞怪鳥，地熱見修蛇。", "遠人夢歸路，瘦馬嘶去家。正有江潭月，徘徊戀九華。"]'),
('yuding-49','游洞庭湖','張說','唐','御定全唐诗','yuding','','[]','平湖曉望分，仙嶠氣氛氳。鼓枻乘清渚，尋峰弄白雲。',84,'御定全唐詩/json/088.json','["平湖曉望分，仙嶠氣氛氳。鼓枻乘清渚，尋峰弄白雲。", "江寒天一色，日靜水重紋。樹坐參猿嘯，沙行入鷺群。", "緣源斑筱密，罥徑綠蘿紛。洞穴傳虛應，楓林覺自熏。", "雙童有靈藥，願取獻明君。"]'),
('yuding-50','巴丘春作','張說','唐','御定全唐诗','yuding','','[]','日出洞庭水，春山掛斷霞。江涔相映發，卉木共紛華。',72,'御定全唐詩/json/088.json','["日出洞庭水，春山掛斷霞。江涔相映發，卉木共紛華。", "湘戍南浮闊，荊關北望賒。湖陰窺魍魎，丘勢辨巴蛇。", "島戶巢為館，漁人艇作家。自憐心問景，三歲客長沙。"]'),
('yuding-51','嶽州夜坐','張說','唐','御定全唐诗','yuding','','[]','炎洲苦三伏，永日臥孤城。賴此閒庭夜，蕭條夜月明。',72,'御定全唐詩/json/088.json','["炎洲苦三伏，永日臥孤城。賴此閒庭夜，蕭條夜月明。", "獨歌還太息，幽感見餘聲。江近鶴時叫，山深猿屢鳴。", "息心觀有欲，棄知返無名。五十知天命，吾其達此生。"]'),
('yuding-52','別灉湖','張說','唐','御定全唐诗','yuding','','[]','念別灉湖去，浮舟更一臨。千峰出浪險，萬木抱煙深。',72,'御定全唐詩/json/088.json','["念別灉湖去，浮舟更一臨。千峰出浪險，萬木抱煙深。", "南郡延恩渥，東山戀宿心。露花香欲醉，時鳥囀餘音。", "涉趣皆留賞，無奇不遍尋。莫言山水間，幽意在鳴琴。"]'),
('yuding-53','伯奴邊見歸田賦因投趙侍禦','張說','唐','御定全唐诗','yuding','','[]','爾家歎窮鳥，吾族賦歸田。莫道榮枯異，同嗟世網牽。',84,'御定全唐詩/json/088.json','["爾家歎窮鳥，吾族賦歸田。莫道榮枯異，同嗟世網牽。", "黃陵浮汨渚，青草會湘川。去國逾三歲，茲山老二年。", "寒鴞鳴捨下，昏虎臥籬前。客淚堪斑竹，離亭欲贈荃。", "放言久無次，觸興感成篇。"]'),
('yuding-54','清遠江峽山寺','張說','唐','御定全唐诗','yuding','','[]','流落經荒外，逍遙此梵宮。雲峰吐月白，石壁淡煙紅。',84,'御定全唐詩/json/088.json','["流落經荒外，逍遙此梵宮。雲峰吐月白，石壁淡煙紅。", "寶塔靈仙湧，懸龕造化功。天香涵竹氣，虛唄引松風。", "簷牖飛花入，廊房激水通。猿鳴知穀靜，魚戲辨江空。", "靜默將何貴，惟應心境同。"]'),
('yuding-55','春雨早雷','張說','唐','御定全唐诗','yuding','','[]','東北春風至，飄飄帶雨來。拂黃先變柳，點素早驚梅。',72,'御定全唐詩/json/088.json','["東北春風至，飄飄帶雨來。拂黃先變柳，點素早驚梅。", "樹藹懸書閣，煙含作賦台。河魚未上凍，江蟄已聞雷。", "美人宵夢著，金屏曙不開。無緣一啟齒，空酌萬年杯。"]'),
('yuding-56','聞雨','張說','唐','御定全唐诗','yuding','','[]','窮冬萬花匝，永夜百憂攢。危戍臨江火，空齋入雨寒。',60,'御定全唐詩/json/088.json','["窮冬萬花匝，永夜百憂攢。危戍臨江火，空齋入雨寒。", "斷猿知屢別，嘶雁覺虛彈。心對爐灰死，顏隨庭樹殘。", "舊恩懷未報，傾膽鏡中看。"]'),
('yuding-57','赦歸在道中作','張說','唐','御定全唐诗','yuding','','[]','陳焦心息盡，死意不期生。何幸光華旦，流人歸上京。',60,'御定全唐詩/json/088.json','["陳焦心息盡，死意不期生。何幸光華旦，流人歸上京。", "愁將網共解，服與代俱明。複是三階正，還逢四海平。", "誰能定禮樂，為國著功成。"]'),
('yuding-58','喜度嶺','張說','唐','御定全唐诗','yuding','','[]','東漢興唐曆，南河複禹謀。寧知瘴癘地，生入帝皇州。',144,'御定全唐詩/json/088.json','["東漢興唐曆，南河複禹謀。寧知瘴癘地，生入帝皇州。", "雷雨蘇蟲蟄，春陽放學鳩。洄沿炎海畔，登降閩山陬。", "嶺路分中夏，川源得上流。見花便獨笑，看草即忘憂。", "自始居重譯，天星已再周。鄉關絕歸望，親戚不相求。", "棄杖枯還植，窮鱗涸更浮。道消黃鶴去，運啟白駒留。", "江妾晨炊黍，津童夜棹舟。盛明良可遇，莫後洛城遊。"]'),
('yuding-0','奉和聖制潼關口號應制','張說','唐','御定全唐诗','yuding','','[]','天德平無外，關門東複西。不將千里隔，何用一丸泥。',24,'御定全唐詩/json/089.json','["天德平無外，關門東複西。不將千里隔，何用一丸泥。"]'),
('yuding-1','奉蕭令嵩酒並詩','張說','唐','御定全唐诗','yuding','','[]','樂奏天恩滿，杯來秋興高。更蒙蕭相國，對席飲醇醪。',24,'御定全唐詩/json/089.json','["樂奏天恩滿，杯來秋興高。更蒙蕭相國，對席飲醇醪。"]'),
('yuding-2','奉宇文黃門融酒','張說','唐','御定全唐诗','yuding','','[]','聖德垂甘露，天章下大風。又乘黃閣賞，願作黑頭公。',24,'御定全唐詩/json/089.json','["聖德垂甘露，天章下大風。又乘黃閣賞，願作黑頭公。"]'),
('yuding-3','奉裴中書光庭酒','張說','唐','御定全唐诗','yuding','','[]','西掖恩華降，南宮命席闌。詎知雞樹後，更接鳳池歡。',24,'御定全唐詩/json/089.json','["西掖恩華降，南宮命席闌。詎知雞樹後，更接鳳池歡。"]'),
('yuding-4','清夜酌','張說','唐','御定全唐诗','yuding','','[]','秋陰士多感，雨息夜無塵。清樽宜明月，複有平生人。',24,'御定全唐詩/json/089.json','["秋陰士多感，雨息夜無塵。清樽宜明月，複有平生人。"]'),
('yuding-5','醉中作','張說','唐','御定全唐诗','yuding','','[]','醉後樂無極，彌勝未醉時。動容皆是舞，出語總成詩。',24,'御定全唐詩/json/089.json','["醉後樂無極，彌勝未醉時。動容皆是舞，出語總成詩。"]'),
('yuding-6','送梁知微渡海東','張說','唐','御定全唐诗','yuding','','[]','今日此相送，明年此相待。天上客星回，知君渡東海。',24,'御定全唐詩/json/089.json','["今日此相送，明年此相待。天上客星回，知君渡東海。"]'),
('yuding-7','寄劉道士舄','張說','唐','御定全唐诗','yuding','','[]','真人降紫氣，邀我丹田宮。遠寄雙飛舄，飛飛不礙空。',24,'御定全唐詩/json/089.json','["真人降紫氣，邀我丹田宮。遠寄雙飛舄，飛飛不礙空。"]'),
('yuding-8','書香能和尚塔','張說','唐','御定全唐诗','yuding','','[]','大師捐世去，空餘法力在。遠寄無礙香，心隨到南海。',24,'御定全唐詩/json/089.json','["大師捐世去，空餘法力在。遠寄無礙香，心隨到南海。"]'),
('yuding-9','被使在蜀','張說','唐','御定全唐诗','yuding','','[]','即今三伏盡，尚自在臨邛。歸途千裏外，秋月定相逢。',24,'御定全唐詩/json/089.json','["即今三伏盡，尚自在臨邛。歸途千裏外，秋月定相逢。"]'),
('yuding-10','正朝摘梅','張說','唐','御定全唐诗','yuding','','[]','蜀地寒猶暖，正朝發早梅。偏驚萬里客，已複一年來。',24,'御定全唐詩/json/089.json','["蜀地寒猶暖，正朝發早梅。偏驚萬里客，已複一年來。"]'),
('yuding-11','蜀道後期','張說','唐','御定全唐诗','yuding','','[]','客心爭日月，來往預期程。秋風不相待，先至洛陽城。',24,'御定全唐詩/json/089.json','["客心爭日月，來往預期程。秋風不相待，先至洛陽城。"]'),
('yuding-12','廣州江中作','張說','唐','御定全唐诗','yuding','','[]','去國年方晏，愁心轉不堪。離人與江水，終日向西南。',24,'御定全唐詩/json/089.json','["去國年方晏，愁心轉不堪。離人與江水，終日向西南。"]'),
('yuding-13','江中誦經','張說','唐','御定全唐诗','yuding','','[]','實相歸懸解，虛心暗在通。澄江明月內，應是色成空。',24,'御定全唐詩/json/089.json','["實相歸懸解，虛心暗在通。澄江明月內，應是色成空。"]'),
('yuding-14','江中遇黃領子劉隆','張說','唐','御定全唐诗','yuding','','[]','危石江中起，孤雲嶺上還。相逢皆得意，何處是鄉關。',24,'御定全唐詩/json/089.json','["危石江中起，孤雲嶺上還。相逢皆得意，何處是鄉關。"]'),
('yuding-15','欽州守歲','張說','唐','御定全唐诗','yuding','','[]','故歲今宵盡，新年明旦來。愁心隨斗柄，東北望春回。',24,'御定全唐詩/json/089.json','["故歲今宵盡，新年明旦來。愁心隨斗柄，東北望春回。"]'),
('yuding-16','嶽州守歲二首','張說','唐','御定全唐诗','yuding','','[]','夜風吹醉舞，庭戶對酣歌。愁逐前年少，歡迎今歲多。',48,'御定全唐詩/json/089.json','["夜風吹醉舞，庭戶對酣歌。愁逐前年少，歡迎今歲多。", "桃枝堪辟惡，爆竹好驚眠。歌舞留今夕，猶言惜舊年。"]'),
('yuding-17','元朝','張說','唐','御定全唐诗','yuding','','[]','今歲元日樂，不謝往年春。知向來心道，誰為昨夜人。',24,'御定全唐詩/json/089.json','["今歲元日樂，不謝往年春。知向來心道，誰為昨夜人。"]'),
('yuding-18','耗磨日飲二首','張說','唐','御定全唐诗','yuding','','[]','耗磨傳茲日，縱橫道未宜。但令不忌醉，翻是樂無為。',48,'御定全唐詩/json/089.json','["耗磨傳茲日，縱橫道未宜。但令不忌醉，翻是樂無為。", "上月今朝減，流傳耗磨辰。還將不事事，同醉俗中人。"]'),
('yuding-19','又','張說','唐','御定全唐诗','yuding','','[]','春來半月度，俗忌一時閑。不酌他鄉酒，惟堪對楚山。',24,'御定全唐詩/json/089.json','["春來半月度，俗忌一時閑。不酌他鄉酒，惟堪對楚山。"]'),
('yuding-20','九日進茱萸山詩五首','張說','唐','御定全唐诗','yuding','','[]','家居洛陽下，舉目見嵩山。刻作茱萸節，情生造化間。',120,'御定全唐詩/json/089.json','["家居洛陽下，舉目見嵩山。刻作茱萸節，情生造化間。", "黃花宜泛酒，青岳好登高。稽首明廷內，心為天下勞。", "菊酒攜山客，萸囊系牧童。路疑隨大隗，心似問鴻蒙。", "九日重陽數，三秋萬實成。時來謁軒後，罷去坐蓬瀛。", "晚節歡重九，高山上五千。醉中知遇聖，夢裏見尋仙。"]'),
('yuding-21','岳州看黃葉','張說','唐','御定全唐诗','yuding','','[]','白首看黃葉，徂顏複幾何。空慚棠樹下，不見政成歌。',24,'御定全唐詩/json/089.json','["白首看黃葉，徂顏複幾何。空慚棠樹下，不見政成歌。"]'),
('yuding-22','嶺南送使二首','張說','唐','御定全唐诗','yuding','','[]','獄中生白髮，嶺外罷紅顏。古來相送處，凡得幾人還。',48,'御定全唐詩/json/089.json','["獄中生白髮，嶺外罷紅顏。古來相送處，凡得幾人還。", "萬里投荒裔，來時不見親。一朝成白首，看取報家人。"]'),
('yuding-23','傷妓人董氏四首','張說','唐','御定全唐诗','yuding','','[]','董氏嬌嬈性，多為窈窕名。人隨秋月落，韻入擣衣聲。',96,'御定全唐詩/json/089.json','["董氏嬌嬈性，多為窈窕名。人隨秋月落，韻入擣衣聲。", "粉蕊粘妝簏，金花竭翠條。夜台無戲伴，魂影向誰嬌。", "舊亭紅粉閣，宿處白雲關。春日雙飛去，秋風獨不還。", "舞席沾殘粉，歌梁委舊塵。獨傷窗裏月，不見帳中人。"]'),
('yuding-24','三月閨怨','張說','唐','御定全唐诗','yuding','','[]','三月時將盡，空房妾獨居。蛾眉愁自結，鬢髮沒情梳。',24,'御定全唐詩/json/089.json','["三月時將盡，空房妾獨居。蛾眉愁自結，鬢髮沒情梳。"]'),
('yuding-25','破陳樂詞二首','張說','唐','御定全唐诗','yuding','','[]','漢兵出頓金微，照日光明鐵衣。百里火幡焰焰，',70,'御定全唐詩/json/089.json','["漢兵出頓金微，照日光明鐵衣。百里火幡焰焰，", "正屬四方朝賀，端知萬舞皇威。", "少年膽氣淩雲，共許驍雄出群。匹馬城西挑戰，", "誓欲成名報國，羞將開閣論勳。"]'),
('yuding-26','舞馬詞六首','張說','唐','御定全唐诗','yuding','','[]','萬玉朝宗鳳扆，千金率領龍媒。眄鼓凝驕躞蹀，',126,'御定全唐詩/json/089.json','["萬玉朝宗鳳扆，千金率領龍媒。眄鼓凝驕躞蹀，", "天鹿遙征衛叔，日龍上借羲和。將共兩驂爭舞，", "彩旄八佾成行，時龍五色因方。屈膝銜杯赴節，", "帝皂龍駒沛艾，星蘭驥子權奇。騰倚驤洋應節，", "二聖先天合德，群靈率土可封。擊石驂驔紫燕，", "聖君出震應籙，神馬浮河獻圖。足踏天庭鼓舞，"]'),
('yuding-27','奉和三日祓禊渭濱應制','張說','唐','御定全唐诗','yuding','','[]','青郊上巳豔陽年，紫禁皇遊祓渭川。',32,'御定全唐詩/json/089.json','["青郊上巳豔陽年，紫禁皇遊祓渭川。", "幸得歡娛承湛露，心同草樹樂春天。"]'),
('yuding-28','桃花園馬上應制','張說','唐','御定全唐诗','yuding','','[]','林間豔色驕天馬，苑裏穠華伴麗人。',32,'御定全唐詩/json/089.json','["林間豔色驕天馬，苑裏穠華伴麗人。", "願逐南風飛帝席，年年含笑舞青春。"]'),
('yuding-29','奉和聖制幸韋嗣立山莊應制','張說','唐','御定全唐诗','yuding','','[]','西京上相出扶陽，東郊別業好池塘。',32,'御定全唐詩/json/089.json','["西京上相出扶陽，東郊別業好池塘。", "自非仁智符天賞，安能日月共回光。"]'),
('yuding-30','奉和聖制同玉真公主游大哥山池題石壁','張說','唐','御定全唐诗','yuding','','[]','池如明鏡月華開，山學香爐雲氣來。',32,'御定全唐詩/json/089.json','["池如明鏡月華開，山學香爐雲氣來。", "神藻飛為鶺鴒賦，仙聲颺出鳳凰台。"]'),
('yuding-31','十五日夜御前口號踏歌詞二首','張說','唐','御定全唐诗','yuding','','[]','花萼樓前雨露新，長安城裏太平人。',64,'御定全唐詩/json/089.json','["花萼樓前雨露新，長安城裏太平人。", "龍銜火樹千重焰，雞踏蓮花萬歲春。", "帝宮三五戲春台，行雨流風莫妒來。", "西域燈輪千影合，東華金闕萬重開。"]'),
('yuding-32','蘇摩遮五首','張說','唐','御定全唐诗','yuding','','[]','摩遮本出海西胡，琉璃寶服紫髯胡。',160,'御定全唐詩/json/089.json','["摩遮本出海西胡，琉璃寶服紫髯胡。", "聞道皇恩遍宇宙，來將歌舞助歡娛。", "繡裝帕額寶花冠，夷歌騎舞借人看。", "自能激水成陰氣，不慮今年寒不寒。", "臘月凝陰積帝台，豪歌急鼓送寒來。", "油囊取得天河水，將添上壽萬年杯。", "寒氣宜人最可憐，故將寒水散庭前。", "惟願聖君無限壽，長取新年續舊年。", "昭成皇后帝家親，榮樂諸人不比倫。", "往日霜前花委地，今年雪後樹逢春。"]'),
('yuding-33','三月三日定昆池奉和蕭令得潭字韻','張說','唐','御定全唐诗','yuding','','[]','暮春三月日重三，春水桃花滿禊潭。',32,'御定全唐詩/json/089.json','["暮春三月日重三，春水桃花滿禊潭。", "廣樂逶迤天上下，仙舟搖衍鏡中酣。"]'),
('yuding-34','和尹從事懋泛洞庭','張說','唐','御定全唐诗','yuding','','[]','平湖一望上連天，林景千尋下洞泉。',32,'御定全唐詩/json/089.json','["平湖一望上連天，林景千尋下洞泉。", "忽驚水上光華滿，疑是乘舟到日邊。"]'),
('yuding-35','送梁六自洞庭山作','張說','唐','御定全唐诗','yuding','','[]','巴陵一望洞庭秋，日見孤峰水上浮。',32,'御定全唐詩/json/089.json','["巴陵一望洞庭秋，日見孤峰水上浮。", "聞道神仙不可接，心隨湖水共悠悠。"]'),
('yuding-36','同趙侍禦望歸舟','張說','唐','御定全唐诗','yuding','','[]','山庭迥迥面長川，江樹重重極遠煙。',32,'御定全唐詩/json/089.json','["山庭迥迥面長川，江樹重重極遠煙。", "形影相追高翥鳥，心腸並斷北風船。"]'),
('yuding-37','襄陽路逢寒食','張說','唐','御定全唐诗','yuding','','[]','去年寒食洞庭波，今年寒食襄陽路。',32,'御定全唐詩/json/089.json','["去年寒食洞庭波，今年寒食襄陽路。", "不辭著處尋山水，只畏還家落春暮。"]'),
('yuding-0','和尹懋登南樓','張均','唐','御定全唐诗','yuding','','[]','客來已兩春，更瞻韶光早。花鳥既環合，江山複駢抱。',48,'御定全唐詩/json/090.json','["客來已兩春，更瞻韶光早。花鳥既環合，江山複駢抱。", "樓形寫北潭，堞勢淩青島。白雲謝歸雁，馳懷洛陽道。"]'),
('yuding-1','江上逢春','張均','唐','御定全唐诗','yuding','','[]','離憂耿未和，春慮忽蹉跎。擇木猿知去，尋泥燕獨過。',48,'御定全唐詩/json/090.json','["離憂耿未和，春慮忽蹉跎。擇木猿知去，尋泥燕獨過。", "驚花翻霽日，垂柳拂煙波。激意屢怡賞，無如鄉念何。"]'),
('yuding-2','九日巴丘登高','張均','唐','御定全唐诗','yuding','','[]','客心驚暮序，賓雁下滄洲。共賞重陽節，言尋戲馬遊。',48,'御定全唐詩/json/090.json','["客心驚暮序，賓雁下滄洲。共賞重陽節，言尋戲馬遊。", "湖風扶戍柳，江雨暗山樓。且酌東籬酒，聊祛南國憂。"]'),
('yuding-3','和尹懋秋夜遊灉湖二首','張均','唐','御定全唐诗','yuding','','[]','遠水沉西日，寒沙聚夜鷗。平湖乘月滿，飛棹接星流。',96,'御定全唐詩/json/090.json','["遠水沉西日，寒沙聚夜鷗。平湖乘月滿，飛棹接星流。", "黃葉鳴淒吹，蒼葭掃暗洲。願移滄浦賞，歸待潁川遊。", "灣潭幽意深，杳靄湧寒岑。石痕秋水落，嵐氣夕陽沉。", "澄澈天為底，淵玄月作心。青溪非大隱，歸弄白雲潯。"]'),
('yuding-4','岳陽晚景','張均','唐','御定全唐诗','yuding','','[]','晚景寒鴉集，秋風旅雁歸。水光浮日出，霞彩映江飛。',48,'御定全唐詩/json/090.json','["晚景寒鴉集，秋風旅雁歸。水光浮日出，霞彩映江飛。", "洲白蘆花吐，園紅柿葉稀。長沙卑濕地，九月未成衣。"]'),
('yuding-5','流合浦嶺外作','張均','唐','御定全唐诗','yuding','','[]','瘴江西去火為山，炎徼南窮鬼作關。',32,'御定全唐詩/json/090.json','["瘴江西去火為山，炎徼南窮鬼作關。", "從此更投人境外，生涯應在有無間。"]'),
('yuding-6','奉和嶽州山城','張垍','唐','御定全唐诗','yuding','','[]','郡館臨清賞，開扃坐白雲。訟虛棠戶曙，觀靜竹簷曛。',48,'御定全唐詩/json/090.json','["郡館臨清賞，開扃坐白雲。訟虛棠戶曙，觀靜竹簷曛。", "懸榻迎賓下，趨庭學禮聞。風傳琴上意，遙向日華紛。"]'),
('yuding-0','偶游龍門北溪忽懷驪山別業因以言志示弟淑奉呈諸大僚','韋嗣立','唐','御定全唐诗','yuding','','[]','幽谷杜陵邊，風煙別幾年。偶來伊水曲，溪嶂覺依然。',120,'御定全唐詩/json/091.json','["幽谷杜陵邊，風煙別幾年。偶來伊水曲，溪嶂覺依然。", "傍浦憐芳樹，尋崖愛綠泉。嶺雲隨馬足，山鳥向人前。", "地合心俱靜，言因理自玄。短才叨重寄，屍祿愧妨賢。", "每挹掛冠侶，思從初服旋。稻粱仍欲報，歲月坐空捐。", "助嶽無纖塊，輸溟謝末涓。還悟北轅失，方求南澗田。"]'),
('yuding-1','奉和九日幸臨渭亭登高應制得深字','韋嗣立','唐','御定全唐诗','yuding','','[]','層觀遠沉沉，鸞旗九日臨。帷宮壓水岸，步輦入煙岑。',48,'御定全唐詩/json/091.json','["層觀遠沉沉，鸞旗九日臨。帷宮壓水岸，步輦入煙岑。", "枝上萸新采，樽中菊始斟。願陪歡樂事，長與歲時深。"]'),
('yuding-2','奉和張岳州王潭州別詩二首','韋嗣立','唐','御定全唐诗','yuding','','[]','茂先王佐才，作牧楚江隈。登樓正欲賦，複遇仲宣來。',96,'御定全唐詩/json/091.json','["茂先王佐才，作牧楚江隈。登樓正欲賦，複遇仲宣來。", "黃鵠飛將遠，雕龍文為開。寧知昔聯事，聽曲有餘哀。", "昔時陪二賢，纓冕會神仙。一去馳江海，相逢共播遷。", "無因千里駕，忽睹四愁篇。覽諷歡何已，歡終徒愴然。"]'),
('yuding-3','奉和初春幸太平公主南莊應制','韋嗣立','唐','御定全唐诗','yuding','','[]','主第岩扃架鵲橋，天門閶闔降鸞鑣。曆亂旌旗轉雲樹，',40,'御定全唐詩/json/091.json','["主第岩扃架鵲橋，天門閶闔降鸞鑣。曆亂旌旗轉雲樹，", "已陪沁水追歡日，行奉茅山訪道朝。"]'),
('yuding-4','自湯還都經龍門北溪贈張左丞崔禮部崔光祿','韋嗣立','唐','御定全唐诗','yuding','','[]','棲閑有愚穀，好事枉朝軒。樹接前驅擁，岩傳後騎喧。',120,'御定全唐詩/json/091.json','["棲閑有愚穀，好事枉朝軒。樹接前驅擁，岩傳後騎喧。", "褰簾出野院，植杖候柴門。既拂林下席，仍攜池上樽。", "深期契幽賞，實謂展歡言。末眷誠未易，佳游時更敦。", "俄看嘯儔侶，各已共飛鶱。延睇盡朝日，長懷通夜魂。", "空聞岸竹動，徒見浦花繁。多愧春鶯曲，相求意獨存。"]'),
('yuding-5','酬崔光祿冬日述懷贈答','韋嗣立','唐','御定全唐诗','yuding','','[]','亭伯負高名，羽儀稱上京。魏珠能燭乘，秦璧許連城。',264,'御定全唐詩/json/091.json','["亭伯負高名，羽儀稱上京。魏珠能燭乘，秦璧許連城。", "六月飛將遠，三冬學已精。洛陽推賈誼，江夏貴黃瓊。", "推演中都術，旋參河尹聲。累遷登禦府，移拜踐名卿。", "庭聚歌鐘麗，門羅棨戟榮。鸚杯飛廣席，獸火列前楹。", "散誕林園意，殷勤敬愛情。無容抱衰疾，良宴每招迎。", "契得心逾重，言忘道益真。相勖忠義節，共談詞賦英。", "雕蟲曾靡棄，白鳳已先鳴。光接神愈駭，音來味不成。", "短歌甘自思，鴻藻彌難清。東裏方希潤，西河敢竊明。", "厚誣空見迫，喪德豈無誠。端守宮闈地，寒煙朝暮平。", "顧才無術淺，懷器識憂盈。月下對雲闕，風前聞夜更。", "昌年雖共偶，歡會此難並。為憐漳浦曲，沉痼有劉楨。"]'),
('yuding-6','上巳日祓禊渭濱應制','韋嗣立','唐','御定全唐诗','yuding','','[]','乘春祓禊逐風光，扈蹕陪鑾渭渚傍。',32,'御定全唐詩/json/091.json','["乘春祓禊逐風光，扈蹕陪鑾渭渚傍。", "還笑當時水濱老，衰年八十待文王。"]'),
('yuding-7','奉酬韋祭酒偶游龍門北溪忽懷驪山別業因以言志示弟淑奉呈諸大僚之作','魏奉古','唐','御定全唐诗','yuding','','[]','有美朝為貴，幽尋地自偏。踐臨伊水汭，想望灞池邊。',120,'御定全唐詩/json/091.json','["有美朝為貴，幽尋地自偏。踐臨伊水汭，想望灞池邊。", "是遇皆新賞，茲遊若舊年。藤蘿隱路接，楊柳禦溝聯。", "道愜神情王，機忘俗理捐。遂初誠已重，兼濟實為賢。", "跡是東山戀，心惟北闕懸。顧慚經拾紫，多謝賦思玄。", "未躧中林步，空承麗藻傳。陽春和已寡，扣寂竟徒然。"]'),
('yuding-8','奉酬韋祭酒偶游龍門北溪忽懷驪山別業因以言志示弟淑並呈諸大僚之作','崔日知','唐','御定全唐诗','yuding','','[]','夙齡秉微尚，中年忽有鄰。以茲山水癖，遂得狎通人。',120,'御定全唐詩/json/091.json','["夙齡秉微尚，中年忽有鄰。以茲山水癖，遂得狎通人。", "迨我咸京道，聞君別業新。岩前窺石鏡，河畔踏芳茵。", "既憐伊浦綠，複憶灞池春。連詞謝家子，同歡冀野賓。", "趣閑魚共樂，情洽鳥來馴。詎念昔遊者，只命獨留秦。", "蕭條穎陽戀，沖漠漢陰真。無由陪勝躅，空此玩書筠。"]'),
('yuding-9','冬日述懷奉呈韋祭酒張左丞蘭台名賢','崔日知','唐','御定全唐诗','yuding','','[]','弱齡好經籍，披卷即怡然。覃精四十載，馳騁數千言。',264,'御定全唐詩/json/091.json','["弱齡好經籍，披卷即怡然。覃精四十載，馳騁數千言。", "孔壁采遺篆，周韋考絕編。袁公論劍術，孫子敘兵篇。", "魯史君臣道，姬書日月懸。從師改炎燠，負笈遍山川。", "上異西河夏，中非北海玄。光榮拾青紫，名價接通賢。", "既重萬鐘樂，寧思二頃田。長戟同分虎，高冠亞附蟬。", "晚懷重虛曠，養志息雕鐫。登高慚思拙，匠物謝情妍。", "不慕張平子，甯希王仲宣。誰謂登龍日，翻成刻鵠年。", "循循勞善誘，軋軋思微牽。琢磨才既竭，鑽仰德彌堅。", "朽木誠為諭，捫心徒自憐。終期吞鳥夢，振翼上雲煙。", "賦成先擲地，詞高直掞天。更執摳衣禮，仍開函丈筵。", "霧披槐市藹，水靜璧池圓。願逐從風葉，飛舞翰林前。"]'),
('yuding-10','奉酬韋嗣立祭酒偶游龍門北溪忽懷驪山別業因以言志示弟淑奉呈諸大僚之作','崔泰之','唐','御定全唐诗','yuding','','[]','關塞臨伊水，驪山枕灞川。俱臨隱路側，同在帝城邊。',120,'御定全唐詩/json/091.json','["關塞臨伊水，驪山枕灞川。俱臨隱路側，同在帝城邊。", "謝公兼出處，攜妓玩林泉。鳴騶噴梅雪，飛蓋曳松煙。", "聞琴幽谷裏，看弈古岩前。落日低幃帳，歸雲繞管弦。", "叨榮慚北闕，微尚愛東田。寂寞灰心盡，蕭條塵事捐。", "朝思登嶄絕，夜夢弄潺湲。宿懷南澗意，況睹北溪篇。"]'),
('yuding-11','同光祿弟冬日述懷','崔泰之','唐','御定全唐诗','yuding','','[]','吾族白眉良，才華動洛陽。觀光初入仕，應宿始為郎。',264,'御定全唐詩/json/091.json','["吾族白眉良，才華動洛陽。觀光初入仕，應宿始為郎。", "飛螢玩書籍，白鳳吐文章。海卿逾往雅，河尹冠前張。", "擇才綏鄢郢，殊化被江湘。高樓臨廣陌，甲第敞通莊。", "列館邙山下，疏亭洛水傍。昌年賞豐陌，暇日悅林塘。", "衣冠皆秀彥，羅綺盡名倡。隔岸聞歌度，臨池見舞行。", "門庭寒變色，棨戟日生光。窮陰方靉靆，殺氣正蒼茫。", "感時興盛作，晚歲共多傷。積德韋丞相，通神張子房。", "吟草遍簪紱，逸韻合宮商。功名守留省，濫跡在文昌。", "家園遙可見，台寺近相望。無庸乘侍謁，有暇共翱翔。", "棣華依雁序，竹葉拂鸞觴。水坐憐秋月，山行弄晚芳。", "恩華慚服冕，友愛勖垂堂。無由報天德，相顧詠時康。"]'),
('yuding-12','奉和聖制送張尚書巡邊','崔泰之','唐','御定全唐诗','yuding','','[]','南庭胡運盡，北斗將星飛。旗鼓臨沙漠，旌旄出洛畿。',120,'御定全唐詩/json/091.json','["南庭胡運盡，北斗將星飛。旗鼓臨沙漠，旌旄出洛畿。", "關山繞玉塞，烽火映金微。屢獻帷謀策，頻承廟勝威。", "躞蹀臨河騎，逶迤度隴旗。地脈平千古，天聲振九圍。", "車馬生邊氣，戈鋋駐落暉。夏近蓬猶轉，秋深草木腓。", "餞送紆天什，恩榮賜禦衣。佇勒燕然頌，鳴騶計日歸。"]'),
('yuding-13','春夜寓直鳳閣懷群公','魏知古','唐','御定全唐诗','yuding','','[]','拜門傳漏晚，寓直索居時。昔重安仁賦，今稱伯玉詩。',48,'御定全唐詩/json/091.json','["拜門傳漏晚，寓直索居時。昔重安仁賦，今稱伯玉詩。", "鴛池滿不溢，雞樹久逾滋。夙夜懷山甫，清風詠所思。"]'),
('yuding-14','奉和春日途中喜雨應詔','魏知古','唐','御定全唐诗','yuding','','[]','皇輿向洛城，時雨應天行。麗日登岩送，陰雲出野迎。',60,'御定全唐詩/json/091.json','["皇輿向洛城，時雨應天行。麗日登岩送，陰雲出野迎。", "濯枝林杏發，潤葉渚蒲生。絲入綸言喜，花依錦字明。", "微臣忝東觀，載筆佇西成。"]'),
('yuding-15','從獵渭川獻詩','魏知古','唐','御定全唐诗','yuding','','[]','嘗聞夏太康，五弟訓禽荒。我後來冬狩，三驅盛禮張。',120,'御定全唐詩/json/091.json','["嘗聞夏太康，五弟訓禽荒。我後來冬狩，三驅盛禮張。", "順時鷹隼擊，講事武功揚。奔走未及去，翾飛豈暇翔。", "非熊從渭水，瑞翟想陳倉。此欲誠難縱，茲游不可常。", "子雲陳羽獵，僖伯諫漁棠。得失鑒齊楚，仁思念禹湯。", "雍熙亮在宥，亭毒匪多傷。辛甲今為史，虞箴遂孔彰。"]'),
('yuding-16','玄元觀尋李先生不遇','魏知古','唐','御定全唐诗','yuding','','[]','羽客今何在，空尋伊洛間。忽聞歸苦縣，複想入函關。',48,'御定全唐詩/json/091.json','["羽客今何在，空尋伊洛間。忽聞歸苦縣，複想入函關。", "未作千年別，猶應七日還。神仙不可見，寂寞返蓬山。"]'),
('yuding-0','招諭有懷贈同行人','李乂','唐','御定全唐诗','yuding','','[]','遠遊冒艱阻，深入勞存諭。春去辭國門，秋還在邊戍。',120,'御定全唐詩/json/092.json','["遠遊冒艱阻，深入勞存諭。春去辭國門，秋還在邊戍。", "軒車行未返，節序催難駐。陌上悲轉蓬，園中想芳樹。", "蜀山自紛糾，岷水恒奔注。臨泛多苦懷，登攀寡歡趣。", "永夕飛淫雨，崇朝蒸毒霧。不求綏嶺桃，寧美邛鄉蒟。", "白浪行欲靜，驄馬何嘗驅。願接軺旆塵，聯翩東北騖。"]'),
('yuding-1','春日侍宴芙蓉園應制','李乂','唐','御定全唐诗','yuding','','[]','水殿臨丹籞，山樓繞翠微。昔遊人托乘，今幸帝垂衣。',48,'御定全唐詩/json/092.json','["水殿臨丹籞，山樓繞翠微。昔遊人托乘，今幸帝垂衣。", "澗筱緣峰合，岩花逗浦飛。朝來江曲地，無處不光輝。"]'),
('yuding-2','奉和登驪山高頂寓目應制','李乂','唐','御定全唐诗','yuding','','[]','崖巘萬尋懸，居高敞禦筵。行戈疑駐日，步輦若登天。',48,'御定全唐詩/json/092.json','["崖巘萬尋懸，居高敞禦筵。行戈疑駐日，步輦若登天。", "城闕霧中近，關河雲外連。謬陪登岱駕，欣奉濟汾篇。"]'),
('yuding-3','奉和七夕兩儀殿會宴應制','李乂','唐','御定全唐诗','yuding','','[]','桂宮明月夜，蘭殿起秋風。雲漢彌年阻，星筵此夕同。',48,'御定全唐詩/json/092.json','["桂宮明月夜，蘭殿起秋風。雲漢彌年阻，星筵此夕同。", "倏來疑有處，旋去已成空。睿作鈞天響，魂飛在夢中。"]'),
('yuding-4','奉和春日游苑喜雨應詔','李乂','唐','御定全唐诗','yuding','','[]','仙蹕九成台，香筵萬壽杯。一旬初降雨，二月早聞雷。',48,'御定全唐詩/json/092.json','["仙蹕九成台，香筵萬壽杯。一旬初降雨，二月早聞雷。", "葉向朝霽密，花含宿潤開。幸承天澤豫，無使日光催。"]'),
('yuding-5','奉和人日清暉閣宴群臣遇雪應制','李乂','唐','御定全唐诗','yuding','','[]','上日登樓賞，中天禦輦飛。後庭聯舞唱，前席仰恩輝。',48,'御定全唐詩/json/092.json','["上日登樓賞，中天禦輦飛。後庭聯舞唱，前席仰恩輝。", "睿作風雲起，農祥雨雪霏。幸陪人勝節，長願奉垂衣。"]'),
('yuding-6','陪幸臨渭亭遇雪應制','李乂','唐','御定全唐诗','yuding','','[]','青陽禦紫微，白雪下彤闈。浹壤流天霈，綿區灑帝輝。',48,'御定全唐詩/json/092.json','["青陽禦紫微，白雪下彤闈。浹壤流天霈，綿區灑帝輝。", "水如銀度燭，雲似玉披衣。為得因風起，還來就日飛。"]'),
('yuding-7','奉和九日侍宴應制得濃字','李乂','唐','御定全唐诗','yuding','','[]','望幸紆千乘，登高自九重。台疑臨戲馬，殿似接疏龍。',48,'御定全唐詩/json/092.json','["望幸紆千乘，登高自九重。台疑臨戲馬，殿似接疏龍。", "捧篋萸香遍，稱觴菊氣濃。更看仙鶴舞，來此慶時雍。"]'),
('yuding-8','送沙門弘景道俊玄奘還荊州應制','李乂','唐','御定全唐诗','yuding','','[]','初日承歸旨，秋風起贈言。漢珠留道味，江璧返真源。',48,'御定全唐詩/json/092.json','["初日承歸旨，秋風起贈言。漢珠留道味，江璧返真源。", "地出南關遠，天回北斗尊。寧知一柱觀，卻啟四禪門。"]'),
('yuding-9','奉和九月九日登慈恩寺浮圖應制','李乂','唐','御定全唐诗','yuding','','[]','湧塔臨玄地，高層瞰紫微。鳴鑾陪帝出，攀橑翊天飛。',48,'御定全唐詩/json/092.json','["湧塔臨玄地，高層瞰紫微。鳴鑾陪帝出，攀橑翊天飛。", "慶洽重陽壽，文含列象輝。小臣叨載筆，欣此頌巍巍。"]'),
('yuding-10','閏九月九日幸總持寺登浮圖應制','李乂','唐','御定全唐诗','yuding','','[]','清蹕幸禪樓，前驅曆禦溝。還疑九日豫，更想六年遊。',48,'御定全唐詩/json/092.json','["清蹕幸禪樓，前驅曆禦溝。還疑九日豫，更想六年遊。", "聖藻輝纓絡，仙花綴冕旒。所欣延億載，甯祗慶重秋。"]'),
('yuding-11','侍宴長寧公主東莊應制','李乂','唐','御定全唐诗','yuding','','[]','紫禁乘宵動，青門訪水嬉。貴游鱣序集，仙女鳳樓期。',48,'御定全唐詩/json/092.json','["紫禁乘宵動，青門訪水嬉。貴游鱣序集，仙女鳳樓期。", "合宴簪紳滿，承恩雨露滋。北辰還捧日，東館幸逢時。"]'),
('yuding-12','幸白鹿觀應制','李乂','唐','御定全唐诗','yuding','','[]','制蹕乘驪阜，回輿指鳳京。南山四皓謁，西嶽兩童迎。',48,'御定全唐詩/json/092.json','["制蹕乘驪阜，回輿指鳳京。南山四皓謁，西嶽兩童迎。", "雲幄臨懸圃，霞杯薦赤城。神明近茲地，何必往蓬瀛。"]'),
('yuding-13','次蘇州','李乂','唐','御定全唐诗','yuding','','[]','洛渚問吳潮，吳門想洛橋。夕煙楊柳岸，春水木蘭橈。',48,'御定全唐詩/json/092.json','["洛渚問吳潮，吳門想洛橋。夕煙楊柳岸，春水木蘭橈。", "城邑南樓近，星辰北斗遙。無因生羽翼，輕舉托還飆。"]'),
('yuding-14','寄胡皓時在南中','李乂','唐','御定全唐诗','yuding','','[]','徭役苦流滯，風波限溯洄。江流通地骨，山道繞天臺。',48,'御定全唐詩/json/092.json','["徭役苦流滯，風波限溯洄。江流通地骨，山道繞天臺。", "有鳥圖南去，無人見北來。閉門滄海曲，雲霧待君開。"]'),
('yuding-15','餞許州宋司馬赴任','李乂','唐','御定全唐诗','yuding','','[]','展驥旌時傑，談雞美代賢。暫離仙掖務，追送近郊筵。',48,'御定全唐詩/json/092.json','["展驥旌時傑，談雞美代賢。暫離仙掖務，追送近郊筵。", "地慘金商節，人康璧假田。從來昆友事，咸以佩刀傳。"]'),
('yuding-16','餞唐州高使君赴任','李乂','唐','御定全唐诗','yuding','','[]','淮源之水清，可以濯君纓。彼美稱才傑，親人佇政聲。',48,'御定全唐詩/json/092.json','["淮源之水清，可以濯君纓。彼美稱才傑，親人佇政聲。", "歲寒疇曩意，春晚別離情。終歎臨岐遠，行看擁傳榮。"]'),
('yuding-17','哭僕射鄂公楊再思','李乂','唐','御定全唐诗','yuding','','[]','端揆凝邦績，臺階闡國猷。方崇大廈棟，忽逝巨川舟。',48,'御定全唐詩/json/092.json','["端揆凝邦績，臺階闡國猷。方崇大廈棟，忽逝巨川舟。", "白日銘安在，清風頌獨留。死生恩命畢，零落掩山丘。"]'),
('yuding-18','故趙王屬贈黃門侍郎上官公挽詞','李乂','唐','御定全唐诗','yuding','','[]','暮歸泉壤隔，朝發城池戀。漢畤結愁陰，秦陵下悲霰。',48,'御定全唐詩/json/092.json','["暮歸泉壤隔，朝發城池戀。漢畤結愁陰，秦陵下悲霰。", "駸駸百駟馳，憫憫群龍餞。石馬徒自施，玉人終不見。"]'),
('yuding-19','淮陽公主挽歌','李乂','唐','御定全唐诗','yuding','','[]','玉顏生漢渚，湯沐榮天女。金縷化邙塵，哀榮感路人。',48,'御定全唐詩/json/092.json','["玉顏生漢渚，湯沐榮天女。金縷化邙塵，哀榮感路人。", "鳳凰曾作伴，螻蟻忽為親。疇日成蹊處，穠華不復春。"]'),
('yuding-20','故西台侍郎上官公挽歌','李乂','唐','御定全唐诗','yuding','','[]','宇內文儒重，朝端禮命優。立言多啟沃，論道盛謀猷。',48,'御定全唐詩/json/092.json','["宇內文儒重，朝端禮命優。立言多啟沃，論道盛謀猷。", "顧日琴安在，沖星劍不留。徒懷東武襚，更掩北原丘。"]'),
('yuding-21','高安公主挽歌二首','李乂','唐','御定全唐诗','yuding','','[]','湯沐三千賦，樓臺十二重。銀爐稱貴幸，玉輦盛過逢。',96,'御定全唐詩/json/092.json','["湯沐三千賦，樓臺十二重。銀爐稱貴幸，玉輦盛過逢。", "嬪則留中饋，娥輝沒下舂。平陽百歲後，歌舞為誰容。", "賓衛儼相依，橫門啟曙扉。靈陰蟾兔缺，仙影鳳凰飛。", "一水秋難渡，三泉夜不歸。況臨青女節，瑤草更前哀。"]'),
('yuding-22','奉和初春幸太平公主南莊應制','李乂','唐','御定全唐诗','yuding','','[]','平陽館外有仙家，沁水園中好物華。地出東郊回日禦，',40,'御定全唐詩/json/092.json','["平陽館外有仙家，沁水園中好物華。地出東郊回日禦，", "已慶時來千億壽，還言日暮九重賒。"]'),
('yuding-23','興慶池侍宴應制','李乂','唐','御定全唐诗','yuding','','[]','神池氾濫水盈科，仙蹕紆徐步輦過。縱棹洄沿萍溜合，',40,'御定全唐詩/json/092.json','["神池氾濫水盈科，仙蹕紆徐步輦過。縱棹洄沿萍溜合，", "寄語乘槎溟海客，回頭來此問天河。"]'),
('yuding-24','侍宴安樂公主山莊應制','李乂','唐','御定全唐诗','yuding','','[]','金輿玉輦背三條，水閣山樓望九霄。野外初迷七聖道，',40,'御定全唐詩/json/092.json','["金輿玉輦背三條，水閣山樓望九霄。野外初迷七聖道，", "回晚平陽歌舞合，前溪更轉木蘭橈。"]'),
('yuding-25','奉和春日幸望春宮應制','李乂','唐','御定全唐诗','yuding','','[]','東城結宇敞千尋，北闕回輿具四臨。麗日祥煙承罕畢，',40,'御定全唐詩/json/092.json','["東城結宇敞千尋，北闕回輿具四臨。麗日祥煙承罕畢，", "謬接鵷鴻陪賞樂，還欣魚鳥遂飛沉。"]'),
('yuding-26','人日重宴大明宮恩賜彩縷人勝應制','李乂','唐','御定全唐诗','yuding','','[]','詰旦行春上苑中，憑高卻下大明宮。千年執象寰瀛泰，',40,'御定全唐詩/json/092.json','["詰旦行春上苑中，憑高卻下大明宮。千年執象寰瀛泰，", "此時朝野歡無算，此歲雲天樂未窮。"]'),
('yuding-27','享龍池樂第八章','李乂','唐','御定全唐诗','yuding','','[]','星分邑裏四人居，水洊源流萬頃餘。魏國君王稱象處，',40,'御定全唐詩/json/092.json','["星分邑裏四人居，水洊源流萬頃餘。魏國君王稱象處，", "自有神靈滋液地，年年雲物史官書。"]'),
('yuding-28','奉和幸禮部尚書竇希玠宅應制','李乂','唐','御定全唐诗','yuding','','[]','家住千門側，亭臨二水傍。貴遊開北地，宸眷幸西鄉。',72,'御定全唐詩/json/092.json','["家住千門側，亭臨二水傍。貴遊開北地，宸眷幸西鄉。", "曳履迎中穀，鳴絲出後堂。浦疑觀萬象，峰似駐三光。", "草向瓊筵樂，花承繡扆香。聖情思舊重，留飲賦雕章。"]'),
('yuding-29','奉和晦日幸昆明池應制','李乂','唐','御定全唐诗','yuding','','[]','玉輅尋春賞，金堤重晦遊。川通黑水浸，地派紫泉流。',72,'御定全唐詩/json/092.json','["玉輅尋春賞，金堤重晦遊。川通黑水浸，地派紫泉流。", "晃朗扶桑出，綿聯杞樹周。烏疑填海處，人似隔河秋。", "劫盡灰猶識，年移石故留。汀洲歸棹晚，簫鼓雜汾謳。"]'),
('yuding-30','奉和幸長安故城未央宮應制','李乂','唐','御定全唐诗','yuding','','[]','鳳輦乘春陌，龍山訪故台。北宮才盡處，南斗獨昭回。',72,'御定全唐詩/json/092.json','["鳳輦乘春陌，龍山訪故台。北宮才盡處，南斗獨昭回。", "肆覽飛宸劄，稱觴引禦杯。已觀蓬海變，誰厭柏梁災。", "代挹孫通禮，朝稱賈誼才。忝儕文雅地，先後各時來。"]'),
('yuding-31','陪幸韋嗣立山莊應制','李乂','唐','御定全唐诗','yuding','','[]','樞掖調梅暇，林園種槿初。入朝榮劍履，退食偶琴書。',96,'御定全唐詩/json/092.json','["樞掖調梅暇，林園種槿初。入朝榮劍履，退食偶琴書。", "地隱東岩室，天回北斗車。旌門臨窈窕，輦道屬扶疏。", "雲罕明丹穀，霜笳徹紫虛。水疑投石處，溪似釣璜餘。", "帝澤頒卮酒，人歡頌裏閭。一承黃竹詠，長奉白茆居。"]'),
('yuding-32','奉和幸望春宮送朔方軍大總管張仁亶','李乂','唐','御定全唐诗','yuding','','[]','邊郊草具腓，河塞有兵機。上宰調梅寄，元戎細柳威。',72,'御定全唐詩/json/092.json','["邊郊草具腓，河塞有兵機。上宰調梅寄，元戎細柳威。", "武貔東道出，鷹隼北庭飛。玉匣謀中野，金輿下太微。", "投醪銜餞酌，緝袞事征衣。勿謂公孫老，行聞奏凱歸。"]'),
('yuding-33','奉和幸三會寺應制','李乂','唐','御定全唐诗','yuding','','[]','睿德總無邊，神皋擇勝緣。二儀齊法駕，三會禮香筵。',72,'御定全唐詩/json/092.json','["睿德總無邊，神皋擇勝緣。二儀齊法駕，三會禮香筵。", "漢闕中黃近，秦山太白連。台疑觀鳥日，池似刻鯨年。", "滿月臨真境，秋風入禦弦。小臣叨下列，持管謬窺天。"]'),
('yuding-34','奉和幸大薦福寺','李乂','唐','御定全唐诗','yuding','','[]','象設隆新宇，龍潛想舊居。碧樓披玉額，丹仗導金輿。',72,'御定全唐詩/json/092.json','["象設隆新宇，龍潛想舊居。碧樓披玉額，丹仗導金輿。", "代日興光近，周星掩曜初。空歌清沛築，梵樂奏胡書。", "帝造環三界，天文賁六虛。康哉孝理日，崇德在真如。"]'),
('yuding-35','夏日都門送司馬員外逸客孫員外佺北征','李乂','唐','御定全唐诗','yuding','','[]','日逐滋南寇，天威撫北垂。析珪行仗節，持印且分麾。',72,'御定全唐詩/json/092.json','["日逐滋南寇，天威撫北垂。析珪行仗節，持印且分麾。", "羽檄雙鳧去，兵車駟馬馳。虎旗懸氣色，龍劍抱雄雌。", "候月期戡翦，經時念別離。坐聞關隴外，無複引弓兒。"]'),
('yuding-36','元日恩賜柏葉應制','李乂','唐','御定全唐诗','yuding','','[]','勁節淩冬勁，芳心待歲芳。能令人益壽，非止麝含香。',24,'御定全唐詩/json/092.json','["勁節淩冬勁，芳心待歲芳。能令人益壽，非止麝含香。"]'),
('yuding-37','侍宴桃花園詠桃花應制','李乂','唐','御定全唐诗','yuding','','[]','綺萼成蹊遍籞芳，紅英撲地滿筵香。',32,'御定全唐詩/json/092.json','["綺萼成蹊遍籞芳，紅英撲地滿筵香。", "莫將秋宴傳王母，來比春華奉聖皇。"]'),
('yuding-38','奉和三日祓禊渭濱','李乂','唐','御定全唐诗','yuding','','[]','上林花鳥暮春時，上巳陪遊樂在茲。',32,'御定全唐詩/json/092.json','["上林花鳥暮春時，上巳陪遊樂在茲。", "此日欣逢臨渭賞，昔年空道濟汾詞。"]'),
('yuding-39','奉和幸韋嗣立山莊侍宴應制','李乂','唐','御定全唐诗','yuding','','[]','曲榭回廊繞澗幽，飛泉噴下溢池流。',32,'御定全唐詩/json/092.json','["曲榭回廊繞澗幽，飛泉噴下溢池流。", "只應感發明王夢，遂得邀迎聖帝遊。"]'),
('yuding-40','侍宴安樂公主新宅應制','李乂','唐','御定全唐诗','yuding','','[]','牽牛南渡象昭回，學鳳樓成帝女來。',32,'御定全唐詩/json/092.json','["牽牛南渡象昭回，學鳳樓成帝女來。", "平旦鵷鸞歌舞席，方宵鸚鵡獻酬杯。"]'),
('yuding-41','餞唐永昌','李乂','唐','御定全唐诗','yuding','','[]','田郎才貌出咸京，潘子文華向洛城。',32,'御定全唐詩/json/092.json','["田郎才貌出咸京，潘子文華向洛城。", "願以深心留善政，當令強項謝高名。"]'),
('yuding-0','九日幸臨渭亭登高應制得開字','盧藏用','唐','御定全唐诗','yuding','','[]','上月重陽滿，中天萬乘來。萸依佩里發，菊向酒邊開。',48,'御定全唐詩/json/093.json','["上月重陽滿，中天萬乘來。萸依佩里發，菊向酒邊開。", "聖澤煙雲動，宸文象緯回。小臣無以答，願奉億千杯。"]'),
('yuding-1','奉和九月九日登慈恩寺浮圖應制','盧藏用','唐','御定全唐诗','yuding','','[]','化塔龍山起，中天鳳輦迂。彩旒牽畫刹，雜佩冒香萸。',48,'御定全唐詩/json/093.json','["化塔龍山起，中天鳳輦迂。彩旒牽畫刹，雜佩冒香萸。", "寶葉擎千座，金英漬百盂。秋雲飄聖藻，霄極捧連珠。"]'),
('yuding-2','宋主簿鳴皋夢趙六予未及報而陳子雲亡今追為此詩荅宋兼貽平昔遊舊','盧藏用','唐','御定全唐诗','yuding','','[]','暮川罕停波，朝雲無留色。故人琴與詩，可存不可識。',384,'御定全唐詩/json/093.json','["暮川罕停波，朝雲無留色。故人琴與詩，可存不可識。", "識心尚可親，琴詩非故人。鳴皋初夢趙，蜀國已悲陳。", "感化傷淪滅，魂交惜未申。冥期失幽報，茲理複今晨。", "前嗟成後泣，已矣將何及。舊感與新悲，虛懷酬昔時。", "趙侯鴻寶氣，獨負青雲姿。群有含妙識，眾象懸清機。", "雄談盡物變，精義解人頤。在陰既獨善，幽躍自為疑。", "踠彼千里足，傷哉一尉欺。陳生富清理，卓犖兼文史。", "思縟巫山雲，調逸岷江水。鏗鏘哀忠義，感激懷知己。", "負劍登薊門，孤游入燕市。浩歌去京國，歸守西山趾。", "幽居探元化，立言見千祀。埋沒經濟情，良圖竟雲已。", "坐憶平生遊，十載懷嵩丘。題書滿古壁，采藥遍岩幽。", "子微化金鼎，仙笙不可求。榮哉宋與陸，名宦美中州。", "存亡一暌阻，岐路方悠悠。自予事山海，及茲人世改。", "傳聞當世榮，皆入古人名。無複平原賦，空餘鄰笛聲。", "泣對西州使，悲訪北邙塋。新墳蔓宿草，舊闕毀殘銘。", "為君成此曲，因言寄友生。默語無窮事，凋傷共此情。"]'),
('yuding-3','餞唐州高使君赴任','盧藏用','唐','御定全唐诗','yuding','','[]','餞酒臨豐樹，褰帷出魯陽。蕙蘭春已晚，桐柏路猶長。',48,'御定全唐詩/json/093.json','["餞酒臨豐樹，褰帷出魯陽。蕙蘭春已晚，桐柏路猶長。", "祖逖方城鎮，安期外氏鄉。從來二千石，天子命唯良。"]'),
('yuding-4','餞許州宋司馬赴任','盧藏用','唐','御定全唐诗','yuding','','[]','國為休征選，輿因仲舉題。山川襄野隔，朋酒灞亭暌。',48,'御定全唐詩/json/093.json','["國為休征選，輿因仲舉題。山川襄野隔，朋酒灞亭暌。", "零雨征軒騖，秋風別驥嘶。驪歌一曲罷，愁望正淒淒。"]'),
('yuding-5','奉和立春遊苑迎春應制','盧藏用','唐','御定全唐诗','yuding','','[]','天游龍輦駐城闉，上苑遲光晚更新。瑤台半入黃山路，',40,'御定全唐詩/json/093.json','["天游龍輦駐城闉，上苑遲光晚更新。瑤台半入黃山路，", "幸預柏台稱獻壽，願陪千畝及農晨。"]'),
('yuding-6','奉和幸安樂公主山莊應制','盧藏用','唐','御定全唐诗','yuding','','[]','皇女瓊台天漢潯，星橋月宇構山林。飛蘿半拂銀題影，',40,'御定全唐詩/json/093.json','["皇女瓊台天漢潯，星橋月宇構山林。飛蘿半拂銀題影，", "瑤池駐蹕恩方久，璧月無文興轉深。"]'),
('yuding-7','夜宴安樂公主宅','盧藏用','唐','御定全唐诗','yuding','','[]','侯家主第一時新，上席華年不惜春。',32,'御定全唐詩/json/093.json','["侯家主第一時新，上席華年不惜春。", "珠釭綴日那知夜，玉斝流霞畏底晨。"]'),
('yuding-8','九月九日幸臨渭亭登高應制得涘字','岑羲','唐','御定全唐诗','yuding','','[]','重九開科曆，千齡逢聖紀。爰豫矚秦垌，升高臨灞涘。',48,'御定全唐詩/json/093.json','["重九開科曆，千齡逢聖紀。爰豫矚秦垌，升高臨灞涘。", "玉醴浮仙菊，瓊筵薦芳芷。一聞帝舜歌，歡娛良未已。"]'),
('yuding-9','奉和九月九日登慈恩寺浮屠應制','岑羲','唐','御定全唐诗','yuding','','[]','寶台聳天外，玉輦步雲端。日麗重陽景，風搖季月寒。',48,'御定全唐詩/json/093.json','["寶台聳天外，玉輦步雲端。日麗重陽景，風搖季月寒。", "梵堂遙集雁，帝樂近翔鸞。願獻延齡酒，長承湛露歡。"]'),
('yuding-10','餞唐州高使君','岑羲','唐','御定全唐诗','yuding','','[]','蒼茫南塞地，明媚上春時。目極傷千里，懷君不自持。',48,'御定全唐詩/json/093.json','["蒼茫南塞地，明媚上春時。目極傷千里，懷君不自持。", "征車別岐路，斜日下崦嵫。一歎軺軒阻，悠悠即所思。"]'),
('yuding-11','奉和春日幸望春宮應制','岑羲','唐','御定全唐诗','yuding','','[]','和風助律應韶年，清蹕乘高入望仙。花笑鶯歌迎帝輦，',40,'御定全唐詩/json/093.json','["和風助律應韶年，清蹕乘高入望仙。花笑鶯歌迎帝輦，", "一奉恩榮同鎬宴，空知率舞聽熏弦。"]'),
('yuding-12','奉和幸安樂公主山莊應制','岑羲','唐','御定全唐诗','yuding','','[]','銀榜重樓出霧開，金輿步輦向天來。泉聲迥入吹簫曲，',40,'御定全唐詩/json/093.json','["銀榜重樓出霧開，金輿步輦向天來。泉聲迥入吹簫曲，", "誠願北極拱堯日，微臣抃舞詠康哉。"]'),
('yuding-13','夜宴安樂公主新宅','岑羲','唐','御定全唐诗','yuding','','[]','金榜重樓開夜扉，瓊筵愛客未言歸。',32,'御定全唐詩/json/093.json','["金榜重樓開夜扉，瓊筵愛客未言歸。", "銜歡不覺銀河曙，盡醉那知玉漏稀。"]'),
('yuding-14','儀坤廟樂章二首','薛稷','唐','御定全唐诗','yuding','','[]','陽靈配德，陰魄昭升。堯壇鳳下，漢室龍興。伣天作對，',85,'御定全唐詩/json/093.json','["陽靈配德，陰魄昭升。堯壇鳳下，漢室龍興。伣天作對，", "我粢既潔，我醴既澄。陰陰靈廟，光靈若憑。德馨惟饗，", "外睦九族，內光一庭。克生睿哲，祚我休明。欽若徽範，", "實受其福，斯乎億齡。"]'),
('yuding-15','九日幸臨渭亭登高應制得曆字','薛稷','唐','御定全唐诗','yuding','','[]','暮節乘原野，宣遊俯崖壁。秋登華實滿，氣嚴鷹隼擊。',48,'御定全唐詩/json/093.json','["暮節乘原野，宣遊俯崖壁。秋登華實滿，氣嚴鷹隼擊。", "仙菊含霜泛，聖藻臨雲錫。願陪九九辰，長奉千千曆。"]'),
('yuding-16','慈恩寺九日應制','薛稷','唐','御定全唐诗','yuding','','[]','寶宮星宿劫，香塔鬼神功。王游盛塵外，睿覽出區中。',48,'御定全唐詩/json/093.json','["寶宮星宿劫，香塔鬼神功。王游盛塵外，睿覽出區中。", "日宇開初景，天詞掩大風。微臣謝時菊，薄采入芳叢。"]'),
('yuding-17','早春魚亭山','薛稷','唐','御定全唐诗','yuding','','[]','春氣動百草，紛榮時斷續。白雲自高妙，裴回空山曲。',60,'御定全唐詩/json/093.json','["春氣動百草，紛榮時斷續。白雲自高妙，裴回空山曲。", "陽林花已紅，寒澗苔未綠。伊余息人事，蕭寂無營欲。", "客行雖雲遠，玩之聊自足。"]'),
('yuding-18','秋日還京陝西十裏作','薛稷','唐','御定全唐诗','yuding','','[]','驅車越陝郊，北顧臨大河。隔河望鄉邑，秋風水增波。',72,'御定全唐詩/json/093.json','["驅車越陝郊，北顧臨大河。隔河望鄉邑，秋風水增波。", "西登咸陽途，日暮憂思多。傅岩既紆鬱，首山亦嵯峨。", "操築無昔老，采薇有遺歌。客游節回換，人生知幾何。"]'),
('yuding-19','奉和送金城公主適西蕃應制','薛稷','唐','御定全唐诗','yuding','','[]','天道寧殊俗，慈仁乃戢兵。懷荒寄赤子，忍愛鞠蒼生。',48,'御定全唐詩/json/093.json','["天道寧殊俗，慈仁乃戢兵。懷荒寄赤子，忍愛鞠蒼生。", "月下瓊娥去，星分寶婺行。關山馬上曲，相送不勝情。"]'),
('yuding-20','春日登樓野望','薛稷','唐','御定全唐诗','yuding','','[]','憑軒聊一望，春色幾芬菲。野外煙初合，樓前花正飛。',48,'御定全唐詩/json/093.json','["憑軒聊一望，春色幾芬菲。野外煙初合，樓前花正飛。", "嬌鶯弄新響，斜日散餘暉。誰忍孤遊客，言念獨依依。"]'),
('yuding-21','餞許州宋司馬赴任','薛稷','唐','御定全唐诗','yuding','','[]','令弟與名兄，高才振兩京。別序聞鴻雁，離章動鶺鴒。',48,'御定全唐詩/json/093.json','["令弟與名兄，高才振兩京。別序聞鴻雁，離章動鶺鴒。", "遠朋馳翰墨，勝地寫丹青。風月相思夜，勞望潁川星。"]'),
('yuding-22','奉和聖制春日幸望春宮應制','薛稷','唐','御定全唐诗','yuding','','[]','九春風景足林泉，四面雲霞敞禦筵。花鏤黃山繡作苑，',40,'御定全唐詩/json/093.json','["九春風景足林泉，四面雲霞敞禦筵。花鏤黃山繡作苑，", "喜奉仙游歸路遠，直言行樂不言旋。"]'),
('yuding-23','奉和幸安樂公主山莊應制','薛稷','唐','御定全唐诗','yuding','','[]','主家園囿極新規，帝郊遊豫奉天儀。歡宴瑤台鎬京集，',40,'御定全唐詩/json/093.json','["主家園囿極新規，帝郊遊豫奉天儀。歡宴瑤台鎬京集，", "借問今朝八龍駕，何如昔日望仙池。"]'),
('yuding-24','秋朝覽鏡','薛稷','唐','御定全唐诗','yuding','','[]','客心驚落木，夜坐聽秋風。朝日看容鬢，生涯在鏡中。',24,'御定全唐詩/json/093.json','["客心驚落木，夜坐聽秋風。朝日看容鬢，生涯在鏡中。"]'),
('yuding-25','夜宴安樂公主新宅','薛稷','唐','御定全唐诗','yuding','','[]','秦樓宴喜月裴回，妓筵銀燭滿庭開。',32,'御定全唐詩/json/093.json','["秦樓宴喜月裴回，妓筵銀燭滿庭開。", "坐中香氣排花出，扇後歌聲逐酒來。"]'),
('yuding-26','餞唐永昌','薛稷','唐','御定全唐诗','yuding','','[]','河洛風煙壯市朝，送君飛鳧去漸遙。',32,'御定全唐詩/json/093.json','["河洛風煙壯市朝，送君飛鳧去漸遙。", "更思明年桃李月，花紅柳綠宴浮橋。"]'),
('yuding-27','九日幸臨渭亭登高應制得酒字','馬懷素','唐','御定全唐诗','yuding','','[]','睿賞葉通三，宸遊契重九。蘭將葉布席，菊用香浮酒。',48,'御定全唐詩/json/093.json','["睿賞葉通三，宸遊契重九。蘭將葉布席，菊用香浮酒。", "落日下桑榆，秋風歇楊柳。幸齊東戶慶，希薦南山壽。"]'),
('yuding-28','奉和九月九日登慈恩寺浮圖應制','馬懷素','唐','御定全唐诗','yuding','','[]','季月啟重陽，金輿陟寶坊。禦旗橫日道，仙塔儼雲莊。',48,'御定全唐詩/json/093.json','["季月啟重陽，金輿陟寶坊。禦旗橫日道，仙塔儼雲莊。", "帝蹕千官從，幹詞七曜光。顧慚文墨職，無以頌時康。"]'),
('yuding-29','奉和送金城公主適西蕃應制','馬懷素','唐','御定全唐诗','yuding','','[]','帝子今何去，重姻適異方。離情愴宸掖，別路繞關梁。',48,'御定全唐詩/json/093.json','["帝子今何去，重姻適異方。離情愴宸掖，別路繞關梁。", "望絕園中柳，悲纏陌上桑。空餘願黃鶴，東顧憶回翔。"]'),
('yuding-30','餞許州宋司馬赴任','馬懷素','唐','御定全唐诗','yuding','','[]','潁川開郡邑，角宿分躔野。君非仲舉才，誰是題輿者。',48,'御定全唐詩/json/093.json','["潁川開郡邑，角宿分躔野。君非仲舉才，誰是題輿者。", "憫憫琴上鶴，蕭蕭路傍馬。嚴程若可留，別袂希再把。"]'),
('yuding-31','餞唐州高使君赴任','馬懷素','唐','御定全唐诗','yuding','','[]','外牧資賢守，斯人奉帝俞。淮南膺建隼，渭北暫分符。',48,'御定全唐詩/json/093.json','["外牧資賢守，斯人奉帝俞。淮南膺建隼，渭北暫分符。", "坐歎煙波隔，行嗟物候殊。何年升美課，回首北城隅。"]'),
('yuding-32','奉和立春遊苑迎春應制','馬懷素','唐','御定全唐诗','yuding','','[]','玄鑰飛灰出洞房，青郊迎氣肇初陽。仙輿暫下宜春苑，',40,'御定全唐詩/json/093.json','["玄鑰飛灰出洞房，青郊迎氣肇初陽。仙輿暫下宜春苑，", "唯有裁花飾簪鬢，恒隨聖藻狎年光。"]'),
('yuding-33','奉和聖制春日幸望春宮應制','馬懷素','唐','御定全唐诗','yuding','','[]','彩仗雕輿俯碧潯，行春禦氣發皇心。搖風細柳縈馳道，',40,'御定全唐詩/json/093.json','["彩仗雕輿俯碧潯，行春禦氣發皇心。搖風細柳縈馳道，", "謬參西掖沾堯酒，願沐南熏解舜琴。"]'),
('yuding-34','奉和人日宴大明宮恩賜彩縷人勝應制','馬懷素','唐','御定全唐诗','yuding','','[]','日宇千門平旦開，天容萬象列昭回。三陽候節金為勝，',40,'御定全唐詩/json/093.json','["日宇千門平旦開，天容萬象列昭回。三陽候節金為勝，", "何幸得參詞賦職，自憐終乏馬卿才。"]'),
('yuding-35','奉和幸安樂公主山莊應制','馬懷素','唐','御定全唐诗','yuding','','[]','主家台沼勝平陽，帝幸歡娛樂未央。掩映雕窗交極浦，',40,'御定全唐詩/json/093.json','["主家台沼勝平陽，帝幸歡娛樂未央。掩映雕窗交極浦，", "聖酒一沾何以報，唯欣頌德奉時康。"]'),
('yuding-36','興慶池侍宴應制','馬懷素','唐','御定全唐诗','yuding','','[]','積水逶迤繞直城，含虛皎鏡有餘清。圖雲曲榭連緹幕，',40,'御定全唐詩/json/093.json','["積水逶迤繞直城，含虛皎鏡有餘清。圖雲曲榭連緹幕，", "無勞海上尋仙客，即此蓬萊在帝京。"]'),
('yuding-37','夜宴安樂公主宅','馬懷素','唐','御定全唐诗','yuding','','[]','鳳樓窈窕淩三襲，翠幌玲瓏瞰九衢。',32,'御定全唐詩/json/093.json','["鳳樓窈窕淩三襲，翠幌玲瓏瞰九衢。", "複道中宵留宴衎，彌令上客想踟躕。"]'),
('yuding-38','餞唐永昌','馬懷素','唐','御定全唐诗','yuding','','[]','聞君出宰洛陽隅，賓友稱觴餞路衢。',32,'御定全唐詩/json/093.json','["聞君出宰洛陽隅，賓友稱觴餞路衢。", "別後相思在何處，只應關下望仙鳧。"]'),
('yuding-0','明冰篇','富嘉謨','唐','御定全唐诗','yuding','','[]','北陸蒼茫河海凝，南山闌幹晝夜冰，素彩峨峨明月升。',168,'御定全唐詩/json/094.json','["北陸蒼茫河海凝，南山闌幹晝夜冰，素彩峨峨明月升。", "深山窮穀不自見，安知采斫備嘉薦，陰房涸冱掩寒扇。", "陽春二月朝始暾，春光潭沱度千門，明冰時出禦至尊。", "彤庭赫赫九儀備，腰玉煌煌千官事，明冰畢賦周在位。", "憶昨沙漠寒風漲，昆侖長河冰始壯，漫汗崚嶒積亭障。", "嗈嗈鳴雁江上來，禁苑池台冰複開，搖青涵綠映樓臺。", "豳歌七月王風始，鑿冰藏用昭物軌，四時不忒千萬祀。"]'),
('yuding-1','長門怨','吳少微','唐','御定全唐诗','yuding','','[]','月出映層城，孤圓上太清。君王眷愛歇，枕席涼風生。',72,'御定全唐詩/json/094.json','["月出映層城，孤圓上太清。君王眷愛歇，枕席涼風生。", "怨咽不能寢，踟躕步前楹。空階白露色，百草寒蟲鳴。", "念昔金房裏，猶嫌玉座輕。如何嬌所誤，長夜泣恩情。"]'),
('yuding-2','和崔侍禦日用游開化寺閣','吳少微','唐','御定全唐诗','yuding','','[]','左憲多才雄，故人尤鷙鶚。護贈單于使，休軺太原郭。',108,'御定全唐詩/json/094.json','["左憲多才雄，故人尤鷙鶚。護贈單于使，休軺太原郭。", "館次厭煩歊，清懷尋寂寞。西緣十裏餘，北上開化閣。", "初入雲樹間，冥蒙未昭廓。漸出欄榥外，萬里秋景焯。", "歲晏風落山，天寒水歸壑。覽物頌幽景，三乘動玄鑰。", "但敷利解言，永用忘昏著。"]'),
('yuding-3','哭富嘉謨','吳少微','唐','御定全唐诗','yuding','','[]','吾友適不死，於戲社稷臣。直祿非造利，長懷大庇人。',120,'御定全唐詩/json/094.json','["吾友適不死，於戲社稷臣。直祿非造利，長懷大庇人。", "乃通承明籍，遘此敦牂春。藥厲其可畏，皇穹故匪仁。", "疇昔與夫子，孰雲異天倫。同病一相失，茫茫不重陳。", "子之文章在，其殆尼父新。鼓興斡河嶽，貞詞毒鬼神。", "可悲不可朽，車輤沒荒榛。聖主賢為寶，籲茲大國貧。"]'),
('yuding-4','過漢故城','吳少微','唐','御定全唐诗','yuding','','[]','大漢昔未定，強秦猶擅場。中原逐鹿罷，高祖郁龍驤。',288,'御定全唐詩/json/094.json','["大漢昔未定，強秦猶擅場。中原逐鹿罷，高祖郁龍驤。", "經始謀帝座，茲焉壯未央。規模窺棟宇，表裏浚城隍。", "群後崇長樂，中朝增建章。句陳被蘭錡，樂府奏芝房。", "翡翠明珠帳，鴛鴦白玉堂。清晨寶鼎食，閑夜鬱金香。", "天馬來東道，佳人傾北方。何其赫隆盛，自謂寶靈長。", "歷數有時盡，哀平嗟不昌。冰堅成巨猾，火德遂頹綱。", "奧位匪虛校，貪天竟速亡。魂神籲社稷，豹虎鬥岩廊。", "金狄移灞岸，銅盤向洛陽。君王無處所，年代幾荒涼。", "宮闕誰家域，蓁蕪罥我裳。井田唯有草，海水變為桑。", "昔在高門內，於今岐路傍。餘基不可識，古墓列成行。", "狐兔驚魍魎，鴟鳥嚇獝狂。空城寒日晚，平野暮雲黃。", "烈烈樊青棘，蕭蕭吹白楊。千秋並萬歲，空使詠歌傷。"]'),
('yuding-5','古意','吳少微','唐','御定全唐诗','yuding','','[]','洛陽芳樹向春開，洛陽女兒平旦來。流車走馬紛相催，',94,'御定全唐詩/json/094.json','["洛陽芳樹向春開，洛陽女兒平旦來。流車走馬紛相催，", "北林朝日鏡明光，南國微風蘇合香。可憐窈窕女，", "歌終舞罷歡無極，樂往悲來長歎息。陽春白日不少留，", "如何年少忽遲暮，坐見明月與白露。明月白露夜已寒，"]'),
('yuding-6','怨歌行','吳少微','唐','御定全唐诗','yuding','','[]','城南有怨婦，含情傍芳叢。自謂二八時，歌舞入漢宮。',128,'御定全唐詩/json/094.json','["城南有怨婦，含情傍芳叢。自謂二八時，歌舞入漢宮。", "皇恩數流眄，承幸玉堂中。綠柏黃花催夜酒，", "君王厭德不忘新，況群豔冶紛來陳。是時別君不再見，", "綺窗蟲網氛塵色，文軒鶯對桃李顏。天王貴宮不貯老，", "小腰麗女奪人奇，金鞍少年曾不顧。", "歸來誰為夫，請謝西家婦，莫辭先醉解羅襦。"]'),
('yuding-7','隴頭水','員半千','唐','御定全唐诗','yuding','','[]','路出金河道，山連玉塞門。旌旗雲裏度，楊柳曲中喧。',84,'御定全唐詩/json/094.json','["路出金河道，山連玉塞門。旌旗雲裏度，楊柳曲中喧。", "喋血多壯膽，裹革無怯魂。嚴霜斂曙色，大明辭朝暾。", "塵銷營卒壘，沙靜都尉垣。霧卷白山出，風吹黃葉翻。", "將軍獻凱入，萬里絕河源。"]'),
('yuding-8','隴右途中遭非語','員半千','唐','御定全唐诗','yuding','','[]','趙有兩毛遂，魯聞二曾參。慈母猶且惑，況在行路心。',84,'御定全唐詩/json/094.json','["趙有兩毛遂，魯聞二曾參。慈母猶且惑，況在行路心。", "冠冕無醜士，賄賂成知己。名利我所無，清濁誰見理。", "敝服空逢春，緩帶不著身。出遊非懷璧，何憂乎忌人。", "正須自保愛，振衣出世塵。"]'),
('yuding-9','儀坤廟樂章','員半千','唐','御定全唐诗','yuding','','[]','孝享雲畢，維徹有章。雲感玄羽，風淒素商。',40,'御定全唐詩/json/094.json','["孝享雲畢，維徹有章。雲感玄羽，風淒素商。", "瞻望神座，祗戀匪遑。禮終樂闋，肅雍鏘鏘。"]'),
('yuding-10','銅雀妓','王適','唐','御定全唐诗','yuding','','[]','日暮銅雀迥，秋深玉座清。蕭森松柏望，委郁綺羅情。',36,'御定全唐詩/json/094.json','["日暮銅雀迥，秋深玉座清。蕭森松柏望，委郁綺羅情。", "君恩不再得，妾舞為誰輕。"]'),
('yuding-11','蜀中言懷','王適','唐','御定全唐诗','yuding','','[]','獨坐年將暮，常懷志不通。有時須問影，無事卻書空。',96,'御定全唐詩/json/094.json','["獨坐年將暮，常懷志不通。有時須問影，無事卻書空。", "棄置如天外，平生似夢中。蓬心猶是客，華髮欲成翁。", "跡滯魂逾窘，情乖路轉窮。別離同夜月，愁思隔秋風。", "老少悲顏駟，盈虛悟翟公。時來不可問，何用求童蒙。"]'),
('yuding-12','古別離','王適','唐','御定全唐诗','yuding','','[]','昔歲驚楊柳，高樓悲獨守。今年芳樹枝，孤棲怨別離。',88,'御定全唐詩/json/094.json','["昔歲驚楊柳，高樓悲獨守。今年芳樹枝，孤棲怨別離。", "珠簾晝不卷，羅幔曉長垂。苦調琴先覺，愁容鏡獨知。", "頻年雁度無消息，罷卻鴛文何用織。夜還羅帳空有情，", "已能憔悴今如此，更複含情一待君。"]'),
('yuding-13','江上有懷','王適','唐','御定全唐诗','yuding','','[]','湛湛江水見底清，荷花蓮子傍江生。採蓮將欲寄同心，',64,'御定全唐詩/json/094.json','["湛湛江水見底清，荷花蓮子傍江生。採蓮將欲寄同心，", "海上雲盡月蒼蒼，萬里分輝滿洛陽。洛陽閨閣夜何央，", "應憐水宿洞庭子，今夕迢遙天一方。"]'),
('yuding-14','江濱梅','王適','唐','御定全唐诗','yuding','','[]','忽見寒梅樹，開花漢水濱。不知春色早，疑是弄珠人。',24,'御定全唐詩/json/094.json','["忽見寒梅樹，開花漢水濱。不知春色早，疑是弄珠人。"]'),
('yuding-15','臨水亭','閭丘均','唐','御定全唐诗','yuding','','[]','高館基曾山，微冪生花草。傍對野村樹，下臨車馬道。',72,'御定全唐詩/json/094.json','["高館基曾山，微冪生花草。傍對野村樹，下臨車馬道。", "清朗悟心術，幽遐備瞻討。回合峰隱雲，聯綿渚縈島。", "氣似滄洲勝，風為青春好。相及盛年時，無令歎衰老。"]'),
('yuding-16','長門怨','齊浣','唐','御定全唐诗','yuding','','[]','煢煢孤思逼，寂寂長門夜。妾妒亦知非，君恩那不借。',48,'御定全唐詩/json/094.json','["煢煢孤思逼，寂寂長門夜。妾妒亦知非，君恩那不借。", "攜琴就玉階，調悲聲未諧。將心托明月，流影入君懷。"]'),
('yuding-17','長門怨','齊浣','唐','御定全唐诗','yuding','','[]','宮殿沉沉月欲分，昭陽更漏不堪聞。',32,'御定全唐詩/json/094.json','["宮殿沉沉月欲分，昭陽更漏不堪聞。", "珊瑚枕上千行淚，不是思君是恨君。"]'),
('yuding-18','儀坤廟樂章','祝欽明','唐','御定全唐诗','yuding','','[]','閟宮實實，清廟微微。降格無象，馨香有依。',40,'御定全唐詩/json/094.json','["閟宮實實，清廟微微。降格無象，馨香有依。", "式昭纂慶，方融嗣徽。明禋是享，神保聿歸。"]'),
('yuding-19','儀坤廟樂章','劉知幾','唐','御定全唐诗','yuding','','[]','妙算申帷幄，神謀出廟廷。兩階文物備，七德武功成。',48,'御定全唐詩/json/094.json','["妙算申帷幄，神謀出廟廷。兩階文物備，七德武功成。", "校獵長楊苑，屯軍細柳營。將軍獻凱入，歌舞溢重城。"]'),
('yuding-20','儀坤廟樂章','胡雄','唐','御定全唐诗','yuding','','[]','送文迎武遞參差，一始一終光聖儀。',32,'御定全唐詩/json/094.json','["送文迎武遞參差，一始一終光聖儀。", "四海生人歌有慶，千齡孝享肅無虧。"]'),
('yuding-21','儀坤廟樂章','張齊賢','唐','御定全唐诗','yuding','','[]','祼圭既濯，郁鬯既陳。畫幕雲舉，黃流玉醇。',40,'御定全唐詩/json/094.json','["祼圭既濯，郁鬯既陳。畫幕雲舉，黃流玉醇。", "儀充獻酌，禮盛眾禋。地察惟孝，愉焉饗親。"]'),
('yuding-22','儀坤廟樂章','鄭善玉','唐','御定全唐诗','yuding','','[]','酌鬱既灌，取蕭方爇，籩豆靜器，簠簋芬飶。',40,'御定全唐詩/json/094.json','["酌鬱既灌，取蕭方爇，籩豆靜器，簠簋芬飶。", "魚臘薦美，牲牷表絜。是戢是將，載迎載列。"]'),
('yuding-23','儀坤廟樂章','丘悅','唐','御定全唐诗','yuding','','[]','孝哉我後，沖乎乃聖。道映重華，德輝文命。慕深視篋，',25,'御定全唐詩/json/094.json','["孝哉我後，沖乎乃聖。道映重華，德輝文命。慕深視篋，"]'),
('yuding-0','芳樹','沈佺期','唐','御定全唐诗','yuding','','[]','何地早芳菲，宛在長門殿。夭桃色若綬，穠李光如練。',48,'御定全唐詩/json/095.json','["何地早芳菲，宛在長門殿。夭桃色若綬，穠李光如練。", "啼鳥弄花疏，遊蜂飲香遍。歎息春風起，飄零君不見。"]'),
('yuding-1','長安道','沈佺期','唐','御定全唐诗','yuding','','[]','秦地平如掌，層城入雲漢。樓閣九衢春，車馬千門旦。',48,'御定全唐詩/json/095.json','["秦地平如掌，層城入雲漢。樓閣九衢春，車馬千門旦。", "綠槐開複合，紅塵聚還散。日晚鬥雞還，經過狹斜看。"]'),
('yuding-2','有所思','沈佺期','唐','御定全唐诗','yuding','','[]','君子事行役，再空芳歲期。美人曠延佇，萬里浮雲思。',48,'御定全唐詩/json/095.json','["君子事行役，再空芳歲期。美人曠延佇，萬里浮雲思。", "園槿綻紅豔，郊桑柔綠滋。坐看長夏晚，秋月照羅幃。"]'),
('yuding-3','臨高臺','沈佺期','唐','御定全唐诗','yuding','','[]','高臺臨廣陌，車馬紛相續。回首思舊鄉，雲山亂心曲。',48,'御定全唐詩/json/095.json','["高臺臨廣陌，車馬紛相續。回首思舊鄉，雲山亂心曲。", "遠望河流緩，周看原野綠。向夕林鳥還，憂來飛景促。"]'),
('yuding-4','鳳笙曲','沈佺期','唐','御定全唐诗','yuding','','[]','憶昔王子晉，鳳笙遊雲空。揮手弄白日，安能戀青宮。',48,'御定全唐詩/json/095.json','["憶昔王子晉，鳳笙遊雲空。揮手弄白日，安能戀青宮。", "豈無嬋娟子，結念羅幃中。憐壽不貴色，身世兩無窮。"]'),
('yuding-5','擬古別離','沈佺期','唐','御定全唐诗','yuding','','[]','白水東悠悠，中有西行舟。舟行有返棹，水去無還流。',96,'御定全唐詩/json/095.json','["白水東悠悠，中有西行舟。舟行有返棹，水去無還流。", "奈何生別者，戚戚懷遠遊。遠遊誰當惜，所悲會難收。", "自君闃芳躧，青陽四五遒。皓月掩蘭室，光風虛蕙樓。", "相思無明晦，長歎累冬秋。離居久遲暮，高駕何淹留。"]'),
('yuding-6','辛醜歲十月上幸長安時扈從出西嶽作','沈佺期','唐','御定全唐诗','yuding','','[]','西鎮何穹崇，壯哉信靈造。諸嶺皆峻秀，中峰特美好。',156,'御定全唐詩/json/095.json','["西鎮何穹崇，壯哉信靈造。諸嶺皆峻秀，中峰特美好。", "傍見巨掌存，勢如石東倒。頗聞首陽去，開坼此河道。", "磅礴壓洪源，巍峨壯清昊。雲泉紛亂瀑，天磴屹橫抱。", "子先呼其巔，宮女世不老。下有府君廟，曆載傳灑掃。", "皇明應天遊，十月戒豐鎬。微末忝閑從，兼得事蘋藻。", "宿心愛茲山，意欲拾靈草。陰壑已永閟，雲竇絕探討。", "芳月期來過，回策思方浩。"]'),
('yuding-7','和杜麟台元志春情','沈佺期','唐','御定全唐诗','yuding','','[]','嘉樹滿中園，氛氳羅秀色。不見仙山雲，倚琴空太息。',60,'御定全唐詩/json/095.json','["嘉樹滿中園，氛氳羅秀色。不見仙山雲，倚琴空太息。", "沉思若在夢，緘怨似無憶。青春坐南移，白日忽西匿。", "蛾眉返清鏡，閨中不相識。"]'),
('yuding-8','別侍禦嚴凝','沈佺期','唐','御定全唐诗','yuding','','[]','七澤雲夢林，三湘洞庭水。自古傳剽俗，有時逋惡子。',48,'御定全唐詩/json/095.json','["七澤雲夢林，三湘洞庭水。自古傳剽俗，有時逋惡子。", "令君出使車，行邁方靡靡。靜言芟枳棘，慎勿傷蘭芷。"]'),
('yuding-9','送喬隨州侃','沈佺期','唐','御定全唐诗','yuding','','[]','結交三十載，同遊一萬里。情為契闊生，心由別離死。',48,'御定全唐詩/json/095.json','["結交三十載，同遊一萬里。情為契闊生，心由別離死。", "拜恩前後人，從宦差池起。今爾歸漢東，明珠報知己。"]'),
('yuding-10','送友人任括州','沈佺期','唐','御定全唐诗','yuding','','[]','青春浩無際，白日乃遲遲。胡為賞心客，歎邁此芳時。',72,'御定全唐詩/json/095.json','["青春浩無際，白日乃遲遲。胡為賞心客，歎邁此芳時。", "甌粵迫茲守，京闕從此辭。茫茫理雲帆，草草念行期。", "紛吾結遠佩，帳餞出河湄。太息東流水，盈觴難再持。"]'),
('yuding-11','餞遠','沈佺期','唐','御定全唐诗','yuding','','[]','任子徇遐祿，結友開舊襟。撰酌輟行歎，指途勤遠心。',48,'御定全唐詩/json/095.json','["任子徇遐祿，結友開舊襟。撰酌輟行歎，指途勤遠心。", "秋皛澄回壑，霽色肅明林。曖然青軒暮，浩思非所任。"]'),
('yuding-12','同工部李侍郎適訪司馬子微','沈佺期','唐','御定全唐诗','yuding','','[]','紫微降天仙，丹地投雲藻。上言華頂事，中問長生道。',192,'御定全唐詩/json/095.json','["紫微降天仙，丹地投雲藻。上言華頂事，中問長生道。", "華頂居最高，大壑朝陽早。長生術何妙，童顏後天老。", "清晨朝鳳京，靜夜思鴻寶。憑崖飲蕙氣，過澗摘靈草。", "人非塚已荒，海變田應燥。昔嘗遊此郡，三霜弄溟島。", "緒言霞上開，機事塵外掃。頃來迫世務，清曠未雲保。", "崎嶇待漏恩，怵惕司言造。軒皇重齋拜，漢武愛祈禱。", "順風懷崆峒，承露在豐鎬。泠然委輕馭，複得散幽抱。", "柱下留伯陽，儲闈登四皓。聞有參同契，何時一探討。"]'),
('yuding-13','自昌樂郡溯流至白石嶺下行入郴州','沈佺期','唐','御定全唐诗','yuding','','[]','茲山界夷夏，天險橫寥廓。太史漏登探，文命限開鑿。',193,'御定全唐詩/json/095.json','["茲山界夷夏，天險橫寥廓。太史漏登探，文命限開鑿。", "北流自南瀉，群峰回眾壑。馳波如電騰，激石似雷落。", "崖留盤古樹，澗蓄神農藥。乳竇何淋漓，苔蘚更彩錯。", "娟娟潭裏虹，渺渺灘邊鶴。歲杪應流火，天高雲物薄。", "金風吹綠梢，玉露洗紅籜。溯舟始興廨，登踐桂陽郭。", "匍匐緣修阪，穹窿曳長dh。礙林阻往來，遇堰每前卻。", "救艱不遑飯，畢昏無暇泊。濯溪寧足懼，磴道誰雲惡。", "我行山水間，湍險皆不若。安能獨見聞，書此貽京洛。"]'),
('yuding-14','過蜀龍門','沈佺期','唐','御定全唐诗','yuding','','[]','龍門非禹鑿，詭怪乃天功。西南出巴峽，不與眾山同。',108,'御定全唐詩/json/095.json','["龍門非禹鑿，詭怪乃天功。西南出巴峽，不與眾山同。", "長竇亙五裏，宛轉複嵌空。伏湍喣潛石，瀑水生輪風。", "流水無晝夜，噴薄龍門中。潭河勢不測，藻葩垂彩虹。", "我行當季月，煙景共舂融。江關勤亦甚，巘崿意難窮。", "勢將息機事，煉藥此山東。"]'),
('yuding-15','入衛作','沈佺期','唐','御定全唐诗','yuding','','[]','淇上風日好，紛紛沿岸多。綠芳幸未歇，氾濫此明波。',48,'御定全唐詩/json/095.json','["淇上風日好，紛紛沿岸多。綠芳幸未歇，氾濫此明波。", "采蘩憶幽吹，理棹想荊歌。郁然懷君子，浩曠將如何。"]'),
('yuding-16','夜泊越州逢北使','沈佺期','唐','御定全唐诗','yuding','','[]','天地降雷雨，放逐還國都。重以風潮事，年月戒回艫。',122,'御定全唐詩/json/095.json','["天地降雷雨，放逐還國都。重以風潮事，年月戒回艫。", "容顏荒外老，心想域中愚。憩泊在茲夜，炎雲逐鬥樞。", "k3k4縈海若，霹靂耿天吳。鼇抃群島失，鯨吞眾流輸。", "偶逢金華使，握手淚相濡。饑共噬齊棗，眠共席秦蒲。", "既北思攸濟，將南睿所圖。往來固無咎，何忽憚前桴。"]'),
('yuding-17','紹隆寺','沈佺期','唐','御定全唐诗','yuding','','[]','吾從釋迦久，無上師涅盤。探道三十載，得道天南端。',120,'御定全唐詩/json/095.json','["吾從釋迦久，無上師涅盤。探道三十載，得道天南端。", "非勝適殊方，起喧歸理難。放棄乃良緣，世慮不曾幹。", "香界縈北渚，花龕隱南巒。危昂階下石，演漾窗中瀾。", "雲蓋看木秀，天空見藤盤。處俗勒宴坐，居貧業行壇。", "試將有漏軀，聊作無生觀。了然究諸品，彌覺靜者安。"]'),
('yuding-18','神龍初廢逐南荒途出郴口北望蘇耽山','沈佺期','唐','御定全唐诗','yuding','','[]','少曾讀仙史，知有蘇耽君。流望來南國，依然會昔聞。',120,'御定全唐詩/json/095.json','["少曾讀仙史，知有蘇耽君。流望來南國，依然會昔聞。", "泊舟問耆老，遙指孤山雲。孤山郴郡北，不與眾山群。", "重崖下縈映，嶛嶢上糾紛。碧峰泉附落，紅壁樹傍分。", "選地今方爾，升天因可雲。不才予竄跡，羽化子遺芬。", "將覽成麟鳳，旋驚禦鬼文。此中迷出處，含思獨氛氳。"]'),
('yuding-19','初達驩州','沈佺期','唐','御定全唐诗','yuding','','[]','流子一十八，命予偏不偶。配遠天遂窮，到遲日最後。',84,'御定全唐詩/json/095.json','["流子一十八，命予偏不偶。配遠天遂窮，到遲日最後。", "水行儋耳國，陸行雕題藪。魂魄遊鬼門，骸骨遺鯨口。", "夜則忍饑臥，朝則抱病走。搔首向南荒，拭淚看北斗。", "何年赦書來，重飲洛陽酒。"]');
